export const ZH_AGENT_GUIDES: Record<string, AgentGuideCopy> = {
  'claude-code': {"title": "Claude Code 做设计 — Open Design", "description": "设计师如何用 Claude Code 做 UI 和网页设计，以及 Open Design 如何把它变成真正的设计 Agent —— 本地优先、自带密钥（BYOK），配套精选 skill 与设计系统库。", "breadcrumb": "Claude Code", "label": "Agent · Claude Code", "heading": "用 Claude Code 做设计。", "lead": "Claude Code 是 Anthropic 的终端编码 Agent。已经有很多人用它做 UI、设计系统和落地页。Open Design 把它接进真正的设计工作流 —— 用你自己的 Anthropic 密钥或 Claude 订阅，所有文件留在本地。", "tldrTitle": "一句话", "tldrBody": "只要给 Claude Code「审美」—— 一套设计系统、一个风格 skill、一个截图迭代循环 —— 它就是个强力的设计生成器。Open Design 把这些做成本地优先的开源层。用你自己的密钥指向它，开始设计。", "toc": ["什么是 Claude Code", "用 Claude Code 做设计", "资源", "配合 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Claude Code 变成一个本地优先、开源的设计 agent —— 用你自己的 Anthropic key 或 Claude 订阅、你自己的文件，外面再包一层精选的 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 里使用 Claude Code", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code 被普遍认为是前端品味最好的 coding agent —— 它对界面的推理格外具体，会给出确切的 hex 色值、间距与字号阶梯，并能在大型代码库里跨文件重构 UI 而不丢失主线。但开箱即用时，如果你不给它设计系统、skill 和真实参考，它仍会滑向一种泛泛的样子。这是一份关于如何把 Claude Code 用于 UI、前端与设计系统工作，并将它接入 Open Design 结构化工作流的端到端实战指南。", "本文涵盖 Claude Code 到底是什么、它为何擅长前端、如何从零搭建、CLAUDE.md 与 Skills 工作流、官方的 Figma 往返、它与 Codex 和 Cursor 的对比、让 AI 产出显得套路化的那些坑，以及 Open Design 如何作为开源、本地优先的设计层来补上这道缺口。"], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Claude Code 设计反馈闭环：终端里做出具体设计决策的 agent、渲染 UI 的浏览器，以及一个工作区，由一条反馈箭头回环", "caption": "核心闭环：Claude Code 在终端里推理出具体的 UI 决策，在真实浏览器里渲染并验证，再对照参考不断收敛。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-claude-code", "label": "Claude Code 究竟是什么"}, {"id": "why-design", "label": "Claude Code 为何擅长设计"}, {"id": "setup", "label": "从零搭建用于设计的 Claude Code"}, {"id": "skills-workflow", "label": "CLAUDE.md 与 Skills 工作流"}, {"id": "figma", "label": "Claude Code + Figma 往返"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "常见坑与“AI 套路感”"}, {"id": "open-design", "label": "在 Open Design 里用 Claude Code 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-claude-code", "heading": "Claude Code 究竟是什么", "blocks": [{"kind": "p", "text": "Claude Code 是 Anthropic 的 agentic 编码工具。它读取你的代码库、编辑文件、运行命令、与你的开发工具集成 —— 从自然语言任务出发去规划、编写并验证，而不只是补全几行代码。"}, {"kind": "p", "text": "它有多个共享同一引擎的形态：终端 CLI、面向 VS Code / Cursor / JetBrains 的 IDE 扩展、带可视化 diff 审阅的桌面应用，以及用于长时任务的网页端。你的 CLAUDE.md 文件、设置与 MCP server 在所有形态间通用。"}, {"kind": "steps", "items": [{"label": "指令文件", "body": "Claude Code 在每次会话开始时读取项目根目录下的 CLAUDE.md —— 这正是写入你的设计规范、token 与审阅清单的天然位置。"}, {"label": "Skills", "body": "Agent Skills 把可复用的指令、脚本与资源打包，由 Claude 按需加载，其中就包括 Anthropic 官方的 Frontend Design skill 来注入品味。"}, {"label": "Plan 与 subagent", "body": "它能先规划再动手，并可派生 subagent 并行处理任务的不同部分，从而让大型 UI 重构保持连贯。"}]}, {"kind": "ul", "items": ["厂商：Anthropic", "凭证：Anthropic API key（BYOK，经 Console）或 Claude 订阅（Pro / Max）", "形态：终端 CLI、VS Code / Cursor / JetBrains 扩展、桌面应用、网页端"]}]}, {"id": "why-design", "heading": "Claude Code 为何擅长设计", "blocks": [{"kind": "p", "text": "在一众 coding agent 里，Claude Code 在前端工作上以“有品味”著称。原因有几点。"}, {"kind": "steps", "items": [{"label": "决策具体，不含糊", "body": "Claude Code 倾向于落到确切的选择 —— 精确的 hex 色值、间距阶梯、字号 ramp 与组件层级，而不是泛泛而谈，而这正是真实界面与占位草稿的分水岭。"}, {"label": "理解代码库的推理", "body": "凭借较大的工作上下文，它能一次性跨多文件重构 UI，复用你已有的组件与 token，而不是另造一套一次性样式。"}, {"label": "官方前端 skill", "body": "Anthropic 提供 Frontend Design skill，让 Claude 先写出设计方向，并刻意避开泛用系统字体与可预料的紫色渐变。"}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "展示设计系统、skill 与参考图三者汇聚成优质设计产出的示意图", "caption": "品味来自你提供的三项输入：设计系统、skill，以及真实参考图。"}, {"kind": "p", "text": "这和 Anthropic 对自家模型的说法一致：Claude 默认并没有品味 —— 放任不管，它会收敛到网页设计的统计中心（Inter、紫色渐变、柔和阴影）。给它约束，它才能产出好设计。Open Design 恰恰把这些输入打包好了，这也是两者天然契合之处（详见下文）。"}]}, {"id": "setup", "heading": "从零搭建用于设计工作的 Claude Code", "blocks": [{"kind": "p", "text": "下面是从一台干净机器到一个能构建并验证 UI 的 Claude Code 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Claude Code（推荐原生安装）\ncurl -fsSL https://claude.ai/install.sh | bash\n# 或：brew install --cask claude-code\n# Windows PowerShell：irm https://claude.ai/install.ps1 | iex\n\n# 2. 在你的项目里启动，首次运行时登录\ncd your-project\nclaude            # 用 Claude 订阅或 API key 登录\n\n# 3. 生成项目上下文\n/init             # 为本项目创建 CLAUDE.md\n\n# 4. 添加官方 Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. 接入 Figma MCP server（可选，用于设计交付）\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "五步搭建流程：安装、认证、配置 CLAUDE.md、添加 skill、验证", "caption": "搭建顺序：安装 → 认证 → 配置 CLAUDE.md → 添加 Frontend Design skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "把设计规则写进去", "body": "把你的 token、基础原语与约定放进 CLAUDE.md 并让 Claude 指向它们，这样产出会贴合品牌，而不是退回到泛用样子。"}, {"label": "加上浏览器验证", "body": "接入 Playwright 或 Chrome MCP，让 Claude 在真实浏览器里渲染，并跨断点检查产出，而不仅仅确认构建通过。"}]}]}, {"id": "skills-workflow", "heading": "CLAUDE.md 与 Skills 工作流", "blocks": [{"kind": "p", "text": "用 Claude Code 做设计、杠杆最高的闭环，是把真实参考连同你的设计上下文一起喂给它，再迭代到 UI 对得上 —— 由 CLAUDE.md 和 Skills 承载约束，免得你每次 prompt 都重新解释一遍。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考出发 —— 而且要包含多种状态（桌面与移动、hover、空态、加载态），不要只给一张 hero 图。", "在 prompt 里说具体；即便是强 agent，含糊的 prompt 也只会产出泛泛的 UI。", "把你的设计系统与约定放进 CLAUDE.md，并告诉 Claude token 与标准原语在哪里。", "添加 Frontend Design skill，让 Claude 在写代码前先确定一个真实的美学方向。", "接好浏览器验证，让 Claude 渲染、调整到各断点，并对照参考做比对 —— 而不只是确认能构建通过。"]}, {"kind": "p", "text": "把一张参考图丢进会话，并用具体约束去提示："}, {"kind": "code", "lang": "bash", "code": "claude \"把 reference-desktop.png 和 reference-mobile.png 用\n  React + Vite + Tailwind + TypeScript 实现。\n  复用 CLAUDE.md 里描述的设计系统组件与 token。\n  匹配间距、布局与层级；做成响应式。\n  在浏览器里渲染，跨断点验证它与参考一致，\n  并迭代到对得上为止。\""}, {"kind": "p", "text": "同时跑一个 dev server，prompt 保持小而聚焦，好的迭代就 commit、坏的就 revert（revert 时告诉 Claude 一声），让每一轮都在干净的基础上推进。较大的重构用 plan 模式，这样动文件前你能先审一遍方案。"}]}, {"id": "figma", "heading": "Claude Code + Figma：设计 ↔ 代码往返", "blocks": [{"kind": "p", "text": "2026 年 2 月，Anthropic 与 Figma 通过 Figma MCP server 推出了一流的双向集成。它在两个方向都能用。"}, {"kind": "steps", "items": [{"label": "设计 → 代码", "body": "在 Figma 里选中一个 frame，或把链接粘进 Claude Code，拉取设计上下文，让它用你已有的组件库来实现这份设计。Code Connect 会让产出与你真实的组件保持对齐。"}, {"label": "代码 → 设计", "body": "在浏览器里构建并预览一个功能，然后说一句“Send this to Figma”，把运行中的 UI 捕获为可编辑的 Figma 图层 —— 整屏或选中的某个元素皆可。"}]}, {"kind": "p", "text": "用 claude plugin install figma@claude-plugins-official 安装一次即可（Dev Mode MCP 需要 Figma 付费方案）。同一个 Figma MCP 对 Claude Code、Codex、Cursor 与 VS Code 都可用 —— 正是 Open Design 所要编排的那类可移植、多 agent 能力。"}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor 做设计", "blocks": [{"kind": "p", "text": "设计工作没有唯一赢家 —— 每个 agent 各有所长，有经验的团队会把它们叠着用。一个公允的概括："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Claude Code", "具体的设计决策（hex、间距、字号）与理解代码库的 UX 推理", "前端推理与大上下文重构"], ["Codex", "强视觉打磨与图像理解；沙箱化异步构建", "委派式异步构建与可移植的 AGENTS.md 规则"], ["Cursor", "带实时预览与内联编辑的“边做边看”闭环", "IDE 内紧凑的“迭代-观察”式 UI 工作"]]}, {"kind": "p", "text": "社区反复得出的结论是：品味来自人。三者在没有 skill、参考与约束时都会默认滑向泛用美学。这才是真正要解决的问题 —— 它是设计工具形状的，而非模型形状的。"}]}, {"id": "pitfalls", "heading": "常见坑，以及如何避开“AI 套路感”", "blocks": [{"kind": "p", "text": "即便 Claude Code 以有品味著称，对 AI 生成设计最常见的吐槽仍是它显得套路 —— Inter 字体、白底上的紫色渐变、柔和阴影、过大的圆角，一种“一看就是 AI 做的”的观感。Anthropic 自己把这归因于分布收敛：安全的选择在网页训练数据里占主导。其他被反映的问题还包括移动端布局错乱、以及指令文字漏进了 UI 文案。"}, {"kind": "steps", "items": [{"label": "装上 Frontend Design skill", "body": "它会逼 Claude 确定一个真实方向，并明确避开被 AI 滥用的字体与渐变。"}, {"label": "启用浏览器验证", "body": "让 Claude 渲染并跨断点自检，避免布局在移动端悄悄崩掉。"}, {"label": "提供 token 与参考", "body": "真实的设计 token 与参考截图，是对产出质量影响最大的单一杠杆。"}, {"label": "把规则写进 CLAUDE.md", "body": "把“不用 hero 卡片、最多两种字体、品牌优先的层级”这类规则，放在 agent 每次都会读到的地方。"}]}, {"kind": "p", "text": "注意每一条缓解措施，本质都是在给 agent 一份精选的设计上下文。逐个项目手工维护这份上下文，正是 Open Design 替你省掉的苦差。"}]}, {"id": "open-design", "heading": "在 Open Design 里用 Claude Code 做设计", "blocks": [{"kind": "p", "text": "Open Design 就是上面那套工作流一直在呼唤的开源设计层。它把 Claude Code 当作一等适配器，并在外面包上一层精选的 skill 与设计系统库、一条结构化渲染流水线，以及一个本地桌面 UI —— 让那份令 Claude Code 出彩的设计上下文，从第一次运行就在位，而不必每次手工拼装。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 Claude Code 作为你的 agent。", "用你的 Anthropic API key（BYOK）或 Claude 订阅认证 —— 凭证留在你自己机器上，绝不经我们中转。", "挑一套设计系统与一个 skill，然后产出风格一致的 deck、原型与落地页。", "每一件产物与 DESIGN.md 文件都存在你自己的仓库里，而非托管云端。"]}, {"kind": "p", "text": "同一个 Claude Code agent、同一把 key —— 外加一套真实、可移植、开源的设计工作流。它本地优先、Apache-2.0，所以你的工作与凭证都不会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Claude Code 适合做设计吗？", "text": "适合 —— 它被普遍认为是前端品味最好的 coding agent，会对 hex 色值、间距与字号阶梯做出具体且理解代码库的决策。配上 Frontend Design skill、一套设计系统与真实参考图，它能产出生产级、响应式的 UI 并在浏览器里验证。缺了这份上下文，它就容易退回泛用样子 —— 这正是 Open Design 要补的缺口。"}, {"name": "用 Claude Code 做设计需要 Claude 订阅吗？", "text": "你可以用 Anthropic API key（BYOK，经 Console）或 Claude 订阅（Pro / Max），两者皆可。无论哪种，Open Design 都不会中转你的凭证 —— 它们由你的 agent 在你机器上直接使用。"}, {"name": "前端设计该用 Claude Code 还是 Codex？", "text": "两者都很强。Claude Code 以具体、理解代码库的设计决策与前端推理著称；Codex 视觉打磨强，擅长委派式的沙箱构建。很多团队两者都用 —— Open Design 让你切换 agent 而无需改动设计工作流。"}, {"name": "怎么把 Claude Code 接到 Figma？", "text": "用 claude plugin install figma@claude-plugins-official 安装官方 Figma 插件。之后你就能借助设计上下文在代码里实现 Figma frame，并用“Send this to Figma”把运行中的 UI 推回成可编辑的 Figma 图层。Dev Mode MCP 需要 Figma 付费方案。"}, {"name": "Skills 和 CLAUDE.md 是什么？", "text": "CLAUDE.md 是你项目根目录里的一个 markdown 文件，Claude Code 在每次会话开始时都会读它 —— 这是写入设计规范的地方。Skills 把可复用的指令与资源打包，由 Claude 按需加载，其中包括 Anthropic 官方的 Frontend Design skill。Open Design 把两者都做成精选库，帮你免去逐项目搭建。"}, {"name": "怎么避开泛用的“AI 套路感”？", "text": "装上 Frontend Design skill，提供真实的设计 token 与参考截图，把品牌规则写进 CLAUDE.md，并启用浏览器验证。Open Design 把这些做成精选库，帮你免去逐项目搭建。"}, {"name": "Open Design 和 Anthropic 有从属关系吗？", "text": "没有。Claude Code 是 Anthropic 的产品；Open Design 是一个独立的开源项目，把它作为一等适配器来支持。Claude 与 Claude Code 是 Anthropic 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全 —— Open Design 本地优先、Apache-2.0。你的文件、产物与 DESIGN.md 都留在你自己的仓库里，你的 Anthropic 凭证由你的 agent 直接使用，绝不经 Open Design 服务器中转。"}], "ctaTitle": "用开放的方式，和 Claude Code 一起做设计。", "ctaBody": "带上你自己的 Anthropic key 或 Claude 订阅，把每个文件都留在本地，再给你已在用的 agent 包上一层精选设计库。", "ctaActions": [{"label": "在 Open Design 里使用 Claude Code", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "See all supported agents"}, "aboutTitle": "什么是 Claude Code", "aboutBody": ["Claude Code 是 Anthropic 的命令行 Agent：你用自然语言描述任务，它在你的项目里读写、运行代码，直到任务完成。", "它是编码 Agent，不是设计工具 —— 但设计是它最强的衍生用途之一。给足 skill 和设计系统上下文后，它能生成生产级 HTML/CSS/React，按截图迭代，维护设计 token。", "Open Design 把 Claude Code 作为一方适配器，让你写代码的同一个 Agent，成为结构化设计工作流背后的引擎。"], "vendorLabel": "厂商", "vendor": "Anthropic", "credentialLabel": "凭据", "credential": "Anthropic API key（BYOK）或 Claude 订阅", "designTitle": "用 Claude Code 做设计", "designLead": "社区已经摸索出几种范式，让 Claude Code 从通用代码生成器变成有真正设计判断力的工具：", "designPoints": [{"label": "先给设计系统", "body": "把 DESIGN.md / token / Tailwind 配置放进项目，让输出贴合品牌，而不是默认输出「AI 味」。"}, {"label": "审美 skill", "body": "Anthropic 的 frontend-design 这类 skill 会让它在写任何代码前先锁定排版／配色／动效方向。"}, {"label": "Figma → 代码", "body": "接入 Figma MCP，Claude Code 就能把 frame 转成带真实 token 的生产组件。"}, {"label": "截图循环", "body": "让它给自己的 UI 截图、对照参考图、反复迭代 —— Agent 式的设计反馈闭环。"}], "linksTitle": "实战资源", "linksLead": "大家真正在用来用 Claude Code 做设计的教程、skill 和实录：", "links": [{"label": "Designing with Claude Code (Steve Schoger, Tailwind Labs)", "href": "https://www.youtube.com/watch?v=lkKGQVHrXzE", "source": "YouTube · Steve Schoger"}, {"label": "Claude Code for Designers in 10 Minutes", "href": "https://www.youtube.com/watch?v=NMi2LnFrUxw", "source": "YouTube · Adrien"}, {"label": "anthropics/skills — frontend-design skill", "href": "https://github.com/anthropics/skills/blob/main/skills/frontend-design/SKILL.md", "source": "GitHub · Anthropic"}, {"label": "Claude Code for designers — full tutorial", "href": "https://www.builder.io/blog/claude-code-for-designers", "source": "Blog · Builder.io"}, {"label": "The web design workflow that actually works", "href": "https://tutorialsdojo.com/claude-code-the-web-design-workflow-that-actually-works/", "source": "Blog · Tutorials Dojo"}], "withOdTitle": "Claude Code + Open Design", "withOdLead": "Open Design 正是 Claude Code 缺的那层设计能力：精选的 skill 与设计系统库、结构化的渲染流水线、一个桌面 UI —— 全开源、本地优先。", "withOdSteps": ["安装 Open Design，选 Claude Code 作为你的 Agent。", "用你自己的 Anthropic API key（BYOK）或 Claude 订阅鉴权 —— 不经过我们中转。", "选一套设计系统和一个 skill，生成审美一致的 deck、原型和落地页。", "所有产物和 DESIGN.md 都留在你自己的 repo。"], "withOdClosing": "同一个 Agent、同一个密钥 —— 外加一套真正的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Claude Code 真能做设计吗？", "text": "能。给它设计系统和审美 skill 上下文，它就能生成生产级 UI。Open Design 把这两样开箱即用地配好，省去你搭环境。"}, {"name": "需要 Claude 订阅吗？", "text": "Anthropic API key（BYOK）或 Claude 订阅都行。Open Design 从不中转你的凭据。"}, {"name": "这是 Anthropic 官方产品吗？", "text": "不是。Open Design 是独立的开源项目。Claude Code 是 Anthropic 的商标，我们以一方适配器的方式集成它。"}], "ctaTitle": "用开源的方式，跟 Claude Code 一起设计。", "ctaBody": "给仓库点 Star、下载桌面版，或加入社区申请新适配器。"},
  codex: {"title": "Codex 做设计：用 OpenAI Codex 搭 UI — Open Design", "description": "用 OpenAI Codex 做 UI 和前端的实操指南 —— 从环境配置、Figma 集成、skill，到怎么避开千篇一律的「AI 味」。Open Design 把 Codex 变成一个免费、本地优先的开源设计 Agent。", "breadcrumb": "Codex", "label": "Agent · Codex", "heading": "用 Codex 做设计。", "lead": "Codex 是 OpenAI 的编码 Agent。靠 Product Design 插件和 Figma 集成，它已经成了一个正经的设计工具。Open Design 把 Codex 接进开源设计工作流 —— 你自己的 OpenAI 密钥或 ChatGPT 订阅，你自己的文件，本地优先。", "tldrTitle": "一句话", "tldrBody": "Codex 能把截图和用户故事变成响应式 UI，还能把设计往返同步到 Figma。Open Design 给它配上精选的设计系统与 skill 库，外加桌面工作流 —— 自带密钥，所有东西留在本地。", "toc": ["什么是 Codex", "用 Codex 做设计", "资源", "配合 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Codex 变成本地优先的开源设计 Agent —— 你自己的 OpenAI 密钥、你自己的文件，外加一套围绕它的精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 里用 Codex", "href": "/quickstart/", "variant": "primary"}, {"label": "给 GitHub 点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面客户端", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Codex 最初只是个代码生成器，但到 2026 年，只要你给对参考、skill 和验证回路，它已经能设计出真正可用的界面。这是一篇端到端的实操指南：怎么用 Codex 做 UI、前端和设计系统，以及怎么用 Open Design 把它接进结构化的设计工作流。", "内容覆盖：Codex 现在到底是什么、为什么它突然擅长前端、怎么从零配好、截图转 UI 的回路、官方的 Figma 双向打通、它跟 Cursor 与 Claude Code 的差异、让 AI 输出显得千篇一律的那些坑，以及 Open Design 作为开源、本地优先的设计层怎么补上缺口。"], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Codex 设计反馈回路：终端 Agent、浏览器渲染 UI、工作区，带一条回流箭头", "caption": "核心回路：Codex 在终端里构建 UI，在真实浏览器里渲染并验证，再对着你的参考图迭代。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-codex", "label": "Codex 到底是什么"}, {"id": "why-design", "label": "为什么 Codex 现在能做设计"}, {"id": "setup", "label": "从零配好 Codex 做设计"}, {"id": "screenshot-workflow", "label": "截图转 UI 的工作流"}, {"id": "figma", "label": "Codex + Figma 双向打通"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "常见坑与「AI 味」"}, {"id": "open-design", "label": "在 Open Design 里用 Codex"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-codex", "heading": "Codex 到底是什么（以及不是什么）", "blocks": [{"kind": "p", "text": "先消歧，几乎每个搜「Codex」的人都会被绊一下。最早的 OpenAI Codex 是 2021 年的代码补全模型，驱动过早期 GitHub Copilot，2023 年已弃用。本文讲的不是它。今天的 Codex 是 OpenAI 的 Agent 式编码工具 —— 从自然语言任务出发，规划、编写、运行并验证代码。"}, {"kind": "p", "text": "现代 Codex 有四种形态：终端 CLI（用 Rust 重写、Apache-2.0 开源）、面向 VS Code / Cursor / Windsurf 的 IDE 扩展、用于异步委派任务的云端/网页版，以及带内置浏览器和 Computer Use 的桌面 App。"}, {"kind": "steps", "items": [{"label": "默认模型", "body": "截至 2026 年中，推荐模型是 gpt-5.5；而 gpt-5.4 是 OpenAI 明确为前端和 Computer Use 训练的那个模型。"}, {"label": "指令文件", "body": "Codex 读取项目里的 AGENTS.md（跨工具通用标准）作为项目规则 —— 也就是写你设计约定最自然的地方。"}, {"label": "沙箱", "body": "它跑在内核级沙箱里（默认 workspace-write），改你 UI 的 Agent 不会跑到项目之外乱动。"}]}, {"kind": "ul", "items": ["厂商：OpenAI", "凭据：OpenAI API key（BYOK）或 ChatGPT 订阅（Free / Go / Plus / Pro / Business / Enterprise）", "CLI 许可：Apache-2.0，开源"]}]}, {"id": "why-design", "heading": "为什么 Codex 现在能做设计", "blocks": [{"kind": "p", "text": "2026 年初有三件事凑到一起，才让 Codex 从通用代码生成器变成真正的设计工具。"}, {"kind": "steps", "items": [{"label": "一个为前端训练的模型", "body": "OpenAI 发布了 GPT-5.4 —— 它第一个主线版为前端和 Computer Use 训练的模型，对设计流程里的图像理解大幅提升，自我验证也更强，甚至能在定稿前先生成情绪板和多个视觉方案。"}, {"label": "一个官方前端 skill", "body": "openai/skills 目录里有一个精选 frontend-skill，强制真审美：无卡片布局、整屏 hero、品牌优先的层级、克制的动效、最多两种字体加一个强调色 —— 还逼 Codex 先写「视觉论点」再动手。"}, {"label": "浏览器验证", "body": "配上 Playwright skill，Codex 会真开浏览器、按断点缩放，并把输出跟参考图比对，而不只是「构建通过」就完事。"}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "设计系统、skill、参考图三者汇聚成优质设计输出的示意图", "caption": "审美来自你提供的三种输入：设计系统、skill 和真实参考图。"}, {"kind": "p", "text": "三件事背后的道理是一样的：Codex 默认没有审美。只有当你给它约束 —— 设计系统、审美 skill、具体参考 —— 它才能产出好设计。Open Design 打包的正是这三种输入，这也是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零配好 Codex 做设计", "blocks": [{"kind": "p", "text": "从一台干净的机器，到一个能构建并验证 UI 的 Codex，完整路径如下。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Codex CLI\nnpm install -g @openai/codex\n# 或：brew install --cask codex\n# 或：curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. 鉴权（推荐用 ChatGPT 登录，额度更高）\ncodex            # 然后选 “Sign in with ChatGPT”\n\n# 3. 生成项目上下文\ncodex            # 在项目里运行 /init 生成 AGENTS.md\n\n# 4. 装官方前端 skill，然后重启 Codex\n# （在 Codex App 里）$skill-installer frontend-skill\n\n# 5. 接 Figma MCP server（可选，做设计交付）\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "五步配置流程：安装、鉴权、配置、装 skill、验证", "caption": "配置顺序：安装 → 鉴权 → 配 AGENTS.md → 装前端 skill → 开浏览器验证。"}, {"kind": "steps", "items": [{"label": "把设计规则写进去", "body": "把 token、基础组件、约定写进 AGENTS.md 或 DESIGN.md 并让 Codex 指向它们，输出就会贴合品牌，而不是退回那套通用样子。"}, {"label": "选对推理档位", "body": "OpenAI 提到：低到中等推理档位的前端效果，往往比最高档更好。"}]}]}, {"id": "screenshot-workflow", "heading": "截图转 UI 的工作流", "blocks": [{"kind": "p", "text": "Codex 做设计最高杠杆的回路，是把参考图变成可用的响应式 UI，再迭代到对齐为止。OpenAI 官方指引归纳为五步。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考出发 —— 而且要包含多个状态（桌面和移动、hover、空态、加载态），不只是一张 hero 图。", "prompt 要具体；含糊的 prompt 只会产出通用 UI。", "准备好设计系统，并告诉 Codex token 和基础组件在哪。", "开启 Playwright 交互 skill，让 Codex 真在浏览器里渲染并按断点缩放。", "迭代时让 Codex 把实现跟截图比对 —— 而不只是确认「能构建」。"]}, {"kind": "p", "text": "喂图可以把截图拖进终端，或用 image 参数，然后用具体约束来 prompt："}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"用 React + Vite + Tailwind + TypeScript 实现这个设计。\n   尽量复用我现有的设计系统组件和 token。\n   对齐间距、布局和层级；做成响应式。\n   用 Playwright skill 验证 UI 跟参考图一致，\n   不一致就一直迭代。\""}, {"kind": "p", "text": "在第二个终端里跑 dev server，prompt 保持小而聚焦，好的迭代就 commit、坏的就 revert（并告诉 Codex 你回退了），这样每一轮都在干净的基础上推进。"}]}, {"id": "figma", "heading": "Codex + Figma：设计 ↔ 代码双向打通", "blocks": [{"kind": "p", "text": "2026 年 2 月 OpenAI 和 Figma 宣布官方合作，把早先的 Figma MCP beta 升级成一等公民级的双向集成。两个方向都能走。"}, {"kind": "steps", "items": [{"label": "设计 → 代码", "body": "在 Figma 里复制某个 frame 的「link to selection」，粘进 Codex 配合 get_design_context，让它用你现有的组件库实现这个设计。"}, {"label": "代码 → 设计", "body": "generate_figma_design 工具（「Code to Canvas」）能把跑起来的 UI 变回可编辑的 Figma frame —— 整屏、选中元素或整个文件都行。"}]}, {"kind": "p", "text": "Figma MCP 以远程 server 形式运行且免限流。接一次，Codex、Claude Code、Cursor、VS Code 等都能用 —— 这种可移植的多 Agent 能力，正是 Open Design 要编排的东西。"}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code 做设计", "blocks": [{"kind": "p", "text": "做设计没有唯一赢家 —— 每个 Agent 强在不同地方，老手会叠着用。公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Codex", "GPT-5.4 + 前端 skill 之后视觉打磨很强；图像理解好", "异步委派构建、沙箱化运行、可移植的 AGENTS.md 规则"], ["Cursor", "边改边看的视觉回路，带实时预览和行内编辑", "IDE 里贴身迭代、即时观察的 UI 工作"], ["Claude Code", "具体的设计决策（hex、间距、字体）和懂代码库的 UX", "前端推理和大上下文重构"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人。三者在没有 skill、参考和约束时，都会退回通用样子。这才是要解决的真问题 —— 而它是「设计工具」形状的，不是「模型」形状的。"}]}, {"id": "pitfalls", "heading": "常见坑，以及怎么避开「AI 味」", "blocks": [{"kind": "p", "text": "对 Codex 生成设计最常见的吐槽是「显得通用」—— 柔和渐变、漂浮面板、超大圆角、夸张阴影，那种 Inter 字体加紫色的味道，「一看就是 AI 做的」。其他常见问题还有移动端布局崩、指令文案泄漏进 UI、以及很快撞到用量上限。"}, {"kind": "steps", "items": [{"label": "装一个前端 skill", "body": "精选的审美 skill 逼 Codex 选定一个真方向，而不是默认那套样子。"}, {"label": "开启 Playwright 验证", "body": "让 Codex 跨断点渲染并自检，布局就不会在移动端悄悄崩。"}, {"label": "喂 token 和参考", "body": "真实的设计 token 和参考截图，是对输出质量影响最大的那个杠杆。"}, {"label": "把规则写进 AGENTS.md", "body": "把「不要 hero 卡片、最多两种字体、品牌优先层级」这类规则放在 Agent 每次都会读到的地方。"}]}, {"kind": "p", "text": "注意：每条缓解措施，本质都是给 Agent 一套精选的设计上下文。而逐个项目手工维护这套上下文，正是 Open Design 帮你省掉的苦活。"}]}, {"id": "open-design", "heading": "在 Open Design 里用 Codex", "blocks": [{"kind": "p", "text": "Open Design 就是上面这套工作流一直在呼唤的那个开源设计层。它把 Codex 当作一方适配器，外面包上精选的 skill 与设计系统库、结构化渲染流水线、本地桌面 UI —— 让那些让 Codex 变好的设计上下文从第一次运行就在，而不是每次手工拼。"}, {"kind": "ol", "items": ["安装 Open Design，选 Codex 作为你的 Agent。", "用 OpenAI API key（BYOK）或 ChatGPT 订阅鉴权 —— 凭据留在你机器上，绝不经我们中转。", "选一套设计系统和一个 skill，生成审美一致的 deck、原型和落地页。", "每个产物和 DESIGN.md 都在你自己的 repo 里，不在托管云端。"]}, {"kind": "p", "text": "同一个 Codex Agent、同一把密钥 —— 外加一套真正可移植的开源设计工作流。它本地优先、Apache-2.0，你的工作和凭据都不离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "OpenAI Codex 真的能做设计吗？", "text": "能 —— 只要上下文里有前端 skill、设计系统和真实参考图，Codex（尤其在 GPT-5.4 上）能产出生产级、响应式的 UI，还能在浏览器里自检。没有这套上下文它就会退回通用样子，而这正是 Open Design 补的缺口。"}, {"name": "这是 OpenAI 的 Codex Product Design 插件吗？", "text": "不是。Open Design 是独立开源项目，把 Codex 作为 Agent 集成，用本地优先的开源 skill 与设计系统库补充官方工具。"}, {"name": "用 Codex 做设计需要 ChatGPT 订阅吗？", "text": "OpenAI API key（BYOK）或 ChatGPT 订阅都行。ChatGPT 登录通常额度更高；无论哪种，Open Design 都不中转你的凭据。"}, {"name": "前端设计该用 Codex 还是 Claude Code？", "text": "两个都强。Claude Code 以具体、懂代码库的设计决策见长；Codex 在 GPT-5.4 之后视觉打磨很强，且擅长沙箱化的异步委派构建。很多团队两个都用 —— Open Design 让你换 Agent 时不用换设计工作流。"}, {"name": "怎么把 Codex 接到 Figma？", "text": "加上官方 Figma MCP server（codex mcp add figma --url https://mcp.figma.com/mcp）。之后用 get_design_context 把 Figma frame 实现成代码，用 generate_figma_design 把跑起来的 UI 推回可编辑的 Figma frame。"}, {"name": "怎么避免那种通用的「AI 味」审美？", "text": "装一个前端 skill、喂真实的设计 token 和参考截图、把品牌规则写进 AGENTS.md、并开启 Playwright 验证。Open Design 把这些做成精选库，你就省掉了逐项目的配置。"}, {"name": "Open Design 跟 OpenAI 有关联吗？", "text": "没有。Codex 是 OpenAI 的产品；Open Design 是独立开源项目，以一方适配器的方式支持它。OpenAI 和 Codex 是 OpenAI 的商标。"}, {"name": "我的文件和凭据安全吗？", "text": "安全 —— Open Design 本地优先。你的文件、产物和 DESIGN.md 都留在自己的 repo，OpenAI 凭据由你的 Agent 直接使用，绝不经 Open Design 服务器中转。"}], "ctaTitle": "用开源的方式，跟 Codex 一起设计。", "ctaBody": "自带 OpenAI 密钥、所有文件留在本地，给你已经在用的 Agent 配上一套精选设计库。", "ctaActions": [{"label": "在 Open Design 里用 Codex", "href": "/quickstart/", "variant": "primary"}, {"label": "给 GitHub 点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面客户端", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看全部支持的 Agent"}, "aboutTitle": "什么是 Codex", "aboutBody": ["Codex 是 OpenAI 的 Agent 式编码系统 —— 一个 CLI 加 ChatGPT 集成的 Agent，从自然语言任务规划、写、跑代码。", "OpenAI 现在提供面向角色的 Product Design 插件和 Figma 集成，Codex 可以探索方向、审查用户流程、从在线 URL 出原型，并导出到 Figma 或 Canva。", "Open Design 把 Codex 作为一方适配器，让它嵌入结构化的开源设计流水线。"], "vendorLabel": "厂商", "vendor": "OpenAI", "credentialLabel": "凭据", "credential": "OpenAI API key（BYOK）或 ChatGPT 订阅", "designTitle": "用 Codex 做设计", "designLead": "Codex 的设计能力在 2026 年快速成型，主要围绕几项官方和社区能力：", "designPoints": [{"label": "Product Design 插件", "body": "OpenAI 的角色插件：探索方向、审查用户流程、从在线 URL 出原型、把截图变可交互、导出 Figma/Canva。"}, {"label": "截图 → 响应式 UI", "body": "Codex 把参考图变成响应式代码，并用 Playwright skill 在各断点上跟参考图做视觉比对。"}, {"label": "Codex ↔ Figma", "body": "Figma MCP 把设计上下文带进代码，再把运行中的 UI 变回可编辑的 Figma frame。"}, {"label": "前端设计 skill", "body": "社区和官方 skill 锁定审美方向，避免输出千篇一律的「紫色 AI 味」。"}], "linksTitle": "实战资源", "linksLead": "用 Codex 做设计的官方文档、Figma 集成和实录：", "links": [{"label": "Build responsive front-end designs (Codex docs)", "href": "https://developers.openai.com/codex/use-cases/frontend-designs", "source": "Docs · OpenAI"}, {"label": "Introducing Codex to Figma", "href": "https://www.figma.com/blog/introducing-codex-to-figma/", "source": "Blog · Figma"}, {"label": "Design with ChatGPT and Codex: The Designer’s Guide", "href": "https://www.youtube.com/watch?v=rW7vVVmKTS8", "source": "YouTube · UI Collective"}, {"label": "openai/skills — frontend design skills", "href": "https://github.com/openai/skills", "source": "GitHub · OpenAI"}, {"label": "New Codex design workflow", "href": "https://www.youtube.com/watch?v=CPg5UYbYLhA", "source": "YouTube · Lukas Margerie"}], "withOdTitle": "Codex + Open Design", "withOdLead": "Open Design 是围绕 Codex 的开源设计层：精选 skill 与设计系统库、结构化渲染流水线、本地桌面 UI。", "withOdSteps": ["安装 Open Design，选 Codex 作为你的 Agent。", "用 OpenAI API key（BYOK）或 ChatGPT 订阅鉴权 —— 凭据留在你机器上。", "选一套设计系统和 skill，生成审美一致的 deck、原型和落地页。", "产物和 DESIGN.md 都在你自己的 repo，不在托管云端。"], "withOdClosing": "同一个 Codex Agent —— 外加一套真正可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "这是 OpenAI 的 Codex Product Design 插件吗？", "text": "不是。Open Design 是独立开源项目，把 Codex 作为 Agent 集成，用本地优先的开源库补充官方插件。"}, {"name": "需要 ChatGPT 订阅吗？", "text": "OpenAI API key（BYOK）或 ChatGPT 订阅都行。Open Design 从不中转你的凭据。"}, {"name": "Open Design 跟 OpenAI 有关联吗？", "text": "没有。Codex 是 OpenAI 的产品；Open Design 是独立开源项目，以一方适配器的方式支持它。"}], "ctaTitle": "用开源的方式，跟 Codex 一起设计。", "ctaBody": "给仓库点 Star、下载桌面版，或加入社区申请新适配器。"},
  cursor: {"title": "Cursor 做设计 — Open Design", "description": "设计师如何用 Cursor 做 UI 和网页设计 —— Design Mode、Figma 转代码、Figma MCP —— 以及 Open Design 如何把 Cursor 变成本地优先的开源设计 Agent。", "breadcrumb": "Cursor Agent", "label": "Agent · Cursor", "heading": "Cursor 给设计师。", "lead": "Cursor 是那个 AI 代码编辑器，现在带了可视化 Design Mode。设计师用它点选、勾画来改 UI，也用它把 Figma 转成代码。Open Design 把 Cursor Agent 接进开源设计工作流，文件全留本地。", "tldrTitle": "一句话", "tldrBody": "Cursor 的 Design Mode 让你点击、勾画或用说话来改在线 UI；它的 Figma MCP 集成把真实设计上下文带进代码。Open Design 在上面叠一层精选 skill 与设计系统库 —— 你自己的模型密钥，你自己的 repo。", "toc": ["什么是 Cursor", "用 Cursor 做设计", "资源", "配合 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Cursor 变成一个本地优先、开源的设计 agent——用你自己的 Cursor 账号或模型密钥、你自己的文件，外面再裹一层精选的 skill 与 design-system 库。", "heroCtaActions": [{"label": "在 Open Design 里使用 Cursor", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面端", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor 是一款 AI 优先的代码编辑器，它让“边写边看渲染”成为做 UI 的默认方式。借助 Agent 模式、行内编辑、编辑器内置预览，以及通过 MCP 接入的 Figma，它已经成为一个真正能用的设计工具——前提是你给它对的参考、规则和一套验证回路。这是一份从头到尾、可落地的指南，讲如何用 Cursor 做 UI、前端和 design-system 工作，并把它接入 Open Design 的结构化设计工作流。", "内容涵盖：Cursor 到底是什么、为什么它“边迭代边看”的紧凑回路适合做设计、如何从零搭起、从预览到 UI 的迭代回路、通过 MCP 与 Figma 的往返、它与 Codex 和 Claude Code 的对比、让 AI 产出显得平庸的那些坑，以及 Open Design 作为开源、本地优先的设计层如何补齐这道缺口。"], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Cursor 设计收敛示意：左侧是编辑器，中间是带 Cursor 标志的精选 skill 与 design-system hub，右侧是渲染出的 UI", "caption": "核心思路：Cursor 在编辑器里编辑并渲染 UI，而一个精选的设计 hub 为它喂入设计系统、skill 和参考，让产出显得是有意为之、而非随手生成。"}, "tocLabel": "本页目录", "toc": [{"id": "what-is-cursor", "label": "Cursor 到底是什么"}, {"id": "why-design", "label": "为什么 Cursor 擅长做设计"}, {"id": "setup", "label": "从零配置 Cursor 做设计"}, {"id": "preview-workflow", "label": "从预览到 UI 的工作流"}, {"id": "figma", "label": "Cursor + Figma（经 MCP）"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "常见坑与“AI 味”观感"}, {"id": "open-design", "label": "在 Open Design 里用 Cursor 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-cursor", "heading": "Cursor 到底是什么", "blocks": [{"kind": "p", "text": "Cursor 是 Anysphere 打造的 AI 优先代码编辑器。它是 VS Code 的一个 fork，所以保留了熟悉的编辑器、扩展和快捷键，但把整个工作流围绕一个 AI agent 重建——这个 agent 能读懂你的整个项目、跨多文件编辑、运行命令，并和你一起在回路里迭代。"}, {"kind": "p", "text": "对设计工作而言，关键的几个能力是：Agent 模式（你描述想要的结果，Cursor 规划并跨文件编辑）、用于快速微调的行内编辑与 Tab 补全、让你不离开窗口就能看到运行中 UI 的编辑器内置预览，以及让它能拉入外部上下文（比如一个实时 Figma 文件）的 MCP 支持。"}, {"kind": "steps", "items": [{"label": "项目规则", "body": "Cursor 会读取项目指令文件——`.cursor/rules` 下纳入版本管理的 `.mdc` 规则，以及一个纯文本 `AGENTS.md`——你可以把设计约定写在 agent 每次都会读到的地方。"}, {"label": "模型", "body": "Cursor 在模型上很灵活：订阅自带前沿模型，也支持用你自己的模型密钥（BYOK），所以同一套编辑器工作流背后用哪台引擎由你定。"}, {"label": "MCP", "body": "它支持 Model Context Protocol，外部 server——最相关的就是 Figma MCP server——可以成为 agent 的一等上下文。"}]}, {"kind": "ul", "items": ["厂商：Anysphere", "凭证：Cursor 账号 / 订阅（Hobby / Pro / Business）或你自己的模型密钥（BYOK）", "形态：AI 优先的代码编辑器（VS Code fork），内置 agent 与预览"]}]}, {"id": "why-design", "heading": "为什么 Cursor 擅长做设计", "blocks": [{"kind": "p", "text": "Cursor 在设计上的优势不是某个单一功能，而是“边写边看”这条回路的紧凑度。有三点让它更像一个设计工具，而不是一个泛泛的代码生成器。"}, {"kind": "steps", "items": [{"label": "紧凑的“边迭代边看”回路", "body": "你给出提示，Cursor 跨文件编辑，编辑器内置预览立刻渲染出结果——于是你能在几秒内调整间距、层级和动效，而不必在另一个终端和浏览器之间来回切换。"}, {"label": "直接的可视化编辑", "body": "除了对话，Cursor 还允许你在预览里选中元素、直接微调样式，让小的视觉修正更像设计编辑、而非翻代码考古。"}, {"label": "项目规则与 MCP 上下文", "body": "有了 `.cursor/rules`（或 `AGENTS.md`）和 Figma MCP server，agent 是对着你的 tokens、组件和真实设计规格在工作，而不是靠猜。"}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "展示 design system、skill 与参考图三者收敛为优质设计产出的示意图", "caption": "审美来自你提供的三个输入：一套设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "结论和每个 agent 教给我们的一样：Cursor 默认并没有审美。只有当你给它约束——一套设计系统、一个审美 skill、具体的参考——它才能产出好设计。Open Design 打包的正是这些输入，这也是两者天然契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零把 Cursor 配置成能做设计", "blocks": [{"kind": "p", "text": "下面是从一台干净机器，到一个能对着你的设计系统构建、预览并验证 UI 的 Cursor 的完整路径。"}, {"kind": "ol", "items": ["从 cursor.com 安装 Cursor，用 Cursor 账号登录，或在设置里配置你自己的模型密钥（BYOK）。", "打开你的项目，在对话 / Agent 面板里选一个模型。", "加项目规则：用 `.cursor/rules/*.mdc` 写结构化、按 glob 作用域生效的约定，或用一个纯文本 `AGENTS.md` 写简单可读的指令。", "接入 Figma MCP server（可选），让 agent 能读取实时设计上下文。", "启动你的 dev server，用编辑器内置预览边迭代边看、边验证 UI。"]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "五步配置流程：安装、认证、配置规则、添加 skill、验证", "caption": "配置顺序：安装 → 认证 → 配置项目规则 → 添加 skill → 启用预览验证。"}, {"kind": "p", "text": "一份最简的项目规则文件，就能让 agent 对着品牌做设计、而不是退回到一个泛泛的样子。把它放在 Cursor 每次都会读到的地方："}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- 复用已有的 design-system tokens 和组件；不要写死 hex 或间距。\n- 最多两种字体、一个强调色。\n- 品牌优先的层级；克制的动效。不要 hero card，不要过大的圆角。\n- 默认做响应式；收尾前先在预览里验证桌面端和移动端。"}, {"kind": "steps", "items": [{"label": "把设计规则写下来", "body": "把你的 tokens、基础元件和约定放进 `.cursor/rules` 或 `AGENTS.md`，并让 Cursor 指向它们，这样产出会贴合品牌、而不是退回到泛泛的样子。"}, {"label": "让提示保持小而聚焦", "body": "Cursor 的紧凑回路偏爱聚焦的请求——一次只迭代一个组件或一种状态，每一轮之间都盯着预览看。"}]}]}, {"id": "preview-workflow", "heading": "从预览到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Cursor 做设计，杠杆最高的回路就是把一张参考变成能跑、且响应式的 UI，并在编辑器里一直盯着实时预览迭代到匹配为止——而不是靠猜。"}, {"kind": "ol", "items": ["从你手上最清晰的视觉参考开始——并且要包含多种状态（桌面与移动、hover、空态、加载态），而不只是一张主视觉。", "提示要具体；含糊的提示只会产出泛泛的 UI。", "准备好设计系统，并告诉 Cursor tokens 和标准基础元件都在哪里。", "让编辑器内置预览开着、dev server 跑着，这样每次编辑都能在你关心的断点上立刻渲染出来。", "通过把渲染出的 UI 和参考反复比对来迭代——小的视觉修正就直接在预览里选中元素来调。"]}, {"kind": "p", "text": "把图片附到对话里来喂参考，然后用具体约束给出提示："}, {"kind": "code", "lang": "text", "code": "用 React + Vite + Tailwind + TypeScript 实现这个设计。\n复用我已有的 design-system 组件和 tokens。\n匹配间距、布局和层级；做成响应式。\n预览一直开着——验证桌面端和移动端都和参考一致，\n迭代到一致为止。"}, {"kind": "p", "text": "好的迭代就提交，坏的就回退（回退时告诉 Cursor 一声），让每一轮都建立在干净的基础上——这是让任何 agent 回路不跑偏的同一条纪律。"}]}, {"id": "figma", "heading": "Cursor + Figma：经 MCP 的设计 ↔ 代码往返", "blocks": [{"kind": "p", "text": "Cursor 通过官方的 Figma MCP server 连接 Figma，让 agent 对一个实时 Figma 文件有结构化访问，而不是只拿到一张扁平截图。这就把交接里的猜测成分去掉了。"}, {"kind": "steps", "items": [{"label": "设计 → 代码", "body": "在 Figma 里复制某个 frame 的链接，粘进 Cursor，让它去实现这个设计。MCP server 暴露的是真实的设计上下文——组件、变量、布局数据、tokens——所以生成的代码是贴合源文件的，而不是近似。"}, {"label": "保持对齐", "body": "只要在 Figma 里一致地使用设计 tokens、样式和组件（有 Code Connect 时用上），Cursor 的产出就会映射到你真实的设计系统，而不是重新发明一套基础元件。"}]}, {"kind": "p", "text": "远程 Figma MCP server 配一次，就能作为一等上下文供 Cursor 使用。由于 MCP 是开放标准，同一个 server 可以在 Cursor、Claude Code、Codex 和 VS Code 之间复用——这正是 Open Design 生来要去编排的那种可移植、多 agent 能力。"}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code：做设计怎么选", "blocks": [{"kind": "p", "text": "做设计没有唯一赢家——每个 agent 各有所长，有经验的团队会把它们叠着用。一个公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Cursor", "“边写边看”的可视化回路，带编辑器内置实时预览与直接选中元素编辑", "IDE 里“边迭代边看”的紧凑 UI 工作"], ["Codex", "配上前端 skill 后视觉打磨强；图像理解 + 沙箱化运行", "托管式异步构建，以及可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex、间距、字体）和懂代码库的 UX", "前端推理与大上下文重构"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人。三者在没有 skill、参考和约束时都会退回到一个泛泛的样子。那才是真正要解决的问题——而它是“设计工具”形状的，不是“模型”形状的。"}]}, {"id": "pitfalls", "heading": "常见坑，以及如何避开“AI 味”观感", "blocks": [{"kind": "p", "text": "对 Cursor 生成设计最常见的抱怨，是它看着很泛——柔和渐变、悬浮面板、过大的圆角、夸张阴影，一股“Inter 字体加紫色”的味道，“一看就是 AI 做的”。其他被反映的问题还包括移动端布局错乱、指令文字泄漏进 UI 文案里。"}, {"kind": "steps", "items": [{"label": "加一个设计 skill", "body": "一个精选的审美 skill 会逼 Cursor 选定一个真实方向，而不是用默认那套。"}, {"label": "用预览来验证", "body": "在编辑器内置预览里跨断点渲染并自检，这样布局就不会在移动端悄悄崩掉。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图，是对产出质量影响最大的那个杠杆。"}, {"label": "把规则写进 `.cursor/rules`", "body": "把“不要 hero card、最多两种字体、品牌优先层级”这类规则，放在 agent 每次都会读到的地方。"}]}, {"kind": "p", "text": "注意到没有：每一条缓解措施都是在给 agent 一份精选的设计上下文。逐个项目、用手去维护这份上下文，正是 Open Design 帮你省掉的苦活。"}]}, {"id": "open-design", "heading": "在 Open Design 里用 Cursor 做设计", "blocks": [{"kind": "p", "text": "Open Design 就是上面这套工作流一直在要的那一层开源设计层。它把 Cursor 当作一等适配器，外面裹上一个精选的 skill 与 design-system 库、一条结构化的渲染流水线，以及一个本地桌面端 UI——让那份让 Cursor 变好用的设计上下文，从第一次运行就在那儿，而不是每次都手工拼。"}, {"kind": "ol", "items": ["安装 Open Design，选 Cursor 作为你的 agent。", "用你的 Cursor 账号或你自己的模型密钥（BYOK）认证——凭证留在你的机器上，绝不经我们代理。", "挑一套设计系统和一个 skill，然后生成审美一致的演示稿、原型和落地页。", "每一份产物和 DESIGN.md 都存在你自己的 repo 里，而不是某个托管云。"]}, {"kind": "p", "text": "同一个 Cursor agent、同一把密钥——外面再加一套真实、可移植、开源的设计工作流。它本地优先、Apache-2.0 授权，所以你的工作和凭证没有任何东西会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Cursor 真的能做设计吗？", "text": "能——只要上下文里有一个设计 skill、一套设计系统和真实参考图，Cursor 就能产出生产级、响应式的 UI，而它的编辑器内置预览让你能在视觉上验证并打磨。缺了这份上下文，它就容易退回到泛泛的样子，而这正是 Open Design 补齐的缺口。"}, {"name": "这是 Cursor 官方产品吗？", "text": "不是。Open Design 是一个独立的开源项目，把 Cursor 作为 agent 集成进来。它用一个本地优先、开源的 skill 与 design-system 库来补充 Cursor。"}, {"name": "用 Cursor 做设计需要 Cursor 订阅吗？", "text": "你可以用 Cursor 账号 / 订阅，也可以用自己的模型密钥（BYOK）。无论哪种方式，Open Design 都不会代理你的凭证——它们由你的 agent 直接使用。"}, {"name": "前端设计选 Cursor 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体、懂代码库的设计决策著称；Cursor 的优势是编辑器里“边写边看”的紧凑回路加实时预览。很多团队两个都用——Open Design 让你切换 agent 时无需改动设计工作流。"}, {"name": "怎么把 Cursor 连到 Figma？", "text": "在 Cursor 里加上官方 Figma MCP server，然后把一个 Figma frame 链接粘进对话，让 Cursor 去实现它。该 server 暴露真实的组件、变量和布局数据，让生成的代码贴合源设计。"}, {"name": "怎么避开泛泛的“AI 味”观感？", "text": "加一个设计 skill、提供真实的设计 tokens 和参考截图、把品牌规则写进 `.cursor/rules` 或 `AGENTS.md`，并在预览里跨断点验证。Open Design 把这些做成一个精选库，让你省掉逐项目的搭建。"}, {"name": "Open Design 和 Cursor 或 Anysphere 有关联吗？", "text": "没有。Cursor 是 Anysphere 的产品；Open Design 是一个独立的开源项目，把它作为一等适配器来支持。Cursor 和 Anysphere 是 Anysphere, Inc. 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先。你的文件、产物和 DESIGN.md 都留在你自己的 repo 里，你的 Cursor 或模型凭证由你的 agent 直接使用，绝不经 Open Design 的服务器中转。"}], "ctaTitle": "用开放的方式，和 Cursor 一起做设计。", "ctaBody": "带上你自己的 Cursor 账号或模型密钥，把每个文件都留在本地，并在你已经在用的 agent 外面，得到一个精选的设计库。", "ctaActions": [{"label": "在 Open Design 里使用 Cursor", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面端", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支持的 agent"}, "aboutTitle": "什么是 Cursor", "aboutBody": ["Cursor 是基于 VS Code 的 AI 优先代码编辑器，内置一个能在整个项目里改代码的 Agent。", "Cursor 推出了 Design Mode —— 点选某个元素、勾画一处改动，或用一句话描述，Cursor 就改底层的 React/Vue/Svelte 源码。配合 Figma MCP，它成了一个可信的设计转代码界面。", "Open Design 把 Cursor Agent 作为一方适配器，让它驱动结构化的开源设计流水线。"], "vendorLabel": "厂商", "vendor": "Cursor（Anysphere）", "credentialLabel": "凭据", "credential": "Cursor 账号，使用你自己的模型凭据", "designTitle": "用 Cursor 做设计", "designLead": "Cursor 的设计生态围绕可视化编辑和 Figma 互通：", "designPoints": [{"label": "Design Mode", "body": "点选、勾画或说话来改 UI，Cursor 改源码 —— 由真实代码支撑的可视化编辑。"}, {"label": "Figma → 代码", "body": "Figma MCP 把真实布局和 token 喂给 Cursor，让它按设计而非截图来构建。"}, {"label": "双向 Figma", "body": "部分 MCP 让 Cursor 不只读取、还能用程序改 Figma 设计。"}, {"label": "设计转代码闭环", "body": "常见范式：先在可视化工具里出稿，导入 Cursor，再用 Agent 精修和扩展。"}], "linksTitle": "实战资源", "linksLead": "用 Cursor 做设计的发布、教程和工具：", "links": [{"label": "Cursor Design Mode announcement", "href": "https://x.com/cursor_ai/status/2062950344687272144", "source": "X · @cursor_ai"}, {"label": "Cursor’s Design Mode (Visual Editing) explained", "href": "https://www.builder.io/blog/cursor-design-mode-visual-editing", "source": "Blog · Builder.io"}, {"label": "Cursor for Designers — Figma to code", "href": "https://www.builder.io/blog/figma-to-cursor-for-designers", "source": "Blog · Builder.io"}, {"label": "Framelink Figma-Context-MCP", "href": "https://github.com/GLips/Figma-Context-MCP", "source": "GitHub · GLips"}, {"label": "cursor-talk-to-figma-mcp", "href": "https://github.com/grab/cursor-talk-to-figma-mcp", "source": "GitHub · Grab"}], "withOdTitle": "Cursor + Open Design", "withOdLead": "Open Design 是围绕 Cursor 的开源设计层：精选 skill 与设计系统库、结构化渲染流水线、本地桌面 UI。", "withOdSteps": ["安装 Open Design，选 Cursor Agent。", "Cursor 用你自己的模型密钥 —— 不经过 Open Design 中转。", "选一套设计系统和 skill，生成审美一致的 deck、原型和落地页。", "一切留在你的 repo，本地优先。"], "withOdClosing": "Cursor 的 Agent，外加一套开放、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Cursor 适合做设计吗？", "text": "配合 Design Mode 和 Figma MCP，它改、建 UI 都不错；从零开始则更需要一套设计系统。Open Design 开箱即提供。"}, {"name": "Open Design 会取代 Cursor 的 Design Mode 吗？", "text": "不会，是互补。Open Design 在 Agent 之上加一层开放、精选的设计系统与 skill 库，以及结构化渲染流水线。"}, {"name": "Open Design 跟 Cursor 有关联吗？", "text": "没有。Cursor 是 Anysphere 的产品；Open Design 是独立开源项目，以一方适配器集成它。"}], "ctaTitle": "用开源的方式，跟 Cursor 一起设计。", "ctaBody": "给仓库点 Star、下载桌面版，或加入社区申请新适配器。"},
  opencode: {"title": "OpenCode 做设计 —— 用开源 Agent 搭 UI", "description": "怎么用 OpenCode 做 UI 和前端 —— design.md 文件、UI/UX skill、Figma MCP —— 以及 Open Design 如何把 OpenCode 变成一个免费、本地优先的开源设计 Agent。", "breadcrumb": "OpenCode", "label": "Agent · OpenCode", "heading": "用 OpenCode 做设计。", "lead": "OpenCode 是开源的终端 AI 编码 Agent。设计师给它挂上设计 skill 和 DESIGN.md 文件来生成真正的 UI。Open Design 把这套做成结构化的开源工作流 —— 用你自己的模型密钥，所有东西留本地。", "tldrTitle": "一句话", "tldrBody": "OpenCode 是完全开源的编码 Agent；设计是靠 skill、design.md 文件和 Figma MCP 衍生出来的用法。Open Design 在它周围打包一套精选设计系统与 skill 库，外加桌面工作流 —— 你的密钥，你的 repo。", "toc": ["什么是 OpenCode", "用 OpenCode 做设计", "资源", "配合 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 OpenCode 变成本地优先、开源的设计 agent——用你自己选的任意模型和 provider key，用你自己的文件，外加一套精选的 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 OpenCode", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode 是一个开源、以终端为先的 AI 编码 agent，刻意做成与模型无关：你自带 provider key，在同一套工作流背后运行任意你想用的模型。这种开放性让它天然适合做设计——但和所有 agent 一样，只有当你给它正确的参考、skill 和一套验证回路时，它才能产出好的 UI。本文是一份从头到尾的实用指南，讲如何用 OpenCode 做 UI、前端和设计系统工作，以及如何把它接入 Open Design 的结构化设计工作流。", "内容涵盖：OpenCode 到底是什么、为什么一个与模型无关的开源 agent 适合做设计、如何从零配置、截图转 UI 的回路、AGENTS.md 与 MCP 如何扩展它、它与 Codex / Claude Code / Cursor 的对比、让 AI 产出显得套路化的那些坑，以及 Open Design 如何作为一个开源、本地优先的设计层来补上这道缺口——这是个天然的搭配，因为两个项目都是开源、都跑在你自己的机器上。"], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "OpenCode 设计反馈回路：终端 TUI agent、在浏览器中渲染 UI，以及一个工作区，带一条回环反馈箭头", "caption": "核心回路：OpenCode 在终端里构建 UI，在真实浏览器中渲染并验证，再对照你的参考反复迭代——用的是你自己选的任意模型。"}, "tocLabel": "本页目录", "toc": [{"id": "what-is-opencode", "label": "OpenCode 究竟是什么"}, {"id": "why-design", "label": "为什么开放、任意模型的 agent 适合做设计"}, {"id": "setup", "label": "从零配置 OpenCode 做设计"}, {"id": "screenshot-workflow", "label": "截图转 UI 的工作流"}, {"id": "extend", "label": "AGENTS.md、MCP 与可分享会话"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "坑，以及那种“AI 味”的观感"}, {"id": "open-design", "label": "在 Open Design 中用 OpenCode 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-opencode", "heading": "OpenCode 究竟是什么", "blocks": [{"kind": "p", "text": "OpenCode 是一个为终端打造的开源 AI 编码 agent，由 SST 背后的团队（Anomaly Innovations）维护。它会读取你的代码仓库、运行命令、编辑文件，并与大语言模型对话——但和被厂商绑定的 agent 不同，它本身不自带模型。你把它指向任意你想用的 provider 和模型，并自带 key。"}, {"kind": "p", "text": "它以终端界面（TUI）运行，并在同一引擎之上提供桌面应用和 IDE 扩展。底层采用客户端/服务端架构，所以真正干活的 agent 与你驱动它的界面是解耦的。它内置 build 和 plan 两个 agent，用 Tab 键切换。"}, {"kind": "steps", "items": [{"label": "与模型无关", "body": "模型和 provider 来自 models.dev 这个开放目录。你在 opencode.json 里用 provider/model-id 字符串配置，并可禁用不想加载的 provider——所以同一套设计工作流可以跑在 Anthropic、OpenAI、Google、OpenRouter、本地模型等之上。"}, {"label": "指令文件", "body": "OpenCode 会读取项目里的 AGENTS.md 文件（跨工具的通用标准，也兼容 CLAUDE.md）作为项目规则——这正是编码你设计约定的天然位置。运行 /init 即可生成一个。"}, {"label": "可扩展", "body": "它支持 LSP 集成、MCP server、主题、快捷键和自定义命令，还有可分享的会话链接用于协作。"}]}, {"kind": "ul", "items": ["维护方：SST / Anomaly Innovations（开源项目）", "凭证：你自己的模型 provider API key（BYOK，无厂商锁定）", "许可：MIT，开源"]}]}, {"id": "why-design", "heading": "为什么开放、任意模型的 agent 适合做设计", "blocks": [{"kind": "p", "text": "OpenCode 不像厂商 agent 那样有某一个“设计模型”——而这恰恰是它的优势。因为与模型无关且开源，你可以在同一套设计工作流上运行当下前端最强的那个模型，之后随时更换，或退回到本地模型，全程不用改配置。"}, {"kind": "p", "text": "但光选对模型并不能买来审美。和所有编码 agent 一样，除非你给它约束，否则 OpenCode 也会产出套路化的 UI。好的设计产出来自你提供的三项输入。"}, {"kind": "steps", "items": [{"label": "一套设计系统", "body": "真实的 tokens、基础组件和约定，让 agent 复用，从而让产出贴合某个品牌，而不是退回到通用的观感。"}, {"label": "一个审美 skill", "body": "一个精选的 skill，强制真正的审美——克制的动效、品牌优先的层级、最多两种字体一种强调色——并让 agent 在动手前先定一个方向。"}, {"label": "具体的参考图", "body": "真实的参考图，以及多种状态（桌面和移动、hover、空态、加载态），而不是只有一张主视觉。"}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "展示设计系统、skill 与参考图三者汇聚成优质设计产出的示意图", "caption": "审美来自你提供的三项输入：一套设计系统、一个 skill 和真实参考图——与你跑哪个模型无关。"}, {"kind": "p", "text": "结论：OpenCode 给了你模型自由，但审美仍来自一套精选的设计上下文。Open Design 恰好把这些输入打包好，这也是两者契合的原因——它们都是开源、都本地优先（下文详述）。"}]}, {"id": "setup", "heading": "从零配置 OpenCode 做设计", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 OpenCode 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# 或：npm i -g opencode-ai@latest\n# 或：brew install sst/tap/opencode\n\n# 2. 在项目里启动 TUI，然后认证你的 provider\nopencode          # 然后运行 /login，选择 provider 并粘贴你的 key\n\n# 3. 生成项目上下文\nopencode          # 在项目里运行 /init 生成 AGENTS.md\n\n# 4. 选择你的模型（任意 provider，经 models.dev）\n#    在 opencode.json 里设置 \"provider/model-id\"，或在 TUI 里切换\n\n# 5. 添加 MCP server（可选，比如用于设计交付）\n#    在 opencode.json 的 \"mcp\" 字段下配置"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "五步配置流程：安装、用你的 provider key 认证、配置 AGENTS.md、添加 skill、验证", "caption": "配置顺序：安装 → 认证（你的 provider key）→ 配置 AGENTS.md → 添加 skill → 在真实浏览器中验证。"}, {"kind": "steps", "items": [{"label": "编码你的设计规则", "body": "把你的 tokens、基础组件和约定放进 AGENTS.md（或从中引用的 DESIGN.md），让产出贴合品牌而非退回通用观感。opencode.json 里的 instructions 选项可以用 glob 指向更多规则文件。"}, {"label": "选一个有能力的模型", "body": "因为 OpenCode 与模型无关，可以为设计这一遍挑选当下前端最强的 provider/模型——而工作流的其余部分保持不变。"}]}]}, {"id": "screenshot-workflow", "heading": "截图转 UI 的工作流", "blocks": [{"kind": "p", "text": "用任何 agent 做设计，杠杆最高的回路都是：把一张参考图变成可用、响应式的 UI，并反复迭代直到匹配。同样的五步在 OpenCode 里也适用。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考开始——并包含多种状态（桌面和移动、hover、空态、加载态），而不只是一张主视觉。", "提示词要具体；含糊的提示会产出套路化的 UI。", "准备好一套设计系统，并告诉 OpenCode tokens 和规范基础组件在哪里（写在 AGENTS.md 里）。", "跑一个 dev server，让 agent 在真实浏览器中渲染，并切换到各断点检查结果。", "让 OpenCode 把它的实现对照截图来迭代——而不只是确认能构建通过。"]}, {"kind": "p", "text": "在 TUI 里用 @ 引用文件会对工作目录做模糊搜索，用开头的 ! 内联运行 shell 命令，用 / 命令驱动各种操作。然后用具体约束来提示："}, {"kind": "code", "lang": "bash", "code": "opencode\n# 在 TUI 里：\n> @reference-desktop.png @reference-mobile.png\n  用 React + Vite + Tailwind + TypeScript 实现这个设计。\n  复用 AGENTS.md 里我现有的设计系统组件和 tokens。\n  匹配间距、布局和层级；做到响应式。\n  运行 dev server，在浏览器中打开，并反复迭代\n  直到 UI 在各断点上都与参考图匹配。"}, {"kind": "p", "text": "提示词保持小而聚焦，好的迭代就提交、坏的就回退（回退时告诉 OpenCode），让每一遍都建立在一个干净的基础上。"}]}, {"id": "extend", "heading": "AGENTS.md、MCP 与可分享会话", "blocks": [{"kind": "p", "text": "三个扩展点让 OpenCode 在持续的设计工作中真正好用，而且它们都能干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "AGENTS.md 规则", "body": "项目规则放在仓库根目录的 AGENTS.md（或全局规则放在 ~/.config/opencode/AGENTS.md）。它是你设计约定的长期归宿，每次运行都会读取，并兼容其他 agent 使用的 CLAUDE.md 文件。"}, {"label": "MCP server", "body": "OpenCode 同时支持本地（命令）和远程（URL）MCP server，在 mcp 字段下配置——这是把设计上下文和外部工具引入进来的可移植方式，跨 agent 通用，而不只服务于 OpenCode。"}, {"label": "可分享会话", "body": "/share 命令会为一段会话创建公开链接，用于协作或评审，/unshare 则收回它——很适合为一遍设计获取反馈。"}]}, {"kind": "p", "text": "这些都是可移植、跨 agent 的能力——正是 Open Design 被设计来去编排的那类东西，而不是每个项目里重造一遍。"}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor 做设计", "blocks": [{"kind": "p", "text": "设计工作没有唯一赢家——每个 agent 各有所长，有经验的团队会叠着用。一个公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["OpenCode", "开源且与模型无关；在一套终端工作流背后运行任意 provider", "BYOK 自由、切换模型、完全开放且本地优先的配置"], ["Codex", "配合前端 skill 的视觉打磨能力强；图像理解", "委托式异步、沙箱化构建、可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex、间距、字体）和对代码库有感知的 UX", "前端推理和大上下文重构"], ["Cursor", "带实时预览和内联编辑的所见即所得回路", "IDE 内紧凑的边改边看 UI 工作"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人——所有这些 agent 在没有 skill、参考和约束时都会退回到通用观感。这才是真正要解决的问题——它是设计工具形状的，不是模型形状的，而这恰恰说明了为什么像 OpenCode 这样的开放 agent 与一个开放的设计层配合得如此之好。"}]}, {"id": "pitfalls", "heading": "坑，以及如何避开那种“AI 味”观感", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的吐槽是它看起来很套路——柔和渐变、悬浮面板、过大的圆角、夸张的阴影，一种 Inter 字体加紫色的味道，“一看就是 AI 做的”。其他被报告的问题还包括移动端布局错乱、指令文字漏进了 UI 文案。这些都不是 OpenCode 独有的；它们是任何 agent 在缺少精选设计上下文时都会发生的事。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会强制 agent 定下一个真正的方向，而不是默认观感。"}, {"label": "在真实浏览器中验证", "body": "让它跨断点渲染并自检，这样布局就不会在移动端悄悄崩掉。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图是对产出质量影响最大的单一杠杆。"}, {"label": "把规则写进 AGENTS.md", "body": "把“不要 hero 卡片、最多两种字体、品牌优先层级”这类规则放在 agent 每次都会读到的地方。"}]}, {"kind": "p", "text": "注意到了吗：每一项缓解措施都是关于给 agent 一套精选的设计上下文——无论你跑哪个模型。靠手工逐项目维护这套上下文，正是 Open Design 帮你免除的苦活。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 OpenCode 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面那套工作流一直在呼唤的开源设计层。它把 OpenCode 当作一等适配器，并为它套上一套精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI——让那些让任何 agent 变好的设计上下文从第一次运行就在那里，而不是每次都手工拼凑。两个项目都是开源、都本地优先，这让它们的搭配水到渠成。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 OpenCode 作为你的 agent。", "用你自己的模型 provider API key（BYOK）认证——凭证留在你的机器上，绝不经我们代理。", "选择任意 provider 和模型，再加上一套设计系统和一个 skill，然后生成审美一致的 deck、原型和落地页。", "每个产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管云端。"]}, {"kind": "p", "text": "同一个 OpenCode agent、同样的模型自由——外加一套真正可移植、开源的设计工作流。它本地优先、采用 Apache-2.0 许可，所以你的工作和凭证都不会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "OpenCode 真的能做设计吗？", "text": "能——当上下文里有审美 skill、设计系统和真实参考图时，OpenCode 能产出生产级、响应式的 UI，并能在浏览器中验证。因为它与模型无关，你可以运行当下前端最强的那个模型。缺少这套精选上下文时，它会倾向于退回到通用观感，而这正是 Open Design 补上的缺口。"}, {"name": "用 OpenCode 做设计该选哪个模型？", "text": "你喜欢哪个都行——OpenCode 经 models.dev 与 provider 无关，所以你可以在同一套工作流背后运行 Anthropic、OpenAI、Google、OpenRouter 或本地模型，并随时切换。设计产出的质量更多取决于你的 skill、设计系统和参考，而非单看模型。"}, {"name": "Open Design 是 OpenCode（SST）团队做的吗？", "text": "不是。Open Design 是一个独立的开源项目，把 OpenCode 集成为一个 agent。它用一套本地优先、开源的 skill 与设计系统库来补足 OpenCode。"}, {"name": "用 OpenCode 做设计需要什么特殊订阅吗？", "text": "不需要——OpenCode 是 BYOK。你自带模型 provider 的 API key，Open Design 绝不代理你的凭证，也没有厂商锁定。"}, {"name": "前端设计选 OpenCode、Codex 还是 Claude Code？", "text": "都很强，很多团队会叠着用。OpenCode 的优势在于完全开源且与模型无关；Codex 擅长委托式、沙箱化构建；Claude Code 以具体、对代码库有感知的设计决策著称。Open Design 让你切换 agent 而不改变你的设计工作流。"}, {"name": "如何为设计上下文扩展 OpenCode？", "text": "把规则写进 AGENTS.md，在 mcp 字段下添加 MCP server 以引入可移植工具和设计上下文，并用可分享会话来做评审。Open Design 直接提供一套精选的 skill 与设计系统库，让你省去逐项目的配置。"}, {"name": "Open Design 与 OpenCode 或 SST 有关联吗？", "text": "没有。OpenCode 是由 SST（Anomaly Innovations）维护的开源项目；Open Design 是一个独立的开源项目，把它作为一等适配器来支持。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的模型 provider 凭证由你的 agent 直接使用，绝不经 Open Design 服务器中转。"}], "ctaTitle": "用开放的方式，借 OpenCode 做设计。", "ctaBody": "自带你的模型 provider key，把每个文件留在本地，并为你已经在用的这个开放 agent 套上一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 OpenCode", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支持的 agent"}, "aboutTitle": "什么是 OpenCode", "aboutBody": ["OpenCode 是开源（MIT）的终端 AI 编码 Agent —— 一个 TUI 加桌面、IDE 界面 —— 由 Anomaly（SST 团队）维护，仓库在 github.com/anomalyco/opencode。", "它是编码 Agent，不是专门的设计工具。设计是靠给它加 skill、DESIGN.md 系统文件，以及 Figma／可视画布 MCP 来控制视觉输出实现的。", "Open Design 把 OpenCode 作为一方适配器，把这些零散范式变成结构化的开放设计流水线。"], "vendorLabel": "厂商", "vendor": "Anomaly（开源，MIT）", "credentialLabel": "凭据", "credential": "通过 OpenCode 配置接入模型凭据（BYOK）", "designTitle": "用 OpenCode 做设计", "designLead": "OpenCode 社区靠配置和 skill 给 Agent 喂「审美」：", "designPoints": [{"label": "design.md 系统", "body": "把品牌 DESIGN.md（Stripe/Linear/Airbnb 风格规则）放进项目，让 OpenCode 生成匹配的 UI。"}, {"label": "UI/UX skill", "body": "设计智能 skill 带来几十种 UI 风格和配色，在写代码前先生成一套设计系统。"}, {"label": "Figma 与可视画布 MCP", "body": "通过 MCP 接 Figma 或可视画布，形成设计转代码闭环。"}, {"label": "模型审美", "body": "因为 OpenCode 是 BYOK，你可以挑最对你审美和预算的模型。"}], "linksTitle": "实战资源", "linksLead": "用 OpenCode 做设计的 skill、design.md 合集和教程：", "links": [{"label": "OpenCode UI/UX skill: build better modern designs", "href": "https://www.youtube.com/watch?v=Pc27ThkuBPQ", "source": "YouTube · AI Stack Engineer"}, {"label": "OpenCode + design.md: stunning designs for free", "href": "https://www.youtube.com/watch?v=sCu34s8zb4o", "source": "YouTube · AI Stack Engineer"}, {"label": "VoltAgent/awesome-design-md", "href": "https://github.com/VoltAgent/awesome-design-md", "source": "GitHub · VoltAgent"}, {"label": "anomalyco/opencode (canonical repo)", "href": "https://github.com/anomalyco/opencode", "source": "GitHub · Anomaly"}, {"label": "OpenCode tutorial: setup, agents, skills & MCP", "href": "https://www.youtube.com/watch?v=uZGDO0L-Dr4", "source": "YouTube · Leon van Zyl"}], "withOdTitle": "OpenCode + Open Design", "withOdLead": "Open Design 是围绕 OpenCode 的开源设计层：精选 skill 与设计系统库、结构化渲染流水线、本地桌面 UI —— 不用再手工拼 design.md 和 skill。", "withOdSteps": ["安装 Open Design，选 OpenCode 作为你的 Agent。", "OpenCode 通过它自己的配置用你的模型密钥（BYOK）—— 不经过中转。", "选一套设计系统和 skill，生成审美一致的 deck、原型和落地页。", "两个项目都开源、本地优先 —— 你的文件永不离开你的机器。"], "withOdClosing": "两个开源 Agent，一套本地优先的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "是哪个 OpenCode？", "text": "是 github.com/anomalyco/opencode 这个开源终端 Agent（原 sst/opencode），由 Anomaly 维护。别跟同名工具混淆。"}, {"name": "OpenCode 能做 UI 设计吗？", "text": "能，给它 design.md 文件和 UI/UX skill 上下文即可。Open Design 提供精选的两者库，省去手工搭建。"}, {"name": "Open Design 跟 OpenCode 是同一个项目吗？", "text": "不是。两者都开源，但是独立项目。Open Design 把 OpenCode 作为一方 Agent 适配器集成。"}], "ctaTitle": "用开源的方式，跟 OpenCode 一起设计。", "ctaBody": "给仓库点 Star、下载桌面版，或加入社区申请新适配器。"},
  gemini: {"title": "用 Gemini CLI 做设计 — Open Design", "description": "设计师如何用 Google 的 Gemini CLI 做 UI 与网页设计——它的多模态图像理解、1M token 上下文、GEMINI.md 与 MCP——以及 Open Design 如何把它变成一个本地优先、开源的设计 agent。", "breadcrumb": "Gemini CLI", "label": "Agent · Gemini CLI", "heading": "用 Gemini CLI 做设计。", "lead": "Gemini CLI 是 Google 的开源终端 agent。它的多模态模型能读截图，1M token 上下文能装下整套设计系统，这让它成为一个真正能用的设计工具——前提是你给它参考、约定和一套验证回路。Open Design 把它接进开源设计工作流：用你的 Google 账号或 API key、你自己的文件、本地优先。", "tldrTitle": "TL;DR", "tldrBody": "Gemini CLI 凭强多模态理解和超大上下文把参考图变成响应式 UI，用 Google 账号即可免费起步。Open Design 在它外面套一套精选的设计系统与 skill 库 + 桌面工作流——BYOK，一切留本地。", "toc": ["什么是 Gemini CLI", "用 Gemini CLI 做设计", "资源", "配合 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Gemini CLI 变成一个本地优先、开源的设计 agent——用你的 Google 账号或 Gemini API key、你自己的文件，外加一套精选的 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 里使用 Gemini CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面端", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Gemini CLI 是 Google 为终端打造的开源 AI agent。有两点让它在设计上格外有意思：它的模型是原生多模态的，能读一张截图并对布局、间距、层级做推理；它的上下文窗口可达 1M token，能一次装下整套设计系统和代码库。配上对的参考、约定和验证回路，它能构建真正的响应式 UI——而且用 Google 账号即可免费起步。这是一份从头到尾、可落地的指南，讲如何用 Gemini CLI 做 UI、前端和设计系统工作，并把它接入 Open Design 的结构化设计工作流。", "内容涵盖：Gemini CLI 到底是什么、为什么它的多模态模型与超大上下文适合做设计、如何从零配置、截图转 UI 的回路、GEMINI.md 与 MCP 如何扩展它、它与 Codex / Claude Code / Cursor 的对比、让 AI 产出显得套路化的那些坑，以及 Open Design 如何作为一个开源、本地优先的设计层补上这道缺口——这是个天然搭配，因为两者都开源、都跑在你自己机器上。"], "heroImage": {"src": "/agents/gemini-design/gemini-design-hero.webp", "alt": "Gemini CLI 设计反馈回路：读参考图的终端 agent、渲染 UI 的浏览器，以及一个工作区，带一条回环反馈箭头", "caption": "核心回路：Gemini CLI 在终端里读取你的参考，在真实浏览器中构建并验证 UI，再对照参考迭代——而且整套设计系统都在上下文里。"}, "tocLabel": "本页目录", "toc": [{"id": "what-is-gemini-cli", "label": "Gemini CLI 到底是什么"}, {"id": "why-design", "label": "为什么多模态 + 超大上下文适合做设计"}, {"id": "setup", "label": "从零配置 Gemini CLI 做设计"}, {"id": "screenshot-workflow", "label": "截图转 UI 的工作流"}, {"id": "extend", "label": "GEMINI.md、MCP 与扩展"}, {"id": "vs", "label": "Gemini CLI vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "常见坑与“AI 味”观感"}, {"id": "open-design", "label": "在 Open Design 里用 Gemini CLI 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-gemini-cli", "heading": "Gemini CLI 到底是什么", "blocks": [{"kind": "p", "text": "Gemini CLI 是 Google 为终端发布的开源（Apache-2.0）AI agent。它读取你的代码仓库、编辑文件、运行 shell 命令、抓取网页，还能用 Google 搜索为答案做事实接地——从自然语言任务出发去规划并验证，而不只是补全几行。同一个引擎也驱动 VS Code 里的 Gemini Code Assist agent。"}, {"kind": "p", "text": "对设计工作而言，有两个特性突出。它的模型原生多模态，所以你把一张截图交给它，它是对着真实布局在推理。它的上下文窗口可达 1M token，大到能一次装下你的整套设计系统、组件库和参考集，而不必把它们摘要掉。"}, {"kind": "steps", "items": [{"label": "上下文文件", "body": "Gemini CLI 读取 GEMINI.md 作为持久项目上下文——这正是写入设计约定、token 与审阅清单的天然位置。个人与团队设置可叠加其上。"}, {"label": "内置工具 + MCP", "body": "它开箱自带文件、shell、网页抓取和 Google 搜索工具，并支持 MCP server（在 ~/.gemini/settings.json 里配置）以引入外部上下文，比如一个实时 Figma 文件。"}, {"label": "免费起步", "body": "用个人 Google 账号登录即可获得相当慷慨的 Gemini 免费额度；你也可以自带 Gemini API key 或用 Vertex AI。"}]}, {"kind": "ul", "items": ["厂商：Google", "凭证：Google 账号（免费额度）或来自 AI Studio 的 Gemini API key（BYOK）或 Vertex AI", "许可：Apache-2.0，开源"]}]}, {"id": "why-design", "heading": "为什么多模态模型与超大上下文适合做设计", "blocks": [{"kind": "p", "text": "Gemini CLI 在设计上的优势来自两个模型特性——但和所有 agent 一样，审美仍需你来提供。"}, {"kind": "steps", "items": [{"label": "强多模态理解", "body": "因为 Gemini 模型原生多模态，agent 能很好地读参考截图——把它渲染出的产出对照一张图来比对，而不是从文字描述里猜。"}, {"label": "1M token 上下文窗口", "body": "大上下文意味着整套设计系统、token 和许多参考状态能一次性塞进去，于是 agent 复用你真实的基础元件，而不是另造一次性样式。"}, {"label": "GEMINI.md 里的约定", "body": "一份 GEMINI.md（加上 Figma MCP server）把 agent 指向你的 token、组件和真实规格，让它对着品牌工作，而不是默认观感。"}]}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-taste-triangle.webp", "alt": "展示设计系统、skill 与参考图三者汇聚成优质设计产出的示意图", "caption": "审美来自你提供的三种输入：一套设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "结论和每个 agent 教给我们的一样：Gemini CLI 默认并没有审美。只有当你给它约束——一套设计系统、一个审美 skill、具体的参考——它才能产出好设计。Open Design 打包的正是这些输入，这也是两者天然契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零把 Gemini CLI 配置成能做设计", "blocks": [{"kind": "p", "text": "下面是从一台干净机器，到一个能构建并验证 UI 的 Gemini CLI 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Gemini CLI（需 Node 20+）\nnpm install -g @google/gemini-cli\n# 或免安装运行：npx https://github.com/google-gemini/gemini-cli\n\n# 2. 在你的项目里启动，首次运行时认证\ncd your-project\ngemini            # 用 Google 账号登录，或设置 GEMINI_API_KEY\n\n# 3. 生成项目上下文\n/init             # 为本项目生成 GEMINI.md\n\n# 4. 接入 Figma MCP server（可选，用于设计交付）\n#    在 ~/.gemini/settings.json 的 \"mcpServers\" 下添加"}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-setup-flow.webp", "alt": "五步配置流程：安装、认证、配置 GEMINI.md、添加 skill、验证", "caption": "配置顺序：安装 → 认证 → 配置 GEMINI.md → 添加 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "把设计规则写进去", "body": "把你的 token、基础元件和约定放进 GEMINI.md 并让 Gemini 指向它们，这样产出会贴合品牌，而不是退回到泛泛的样子。"}, {"label": "加上浏览器验证", "body": "接入 Playwright 或浏览器 MCP，让 Gemini 在真实浏览器里渲染，并跨断点检查产出，而不仅仅确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图转 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Gemini CLI 做设计、杠杆最高的回路，是把一张参考图变成能跑、且响应式的 UI，并迭代到匹配为止——靠多模态模型把产出对照参考来比对。"}, {"kind": "ol", "items": ["从你手上最清晰的视觉参考开始——并且要包含多种状态（桌面与移动、hover、空态、加载态），而不只是一张主视觉。", "提示要具体；即便是强模型，含糊的提示也只会产出泛泛的 UI。", "把你的设计系统与约定放进 GEMINI.md，并告诉 Gemini token 与标准基础元件在哪里。", "跑一个 dev server，让 Gemini 在真实浏览器中渲染，并切到各断点检查结果。", "通过让 Gemini 把它的实现对照截图来迭代——而不只是确认能构建通过。"]}, {"kind": "p", "text": "用 @ 引用一张图片把它附到提示里，然后用具体约束给出提示："}, {"kind": "code", "lang": "bash", "code": "gemini\n# 在提示里：\n> @reference-desktop.png @reference-mobile.png\n  用 React + Vite + Tailwind + TypeScript 实现这个设计。\n  复用 GEMINI.md 里我现有的设计系统组件和 token。\n  匹配间距、布局和层级；做成响应式。\n  在浏览器中渲染，并迭代到 UI 在各断点上都与参考一致。"}, {"kind": "p", "text": "提示保持小而聚焦，好的迭代就提交、坏的就回退（回退时告诉 Gemini 一声），让每一轮都建立在干净的基础上。"}]}, {"id": "extend", "heading": "GEMINI.md、MCP 与扩展", "blocks": [{"kind": "p", "text": "三个扩展点让 Gemini CLI 在持续的设计工作中真正好用，而且它们都能干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "GEMINI.md 上下文", "body": "项目规则放在仓库根目录的 GEMINI.md（还有全局与团队层）。它是你设计约定的长期归宿，每次运行都会读取。"}, {"label": "MCP server", "body": "在 ~/.gemini/settings.json 下配置 MCP server——这是把设计上下文和外部工具（最相关的是 Figma MCP server）引入进来的可移植方式，跨 agent 通用，而不只服务于 Gemini。"}, {"label": "扩展与内置工具", "body": "Gemini CLI 的扩展，以及它内置的 Google 搜索、文件、shell、网页抓取工具，让它能在不离开终端的情况下收集参考、跑完验证回路。"}]}, {"kind": "p", "text": "这些都是可移植、跨 agent 的能力——正是 Open Design 被设计来去编排的那类东西，而不是每个项目里重造一遍。"}]}, {"id": "vs", "heading": "Gemini CLI vs Codex vs Claude Code vs Cursor 做设计", "blocks": [{"kind": "p", "text": "做设计没有唯一赢家——每个 agent 各有所长，有经验的团队会把它们叠着用。一个公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Gemini CLI", "强多模态图像理解 + 1M token 上下文；开源且有免费额度", "截图密集的工作，以及把整套设计系统装进上下文"], ["Codex", "配上前端 skill 后视觉打磨强；沙箱化异步构建", "托管式异步构建，以及可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex、间距、字体）和懂代码库的 UX", "前端推理与大上下文重构"], ["Cursor", "带实时预览与行内编辑的“边写边看”回路", "IDE 里“边迭代边看”的紧凑 UI 工作"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人。它们在没有 skill、参考和约束时都会退回到一个泛泛的样子。那才是真正要解决的问题——而它是“设计工具”形状的，不是“模型”形状的。"}]}, {"id": "pitfalls", "heading": "常见坑，以及如何避开“AI 味”观感", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨，是它看着很泛——柔和渐变、悬浮面板、过大的圆角、夸张阴影，一股“Inter 字体加紫色”的味道，“一看就是 AI 做的”。其他被反映的问题还包括移动端布局错乱、指令文字泄漏进 UI 文案里。这些都不是 Gemini CLI 独有的；它们是任何 agent 在缺少精选设计上下文时都会发生的事。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会逼 agent 选定一个真实方向，而不是用默认那套。"}, {"label": "在真实浏览器里验证", "body": "用多模态模型跨断点渲染并自检，这样布局就不会在移动端悄悄崩掉。"}, {"label": "提供 token 和参考", "body": "真实的设计 token 和参考截图，是对产出质量影响最大的那个杠杆。"}, {"label": "把规则写进 GEMINI.md", "body": "把“不要 hero 卡片、最多两种字体、品牌优先层级”这类规则，放在 agent 每次都会读到的地方。"}]}, {"kind": "p", "text": "注意到没有：每一条缓解措施都是在给 agent 一份精选的设计上下文。逐个项目、用手去维护这份上下文，正是 Open Design 帮你省掉的苦活。"}]}, {"id": "open-design", "heading": "在 Open Design 里用 Gemini CLI 做设计", "blocks": [{"kind": "p", "text": "Open Design 就是上面这套工作流一直在要的那一层开源设计层。它把 Gemini CLI 当作一等适配器，外面裹上一个精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面端 UI——让那份让 Gemini 变好用的设计上下文，从第一次运行就在那儿，而不是每次都手工拼。两者都开源、都本地优先，这让搭配水到渠成。"}, {"kind": "ol", "items": ["安装 Open Design，选 Gemini CLI 作为你的 agent。", "用你的 Google 账号或 Gemini API key（BYOK）认证——凭证留在你的机器上，绝不经我们代理。", "挑一套设计系统和一个 skill，然后生成审美一致的演示稿、原型和落地页。", "每一份产物和 DESIGN.md 都存在你自己的 repo 里，而不是某个托管云。"]}, {"kind": "p", "text": "同一个 Gemini CLI agent、同一把密钥——外面再加一套真实、可移植、开源的设计工作流。它本地优先、Apache-2.0 授权，所以你的工作和凭证没有任何东西会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Gemini CLI 真的能做设计吗？", "text": "能——只要上下文里有一个审美 skill、一套设计系统和真实参考图，Gemini CLI 就能产出生产级、响应式的 UI，而它的强多模态模型会把产出对照参考做验证。缺了这份上下文，它就容易退回到泛泛的样子，而这正是 Open Design 补齐的缺口。"}, {"name": "用 Gemini CLI 做设计要付费吗？", "text": "不一定——用 Google 账号登录就有相当慷慨的免费额度，你也可以自带 Gemini API key（BYOK）或用 Vertex AI。无论哪种方式，Open Design 都不会代理你的凭证。"}, {"name": "Gemini CLI 在设计上具体强在哪？", "text": "两点：它的模型强多模态，能很好地读参考截图；它的 1M token 上下文能一次装下整套设计系统和参考集。这都有帮助——但审美仍来自你提供的设计系统、skill 和参考。"}, {"name": "前端设计选 Gemini CLI 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体、懂代码库的设计决策著称；Gemini CLI 的优势是多模态理解加超大上下文和免费额度。很多团队两个都用——Open Design 让你切换 agent 时无需改动设计工作流。"}, {"name": "怎么把 Gemini CLI 连到 Figma？", "text": "在 ~/.gemini/settings.json 的 mcpServers 下加上 Figma MCP server。Gemini 就能拉取真实的设计上下文——组件、变量、布局数据——让生成的代码贴合源设计，而不是近似。"}, {"name": "Open Design 和 Google 有关联吗？", "text": "没有。Gemini CLI 是 Google 的产品；Open Design 是一个独立的开源项目，把它作为一等适配器来支持。Gemini 是 Google 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先、Apache-2.0。你的文件、产物和 DESIGN.md 都留在你自己的 repo 里，你的 Google 凭证由你的 agent 直接使用，绝不经 Open Design 的服务器中转。"}], "ctaTitle": "用开放的方式，和 Gemini CLI 一起做设计。", "ctaBody": "带上你自己的 Google 账号或 Gemini API key，把每个文件都留在本地，并在你已经在用的 agent 外面，得到一个精选的设计库。", "ctaActions": [{"label": "在 Open Design 里使用 Gemini CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面端", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支持的 agent"}, "aboutTitle": "什么是 Gemini CLI", "aboutBody": ["Gemini CLI 是 Google 的开源（Apache-2.0）终端 AI agent。它读取代码库、编辑文件、运行命令、抓取网页，并用 Google 搜索为答案做事实接地。", "它的模型原生多模态，上下文窗口达 1M token，因此能读参考截图、一次性装下整套设计系统。", "Open Design 把 Gemini CLI 当作一等适配器，让它接入一条结构化、开源的设计流水线。"], "vendorLabel": "厂商", "vendor": "Google", "credentialLabel": "凭证", "credential": "Google 账号（免费额度）或 Gemini API key（BYOK）", "designTitle": "用 Gemini CLI 做设计", "designLead": "Gemini CLI 的设计强项围绕它的模型与上下文：", "designPoints": [{"label": "多模态截图 → UI", "body": "强图像理解把参考图变成响应式标记，并对照它检查结果。"}, {"label": "1M token 上下文", "body": "整套设计系统、组件库和参考集一次装下，产出复用你真实的基础元件。"}, {"label": "GEMINI.md + MCP", "body": "上下文文件承载你的约定；Figma MCP server 把真实设计上下文带进代码。"}, {"label": "开源且免费起步", "body": "Apache-2.0，用 Google 账号有慷慨免费额度，也可经 Gemini API BYOK。"}], "linksTitle": "真实资源", "linksLead": "Gemini CLI 的官方仓库与文档：", "links": [{"label": "google-gemini/gemini-cli（GitHub）", "href": "https://github.com/google-gemini/gemini-cli", "source": "GitHub · Google"}, {"label": "官方发布：Introducing Gemini CLI", "href": "https://blog.google/innovation-and-ai/technology/developers-tools/introducing-gemini-cli-open-source-ai-agent/", "source": "Blog · Google"}, {"label": "Gemini CLI 文档", "href": "https://google-gemini.github.io/gemini-cli/", "source": "Docs · Google"}], "withOdTitle": "Gemini CLI + Open Design", "withOdLead": "Open Design 是 Gemini CLI 外面那层开源设计层：精选的 skill 与设计系统库、结构化渲染流水线，以及本地桌面端 UI。", "withOdSteps": ["安装 Open Design，选 Gemini CLI 作为你的 agent。", "用你的 Google 账号或 Gemini API key（BYOK）认证——凭证留在你的机器上。", "挑一套设计系统和 skill，然后生成审美一致的演示稿、原型和落地页。", "产物和 DESIGN.md 都存在你自己的 repo 里，而非托管云。"], "withOdClosing": "同一个 Gemini CLI agent——外面加一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Google 做的吗？", "text": "不是。Gemini CLI 是 Google 的产品；Open Design 是一个独立的开源项目，把它作为一等适配器集成进来。"}, {"name": "要付费吗？", "text": "不一定——Google 账号有免费额度，也可自带 Gemini API key（BYOK）。Open Design 不代理你的凭证。"}, {"name": "Open Design 和 Google 有关联吗？", "text": "没有。Open Design 独立；Gemini 是 Google 的商标。"}], "ctaTitle": "用开放的方式，和 Gemini CLI 一起做设计。", "ctaBody": "给仓库点 Star、下载桌面版，或加入社区申请新适配器。"},
  copilot: {"title": "用 GitHub Copilot CLI 做设计 — Open Design", "description": "人们如何用 GitHub Copilot CLI 做 UI 和网页设计——它原生于终端的编码 agent、自定义指令文件、MCP 支持以及多模型选择——以及 Open Design 如何把 Copilot CLI 变成一个本地优先、开源的设计 agent。", "breadcrumb": "GitHub Copilot CLI", "label": "Agent · GitHub Copilot CLI", "heading": "用 GitHub Copilot CLI 做设计。", "lead": "GitHub Copilot CLI 是 GitHub 原生于终端的编码 agent。它能在整个仓库范围内规划与编辑，从 Claude、GPT 等前沿模型中任选其一，并读取你的仓库指令——这让它在你提供了参考、规范和验证闭环之后，成为一个真正的设计工具。Open Design 把它接入开源的设计工作流：用你的 GitHub Copilot 订阅、你的文件，本地优先。", "tldrTitle": "TL;DR", "tldrBody": "Copilot CLI 在终端里把参考图和自然语言任务变成响应式 UI，支持模型选择和深度的 GitHub 集成——用你现有的 Copilot 订阅即可。Open Design 为它配上一套精选的设计系统与 skill 库以及桌面工作流，并把一切都留在本地。", "toc": ["什么是 GitHub Copilot CLI", "用 Copilot CLI 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 GitHub Copilot CLI 变成一个本地优先、开源的设计 agent——你的 GitHub Copilot 订阅、你的文件，外加围绕它的一套精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Copilot CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["GitHub Copilot CLI 是 GitHub 原生于终端的编码 agent——与驱动 Copilot 编码 agent 的同一套 agentic 框架，被搬到了你的命令行。有两点让它对设计尤其有意思：它会读取你的仓库指令和 AGENTS.md，因此你的设计规范每次运行都会随 agent 一起生效；同时它允许你按任务在 Anthropic、OpenAI 和 Google 的前沿模型之间任选其一，从而挑出对某个 UI 推理最佳的那个。配上恰当的参考、规范和验证闭环，它能构建真正可用的响应式 UI——而且它跑在你可能已经拥有的 Copilot 订阅上。这是一份关于如何用 Copilot CLI 做 UI、前端和设计系统工作，并把它接入 Open Design 结构化设计工作流的实用端到端指南。", "本文涵盖：Copilot CLI 究竟是什么、为什么仓库指令和模型选择契合设计、如何从零开始配置它、截图转 UI 的闭环、自定义指令和 MCP 如何扩展它、它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比、那些让 AI 输出显得千篇一律的陷阱，以及 Open Design 如何作为一个开放、本地优先的设计层来弥合差距——你的订阅和凭证留在你自己的机器上，你的产物留在你自己的仓库里。"], "heroImage": {"src": "/agents/copilot-design/copilot-design-hero.webp", "alt": "GitHub Copilot CLI 设计反馈闭环：一个终端 agent 读取参考图，一个浏览器渲染 UI，加上一个工作区，还有一条反馈箭头回环", "caption": "核心闭环：Copilot CLI 在终端里读取你的参考，在真实浏览器中构建并验证 UI，然后对照参考迭代——你的设计规范则放在仓库指令里。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-copilot", "label": "GitHub Copilot CLI 究竟是什么"}, {"id": "why-design", "label": "为什么指令 + 模型选择契合设计"}, {"id": "setup", "label": "从零开始为设计配置 Copilot CLI"}, {"id": "screenshot-workflow", "label": "截图转 UI 的工作流"}, {"id": "extend", "label": "自定义指令、MCP 与扩展"}, {"id": "vs", "label": "Copilot CLI 对比 Codex、Claude Code、Cursor、Gemini CLI"}, {"id": "pitfalls", "label": "陷阱与“AI 流水线感”的观感"}, {"id": "open-design", "label": "在 Open Design 中用 Copilot CLI 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-copilot", "heading": "GitHub Copilot CLI 究竟是什么", "blocks": [{"kind": "p", "text": "GitHub Copilot CLI 是 GitHub 原生于终端的编码 agent。它读取你的仓库、编辑文件、运行 shell 命令，并直接结合你的 GitHub 上下文——issue、pull request 和仓库——用你现有的 GitHub 账号鉴权。它由与 GitHub Copilot 编码 agent 同一套 agentic 框架驱动，因此能规划复杂任务并迭代，而不只是补全代码行。它在 2025 年 9 月开启公开预览后，于 2026 年 2 月正式全面上线。"}, {"kind": "p", "text": "对设计工作而言，有两点尤为突出。它会读取自定义指令文件——位于 .github/copilot-instructions.md 的仓库级规则以及 AGENTS.md——因此你的设计规范每次运行都会被自动纳入。它还支持多家基础模型提供方，因此你可以用 /model 命令按任务切换到对某个 UI 推理最佳的那个模型。"}, {"kind": "steps", "items": [{"label": "指令文件", "body": "Copilot CLI 会读取 .github/copilot-instructions.md 中的仓库指令、.github/instructions 下的路径专属文件，以及 AGENTS.md——这是为你的设计规范、tokens 和评审清单编码的天然之处。"}, {"label": "内置工具 + MCP", "body": "它内置了 GitHub 的 MCP server，并运行文件和 shell 工具，你还可以用 /mcp add 添加自定义 MCP server（配置存于 ~/.copilot 下的 mcp-config.json），以引入诸如实时 Figma 文件这样的外部上下文。"}, {"label": "模型选择", "body": "用 /model 命令在 Anthropic、OpenAI 和 Google 的前沿模型之间任选其一——按任务切换，全部跑在你现有的 Copilot 订阅上。"}]}, {"kind": "ul", "items": ["厂商：GitHub", "凭证：一个有效的 GitHub Copilot 订阅（Pro、Pro+、Business 或 Enterprise）", "安装：npm install -g @github/copilot，然后运行 copilot"]}]}, {"id": "why-design", "heading": "为什么仓库指令和模型选择契合设计", "blocks": [{"kind": "p", "text": "Copilot CLI 的设计优势来自两点——但和每个 agent 一样，审美仍需由你提供。"}, {"kind": "steps", "items": [{"label": "随仓库一起流转的规范", "body": "因为 Copilot CLI 会自动读取 .github/copilot-instructions.md 和 AGENTS.md，你的 tokens、基础组件和评审规则每次运行都在上下文里——agent 是面向一个品牌而非默认观感来工作。"}, {"label": "按任务挑对模型", "body": "在 Anthropic、OpenAI 和 Google 之间做模型选择，意味着你可以为某个布局选用推理最佳的模型，再为下一个任务切换——而无需改变你的工作流。"}, {"label": "通过 MCP 接入真实规格", "body": "内置的 GitHub MCP server 加上 Figma MCP server，把 agent 指向你的 tokens、组件和真实规格，于是它从源头构建，而不是近似猜测。"}]}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-taste-triangle.webp", "alt": "示意图：设计系统、skill 和参考图汇聚成优秀的设计输出", "caption": "审美来自你提供的三项输入：一套设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这个教训和每个 agent 给我们的一样：Copilot CLI 默认并没有审美。当你给它约束时——一套设计系统、一个审美 skill 和具体参考——它才能产出好设计。Open Design 正是把这些输入打包好，这也是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零开始为设计工作配置 Copilot CLI", "blocks": [{"kind": "p", "text": "下面是从一台干净机器到一个能构建并验证 UI 的 Copilot CLI 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Copilot CLI（需要 Node.js）\nnpm install -g @github/copilot\n\n# 2. 在你的项目中启动它，并在首次运行时鉴权\ncd your-project\ncopilot           # 运行 /login 并按提示登录\n\n# 3. 为任务选择一个模型\n#    在会话中：\n/model            # 从 Anthropic、OpenAI 或 Google 中挑一个前沿模型\n\n# 4. 添加自定义指令和 Figma MCP server（可选）\n#    编写 .github/copilot-instructions.md 或 AGENTS.md\n/mcp add          # 添加 Figma MCP server 用于设计交付"}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-setup-flow.webp", "alt": "五步配置流程：安装、鉴权、选择模型、配置指令、验证", "caption": "配置顺序：安装 → 鉴权 → 选择模型 → 编写指令 → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "为你的设计规则编码", "body": "把你的 tokens、基础组件和规范放进 .github/copilot-instructions.md 或 AGENTS.md，让输出贴合一个品牌，而非退回到千篇一律的观感。"}, {"label": "加入浏览器验证", "body": "接入 Playwright 或浏览器 MCP，让 Copilot 在真实浏览器中渲染，并跨断点检查输出，而不只是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图转 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Copilot CLI 做设计、杠杆最高的闭环，是把一张参考图变成可用的响应式 UI，并不断迭代直到匹配——借助一个强大的多模态模型把输出对照参考来比较。"}, {"kind": "ol", "items": ["从你手上最清晰的视觉参考出发——并包含多种状态（桌面与移动、悬停、空态、加载态），而不只是一张主视觉。", "在 prompt 里写具体；即便用了强模型，含糊的 prompt 也会产出千篇一律的 UI。", "把你的设计系统和规范放进 .github/copilot-instructions.md 或 AGENTS.md，并告诉 Copilot tokens 和标准基础组件在哪里。", "运行一个 dev server，让 Copilot 在真实浏览器中渲染，调整到各断点来检查结果。", "让 Copilot 把它的实现对照截图来比较以进行迭代——而不只是确认能构建通过。"]}, {"kind": "p", "text": "把 Copilot 指向你的参考图并给出具体约束；它在运行前会预览每一次文件编辑或命令，等你批准："}, {"kind": "code", "lang": "bash", "code": "copilot\n# 在 prompt 中：\n> Implement the design in reference-desktop.png and reference-mobile.png\n  in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens described in\n  .github/copilot-instructions.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "保持 prompt 小而聚焦，提交好的迭代、回退坏的迭代（回退时告诉 Copilot），这样每一轮都建立在干净的基础之上。"}]}, {"id": "extend", "heading": "自定义指令、MCP 与扩展", "blocks": [{"kind": "p", "text": "有三个扩展点让 Copilot CLI 适合持续的设计工作，而且这三者都能干净地映射到开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "自定义指令", "body": "仓库规则存于 .github/copilot-instructions.md（连同 .github/instructions 下的路径专属文件和 AGENTS.md）。它们是你设计规范的长期归宿，每次运行都会被自动纳入。"}, {"label": "MCP server", "body": "Copilot CLI 内置了 GitHub 的 MCP server，并允许你通过 /mcp add 添加自定义 server（配置存于 ~/.copilot 下的 mcp-config.json）——这是引入设计上下文（最相关的就是 Figma MCP server）的可移植方式，可跨多个 agent 通用，而不止 Copilot。"}, {"label": "专用 agent 与内置工具", "body": "Copilot CLI 的专用模式——用于代码库探索、运行构建与测试、变更评审和规划——加上它的文件和 shell 工具，让它无需离开终端就能收集参考并跑完验证闭环。"}]}, {"kind": "p", "text": "这些都是可移植的、多 agent 通用的能力——正是 Open Design 旨在编排、而非在每个项目里重复造的那类东西。"}]}, {"id": "vs", "heading": "做设计时 Copilot CLI 对比 Codex、Claude Code、Cursor、Gemini CLI", "blocks": [{"kind": "p", "text": "设计工作没有唯一赢家——每个 agent 各有所长，有经验的团队会把它们叠加使用。一个公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Copilot CLI", "多模型选择（Anthropic、OpenAI、Google）以及在你的 Copilot 订阅上深度的 GitHub 集成", "按任务挑选最佳模型，以及与你的 GitHub 仓库绑定的指令驱动型工作"], ["Codex", "凭借前端 skill 带来出色的视觉打磨；沙箱化的异步构建", "委托式异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex、间距、字体）和理解代码库的 UX", "前端推理和大上下文重构"], ["Cursor", "带实时预览和内联编辑的“边构建边看”视觉闭环", "在 IDE 内紧凑的“边迭代边观察”UI 工作"], ["Gemini CLI", "强大的多模态图像理解和 100 万 token 上下文；开源且带免费额度", "大量依赖截图的工作，以及在上下文中容纳整套设计系统"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人——没有 skill、参考和约束，它们都会默认退回到千篇一律的观感。这才是真正要解决的问题——而且它是设计工具的形状，不是模型的形状。"}]}, {"id": "pitfalls", "heading": "陷阱，以及如何避免“AI 流水线感”的观感", "blocks": [{"kind": "p", "text": "关于 AI 生成设计最常见的抱怨是它看起来千篇一律——柔和渐变、悬浮面板、过大的圆角、夸张的阴影，以及一种 Inter 字体配紫色、“一眼就是 AI 做的”的气质。其他被反映的问题还包括移动端布局错乱、指令文字漏进 UI 文案。这些都不是 Copilot CLI 独有的；任何 agent 在缺少精选设计上下文时运行，都会这样。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会迫使 agent 投入到一个真正的方向上，而非默认观感。"}, {"label": "在真实浏览器中验证", "body": "用浏览器 MCP 跨断点渲染并自检，这样布局就不会在移动端悄无声息地崩坏。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图，是对输出质量影响最大的单一杠杆。"}, {"label": "把规则写进自定义指令", "body": "把诸如“不用 hero 卡片、最多两种字体、品牌优先的层级”这类风格规则放进 .github/copilot-instructions.md 或 AGENTS.md，agent 每次运行都会读到。"}]}, {"kind": "p", "text": "注意，每一项缓解措施都是在给 agent 提供精选的设计上下文。手工地、逐项目地维护这份上下文，正是 Open Design 要消除的苦工。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Copilot CLI 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面那套工作流一直在呼唤的开源设计层。它把 GitHub Copilot CLI 当作一等适配器，并用一套精选的 skill 与设计系统库、一条结构化的渲染流水线和一个本地桌面 UI 把它包裹起来——这样让 Copilot 变好的那份设计上下文，从第一次运行就已就位，而不必每次手工拼装。Open Design 独立、开源（Apache-2.0）且本地优先，这正是两者契合的原因：agent 干活，你的文件和凭证仍归你所有。"}, {"kind": "ol", "items": ["安装 Open Design 并选择 GitHub Copilot CLI 作为你的 agent。", "用你的 GitHub Copilot 订阅鉴权——凭证留在你的机器上，绝不经我们代理。", "选一套设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "每一个产物和 DESIGN.md 文件都存在你自己的仓库里，而非托管的云端。"]}, {"kind": "p", "text": "同一个 Copilot CLI agent、同一份订阅——外加围绕它的一套真实、可移植、开源的设计工作流。Open Design 本地优先且采用 Apache-2.0，所以关于你的工作或凭证的一切都不会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "GitHub Copilot CLI 真的能做设计工作吗？", "text": "能——只要在上下文里有一个审美 skill、一套设计系统和真实参考图，Copilot CLI 就能产出生产级、响应式的 UI，而且你可以挑选最能对照参考验证输出的那个模型。缺少这份上下文时，它往往会默认退回到千篇一律的观感，而这正是 Open Design 要填补的差距。"}, {"name": "用 Copilot CLI 做设计需要订阅吗？", "text": "需要——Copilot CLI 跑在一个有效的 GitHub Copilot 订阅上（Pro、Pro+、Business 或 Enterprise）；它不是 BYOK。你用 GitHub 账号鉴权。Open Design 绝不代理你的凭证——你的订阅由你的 agent 直接使用。"}, {"name": "Copilot CLI 具体好在哪、为什么适合设计？", "text": "两点：它会自动读取仓库指令和 AGENTS.md，于是你的设计规范随仓库流转；它还让你按任务在 Anthropic、OpenAI 和 Google 的前沿模型之间切换。两者都有帮助——但审美仍来自你提供的设计系统、skill 和参考。"}, {"name": "前端设计该用 Copilot CLI 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体、理解代码库的设计决策著称；Copilot CLI 的优势在于跨提供方的模型选择，以及在你可能已经拥有的订阅上深度的 GitHub 集成。许多团队两者并用——Open Design 让你切换 agent 而无需改变设计工作流。"}, {"name": "怎么把 Copilot CLI 连接到 Figma？", "text": "用 /mcp add 命令添加 Figma MCP server；设置存于 ~/.copilot 下的 mcp-config.json。之后 Copilot 就能拉取真实的设计上下文——组件、变量、布局数据——让生成的代码贴合源头，而非近似猜测。"}, {"name": "Open Design 与 GitHub 或 Microsoft 有关联吗？", "text": "没有。GitHub Copilot CLI 是 GitHub 的产品；Open Design 是一个独立的开源项目，以一等适配器的方式支持它。GitHub Copilot 是 GitHub, Inc. 和 Microsoft 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且采用 Apache-2.0。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的 GitHub Copilot 凭证由你的 agent 直接使用，绝不经 Open Design 服务器路由。"}], "ctaTitle": "用 GitHub Copilot CLI 做设计，以开放的方式。", "ctaBody": "带上你的 GitHub Copilot 订阅，把每个文件都留在本地，围绕你已经在用的 agent 获得一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Copilot CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "什么是 GitHub Copilot CLI", "aboutBody": ["GitHub Copilot CLI 是 GitHub 原生于终端的编码 agent，由与 Copilot 编码 agent 同一套 agentic 框架驱动。它读取你的代码库、编辑文件、运行命令，并结合你的 GitHub issue、PR 和仓库工作。", "它会自动读取自定义指令文件和 AGENTS.md，并让你按任务在 Anthropic、OpenAI 和 Google 的前沿模型之间切换。", "Open Design 把 Copilot CLI 当作一等适配器，于是这个 agent 能嵌入一条结构化、开源的设计流水线。"], "vendorLabel": "厂商", "vendor": "GitHub", "credentialLabel": "凭证", "credential": "GitHub Copilot 订阅", "designTitle": "用 Copilot CLI 做设计", "designLead": "Copilot CLI 的设计强项集中在指令和模型选择上：", "designPoints": [{"label": "截图 → UI", "body": "挑一个强大的多模态模型，把参考图变成响应式标记，再对照它检查结果。"}, {"label": "多模型选择", "body": "用 /model 按任务在 Anthropic、OpenAI 和 Google 的前沿模型之间切换，全部跑在你的 Copilot 订阅上。"}, {"label": "指令 + MCP", "body": "自定义指令和 AGENTS.md 承载你的规范；Figma MCP server 把真实设计上下文带入代码。"}, {"label": "深度 GitHub 集成", "body": "内置 GitHub MCP server，可访问你的仓库、issue 和 PR，用你现有的 GitHub 账号鉴权。"}], "linksTitle": "真实世界的资源", "linksLead": "GitHub Copilot CLI 的官方仓库和文档：", "links": [{"label": "github/copilot-cli (GitHub)", "href": "https://github.com/github/copilot-cli", "source": "GitHub · GitHub"}, {"label": "使用 GitHub Copilot CLI", "href": "https://docs.github.com/en/copilot/how-tos/copilot-cli/use-copilot-cli/overview", "source": "Docs · GitHub"}, {"label": "GitHub Copilot CLI 现已全面上线", "href": "https://github.blog/changelog/2026-02-25-github-copilot-cli-is-now-generally-available/", "source": "Changelog · GitHub"}], "withOdTitle": "Copilot CLI + Open Design", "withOdLead": "Open Design 是围绕 Copilot CLI 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design 并选择 GitHub Copilot CLI 作为你的 agent。", "用你的 GitHub Copilot 订阅鉴权——凭证留在你的机器上。", "选一套设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都存在你自己的仓库里，而非托管的云端。"], "withOdClosing": "同一个 Copilot CLI agent——外加围绕它的一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 GitHub 出品的吗？", "text": "不是。GitHub Copilot CLI 是 GitHub 的产品；Open Design 是一个独立的开源项目，以一等适配器的方式集成它。"}, {"name": "我需要订阅吗？", "text": "需要——Copilot CLI 跑在一个有效的 GitHub Copilot 订阅上（Pro、Pro+、Business 或 Enterprise）。Open Design 绝不代理你的凭证。"}, {"name": "Open Design 与 GitHub 或 Microsoft 有关联吗？", "text": "没有。Open Design 独立运作；GitHub Copilot 是 GitHub, Inc. 和 Microsoft 的商标。"}], "ctaTitle": "用 GitHub Copilot CLI 做设计，以开放的方式。", "ctaBody": "给仓库点 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  qwen: {"title": "用 Qwen Code 做设计 — Open Design", "description": "人们如何用阿里巴巴开源的 Qwen Code CLI 做 UI 和网页设计——它的 Qwen3-Coder 模型、超大上下文窗口、QWEN.md 和 MCP——以及 Open Design 如何把 Qwen Code 变成一个本地优先、开源的设计 agent。", "breadcrumb": "Qwen Code", "label": "Agent · Qwen Code", "heading": "用 Qwen Code 做设计。", "lead": "Qwen Code 是阿里巴巴开源的终端 agent，由 Gemini CLI 改造而来，并针对 Qwen3-Coder 模型做了调优。它超大的上下文窗口能一次性装下整套设计系统，这让它成为一个真正可用的设计工具——前提是你给它参考、规范和一套验证闭环。Open Design 把它接入开源设计工作流：用你自己的 DashScope 或 Qwen API key、你自己的文件，全程本地优先。", "tldrTitle": "太长不看", "tldrBody": "Qwen Code 凭借强大的 agent 化编码能力和超大上下文窗口，把清晰的参考转化为响应式 UI，BYOK 只需一个 DashScope 或 OpenAI 兼容的 key。Open Design 为它配上一套精选的设计系统与 skill 库，再加上桌面端工作流——BYOK 并把一切都留在本地。", "toc": ["什么是 Qwen Code", "用 Qwen Code 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Qwen Code 变成一个本地优先、开源的设计 agent——用你自己的 DashScope 或 Qwen API key、你自己的文件，外加围绕它的一套精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Qwen Code", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qwen Code 是阿里巴巴开源的终端 AI agent。它由 Google 的 Gemini CLI 改造而来，在解析器层面和提示词上做了适配，让它能充分发挥 Qwen3-Coder 模型的能力。有两点让它在设计场景中尤其值得关注：它是一个强大的 agent 化编码模型，能从一个自然语言任务出发，自己规划、编辑文件、跑构建和验证闭环；它的超大上下文窗口能一次性装下整套设计系统和代码库。配上恰当的参考、规范和一套验证闭环，它能构建出真实、响应式的 UI——而且它是开源、BYOK 的，你自带 key 就能用。这是一份实用的端到端指南，讲如何用 Qwen Code 做 UI、前端和设计系统的工作，以及如何用 Open Design 把它接入一套结构化的设计工作流。", "本文涵盖：Qwen Code 究竟是什么，为什么一个强编码模型加超大上下文契合设计，如何从零搭好它，参考到 UI 的闭环，QWEN.md 和 MCP 如何扩展它，它与 Codex、Claude Code、Cursor、Gemini CLI 相比如何，那些让 AI 产出显得平庸的坑，以及 Open Design 如何作为一个开放、本地优先的设计层补上缺口——这是一对天然组合，因为两者都开源、都跑在你自己的机器上。"], "heroImage": {"src": "/agents/qwen-design/qwen-design-hero.webp", "alt": "Qwen Code 设计反馈闭环：终端 agent 读取一张参考图、浏览器渲染 UI、一个工作区，外加一条回环的反馈箭头", "caption": "核心闭环：Qwen Code 在终端里读取你的参考，在真实浏览器里构建并验证 UI，并对照参考反复迭代——整套设计系统始终在上下文里。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-qwen", "label": "Qwen Code 究竟是什么"}, {"id": "why-design", "label": "为什么强编码模型 + 超大上下文契合设计"}, {"id": "setup", "label": "从零搭好用于设计的 Qwen Code"}, {"id": "screenshot-workflow", "label": "参考到 UI 的工作流"}, {"id": "extend", "label": "QWEN.md、MCP 和扩展"}, {"id": "vs", "label": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "坑，以及那种「AI 味」外观"}, {"id": "open-design", "label": "在 Open Design 中用 Qwen Code 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-qwen", "heading": "Qwen Code 究竟是什么", "blocks": [{"kind": "p", "text": "Qwen Code 是阿里巴巴为终端发布的开源（Apache-2.0）AI agent。它读取你的仓库、编辑文件、运行 shell 命令、上网检索——从自然语言任务出发去规划和验证工作，而不只是补全几行代码。它由 Google 的 Gemini CLI 改造而来，在解析器层面和提示词上做了调优，以释放 Qwen3-Coder 模型在 agent 化编码任务上的能力。"}, {"kind": "p", "text": "对设计工作来说，有两个特性格外突出。它是一个强大的 agent 化编码器，能拿着一份参考和一份清晰的需求去构建、运行并自我纠正出响应式 UI。而 Qwen3-Coder 模型自带超大上下文窗口，大到足以一次性装下你整套设计系统、组件库和参考集，而不必把它们压缩概括掉。"}, {"kind": "steps", "items": [{"label": "上下文文件", "body": "Qwen Code 会读取一个 QWEN.md 文件作为持久的项目上下文——这正是编写你的设计规范、tokens 和评审清单的天然位置。个人和项目级设置会层层叠加在其上。"}, {"label": "内置工具 + MCP", "body": "它开箱即带文件、shell 和 web 工具，并支持 MCP server（在 ~/.qwen/settings.json 的 mcpServers 下配置），以接入像实时 Figma 文件这样的外部上下文。"}, {"label": "从 BYOK 起步", "body": "你自带 key——一个 DashScope（阿里云百炼）API key，或任意 OpenAI 兼容端点，或 ModelScope——并在 settings.json 中配置。"}]}, {"kind": "ul", "items": ["厂商：Alibaba", "凭证：DashScope / Qwen API key（BYOK），或 OpenAI 兼容端点 / ModelScope", "许可：Apache-2.0，开源（由 Gemini CLI 改造而来）"]}]}, {"id": "why-design", "heading": "为什么强编码模型和超大上下文契合设计", "blocks": [{"kind": "p", "text": "Qwen Code 的设计优势来自两个特性——但和每个 agent 一样，审美仍然得由你来提供。"}, {"kind": "steps", "items": [{"label": "强大的 agent 化编码", "body": "Qwen3-Coder 模型针对 agent 化任务做了调优，因此这个 agent 会规划、编辑、跑构建并自我纠正——把一份清晰的参考和需求变成响应式标记，而不是一锤子的瞎猜。"}, {"label": "超大上下文窗口", "body": "Qwen3-Coder 的超大上下文意味着整套设计系统、tokens 和许多参考状态能一次性装下，于是 agent 会复用你真实的基础原语，而不是凭空造出一次性的样式。"}, {"label": "QWEN.md 里的规范", "body": "一份 QWEN.md（加上 Figma MCP server）把 agent 指向你的 tokens、组件和真实规格，于是它是对着一个品牌干活，而不是套用一套默认外观。"}]}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-taste-triangle.webp", "alt": "图示：设计系统、skill 和参考图汇聚成优质的设计产出", "caption": "审美来自你提供的三个输入：一套设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这个教训和每个 agent 教给我们的一样：Qwen Code 默认并不具备审美。当你给它约束时——一套设计系统、一个审美 skill 和具体的参考——它才能产出好设计。Open Design 恰恰把这些输入打包好了，这正是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零搭好用于设计工作的 Qwen Code", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 Qwen Code 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Qwen Code（Node 22+）\nnpm install -g @qwen-code/qwen-code@latest\n# 或：brew install qwen-code\n\n# 2. 在你的项目里启动它，首次运行时完成认证\ncd your-project\nqwen              # 运行 /auth，或在 ~/.qwen/settings.json 里设置一个 key\n\n# 3. 在 settings.json 里配置一个 DashScope（OpenAI 兼容）key\n#    baseUrl: https://dashscope.aliyuncs.com/compatible-mode/v1\n#    model:   qwen3-coder-plus   （设置 DASHSCOPE_API_KEY）\n\n# 4. 添加一个 QWEN.md 并接好 Figma MCP server（可选）\n#    在 ~/.qwen/settings.json 的 \"mcpServers\" 下添加 MCP"}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-setup-flow.webp", "alt": "五步搭建流程：安装、认证、配置 QWEN.md、添加 skill、验证", "caption": "搭建顺序：安装 → 认证 → 配置 QWEN.md → 添加 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "写下你的设计规则", "body": "把你的 tokens、基础原语和规范放进 QWEN.md，并让 Qwen Code 指向它们，这样产出会贴合一个品牌，而不是退回到一套通用外观。"}, {"label": "加入浏览器验证", "body": "接好一个 Playwright 或浏览器 MCP，让 Qwen Code 在真实浏览器里渲染，并跨断点检查产出，而不只是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "参考到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Qwen Code 收益最高的设计闭环，是把一份参考变成可用的响应式 UI，并反复迭代直到匹配——依靠 agent 去构建、渲染，并把产出对照参考做比较。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考开始——并描述多个状态（桌面与移动、悬停、空态、加载中），而不只是一张主视觉。", "提示词要具体；含糊的提示词即便用强模型也只会产出通用 UI。", "把你的设计系统和规范放在 QWEN.md 里，并告诉 Qwen Code tokens 和标准基础原语在哪里。", "跑一个 dev server，让 Qwen Code 在真实浏览器里渲染，调整到各个断点尺寸来检查结果。", "通过让 Qwen Code 把它的实现对照参考做比较来迭代——而不只是确认它能构建通过。"]}, {"kind": "p", "text": "用 @ 引用一个文件把它附到提示词里，然后给出具体约束："}, {"kind": "code", "lang": "bash", "code": "qwen\n# 在提示词里：\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from QWEN.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "把提示词保持小而聚焦，提交好的迭代、回退坏的迭代（回退时告诉 Qwen Code），这样每一轮都在一个干净的基础上推进。"}]}, {"id": "extend", "heading": "QWEN.md、MCP 和扩展", "blocks": [{"kind": "p", "text": "三个扩展点让 Qwen Code 能胜任持续的设计工作，而这三者都能干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "QWEN.md 上下文", "body": "项目规则放在仓库根目录的 QWEN.md 里（带全局层和项目层）。它是你设计规范的长久归宿，每次运行都会被读取。"}, {"label": "MCP server", "body": "在 ~/.qwen/settings.json 的 mcpServers 下配置 MCP server——这是引入设计上下文和外部工具的可移植方式，其中最相关的是 Figma MCP server，它们能跨 agent 通用，而不只服务于 Qwen Code。"}, {"label": "skill 与内置工具", "body": "Qwen Code 的 skill 以及它内置的文件、shell 和 web 工具，让它无需离开终端就能收集参考并运行验证闭环。"}]}, {"kind": "p", "text": "这些都是可移植、跨 agent 的能力——正是 Open Design 旨在编排的那类东西，而不是在每个项目里重新造一遍。"}]}, {"id": "vs", "heading": "做设计时 Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI", "blocks": [{"kind": "p", "text": "设计工作没有唯一赢家——每个 agent 各有所长，老练的团队会把它们叠着用。一个公允的概括："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Qwen Code", "在开放的 Qwen3-Coder 模型上具备强大的 agent 化编码能力，外加超大上下文；开源且 BYOK", "开源、key 灵活、且能把整套设计系统装进上下文的构建"], ["Codex", "凭借前端 skill 带来出色的视觉打磨；沙箱化的异步构建", "委托式异步构建与可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex、间距、字体）和理解代码库的 UX", "前端推理与大上下文重构"], ["Cursor", "带实时预览和行内编辑的可视化「构建即所见」闭环", "在 IDE 内紧凑的「边改边看」UI 工作"], ["Gemini CLI", "强大的多模态图像理解与 1M-token 上下文；Qwen Code 正是由它改造而来", "大量截图的工作与超大上下文"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人类——它们在没有 skill、参考和约束时，都会默认退回一套通用审美。这才是真正要解决的问题——而它是设计工具形状的，不是模型形状的。"}]}, {"id": "pitfalls", "heading": "坑，以及如何避开那种「AI 味」外观", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨是它看起来很通用——柔和的渐变、悬浮的面板、过大的圆角、夸张的阴影，一股「Inter 字体加紫色」的味道，「一看就是 AI 做的」。其他被反映的问题还包括移动端布局崩坏、以及指令泄漏进 UI 文案里。这些都不是 Qwen Code 独有的；任何 agent 在缺少精选设计上下文时运行，都会这样。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会逼着 agent 笃定一个真实的方向，而不是套用默认外观。"}, {"label": "在真实浏览器里验证", "body": "让 agent 跨断点渲染并自检，这样布局就不会在移动端悄悄崩掉。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图，是对产出质量最大的单一杠杆。"}, {"label": "把规则写进 QWEN.md", "body": "把诸如「不要 hero 卡片、最多两种字体、品牌优先的层级」这类风格规则，放在 agent 每次运行都会读到的地方。"}]}, {"kind": "p", "text": "注意到了吗，每一项缓解措施都是在给 agent 一份精选的设计上下文。逐个项目手工维护这份上下文，正是 Open Design 替你免去的苦活。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Qwen Code 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面那套工作流一再呼唤的那个开源设计层。它把 Qwen Code 当作一等公民适配器，并用一套精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI 把它包起来——于是让 Qwen Code 好用的那份设计上下文，从第一次运行就在那里，而不必每次手工拼凑。两者都开源、都本地优先，这让这对组合天然契合。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 Qwen Code 作为你的 agent。", "用你的 DashScope 或 Qwen API key 认证（BYOK）——凭证留在你自己的机器上，绝不经我们中转。", "选一套设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "每一份产物和 DESIGN.md 文件都留在你自己的仓库里，而非托管云端。"]}, {"kind": "p", "text": "同一个 Qwen Code agent、同一个 key——外加围绕它的一套真实、可移植、开源的设计工作流。它本地优先、Apache-2.0，所以你的工作和凭证都不会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Qwen Code 真能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一套设计系统和真实的参考图，Qwen Code 就能产出生产级的响应式 UI，并且它的 agent 化闭环会构建、渲染，并对照参考验证产出。缺了这份上下文，它往往会退回一套通用外观，而这正是 Open Design 填补的缺口。"}, {"name": "用 Qwen Code 做设计需要付费吗？", "text": "Qwen Code 免费且开源，但它是 BYOK——你自带一个 DashScope（阿里云百炼）API key、一个 OpenAI 兼容端点，或 ModelScope。阿里巴巴也提供一个固定费用的编码套餐。无论哪种方式，Open Design 都绝不中转你的凭证。"}, {"name": "Qwen Code 具体好在哪里适合做设计？", "text": "两点：Qwen3-Coder 模型针对 agent 化编码做了调优，于是 agent 会构建并自我纠正出响应式 UI；它们的超大上下文能一次性装下整套设计系统和参考集。两者都有帮助——但审美仍然来自你提供的设计系统、skill 和参考。"}, {"name": "Qwen Code 和 Gemini CLI 是一回事吗？", "text": "不是。Qwen Code 由 Google 的 Gemini CLI 改造而来——同源的开源血统——在解析器层面和提示词上做了适配，以针对 Qwen3-Coder 模型调优。Open Design 两者都支持，所以你能在不改设计工作流的前提下切换 agent。"}, {"name": "我怎么把 Qwen Code 连到 Figma？", "text": "在 ~/.qwen/settings.json 的 mcpServers 下添加 Figma MCP server。然后 Qwen Code 就能拉取真实的设计上下文——组件、变量、布局数据——让生成的代码贴合源文件，而不是近似猜测。"}, {"name": "Open Design 和 Alibaba 或 Qwen 有关联吗？", "text": "没有。Qwen Code 是 Alibaba 的产品；Open Design 是一个独立的开源项目，把它作为一等公民适配器来支持。Qwen 是 Alibaba 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先、Apache-2.0。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的 DashScope 或 Qwen 凭证由你的 agent 直接使用，绝不经 Open Design 的服务器路由。"}], "ctaTitle": "用开放的方式，跟 Qwen Code 一起做设计。", "ctaBody": "自带你的 DashScope 或 Qwen API key，把每个文件都留在本地，并围绕你已经在用的 agent 获得一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Qwen Code", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "什么是 Qwen Code", "aboutBody": ["Qwen Code 是阿里巴巴开源的（Apache-2.0）终端 AI agent，由 Google 的 Gemini CLI 改造而来。它读取你的代码库、编辑文件、运行命令并上网检索。", "它针对 Qwen3-Coder 模型做了调优，这些模型的超大上下文窗口让它能一次性装下整套设计系统和参考集。", "Open Design 把 Qwen Code 当作一等公民适配器，于是这个 agent 能嵌入一条结构化、开源的设计管线。"], "vendorLabel": "厂商", "vendor": "Alibaba", "credentialLabel": "凭证", "credential": "DashScope / Qwen API key（BYOK）", "designTitle": "用 Qwen Code 做设计", "designLead": "Qwen Code 的设计强项围绕它的模型和上下文展开：", "designPoints": [{"label": "参考 → UI", "body": "强大的 agent 化编码把一份清晰的参考和需求变成响应式标记，并对照参考自检结果。"}, {"label": "超大上下文", "body": "整套设计系统、组件库和参考集能一次性装下，于是产出会复用你真实的基础原语。"}, {"label": "QWEN.md + MCP", "body": "上下文文件承载你的规范；Figma MCP server 把真实的设计上下文带进代码。"}, {"label": "开放且 BYOK", "body": "Apache-2.0 且 key 灵活——一个 DashScope 或 Qwen API key、一个 OpenAI 兼容端点，或 ModelScope。"}], "linksTitle": "实战资源", "linksLead": "Qwen Code 的官方仓库和文档：", "links": [{"label": "QwenLM/qwen-code（GitHub）", "href": "https://github.com/QwenLM/qwen-code", "source": "GitHub · Alibaba / Qwen"}, {"label": "Qwen Code 文档", "href": "https://qwenlm.github.io/qwen-code-docs/en/", "source": "Docs · Qwen"}, {"label": "Qwen3-Coder：让 Agent 化编码走进现实", "href": "https://qwen.ai/blog?id=qwen3-coder", "source": "Blog · Qwen"}], "withOdTitle": "Qwen Code + Open Design", "withOdLead": "Open Design 是围绕 Qwen Code 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design，并选择 Qwen Code 作为你的 agent。", "用你的 DashScope 或 Qwen API key 认证（BYOK）——凭证留在你自己的机器上。", "选一套设计系统和 skill，然后以一致的审美生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都留在你自己的仓库里，而非托管云端。"], "withOdClosing": "同一个 Qwen Code agent——外加围绕它的一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Alibaba 做的吗？", "text": "不是。Qwen Code 是 Alibaba 的产品；Open Design 是一个独立的开源项目，把它作为一等公民适配器集成进来。"}, {"name": "我需要付费吗？", "text": "Qwen Code 开源但 BYOK——自带一个 DashScope 或 Qwen API key、一个 OpenAI 兼容端点，或 ModelScope。Open Design 绝不中转你的凭证。"}, {"name": "Open Design 和 Alibaba 或 Qwen 有关联吗？", "text": "没有。Open Design 是独立的；Qwen 是 Alibaba 的商标。"}], "ctaTitle": "用开放的方式，跟 Qwen Code 一起做设计。", "ctaBody": "给仓库点个 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  grok: {"title": "用于设计的 Grok Build — Open Design", "description": "人们如何使用 xAI 的 Grok Build（Grok Build）做 UI 与网页设计——它的计划模式、AGENTS.md 和 MCP、能识别图像的 Grok 模型以及超大上下文——以及 Open Design 如何把 Grok Build 变成一个本地优先、开源的设计 agent。", "breadcrumb": "Grok Build", "label": "Agent · Grok Build", "heading": "用于设计的 Grok Build。", "lead": "Grok Build 是 xAI 的终端编码 agent。它在动你的文件之前先规划好多步工作，把图像和代码一起读取，并在你的仓库里跑构建并验证的循环——只要你给它参考、规范和一个验证环节，它就能成为一个真正的设计工具。Open Design 把它接入开源设计工作流：用你的 SuperGrok 登录或 xAI API key，操作你自己的文件，本地优先。", "tldrTitle": "太长不看", "tldrBody": "Grok Build 借助计划模式审查、并行子 agent 以及能识别图像的 Grok 模型，把参考图变成响应式 UI，并通过你的 SuperGrok 或 X Premium+ 账户进行身份验证。Open Design 为它配上一套精选的设计系统与 skill 库，外加一个桌面工作流——BYOK，一切都留在本地。", "toc": ["什么是 Grok Build", "用 Grok Build 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Grok Build 变成一个本地优先、开源的设计 agent——用你的 SuperGrok 登录或 xAI API key，操作你自己的文件，并在外围配上一套精选的 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Grok Build", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Grok Build——xAI 的终端编码 agent，以 Grok Build 之名发布——是一个驻留在你终端里的 agentic 工具。有两点让它对设计尤其有意思：它在动手之前会先规划有风险的工作，所以你可以在任何文件改动之前审查它提出的方案；而且它的 Grok 模型支持图像输入，因此它能在编写代码的同时对一张参考截图进行推理。配上恰当的参考、规范和一个验证循环，它能构建出真实、响应式的 UI——直接通过你的 SuperGrok 或 X Premium+ 账户进行身份验证，无需折腾 API key。这是一份实用的端到端指南，教你如何用 Grok Build 做 UI、前端和设计系统工作，并把它接入 Open Design 提供的结构化设计工作流。", "本文涵盖：Grok Build 究竟是什么，为什么计划模式和能识别图像的模型契合设计，如何从零开始搭建它，截图到 UI 的循环，AGENTS.md 和 MCP 如何扩展它，它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比，让 AI 产出显得千篇一律的那些陷阱，以及 Open Design 如何作为一个开放、本地优先的设计层来弥合差距——你的凭证和产物从不离开你的机器。"], "heroImage": {"src": "/agents/grok-design/grok-design-hero.webp", "alt": "Grok Build 设计反馈循环：一个终端 agent 依据参考图进行规划，一个浏览器渲染 UI，以及一个工作区，反馈箭头回流形成闭环", "caption": "核心循环：Grok Build 在终端里依据你的参考进行规划，在真实浏览器中构建并验证 UI，并对照参考反复迭代——你的规范则写在 AGENTS.md 里。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-grok", "label": "Grok Build 究竟是什么"}, {"id": "why-design", "label": "为什么计划模式 + 图像输入契合设计"}, {"id": "setup", "label": "从零搭建用于设计的 Grok Build"}, {"id": "screenshot-workflow", "label": "截图到 UI 的工作流"}, {"id": "extend", "label": "AGENTS.md、MCP 与子 agent"}, {"id": "vs", "label": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "陷阱与“AI 味”观感"}, {"id": "open-design", "label": "在 Open Design 中用 Grok Build 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-grok", "heading": "Grok Build 究竟是什么", "blocks": [{"kind": "p", "text": "Grok Build 是 xAI 的终端编码 agent，以 Grok Build 之名发布。它读取你的仓库、编辑文件、运行 shell 命令，并依据自然语言任务规划多步工程工作，而不只是补全代码行。它围绕 xAI 的 Grok 模型构建——在 xAI API 上以 grok-build 模型家族的形式暴露——并通过你的 xAI 账户进行身份验证，因此 agent 和模型都出自同一家厂商。"}, {"kind": "p", "text": "对设计工作来说，有两个特性尤为突出。它有一个计划模式，会先草拟一份结构化方案，供你在任何改动落地之前批准、评论或重写——当你在迭代 UI 时，这是个很有用的关卡。而它的 Grok 模型支持图像输入，所以你可以把一张参考截图交给它，它会对实际布局进行推理，而不是从一段文字描述里瞎猜。"}, {"kind": "steps", "items": [{"label": "上下文文件", "body": "Grok Build 会读取 AGENTS.md 文件来获取持久的项目上下文——这正是用来编码你的设计规范、tokens 和审查清单的自然位置。它遵循 Codex 和其他 agent 同样使用的开放 AGENTS.md 约定。"}, {"label": "工具、MCP + 子 agent", "body": "它能编辑文件、运行 shell 命令，并支持 MCP 服务器来引入外部上下文，比如一个实时的 Figma 文件；对于较大的任务，它可以委派给并行的子 agent，让它们同时进行调研、构建和审查。"}, {"label": "用你的账户登录", "body": "你通过浏览器以 SuperGrok 或 X Premium+ 订阅登录来完成身份验证；你也可以带上自己的 xAI API key 用于无头运行和 CI 场景。"}]}, {"kind": "ul", "items": ["厂商：xAI", "凭证：xAI SuperGrok OAuth（`grok login`），或用于无头场景的 xAI API key（BYOK）", "模型：xAI Grok 模型（xAI API 上的 grok-build 家族），支持图像输入"]}]}, {"id": "why-design", "heading": "为什么计划模式和能识别图像的模型契合设计", "blocks": [{"kind": "p", "text": "Grok Build 的设计优势来自两个特性——但和所有 agent 一样，品味仍然得由你来提供。"}, {"kind": "steps", "items": [{"label": "能识别图像的推理", "body": "因为 Grok 模型支持图像输入，agent 能读取参考截图——把自己渲染出的产出与图像对照，而不是从一段文字描述里瞎猜。"}, {"label": "改动落地前的计划模式", "body": "计划模式会草拟一份结构化方案，供你在文件改动前批准，于是设计意图在一开始就被审查，而不是等差异出来之后才发现。"}, {"label": "写在 AGENTS.md 里的规范", "body": "一份 AGENTS.md（再加上 Figma MCP 服务器）会把 agent 指向你的 tokens、组件和真实规格，让它针对一个品牌来工作，而不是套用默认观感。"}]}, {"kind": "image", "src": "/agents/grok-design/grok-design-taste-triangle.webp", "alt": "示意图展示设计系统、skill 和参考图汇聚成优秀的设计产出", "caption": "品味来自你提供的三项输入：一个设计系统、一个 skill 和真实的参考图。"}, {"kind": "p", "text": "这条教训和每个 agent 教给我们的一样：Grok Build 默认并不具备品味。当你给它约束时——一个设计系统、一个审美 skill 和具体的参考——它才会产出好的设计。Open Design 恰恰把这些输入打包好了，这正是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零开始搭建用于设计工作的 Grok Build", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 Grok Build 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 在 macOS/Linux 上安装 Grok Build（Grok Build）\ncurl -fsSL https://x.ai/cli/install.sh | bash\n\n# 2. 在你的项目里启动它，并在首次运行时进行身份验证\ncd your-project\ngrok login   # 打开浏览器；用 SuperGrok / X Premium+ 登录\n#   或者，对于无头 / CI 场景，设置 xAI API key：\n#   export XAI_API_KEY=xai-...\n\n# 3. 添加项目上下文\n#    在仓库根目录创建一个 AGENTS.md，写入你的设计规范\n\n# 4. 接入 Figma MCP 服务器（可选，用于设计交付）\n#    把它加到你的 MCP 服务器配置里"}, {"kind": "image", "src": "/agents/grok-design/grok-design-setup-flow.webp", "alt": "五步搭建流程：安装、身份验证、配置 AGENTS.md、添加 skill、验证", "caption": "搭建顺序：安装 → 身份验证 → 配置 AGENTS.md → 添加 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "编码你的设计规则", "body": "把你的 tokens、基础元素和规范写进 AGENTS.md 并让 Grok 指向它们，这样产出就会贴合一个品牌，而不是退回到千篇一律的默认观感。"}, {"label": "加入浏览器验证", "body": "接入 Playwright 或浏览器 MCP，让 Grok 在真实浏览器中渲染，并跨断点检查它的产出，而不仅仅是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Grok Build 时杠杆最高的设计循环，就是把一张参考图变成可用的响应式 UI 并不断迭代直到吻合——靠计划模式就方案达成一致，靠能识别图像的模型把产出与参考对照。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考出发——并包含多种状态（桌面端和移动端、hover、空态、加载态），而不只是一张主视觉。", "在提示里写具体；含糊的提示即使配上强模型也只会产出千篇一律的 UI。", "把你的设计系统和规范放进 AGENTS.md，并告诉 Grok tokens 和规范基础元素在哪里。", "用计划模式审查方案，然后启动一个 dev server，让 Grok 在真实浏览器中渲染，调整到各个断点来检查结果。", "通过让 Grok 把自己的实现与截图对照来迭代——而不仅仅是确认它能构建。"]}, {"kind": "p", "text": "附上你的参考图，并给出具体约束："}, {"kind": "code", "lang": "bash", "code": "grok\n# 在提示里（附上 reference-desktop.png 和 reference-mobile.png）：\n> 用 React + Vite + Tailwind + TypeScript 实现这个设计。\n  复用我已有的设计系统组件和 AGENTS.md 里的 tokens。\n  匹配间距、布局和层级；做成响应式。\n  先把方案给我看，然后在浏览器里渲染并迭代，\n  直到它在各个断点上都与参考吻合。"}, {"kind": "p", "text": "让提示保持小而聚焦，提交好的迭代、回退差的迭代（回退时告诉 Grok），这样每一轮都能在一个干净的基础上推进。"}]}, {"id": "extend", "heading": "AGENTS.md、MCP 与子 agent", "blocks": [{"kind": "p", "text": "三个扩展点让 Grok Build 适合持续的设计工作，而这三者都能干净地映射到一个开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "AGENTS.md 上下文", "body": "项目规则写在仓库根目录的 AGENTS.md 里。它是你设计规范的持久归宿，每次运行都会被读取——而且它是其他 agent 也能理解的同一种开放格式，所以这些规则会随你一起迁移。"}, {"label": "MCP 服务器", "body": "配置 MCP 服务器来引入设计上下文和外部工具，其中最相关的是 Figma MCP 服务器——它是把真实规格喂进代码的可移植方式，跨 agent 通用，不只限于 Grok。"}, {"label": "子 agent 与内置工具", "body": "Grok Build 能派生出并行的子 agent 来同时进行调研、构建和审查，而它的文件、shell 和搜索工具让它无需离开终端就能收集参考并跑完验证循环。"}]}, {"kind": "p", "text": "这些都是可移植的多 agent 能力——正是 Open Design 旨在编排、而非在每个项目里重造的那类东西。"}]}, {"id": "vs", "heading": "做设计时 Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI", "blocks": [{"kind": "p", "text": "设计工作没有唯一赢家——每个 agent 各有所长，经验丰富的团队会把它们叠着用。一个公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Grok Build", "改动落地前的计划模式审查、能识别图像的 Grok 模型，以及并行子 agent；用你的 SuperGrok 账户登录", "在循环中带着 xAI 模型、经过审查、计划优先的 UI 构建"], ["Codex", "凭借前端 skill 带来出色的视觉打磨；沙箱化的异步构建", "委派式异步构建与可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex、间距、字体）以及理解代码库的 UX", "前端推理与大上下文重构"], ["Cursor", "带实时预览和内联编辑的可视化构建即所见循环", "在 IDE 内进行紧凑的迭代即观察 UI 工作"], ["Gemini CLI", "强大的多模态图像理解和超大上下文；开源且带免费额度", "截图密集的工作，以及把整个设计系统装进上下文"]]}, {"kind": "p", "text": "社区反复得出的结论是：品味来自人类——没有 skill、参考和约束，它们全都会退回到千篇一律的审美。这才是真正要解决的问题——而它是设计工具形态的，不是模型形态的。"}]}, {"id": "pitfalls", "heading": "陷阱，以及如何避开“AI 味”观感", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨是它看起来千篇一律——柔和的渐变、悬浮的面板、过大的圆角、夸张的阴影，一股 Inter 字体加紫色的味道，“一看就是 AI 做的”。其他被反映的问题还包括移动端布局崩坏，以及指令文字泄漏进 UI 文案。这些都不是 Grok Build 独有的；任何 agent 在没有精选设计上下文的情况下运行都会这样。"}, {"kind": "steps", "items": [{"label": "加入一个审美 skill", "body": "一个精选的设计 skill 会迫使 agent 承诺一个真实的方向，而不是套用默认观感。"}, {"label": "在真实浏览器中验证", "body": "跨断点渲染并自检，让布局不会在移动端悄无声息地崩坏。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图是对产出质量影响最大的那个杠杆。"}, {"label": "把规则编码进 AGENTS.md", "body": "把“不要主视觉卡片、最多两种字体、品牌优先的层级”这类规则放到 agent 每次运行都会读取的地方。"}]}, {"kind": "p", "text": "注意，每一种缓解办法都是在给 agent 一份精选的设计上下文。手工地、按项目维护这份上下文，正是 Open Design 替你免去的苦差事。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Grok Build 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面那套工作流一直在呼唤的开源设计层。它把 Grok Build 当作一等适配器，并在外围包上一套精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI——于是让 Grok 表现出色的那份设计上下文从第一次运行起就已就位，而不必每次都手工拼凑。Open Design 是独立的、采用 Apache-2.0 协议，并运行在你自己的机器上，这让二者天然契合。"}, {"kind": "ol", "items": ["安装 Open Design 并选择 Grok Build 作为你的 agent。", "用你的 SuperGrok 账户或 xAI API key（BYOK）进行身份验证——凭证留在你的机器上，从不经我们中转。", "挑一个设计系统和一个 skill，然后以一致的品味生成演示稿、原型和落地页。", "每一份产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管云端。"]}, {"kind": "p", "text": "同一个 Grok Build agent、同一套凭证——外加在外围包裹的一套真实、可移植、开源的设计工作流。它本地优先、采用 Apache-2.0，所以你的工作和凭证全都不会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Grok Build 真的能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一个设计系统和真实的参考图，Grok Build 就能产出生产级、响应式的 UI，而它能识别图像的 Grok 模型还能帮你把产出与参考对照验证。没有这份上下文，它往往会退回到千篇一律的观感，而这正是 Open Design 要填补的缺口。"}, {"name": "我该如何对 Grok Build 进行身份验证？", "text": "你通过浏览器以 SuperGrok 或 X Premium+ 订阅登录（`grok login`），所以无需管理 API key。对于无头或 CI 场景，你可以改用 xAI API key。无论哪种方式，Open Design 都不会中转你的凭证。"}, {"name": "Grok Build 具体好在哪里、适合设计？", "text": "两点：它的计划模式让你在任何改动落地前审查方案，而它的 Grok 模型支持图像输入，所以它能很好地读取参考截图。两者都有帮助——但品味仍然来自你提供的设计系统、skill 和参考。"}, {"name": "前端设计该选 Grok Build 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体的、理解代码库的设计决策著称；Grok Build 的优势在于计划模式审查和能识别图像的 xAI 模型。很多团队两者都用——Open Design 让你在不改变设计工作流的前提下切换 agent。"}, {"name": "我该如何把 Grok Build 连接到 Figma？", "text": "把 Figma MCP 服务器加到你的 MCP 配置里。这样 Grok 就能拉取真实的设计上下文——组件、变量、布局数据——于是生成的代码会匹配源文件，而不是近似模仿。"}, {"name": "Open Design 隶属于 xAI 吗？", "text": "不是。Grok Build 是 xAI 的产品；Open Design 是一个独立的开源项目，以一等适配器的方式支持它。Grok 是 xAI 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且采用 Apache-2.0。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，而你的 xAI 凭证由你的 agent 直接使用，绝不会经过 Open Design 的服务器路由。"}], "ctaTitle": "用 Grok Build 做设计，以开放的方式。", "ctaBody": "带上你自己的 SuperGrok 账户或 xAI API key，让每一个文件都留在本地，并在你已经在用的 agent 外围获得一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Grok Build", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "什么是 Grok Build", "aboutBody": ["Grok Build 是 xAI 的终端编码 agent，以 Grok Build 之名发布。它读取你的代码库、编辑文件、运行 shell 命令，并在动手之前规划多步工程工作。", "它构建于 xAI 的 Grok 模型之上，这些模型支持图像输入，因此它能在编写代码的同时对一张参考截图进行推理，并会读取 AGENTS.md 来获取项目规范。", "Open Design 把 Grok Build 当作一等适配器，于是这个 agent 能嵌入一条结构化、开源的设计管线。"], "vendorLabel": "厂商", "vendor": "xAI", "credentialLabel": "凭证", "credential": "xAI SuperGrok OAuth（`grok login`）", "designTitle": "用 Grok Build 做设计", "designLead": "Grok Build 的设计强项主要集中在它的工作流和模型上：", "designPoints": [{"label": "能识别图像的截图 → UI", "body": "Grok 模型支持图像输入，把一张参考图变成响应式标记，并对照它检查结果。"}, {"label": "改动前的计划模式", "body": "一份你在文件改动前批准的结构化计划，让设计意图在一开始就被审查，而不是等差异出来之后。"}, {"label": "AGENTS.md + MCP", "body": "上下文文件承载你的规范；Figma MCP 服务器把真实的设计上下文带进代码。"}, {"label": "用你的账户登录", "body": "通过 SuperGrok 或 X Premium+ 以 OAuth 进行身份验证，或带上 xAI API key（BYOK）用于无头场景。"}], "linksTitle": "实际资源", "linksLead": "Grok Build（Grok Build）的官方页面和文档：", "links": [{"label": "Grok Build（Grok Build）", "href": "https://x.ai/cli", "source": "xAI"}, {"label": "Grok Build 发布介绍", "href": "https://x.ai/news/grok-build-cli", "source": "新闻 · xAI"}, {"label": "xAI 模型文档", "href": "https://docs.x.ai/docs/models", "source": "文档 · xAI"}], "withOdTitle": "Grok Build + Open Design", "withOdLead": "Open Design 是围绕 Grok Build 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design 并选择 Grok Build 作为你的 agent。", "用你的 SuperGrok 账户或 xAI API key（BYOK）进行身份验证——凭证留在你的机器上。", "选择一个设计系统和 skill，然后以一致的品味生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管云端。"], "withOdClosing": "同一个 Grok Build agent——外加围绕它的一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 xAI 做的吗？", "text": "不是。Grok Build 是 xAI 的产品；Open Design 是一个独立的开源项目，以一等适配器的方式集成它。"}, {"name": "我该如何登录？", "text": "Grok Build 通过浏览器以 SuperGrok 或 X Premium+ 订阅登录，你也可以带上 xAI API key（BYOK）。Open Design 绝不会中转你的凭证。"}, {"name": "Open Design 隶属于 xAI 吗？", "text": "不是。Open Design 是独立的；Grok 是 xAI 的商标。"}], "ctaTitle": "用 Grok Build 做设计，以开放的方式。", "ctaBody": "为仓库点 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  kimi: {"title": "用于设计的 Kimi CLI — Open Design", "description": "人们如何使用 Moonshot AI 的 Kimi CLI 进行 UI 和网页设计——借助其 Kimi K2 智能体模型、超大上下文、AGENTS.md 与 MCP——以及 Open Design 如何把 Kimi CLI 变成一个本地优先、开源的设计智能体。", "breadcrumb": "Kimi CLI", "label": "智能体 · Kimi CLI", "heading": "用于设计的 Kimi CLI。", "lead": "Kimi CLI 是 Moonshot AI 推出的开源终端智能体，由 Kimi K2 系列模型驱动。它强大的智能体式编码能力和超大上下文窗口，让它能够装下整套设计系统并对照参考稿反复迭代——只要你给它约定和一套验证闭环，它就会成为真正的设计工具。Open Design 把它接入了一套开源的设计工作流：用你自己的 Moonshot API 密钥、你自己的文件，本地优先。", "tldrTitle": "太长不看", "tldrBody": "Kimi CLI 凭借智能体式的 Kimi K2 模型和超大上下文窗口，把参考稿和约定转化为响应式 UI，支持 BYOK 或 OAuth 登录。Open Design 为它配备了精选的设计系统与 skill 库以及桌面工作流——自带密钥（BYOK），一切都留在本地。", "toc": ["什么是 Kimi CLI", "用 Kimi CLI 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Kimi CLI 变成一个本地优先、开源的设计智能体——用你自己的 Moonshot API 密钥、你自己的文件，外加一套环绕它的精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Kimi CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kimi CLI 是 Moonshot AI 面向终端推出的开源 AI 智能体。有两点让它在设计场景中格外值得关注：它由 Kimi K2 系列驱动——这是一个万亿参数的混合专家模型，专为智能体式编码与工具调用精心优化；而这个模型还带有超大上下文窗口（近期 K2 版本可达 256k tokens），足以一次性装下整套设计系统和代码库。配合恰当的参考稿、约定和一套验证闭环，它能构建出真正可用的响应式 UI——你可以从 OAuth 登录起步，也可以用自己的 Moonshot API 密钥。本文是一份实用的端到端指南，讲述如何用 Kimi CLI 做 UI、前端和设计系统方面的工作，并把它接入由 Open Design 支撑的结构化设计工作流。", "内容涵盖：Kimi CLI 究竟是什么，为什么它智能体式的 Kimi K2 模型和超大上下文适合做设计，如何从零开始把它配置起来，从参考稿到 UI 的闭环，AGENTS.md、MCP 与子智能体如何扩展它，它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比，哪些坑会让 AI 产物看起来千篇一律，以及 Open Design 如何作为一个开放、本地优先的设计层来弥合落差——这是一对天然的搭配，因为两者都是开源的、都运行在你自己的机器上。"], "heroImage": {"src": "/agents/kimi-design/kimi-design-hero.webp", "alt": "Kimi CLI 设计反馈闭环：一个终端智能体读取参考图、一个浏览器渲染 UI、一个工作区，外加一条回流的反馈箭头", "caption": "核心闭环：Kimi CLI 在终端里读取你的参考稿，在真实浏览器中构建并验证 UI，对照参考不断迭代——而整套设计系统都在上下文之中。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-kimi", "label": "Kimi CLI 究竟是什么"}, {"id": "why-design", "label": "为什么智能体式 K2 + 超大上下文适合做设计"}, {"id": "setup", "label": "为设计配置 Kimi CLI（从零开始）"}, {"id": "screenshot-workflow", "label": "从参考稿到 UI 的工作流"}, {"id": "extend", "label": "AGENTS.md、MCP 与子智能体"}, {"id": "vs", "label": "Kimi CLI 对比 Codex、Claude Code、Cursor 与 Gemini CLI"}, {"id": "pitfalls", "label": "常见坑与“AI 味”外观"}, {"id": "open-design", "label": "在 Open Design 中用 Kimi CLI 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-kimi", "heading": "Kimi CLI 究竟是什么", "blocks": [{"kind": "p", "text": "Kimi CLI 是 Moonshot AI 面向终端发布的一款开源（Apache-2.0）AI 智能体。它会读取你的仓库、编辑文件、运行 shell 命令、搜索文件、抓取网页，并根据得到的反馈决定下一步——它从自然语言任务出发去规划和验证工作，而不仅仅是补全代码行。它是一个 Python 工具，用 uv 安装，背后驱动着 Kimi K2 模型家族。"}, {"kind": "p", "text": "在设计工作中，有两个特性尤为突出。Kimi K2 模型明确针对智能体式、长链路的编码与工具调用做了调优，因此智能体能把一项多步骤的构建任务一直推进到可用的结果。而上下文窗口在近期 K2 版本中可达 256k tokens，足以一次性装下你的整套设计系统、组件库和参考集，而不必把它们压缩概括掉。"}, {"kind": "steps", "items": [{"label": "上下文文件", "body": "Kimi CLI 会读取一个 AGENTS.md 文件作为持久的项目上下文——这正是编写你的设计约定、tokens 和评审清单的天然之处。对于尚未配置的项目，运行 /init 即可为其生成一个。"}, {"label": "MCP、ACP + 子智能体", "body": "它通过 /mcp-config 以对话方式管理 MCP 服务器，通过 Agent Client Protocol（kimi acp）把会话暴露给 Zed 和 JetBrains，并能在隔离的上下文中调度内置的 coder、explore 和 plan 子智能体。"}, {"label": "登录或 BYOK", "body": "首次启动时，/login 让你通过 OAuth（Kimi Code）授权，或输入你自己的 Moonshot API 密钥；Kimi 的平台还提供 OpenAI 兼容和 Anthropic 兼容的端点。"}]}, {"kind": "ul", "items": ["厂商：Moonshot AI", "凭证：Moonshot API 密钥（BYOK），或通过 Kimi Code 进行 OAuth 登录", "许可证：Apache-2.0，开源"]}]}, {"id": "why-design", "heading": "为什么智能体式 K2 模型和超大上下文适合做设计", "blocks": [{"kind": "p", "text": "Kimi CLI 的设计优势来自两项模型特性——但和所有智能体一样，审美品味仍然得由你来提供。"}, {"kind": "steps", "items": [{"label": "智能体式、长链路编码", "body": "Kimi K2 模型针对工具调用和多步骤工作做了优化，因此智能体能拿着参考稿和需求说明，真正去构建、运行并打磨 UI，而不是止步于初稿。"}, {"label": "超大上下文窗口", "body": "近期 K2 版本可达 256k tokens，意味着整套设计系统、tokens 和大量参考状态能一次性装下，于是智能体会复用你真实的基础元素，而不是凭空造出一次性的样式。"}, {"label": "把约定写进 AGENTS.md", "body": "一份 AGENTS.md（外加一个像 Figma 这样的 MCP 服务器）把智能体指向你的 tokens、组件和真实规范，于是它是在对照某个品牌工作，而不是套用默认外观。"}]}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-taste-triangle.webp", "alt": "示意图，展示设计系统、skill 和参考图汇聚成优秀的设计产出", "caption": "品味来自你提供的三项输入：一套设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这条教训和每个智能体教会我们的都一样：Kimi CLI 默认并不具备品味。当你给它约束——一套设计系统、一个审美 skill 和具体的参考稿——它就能产出优秀的设计。Open Design 恰恰把这些输入打包好了，这也是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零开始为设计工作配置 Kimi CLI", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 Kimi CLI 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Kimi CLI（使用 uv；Python 3.12–3.14，推荐 3.13）\ncurl -LsSf https://code.kimi.com/install.sh | bash\n# 或者，如果你已经装了 uv：\nuv tool install --python 3.13 kimi-cli\n\n# 2. 在你的项目中启动它，并在首次运行时完成认证\ncd your-project\nkimi              # 然后运行 /login：通过 Kimi Code 进行 OAuth，或粘贴一个 Moonshot API 密钥\n\n# 3. 生成项目上下文\n/init             # 为该项目生成一个 AGENTS.md\n\n# 4. 接入一个 MCP 服务器（可选，例如用 Figma 做设计交付）\n/mcp-config       # 以对话方式添加、编辑和认证 MCP 服务器"}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-setup-flow.webp", "alt": "五步配置流程：安装、认证、配置 AGENTS.md、添加 skill、验证", "caption": "配置顺序：安装 → 认证 → 配置 AGENTS.md → 添加 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "把你的设计规则写下来", "body": "把你的 tokens、基础元素和约定写进 AGENTS.md 并让 Kimi 指向它们，这样产出就会贴合某个品牌，而不是退回到千篇一律的外观。"}, {"label": "加上浏览器验证", "body": "接入一个 Playwright 或浏览器 MCP，让 Kimi 在真实浏览器中渲染，并在各个断点上检查产出，而不只是确认构建能通过。"}]}]}, {"id": "screenshot-workflow", "heading": "从参考稿到 UI 的工作流", "blocks": [{"kind": "p", "text": "在 Kimi CLI 上收益最高的设计闭环，就是把参考素材转化为可用的响应式 UI，并不断迭代直到匹配——把参考稿喂给智能体，让它在真实浏览器中把渲染产出与参考稿对照回看。"}, {"kind": "ol", "items": ["从你手头最清晰的参考稿出发——并且包含多种状态（桌面端和移动端、悬停态、空状态、加载态），而不只是一张主视觉图。", "在提示词里说清楚；含糊的提示词即便配上强大的智能体，也会产出千篇一律的 UI。", "把你的设计系统和约定放进 AGENTS.md，并告诉 Kimi tokens 和规范性基础元素位于何处。", "运行一个开发服务器，让 Kimi 在真实浏览器中渲染，并调整到各个断点来检查结果。", "让 Kimi 把自己的实现与参考稿对照回看来迭代——而不只是确认它能构建通过。"]}, {"kind": "p", "text": "把 Kimi 指向你的参考稿和开发服务器，然后给出具体的约束："}, {"kind": "code", "lang": "bash", "code": "kimi\n# 在提示词中：\n> 使用 React + Vite + Tailwind + TypeScript 实现 ./references 中的设计\n  （reference-desktop.png、reference-mobile.png）。\n  复用我已有的设计系统组件，以及 AGENTS.md 中的 tokens。\n  匹配间距、布局和层级；做成响应式。\n  运行开发服务器，在浏览器中渲染，并不断迭代，\n  直到它在各个断点上都与参考稿匹配。"}, {"kind": "p", "text": "让提示词保持小而聚焦，提交好的迭代、回退差的迭代（回退时告诉 Kimi），这样每一轮都建立在一个干净的基础之上。当某个流程难以用文字描述时，Kimi CLI 也可以接收一段简短的屏幕录制或演示片段。"}]}, {"id": "extend", "heading": "AGENTS.md、MCP 与子智能体", "blocks": [{"kind": "p", "text": "三个扩展点让 Kimi CLI 能够胜任持续的设计工作，而且这三者都能干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "AGENTS.md 上下文", "body": "项目规则存放在仓库根目录的 AGENTS.md 中。它是你设计约定的持久归宿，每次运行都会被读取——而且它是其他智能体也在用的同一种可移植格式。"}, {"label": "MCP 服务器", "body": "用 /mcp-config 以对话方式添加 MCP 服务器——这是引入设计上下文和外部工具的可移植方式，其中最相关的是 Figma MCP 服务器，它们能跨智能体通用，而不只对 Kimi 有效。"}, {"label": "子智能体与插件市场", "body": "在隔离的上下文中调度内置的 coder、explore 和 plan 子智能体，并从市场或任意 GitHub 仓库安装 skill、MCP 服务器和数据源，用来收集参考稿并跑通验证闭环。"}]}, {"kind": "p", "text": "这些都是可移植的、跨智能体的能力——而这恰恰是 Open Design 生来要去编排的东西，而不是每个项目都重造一遍。"}]}, {"id": "vs", "heading": "做设计时 Kimi CLI 对比 Codex、Claude Code、Cursor 与 Gemini CLI", "blocks": [{"kind": "p", "text": "在设计工作上没有唯一的赢家——每个智能体各有所长，有经验的团队会把它们叠在一起用。一个中肯的总结："}, {"kind": "table", "columns": ["智能体", "设计优势", "最适合"], "rows": [["Kimi CLI", "针对长链路编码和工具调用调优的智能体式 Kimi K2 模型，搭配超大上下文；开源且 BYOK", "多步骤构建，以及以低成本把整套设计系统装进上下文"], ["Codex", "凭借前端 skill 实现出色的视觉打磨；沙箱化的异步构建", "委派式异步构建，以及可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（色值、间距、字体）以及理解代码库的 UX", "前端推理与大上下文重构"], ["Cursor", "带实时预览和行内编辑的“边构建边看”视觉闭环", "在 IDE 内紧密的“迭代即看”UI 工作"], ["Gemini CLI", "强大的多模态图像理解能力和 1M-token 上下文；免费档", "大量依赖截图的工作以及超大上下文"]]}, {"kind": "p", "text": "社区反复得出的结论是：品味来自人类——它们在没有 skill、参考稿和约束的情况下，都会退回到一种千篇一律的审美。这才是真正要解决的问题——而它是设计工具形态的问题，不是模型形态的问题。"}]}, {"id": "pitfalls", "heading": "常见坑，以及如何避免“AI 味”外观", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨就是它看起来千篇一律——柔和渐变、漂浮面板、超大圆角、夸张阴影，一股“一眼就是 AI 做的”的 Inter 加紫色的气味。其他被反映的问题还包括移动端布局崩坏，以及指令文字泄漏进 UI 文案。这些都不是 Kimi CLI 独有的；只要任何智能体在缺乏精选设计上下文的情况下运行，就会出现这些情况。"}, {"kind": "steps", "items": [{"label": "加上一个审美 skill", "body": "一个精选的设计 skill 会逼着智能体确立一个真实的方向，而不是套用默认外观。"}, {"label": "在真实浏览器中验证", "body": "让 Kimi 渲染并在各个断点上自检，这样布局就不会在移动端悄无声息地崩坏。"}, {"label": "提供 tokens 和参考稿", "body": "真实的设计 tokens 和参考截图是对产出质量影响最大的那个杠杆。"}, {"label": "把规则写进 AGENTS.md", "body": "把“不要主视觉卡片、最多两种字体、品牌优先的层级”这类风格规则，放在智能体每次运行都会读到的地方。"}]}, {"kind": "p", "text": "注意，每一项缓解措施都是关于给智能体一份精选的设计上下文。逐个项目地用手维护这份上下文，正是 Open Design 帮你免去的苦差事。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Kimi CLI 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面这套工作流一直在呼唤的那个开源设计层。它把 Kimi CLI 当作一等适配器，并用精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI 把它包裹起来——于是让 Kimi 表现出色的那份设计上下文从第一次运行就已就位，无需每次手动拼凑。两者都是开源、本地优先的，这让这对组合成为天然的契合。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 Kimi CLI 作为你的智能体。", "用你的 Moonshot API 密钥认证（BYOK）——凭证留在你的机器上，绝不经我们代理。", "选定一套设计系统和一个 skill，然后以一致的品味生成演示稿、原型和落地页。", "每一份产物和 DESIGN.md 文件都存放在你自己的仓库里，而不是托管的云端。"]}, {"kind": "p", "text": "同一个 Kimi CLI 智能体、同一把密钥——外加一套环绕它的、真实可移植的开源设计工作流。它本地优先、采用 Apache-2.0，所以你的工作内容和凭证都不会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Kimi CLI 真的能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一套设计系统和真实的参考图，Kimi CLI 就能产出生产级、响应式的 UI，而它智能体式的 Kimi K2 模型还能渲染产出并对照参考稿做验证。缺了这份上下文，它往往会退回到千篇一律的外观，而这正是 Open Design 要填补的落差。"}, {"name": "用 Kimi CLI 做设计需要付费吗？", "text": "你自带凭证：通过 Kimi Code 的 OAuth 登录授权，或粘贴一个 Moonshot API 密钥（BYOK），由 Moonshot 平台计费。无论哪种方式，Open Design 都绝不代理你的凭证。"}, {"name": "Kimi CLI 具体好在哪、为什么适合设计？", "text": "两点：Kimi K2 模型针对智能体式、长链路的编码与工具调用做了调优，因此智能体能一路构建和打磨直到拿出可用的结果；而上下文窗口可达 256k tokens，足以一次性装下整套设计系统和参考集。两者都有帮助——但品味仍来自你提供的设计系统、skill 和参考稿。"}, {"name": "前端设计该用 Kimi CLI 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体的、理解代码库的设计决策著称；Kimi CLI 的优势在于它智能体式的 Kimi K2 模型，以及带 BYOK 经济性的超大上下文。许多团队两者都用——Open Design 让你在不改变设计工作流的前提下切换智能体。"}, {"name": "我该如何把 Kimi CLI 连接到 Figma？", "text": "在 Kimi CLI 内运行 /mcp-config，来添加并认证 Figma MCP 服务器。随后 Kimi 就能拉取真实的设计上下文——组件、变量、布局数据——让生成的代码贴合源头，而不是近似还原。"}, {"name": "Open Design 隶属于 Moonshot AI 吗？", "text": "不。Kimi CLI 是 Moonshot AI 的产品；Open Design 是一个独立的开源项目，把它作为一等适配器来支持。Kimi 是 Moonshot AI 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先、采用 Apache-2.0。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，而你的 Moonshot 凭证由你的智能体直接使用，绝不经 Open Design 服务器中转。"}], "ctaTitle": "用开放的方式，与 Kimi CLI 一起做设计。", "ctaBody": "自带你的 Moonshot API 密钥，让每个文件都留在本地，并为你已经在用的智能体配上一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Kimi CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的智能体"}, "aboutTitle": "什么是 Kimi CLI", "aboutBody": ["Kimi CLI 是 Moonshot AI 推出的开源（Apache-2.0）终端 AI 智能体，由 Kimi K2 系列模型驱动。它会读取你的代码库、编辑文件、运行命令、搜索文件并抓取网页。", "Kimi K2 模型针对智能体式、长链路的编码做了调优，上下文窗口可达 256k tokens，因此能一次性装下整套设计系统。", "Open Design 把 Kimi CLI 当作一等适配器，让这个智能体能嵌入一条结构化、开源的设计流水线。"], "vendorLabel": "厂商", "vendor": "Moonshot", "credentialLabel": "凭证", "credential": "Moonshot API 密钥（BYOK）", "designTitle": "用 Kimi CLI 做设计", "designLead": "Kimi CLI 的设计优势主要围绕它的模型和上下文：", "designPoints": [{"label": "智能体式的 参考稿 → UI", "body": "长链路的 Kimi K2 编码把参考稿转化为响应式标记，并在真实浏览器中对照参考核查结果。"}, {"label": "256k-token 上下文", "body": "整套设计系统、组件库和参考集能一次性装下，于是产出会复用你真实的基础元素。"}, {"label": "AGENTS.md + MCP", "body": "上下文文件承载你的约定；Figma MCP 服务器把真实的设计上下文带入代码。"}, {"label": "开放且 BYOK", "body": "Apache-2.0，支持 OAuth 登录或你自己的 Moonshot API 密钥，外加 OpenAI 兼容和 Anthropic 兼容的端点。"}], "linksTitle": "实战资源", "linksLead": "Kimi CLI 的官方仓库和文档：", "links": [{"label": "MoonshotAI/kimi-cli（GitHub）", "href": "https://github.com/MoonshotAI/kimi-cli", "source": "GitHub · Moonshot AI"}, {"label": "Kimi CLI 文档 — 快速上手", "href": "https://moonshotai.github.io/kimi-cli/en/guides/getting-started.html", "source": "文档 · Moonshot AI"}, {"label": "Kimi K2（GitHub）", "href": "https://github.com/MoonshotAI/Kimi-K2", "source": "GitHub · Moonshot AI"}], "withOdTitle": "Kimi CLI + Open Design", "withOdLead": "Open Design 是环绕 Kimi CLI 的开源设计层：精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design，并选择 Kimi CLI 作为你的智能体。", "用你的 Moonshot API 密钥认证（BYOK）——凭证留在你的机器上。", "选定一套设计系统和一个 skill，然后以一致的品味生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都存放在你自己的仓库里，而不是托管的云端。"], "withOdClosing": "同一个 Kimi CLI 智能体——外加一套环绕它的、真实可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Moonshot AI 做的吗？", "text": "不。Kimi CLI 是 Moonshot AI 的产品；Open Design 是一个独立的开源项目，把它作为一等适配器集成进来。"}, {"name": "我需要付费吗？", "text": "你自带凭证——OAuth 登录或一个 Moonshot API 密钥（BYOK），由 Moonshot 计费。Open Design 绝不代理你的凭证。"}, {"name": "Open Design 隶属于 Moonshot AI 吗？", "text": "不。Open Design 是独立的；Kimi 是 Moonshot AI 的商标。"}], "ctaTitle": "用开放的方式，与 Kimi CLI 一起做设计。", "ctaBody": "为仓库点 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  deepseek: {"title": "用于设计的 DeepSeek TUI —— Open Design", "description": "人们如何用一个由 DeepSeek 驱动的终端编码 agent 进行 UI 与网页设计——它强大的编码模型、100 万 token 上下文、成本效率、上下文文件与 MCP——以及 Open Design 如何把 DeepSeek TUI 变成一个本地优先、开源的设计 agent。", "breadcrumb": "DeepSeek TUI", "label": "Agent · DeepSeek TUI", "heading": "用于设计的 DeepSeek TUI。", "lead": "DeepSeek TUI 是一个由 DeepSeek 模型驱动的终端编码 agent。它强大且具成本效率的编码模型，加上 100 万 token 的上下文，可以一次性容纳整套设计系统和代码库，这让它成为一款真正的设计工具——前提是你给它参考、规范以及一套验证循环。Open Design 把它接入开源设计工作流：用你自己的 DeepSeek API 密钥、你自己的文件，本地优先。", "tldrTitle": "TL;DR", "tldrBody": "DeepSeek TUI 借助强大的编码模型、巨大的上下文窗口以及极低的单 token 成本，把描述出来的布局和参考规范转化为响应式 UI——自带你自己的 DeepSeek API 密钥。Open Design 为它配上一套精选的设计系统与 skill 库，外加一套桌面工作流——BYOK，并把一切都留在本地。", "toc": ["什么是 DeepSeek TUI", "用 DeepSeek TUI 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 DeepSeek TUI 变成一个本地优先、开源的设计 agent——用你自己的 DeepSeek API 密钥、你自己的文件，并在它周围配上一套精选的 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 内使用 DeepSeek TUI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek TUI 是一个由 DeepSeek 模型驱动、基于终端的 AI 编码 agent。它在设计上之所以值得关注，有两点：它的编码模型既强大又异常具成本效率，因此你可以放开手脚地反复迭代而无需盯着计费表；它的上下文窗口最高可达 100 万 token，大到足以一次性容纳整套设计系统和代码库，而不必把它们压缩省略掉。配上恰当的参考、规范以及一套验证循环，它就能构建出真正的、响应式的 UI。这是一份实用的端到端指南，讲解如何用一个由 DeepSeek 驱动的终端 agent 来做 UI、前端与设计系统相关的工作，并把它接入 Open Design 的结构化设计工作流。", "本文涵盖：DeepSeek TUI 究竟是什么，为什么强大的编码模型、巨大的上下文和低成本恰好契合设计，如何从零开始把它配置好，从参考到 UI 的循环，上下文文件与 MCP 如何扩展它，它与 Codex、Claude Code、Cursor 和 Gemini CLI 相比如何，让 AI 产出显得平庸的那些陷阱，以及 Open Design 如何作为一个开放、本地优先的设计层来弥合这道鸿沟——这是天然的搭配，因为两者都开源、都跑在你自己的机器上。"], "heroImage": {"src": "/agents/deepseek-design/deepseek-design-hero.webp", "alt": "DeepSeek TUI 设计反馈循环：一个终端 agent 读取参考与规范，一个浏览器渲染 UI，以及一个工作区，还有一条反馈箭头回环", "caption": "核心循环：DeepSeek TUI 在终端里读取你的参考和规范，在真实浏览器中构建并验证 UI，然后对照它们迭代——而整套设计系统都在上下文里。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-deepseek", "label": "DeepSeek TUI 究竟是什么"}, {"id": "why-design", "label": "为什么强大的编码模型 + 巨大上下文契合设计"}, {"id": "setup", "label": "为设计配置 DeepSeek TUI（从零开始）"}, {"id": "screenshot-workflow", "label": "从参考到 UI 的工作流"}, {"id": "extend", "label": "上下文文件、MCP 与工具"}, {"id": "vs", "label": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "陷阱与“AI 味”外观"}, {"id": "open-design", "label": "在 Open Design 中用 DeepSeek TUI 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-deepseek", "heading": "DeepSeek TUI 究竟是什么", "blocks": [{"kind": "p", "text": "DeepSeek TUI 是一个以键盘操作为主、运行 DeepSeek 模型的终端 AI agent。它读取你的代码仓库、编辑文件、运行 shell 命令、管理 git，还能搜索网络——它根据自然语言任务来规划并验证工作，而不只是补全代码行。DeepSeek 本身是模型提供方：一个与 OpenAI 兼容的 API（它还暴露了一个 Anthropic 格式的端点），因此只要设置一个 base URL 和密钥，就能把大量社区终端 agent 指向 DeepSeek。好几个开源 TUI 都把 DeepSeek 作为一等公民般的提供方内置支持。"}, {"kind": "p", "text": "对设计工作而言，有三个特性尤为突出。DeepSeek 的编码模型很强，因此 agent 能根据清晰的描述对布局、结构和组件层级进行推理。它的上下文窗口最高可达 100 万 token，大到足以一次性容纳你整套设计系统和组件库。而它的单 token 价格很低，再叠加前缀上下文缓存——所以围绕一个设计反复迭代成本很低。"}, {"kind": "steps", "items": [{"label": "上下文文件", "body": "终端 agent 会读取一个项目上下文文件（AGENTS.md 风格的文件，或该 agent 自己的约定）以获取持久规则——这是编码你的设计规范、tokens 和评审清单的天然位置。"}, {"label": "工具 + MCP", "body": "大多数 DeepSeek TUI 都内置文件、shell、git 和网络工具，并支持 MCP 服务器以接入外部上下文，比如一个实时的 Figma 文件——DeepSeek 的 API 支持工具调用，而这些 agent 正依赖于此。"}, {"label": "自带密钥", "body": "你用一个来自 DeepSeek 平台的 DeepSeek API 密钥进行鉴权。由于该 API 与 OpenAI 兼容，把一个 agent 指向 DeepSeek 通常只需两行：base URL 和密钥。"}]}, {"kind": "ul", "items": ["厂商：DeepSeek（模型与 API 提供方）", "凭证：来自 DeepSeek 平台的 DeepSeek API 密钥（BYOK）", "模型：deepseek-v4-flash 和 deepseek-v4-pro（纯文本；无原生图像输入）"]}]}, {"id": "why-design", "heading": "为什么强大的编码模型和巨大上下文契合设计", "blocks": [{"kind": "p", "text": "DeepSeek TUI 的设计优势来自模型本身及其经济性——但和每一个 agent 一样，品味仍然得由你来提供。"}, {"kind": "steps", "items": [{"label": "强大且具成本效率的编码", "body": "DeepSeek 的编码模型能力强且价格低廉，因此 agent 能很好地推理布局与结构，而你可以一遍又一遍地迭代，成本不再是约束。"}, {"label": "100 万 token 的上下文窗口", "body": "大上下文意味着整套设计系统、tokens 以及许多参考状态都能一次性放进去，于是 agent 会复用你真实的基础组件，而不是临时发明一次性的样式——而上下文缓存让重复的提示保持低成本。"}, {"label": "把规范写进上下文文件", "body": "一个项目上下文文件（再加上 Figma MCP 服务器）把 agent 指向你的 tokens、组件和真实规格，于是它是面向一个品牌工作，而不是一套默认外观。"}]}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-taste-triangle.webp", "alt": "图示：设计系统、skill 和参考汇聚成优秀的设计产出", "caption": "品味来自你提供的三项输入：一套设计系统、一个 skill，以及真实的参考。"}, {"kind": "p", "text": "这个教训和每个 agent 教给我们的一样：DeepSeek TUI 默认并不具备品味。当你给它约束时，它才能产出优秀的设计——一套设计系统、一个审美 skill，以及具体的参考。Open Design 恰好把这些输入打包好，这正是两者契合的原因（下文还有更多）。"}]}, {"id": "setup", "heading": "从零开始，为设计工作配置 DeepSeek TUI", "blocks": [{"kind": "p", "text": "这是从一台干净的机器到一个能构建并验证 UI 的 DeepSeek TUI 的完整路径。具体的安装和命令名称会因你选用哪个终端 agent 而异，所以下面的步骤停留在对各个 agent 都成立的层面上。"}, {"kind": "code", "lang": "bash", "code": "# 1. 从 DeepSeek 平台获取一个 DeepSeek API 密钥\n#    https://platform.deepseek.com\nexport DEEPSEEK_API_KEY=sk-...\n\n# 2. 安装一个支持 DeepSeek 的终端 agent（按其 README 操作），\n#    然后把它指向 DeepSeek。该 API 与 OpenAI 兼容：\n#      base URL: https://api.deepseek.com\n#      model:    deepseek-v4-flash（或 deepseek-v4-pro）\n#    （/anthropic 处还有一个 Anthropic 格式的端点）\n\n# 3. 在你的项目里启动它并生成项目上下文\ncd your-project\n#   创建/搭建一个写有你设计规则的项目上下文文件\n\n# 4. 接入 Figma MCP 服务器（可选，用于设计交付）\n#    把它加入该 agent 的 MCP 服务器配置"}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-setup-flow.webp", "alt": "五步配置流程：获取密钥、安装 agent、配置上下文文件、添加 skill、验证", "caption": "配置顺序：获取密钥 → 把 agent 指向 DeepSeek → 配置上下文文件 → 添加 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "编码你的设计规则", "body": "把你的 tokens、基础组件和规范放进 agent 的上下文文件并把它指向这些内容，让产出贴合一个品牌，而不是退回到一套平庸的默认外观。"}, {"label": "加入浏览器验证", "body": "接入一个 Playwright 或浏览器 MCP，让 agent 在真实浏览器中渲染，并跨断点检查其产出，而不只是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "从参考到 UI 的工作流", "blocks": [{"kind": "p", "text": "DeepSeek 的模型是纯文本的——它们不原生读取图像——所以收益最高的设计循环，是把清晰的参考和描述出来的布局转化为可工作的、响应式的 UI，然后在真实浏览器中验证结果，而不是让模型去“看”一张截图。"}, {"kind": "ol", "items": ["从你手头最清晰的参考出发——并描述出多种状态（桌面端和移动端、悬停、空态、加载中），而不只是一张主视觉。", "在提示里要具体；即便用强大的模型，含糊的提示也会产出平庸的 UI。把间距、层级以及要复用的组件讲清楚。", "把你的设计系统和规范放在上下文文件里，并告诉 agent tokens 和规范化的基础组件位于何处。", "运行一个 dev server，让 agent 在真实浏览器中渲染，并调整到各个断点来检查结果——验证就发生在这里，因为模型本身看不到图像。", "通过让 agent 把渲染出的 DOM 和计算样式与你描述的规格相对照来迭代——而不仅仅是确认它能构建通过。"]}, {"kind": "p", "text": "精确地描述目标，并给出具体约束："}, {"kind": "code", "lang": "bash", "code": "# 在 agent 的提示里：\n> 用 React + Vite + Tailwind + TypeScript 实现这个设计。\n  布局：两栏式仪表盘，240px 侧边栏，24px 间距，\n  卡片网格在 桌面/平板/移动 下分别为 3/2/1 列。\n  复用上下文文件里我已有的设计系统组件和 tokens。\n  在间距、布局和层级上保持一致；做成响应式。\n  运行 dev server，在浏览器中渲染，并跨断点对照\n  规格迭代，直到匹配为止。"}, {"kind": "p", "text": "让提示保持小而聚焦，把好的迭代提交、把坏的回退（回退时告诉 agent），这样每一轮都建立在一个干净的基础上。"}]}, {"id": "extend", "heading": "上下文文件、MCP 与工具", "blocks": [{"kind": "p", "text": "有三个扩展点能让 DeepSeek TUI 适用于持续的设计工作，而这三者都能干净地对应到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "项目上下文文件", "body": "项目规则存放在仓库根目录的一个上下文文件里（带有全局层和团队层）。它是你设计规范的持久归宿，每次运行都会被读取。"}, {"label": "MCP 服务器", "body": "在 agent 里配置 MCP 服务器——这是引入设计上下文和外部工具的可移植方式，其中最相关的就是 Figma MCP 服务器，它们能跨多个 agent 通用，而不只在某一个里有效。DeepSeek 的 API 支持这些服务器所依赖的工具调用。"}, {"label": "内置工具", "body": "DeepSeek TUI 内置文件、shell、git 和网络工具，让 agent 无需离开终端就能收集参考并跑完验证循环。"}]}, {"kind": "p", "text": "这些都是可移植的、多 agent 通用的能力——正是 Open Design 生来要去编排的那类东西，而不是在每个项目里重新造一遍。"}]}, {"id": "vs", "heading": "在设计上，DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI", "blocks": [{"kind": "p", "text": "在设计工作上并没有唯一的赢家——每个 agent 都有不同的强项，有经验的团队会把它们叠加使用。一个公允的概括："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["DeepSeek TUI", "强大、极具成本效率的编码模型，开放权重，100 万 token 上下文；纯文本（无原生视觉）", "在预算之内做高频迭代，并把整套设计系统持有在上下文中"], ["Codex", "出色的视觉打磨配上前端 skill；沙箱化的异步构建", "委派式异步构建以及可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex 色值、间距、字体）以及理解代码库的 UX", "前端推理与大上下文重构"], ["Cursor", "带实时预览和行内编辑的可视化“边构建边看”循环", "在 IDE 内进行紧凑的“迭代-观察”式 UI 工作"], ["Gemini CLI", "原生多模态图像理解以及 100 万 token 上下文；开源且有免费额度", "大量依赖截图、需要 agent 直接读取参考的工作"]]}, {"kind": "p", "text": "社区反复得出的结论是：品味来自人类——在没有 skills、参考和约束的情况下，它们全都会退回到一套平庸的审美。这才是真正要解决的问题——而它的形态像是个设计工具问题，而非模型问题。"}]}, {"id": "pitfalls", "heading": "陷阱，以及如何避免“AI 味”外观", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨是它看起来很平庸——柔和的渐变、漂浮的面板、过大的圆角、夸张的阴影，一种 Inter 字体加紫色的调调，“一看就是 AI 做的”。其他被反映的问题还包括移动端布局错乱，以及指令文字泄漏进 UI 文案里。这些都不是 DeepSeek TUI 独有的；任何 agent 在缺少精选设计上下文的情况下运行都会这样。由于 DeepSeek 是纯文本的，在真实浏览器中验证就尤为重要，而不是指望模型去“看”结果。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会迫使 agent 承诺一个真实的方向，而不是默认外观。"}, {"label": "在真实浏览器中验证", "body": "用一个浏览器工具跨断点渲染并自检——这在这里至关重要，因为模型自己读不了截图——这样布局就不会在移动端悄无声息地崩掉。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和具体的、描述清楚的参考，是对产出质量影响最大的单一杠杆。"}, {"label": "把规则编码进上下文文件", "body": "把诸如“不要主视觉大卡片、最多两种字体、品牌优先的层级”这类规则，放到 agent 每次运行都会读取的地方。"}]}, {"kind": "p", "text": "请注意，每一项缓解措施都是在给 agent 一套精选的设计上下文。逐个项目手工维护这套上下文，正是 Open Design 替你免去的繁琐劳作。"}]}, {"id": "open-design", "heading": "在 Open Design 内用 DeepSeek TUI 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面那套工作流一再呼唤的开源设计层。它把 DeepSeek agent 当作一等适配器，并在其外包上一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI——于是让 DeepSeek 变好用的那套设计上下文，从第一次运行起就在那里，而不是每次都手工拼凑。两者都开源、都本地优先，这让这对搭配水到渠成。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 DeepSeek TUI 作为你的 agent。", "用你自己的 DeepSeek API 密钥进行鉴权（BYOK）——凭证留在你的机器上，绝不经我们代理。", "选一套设计系统和一个 skill，然后以一致的品味生成演示文稿、原型和落地页。", "每一个产物和 DESIGN.md 文件都存放在你自己的仓库里，而不是托管的云端。"]}, {"kind": "p", "text": "同一个 DeepSeek agent、同一个密钥——再加上一套围绕它的真实、可移植、开源的设计工作流。它本地优先且采用 Apache-2.0 协议，所以你的工作内容和凭证没有任何东西会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "DeepSeek TUI 真的能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一套设计系统和具体的参考，一个由 DeepSeek 驱动的终端 agent 就能产出生产级的响应式 UI，然后你在真实浏览器中验证产出。DeepSeek 的模型是纯文本的，所以这套验证循环替代了原生的图像读取。缺了那套上下文，它就倾向于退回到一套平庸的外观，而这正是 Open Design 所填补的缺口。"}, {"name": "用 DeepSeek TUI 做设计要花多少钱？", "text": "很少——DeepSeek 的 API 单 token 价格属于最便宜之列，而前缀上下文缓存又进一步削减了重复提示的成本，所以你可以放开手脚地迭代。你自带 DeepSeek API 密钥（BYOK）；Open Design 绝不代理你的凭证。"}, {"name": "DeepSeek 具体好在哪里，适合做设计？", "text": "强大且具成本效率的编码模型、开放权重，以及一个能一次性容纳整套设计系统和参考集合的 100 万 token 上下文。DeepSeek 是纯文本的——它不原生读取图像——所以品味仍然来自你提供的设计系统、skill 和描述出来的参考，并在浏览器中验证。"}, {"name": "前端设计该选 DeepSeek TUI 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体的、理解代码库的设计决策著称；DeepSeek TUI 的优势在于开放权重、极低成本，以及适合高频迭代的巨大上下文。许多团队两者都用——Open Design 让你在不改变设计工作流的前提下切换 agent。"}, {"name": "我该如何把 DeepSeek TUI 连接到 Figma？", "text": "在你终端 agent 的 MCP 配置里加入 Figma MCP 服务器。这样 agent 就能拉取真实的设计上下文——组件、变量、布局数据——让生成的代码与源文件一致，而不是近似还原。DeepSeek 的 API 支持 MCP 所依赖的工具调用。"}, {"name": "Open Design 与 DeepSeek 有关联吗？", "text": "没有。DeepSeek 是模型与 API 提供方；Open Design 是一个独立的开源项目，把由 DeepSeek 驱动的终端 agent 作为一等适配器来支持。DeepSeek 是 DeepSeek 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且采用 Apache-2.0 协议。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，而你的 DeepSeek API 密钥由你的 agent 直接使用，绝不经过 Open Design 的服务器路由。"}], "ctaTitle": "以开放的方式，用 DeepSeek TUI 做设计。", "ctaBody": "自带你自己的 DeepSeek API 密钥，把每个文件都留在本地，并在你已经在用的 agent 周围获得一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 内使用 DeepSeek TUI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "什么是 DeepSeek TUI", "aboutBody": ["DeepSeek TUI 是一个由 DeepSeek 模型驱动的终端 AI 编码 agent。它读取你的代码库、编辑文件、运行命令、管理 git，并搜索网络。DeepSeek 是模型提供方，暴露一个与 OpenAI 兼容的 API（以及一个 Anthropic 格式的端点）。", "它的编码模型强大且极具成本效率，上下文窗口可达 100 万 token，因此能一次性容纳整套设计系统。这些模型是纯文本的，所以设计参考是被描述出来、并在浏览器中验证的，而不是作为图像被读取。", "Open Design 把 DeepSeek agent 当作一等适配器，因此它能嵌入一条结构化的开源设计流水线。"], "vendorLabel": "厂商", "vendor": "DeepSeek", "credentialLabel": "凭证", "credential": "DeepSeek API 密钥（BYOK）", "designTitle": "用 DeepSeek TUI 做设计", "designLead": "DeepSeek TUI 的设计强项集中在它的模型和经济性上：", "designPoints": [{"label": "强大、便宜的编码", "body": "能力出众的编码模型加上极低的单 token 成本，把描述出来的布局转化为响应式标记，并让你自由迭代。"}, {"label": "100 万 token 上下文", "body": "整套设计系统、组件库和参考集合都能一次性放进去，于是产出会复用你真实的基础组件——重复时还有上下文缓存。"}, {"label": "上下文文件 + MCP", "body": "上下文文件承载你的规范；Figma MCP 服务器借助 DeepSeek 的工具调用把真实的设计上下文带进代码。"}, {"label": "开放权重，BYOK", "body": "DeepSeek 提供开放权重，而你自带自己的 DeepSeek API 密钥——纯文本，所以请在真实浏览器中验证视觉效果。"}], "linksTitle": "真实世界的资源", "linksLead": "DeepSeek API 与平台的官方文档：", "links": [{"label": "DeepSeek API 文档", "href": "https://api-docs.deepseek.com/", "source": "文档 · DeepSeek"}, {"label": "模型与定价", "href": "https://api-docs.deepseek.com/quick_start/pricing", "source": "文档 · DeepSeek"}, {"label": "Anthropic API 兼容性", "href": "https://api-docs.deepseek.com/guides/anthropic_api", "source": "文档 · DeepSeek"}], "withOdTitle": "DeepSeek TUI + Open Design", "withOdLead": "Open Design 是围绕 DeepSeek TUI 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design，并选择 DeepSeek TUI 作为你的 agent。", "用你自己的 DeepSeek API 密钥进行鉴权（BYOK）——凭证留在你的机器上。", "选一套设计系统和一个 skill，然后以一致的品味生成演示文稿、原型和落地页。", "产物和 DESIGN.md 文件都存放在你自己的仓库里，而不是托管的云端。"], "withOdClosing": "同一个 DeepSeek agent——再加上一套围绕它的真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 DeepSeek 做的吗？", "text": "不是。DeepSeek 是模型与 API 提供方；Open Design 是一个独立的开源项目，把由 DeepSeek 驱动的终端 agent 作为一等适配器集成进来。"}, {"name": "我需要付费吗？", "text": "你自带自己的 DeepSeek API 密钥（BYOK）。DeepSeek 的 API 单 token 价格极低，而 Open Design 绝不代理你的凭证。"}, {"name": "Open Design 与 DeepSeek 有关联吗？", "text": "没有。Open Design 是独立的；DeepSeek 是 DeepSeek 的商标。"}], "ctaTitle": "以开放的方式，用 DeepSeek TUI 做设计。", "ctaBody": "为仓库点个 Star、下载桌面应用，或加入社区来请求一个适配器。"},
  'trae-cli': {"title": "用 Trae CLI 做设计 — Open Design", "description": "人们如何用字节跳动的 Trae CLI（trae-agent）做 UI 和网页设计——它是一个开源、模型无关的命令行 CLI agent，可自带 LLM 提供商，并采用配置驱动的工作流——以及 Open Design 如何通过 ACP 把 Trae CLI 变成一个本地优先、开源的设计 agent。", "breadcrumb": "Trae CLI", "label": "Agent · Trae CLI", "heading": "用 Trae CLI 做设计。", "lead": "Trae CLI 是字节跳动的开源终端 agent（trae-agent）。它模型无关——你把它指向你信任的 LLM 提供商即可——它会读取你的仓库、编辑文件，并根据自然语言任务运行命令；一旦你给它参考、规范和一套验证循环，它就成了真正的设计工具。Open Design 通过 ACP 把它接入一套开源的设计工作流：用你自己的提供商密钥、你自己的文件，本地优先。", "tldrTitle": "太长不看", "tldrBody": "Trae CLI 是一个免费、开源、模型无关的编码 agent：自带你的 LLM 提供商密钥，它就能根据自然语言任务构建 UI。Open Design 通过 ACP 驱动它，并为它配上一套精选的设计系统与 skill 库以及桌面工作流——BYOK，且一切保持本地。", "toc": ["什么是 Trae CLI", "用 Trae CLI 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Trae CLI 变成一个本地优先、开源的设计 agent——用你自己的 LLM 提供商密钥、你自己的文件，外加一套精选的 skill 与设计系统库，通过 ACP 驱动。", "heroCtaActions": [{"label": "在 Open Design 中使用 Trae CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Trae CLI 是字节跳动面向终端的开源 AI agent，以 trae-agent 项目的形式发布。有两点让它对设计尤其有意思：它模型无关，因此你可以自带任何你信任的 LLM 提供商，而不被某一家厂商锁定；同时它是一个透明、采用 MIT 许可的 agent，能根据自然语言任务读取你的代码库、编辑文件并运行 shell 命令。配上恰当的参考、规范和一套验证循环，它就能构建出真正的响应式 UI——而且起步免费、开放，你只需提供一个提供商密钥。这是一份实用的端到端指南，讲如何用 Trae CLI 做 UI、前端和设计系统的工作，以及如何用 Open Design 把它接入一套结构化的设计工作流。", "本文涵盖：Trae CLI 究竟是什么、为什么一个开放、模型无关的 agent 适合做设计、如何从零开始配置它、截图到 UI 的循环、它的配置文件和工具如何对它进行扩展、它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比、那些让 AI 产物显得千篇一律的陷阱，以及 Open Design 如何作为一个开放、本地优先的设计层来弥合这道鸿沟——这是天然的搭配，因为两者都是开源、都跑在你自己的机器上，而 Open Design 通过 Agent Client Protocol（ACP）驱动 Trae CLI。"], "heroImage": {"src": "/agents/trae-cli-design/trae-cli-design-hero.webp", "alt": "Trae CLI 设计反馈循环：一个终端 agent 读取参考图、一个浏览器渲染 UI、一个工作区，反馈箭头回环", "caption": "核心循环：Trae CLI 在终端里读取你的参考和规范，在真实浏览器中构建并验证 UI，并据此反复迭代。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-trae-cli", "label": "Trae CLI 究竟是什么"}, {"id": "why-design", "label": "为什么开放、模型无关的 agent 适合做设计"}, {"id": "setup", "label": "从零配置 Trae CLI 来做设计"}, {"id": "screenshot-workflow", "label": "截图到 UI 的工作流"}, {"id": "extend", "label": "配置、工具与提供商"}, {"id": "vs", "label": "Trae CLI 对比 Codex、Claude Code、Cursor、Gemini CLI"}, {"id": "pitfalls", "label": "陷阱与「AI 廉价感」的外观"}, {"id": "open-design", "label": "在 Open Design 中用 Trae CLI 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-trae-cli", "heading": "Trae CLI 究竟是什么", "blocks": [{"kind": "p", "text": "Trae CLI 是字节跳动开源 trae-agent 项目中的命令行 agent。它会读取你的仓库，查看、创建和编辑文件，并在一个持久化的环境中运行 shell 命令——根据自然语言任务进行规划和验证，而不只是补全几行代码。它采用 MIT 许可，围绕透明、模块化的架构构建，因此易于审视和扩展。它与另一款独立的 Trae IDE（字节跳动基于 VS Code 的 AI 编辑器）不同，尽管两者出自同一厂商。"}, {"kind": "p", "text": "对设计工作来说，有两个特性尤为突出。它模型无关——你选择 LLM 提供商，所以永远不会被某个模型的长处或局限所束缚。它也完全开放、配置驱动，因此它的行为、工具和提供商都可以和你的项目一起固定在版本控制里，而不是藏在某个托管服务背后。"}, {"kind": "steps", "items": [{"label": "运行模式与交互模式", "body": "Trae CLI 用 `trae-cli run \"...\"` 运行单个任务，或用 `trae-cli interactive` 保持一个持续会话——这正是对照你的设计规范来迭代 UI 的好地方。"}, {"label": "内置工具", "body": "它开箱即带文件编辑、bash/shell 执行和结构化推理工具，因此能构建、跑起开发服务器并检查运行时错误，全程不用离开终端。"}, {"label": "自带你的提供商", "body": "你为信任的提供商提供一个 API 密钥——OpenAI、Anthropic、Google、OpenRouter、Doubao、Azure，或本地的 Ollama 模型——通过环境变量或配置文件设置。"}]}, {"kind": "ul", "items": ["厂商：字节跳动（开源 trae-agent 项目）", "凭证：一个 LLM 提供商 API 密钥（BYOK）——例如 OpenAI、Anthropic、Google、OpenRouter、Doubao、Azure，或本地的 Ollama 模型", "许可：MIT，开源"]}]}, {"id": "why-design", "heading": "为什么开放、模型无关的 agent 适合做设计", "blocks": [{"kind": "p", "text": "Trae CLI 在设计上的优势来自它的开放和提供商灵活性——但和每一个 agent 一样，品味仍然得由人来提供。"}, {"kind": "steps", "items": [{"label": "天生模型无关", "body": "因为提供商由你选择，你可以把设计工作交给当下在布局和前端代码上推理最好的模型，日后再换掉它也不必改动工作流。"}, {"label": "开放且配置驱动", "body": "agent、它的工具及其提供商都固定在一个你可以提交的配置文件里，于是团队在每台机器上都得到相同的 agent 行为，而不是因开发者而异地漂移。"}, {"label": "规范留在你的仓库里", "body": "把 agent 指向你的 tokens、组件和真实规格——它们都保存在你的项目里——这样它就是在针对一个品牌工作，而不是退回到千篇一律的外观。"}]}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-taste-triangle.webp", "alt": "图示：设计系统、skill 和参考图汇聚成优质的设计产出", "caption": "品味来自你提供的三项输入：一个设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这条教训和每个 agent 教给我们的一样：Trae CLI 默认并不具备品味。当你给它约束——一个设计系统、一个审美 skill 以及具体的参考——它才会产出好的设计。Open Design 恰好把这些输入打包好，并通过 ACP 喂给 Trae CLI，这正是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零开始配置 Trae CLI 来做设计", "blocks": [{"kind": "p", "text": "这是从一台干净的机器到一个能构建并验证 UI 的 Trae CLI 的完整路径。Trae CLI 用 uv 从源码安装，然后配置上你想用的 LLM 提供商。"}, {"kind": "code", "lang": "bash", "code": "# 1. 从源码获取 Trae CLI（trae-agent）——需要 uv\ngit clone https://github.com/bytedance/trae-agent.git\ncd trae-agent\nuv sync --all-extras\nsource .venv/bin/activate\n\n# 2. 通过把它指向你的 LLM 提供商密钥来完成认证\n#    在环境变量里设置（或写进 trae_config.yaml 文件）\nexport OPENAI_API_KEY=...        # 或 ANTHROPIC_API_KEY、GOOGLE_API_KEY 等\n\n# 3. 在你的项目中运行一个任务\ntrae-cli run \"Create a hello world page\"\n#    或保持一个会话：\ntrae-cli interactive\n\n# 4. 查看解析后的配置（密钥会被打码）\ntrae-cli show-config"}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-setup-flow.webp", "alt": "五步配置流程：安装、认证、配置规范、添加 skill、验证", "caption": "配置顺序：安装 → 用提供商密钥认证 → 配置你的设计规范 → 添加 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "把你的设计规则编码进去", "body": "把你的 tokens、原语和规范放在仓库里并把 Trae CLI 指向它们，这样产出就会匹配一个品牌，而不是退回到千篇一律的外观。"}, {"label": "加入浏览器验证", "body": "让 Trae CLI 跑起开发服务器并在真实浏览器中渲染，这样它就会跨断点检查自己的产出，而不只是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Trae CLI 做设计时，杠杆最高的循环是把一张参考图变成可用的响应式 UI，并不断迭代直到匹配。因为 Trae CLI 模型无关，把它指向一个其模型能很好处理参考图的提供商，并依靠真实浏览器来检查结果。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考出发——并描述多种状态（桌面端和移动端、悬停、空态、加载中），而不只是一张主视觉。", "提示词要具体；含糊的提示即便配上强模型也会产出千篇一律的 UI。", "把你的设计系统和规范留在仓库里，并告诉 Trae CLI tokens 和标准原语在哪里。", "跑起开发服务器，让 Trae CLI 在真实浏览器中渲染，调整到各个断点来检查结果。", "让 Trae CLI 把它的实现拿回去和参考对比来迭代——而不只是确认它能构建。"]}, {"kind": "p", "text": "运行一个交互式会话，给出具体的约束，而不是一句话的请求："}, {"kind": "code", "lang": "bash", "code": "trae-cli interactive\n# in the session:\n> Implement the attached reference design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "保持提示词小而聚焦，提交好的迭代、回退坏的迭代（回退时告诉 Trae CLI），这样每一轮都建立在干净的基础之上。"}]}, {"id": "extend", "heading": "配置、工具与提供商", "blocks": [{"kind": "p", "text": "三个扩展点让 Trae CLI 适合长期的设计工作，而且三者都能干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "配置文件", "body": "Trae CLI 读取一个 trae_config.yaml，它固定了你的提供商、模型和各项设置——这是 agent 在项目上如何运行的持久、可版本控制的归宿。"}, {"label": "提供商选择", "body": "由于它支持众多提供商（OpenAI、Anthropic、Google、OpenRouter、Doubao、Azure、Ollama），你可以把设计工作交给你信任的模型，并在不重接工作流的情况下换掉它。"}, {"label": "内置工具", "body": "它的文件编辑、shell 和结构化推理工具让它能收集上下文、构建、跑起开发服务器并运行验证循环，全程不用离开终端。"}]}, {"kind": "p", "text": "这些都是可移植的、agent 级别的能力——恰恰是 Open Design 被设计用来通过 ACP 编排的那类东西，而不必每个项目都重新搭一遍。"}]}, {"id": "vs", "heading": "做设计时 Trae CLI 对比 Codex、Claude Code、Cursor、Gemini CLI", "blocks": [{"kind": "p", "text": "设计工作没有唯一的赢家——每个 agent 各有不同的强项，有经验的团队会把它们叠着用。一个公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Trae CLI", "开源（MIT）且模型无关；自带提供商密钥，配置驱动且透明", "想要一个免费、可审视的 agent，并自由选择或更换 LLM 提供商的团队"], ["Codex", "凭借前端 skill 带来出色的视觉打磨；沙箱化的异步构建", "委托式异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（十六进制色值、间距、字体）和代码库感知的 UX", "前端推理和大上下文重构"], ["Cursor", "可视化的「边构建边看」循环，带实时预览和行内编辑", "在 IDE 内紧凑的「迭代-观察」UI 工作"], ["Gemini CLI", "出色的多模态图像理解和 100 万 token 的上下文；开源且有免费额度", "大量截图的工作，以及把整个设计系统装进上下文"]]}, {"kind": "p", "text": "社区反复得出的结论是：品味来自人——没有 skill、参考和约束时，它们全都会退回到千篇一律的审美。这才是真正要解决的问题——而它是设计工具形状的，不是模型形状的。"}]}, {"id": "pitfalls", "heading": "陷阱，以及如何避开「AI 廉价感」的外观", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨是它看起来千篇一律——柔和的渐变、悬浮的面板、过大的圆角、夸张的阴影，一种 Inter 字体加紫色的调调，「一看就是 AI 做的」。其他被反映的问题还包括移动端布局错乱，以及指令泄漏进 UI 文案。这些都不是 Trae CLI 独有的；任何 agent 在缺乏精选的设计上下文下运行时都会这样。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会迫使 agent 选定一个真正的方向，而不是默认外观。"}, {"label": "在真实浏览器中验证", "body": "让 Trae CLI 跨断点渲染并自检，这样布局就不会在移动端悄悄崩坏。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图是撬动产出质量的最大单一杠杆。"}, {"label": "把规则编码进你的仓库", "body": "把「不用主视觉卡片、最多两种字体、品牌优先的层级」这类风格规则放在 agent 每次运行都会读到的地方。"}]}, {"kind": "p", "text": "注意到了吗，每一项缓解措施都在于给 agent 一份精选的设计上下文。逐个项目手工维护这份上下文，正是 Open Design 替你省掉的苦力活。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Trae CLI 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面那套工作流一再呼唤的那个开源设计层。它把 Trae CLI 当作一等适配器——通过其 trae-cli 二进制文件、用 Agent Client Protocol（ACP）来驱动它——并把它包进一套精选的 skill 与设计系统库、一条结构化的渲染流水线和一个本地桌面 UI，于是让 Trae CLI 出彩的那份设计上下文从第一次运行起就在那里，不必每次手工拼凑。两者都是开源、本地优先，这让它们的搭配成了天然之选。"}, {"kind": "ol", "items": ["安装 Open Design 并选择 Trae CLI 作为你的 agent。", "用你自己的 LLM 提供商密钥（BYOK）认证——凭证留在你的机器上，绝不经我们代理。", "挑一个设计系统和一个 skill，然后以一致的品味生成演示稿、原型和落地页。", "每一个产物和 DESIGN.md 文件都存在你自己的仓库里，而不是某个托管云上。"]}, {"kind": "p", "text": "同一个 Trae CLI agent、同一个提供商密钥——外加一套真正可移植、开源的设计工作流围着它运转。它本地优先、开源，所以关于你的工作或你的凭证，没有任何东西会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Trae CLI 真的能做设计工作吗？", "text": "能——配上一个审美 skill、一个设计系统和真实的参考上下文，Trae CLI 能产出生产级、响应式的 UI；而且因为它模型无关，你可以把工作交给在你的前端上推理最好的提供商。没有这份上下文时，它往往会退回到千篇一律的外观，这正是 Open Design 填补的鸿沟。"}, {"name": "用 Trae CLI 做设计需要付费吗？", "text": "Trae CLI 本身免费且开源（MIT）。你自带 LLM 提供商密钥，所以你唯一的成本是那家提供商收的费用——或者如果你通过 Ollama 跑本地模型，则分文不花。无论哪种方式，Open Design 都不会代理你的凭证。"}, {"name": "Trae CLI 具体好在哪里、适合做设计？", "text": "两点：它模型无关，所以你可以选择最适合前端工作的 LLM 提供商；它完全开放、配置驱动，所以它的行为对一个团队来说透明且可复现。但品味仍然来自你提供的设计系统、skill 和参考。"}, {"name": "前端设计该用 Trae CLI 还是 Claude Code？", "text": "两者都很能干。Claude Code 以具体、代码库感知的设计决策著称；Trae CLI 的优势是开源且提供商灵活，所以你永远不会被锁定在某一个模型上。许多团队两个都用——Open Design 让你在不改动设计工作流的情况下切换 agent。"}, {"name": "Open Design 运行 Trae CLI 需要什么？", "text": "Open Design 通过 Agent Client Protocol（ACP）驱动 Trae CLI 的 trae-cli 二进制文件，并使用你配置的 LLM 提供商密钥。你选择 Trae CLI 作为你的 agent，把它指向一个提供商，Open Design 就在它周围提供那份精选的设计上下文。"}, {"name": "Open Design 和字节跳动或 Trae 有关联吗？", "text": "没有。Trae CLI（trae-agent）是字节跳动的产品；Open Design 是一个独立的开源项目，把它作为一等适配器来支持。Trae 是字节跳动的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且开源。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的 LLM 提供商凭证由你的 agent 直接使用，绝不经 Open Design 的服务器中转。"}], "ctaTitle": "用开放的方式，借 Trae CLI 做设计。", "ctaBody": "自带你的 LLM 提供商密钥，把每个文件都留在本地，并在你已经在用的 agent 周围获得一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Trae CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支持的 agent"}, "aboutTitle": "什么是 Trae CLI", "aboutBody": ["Trae CLI 是字节跳动的开源（MIT）终端 AI agent，以 trae-agent 项目的形式发布。它会根据自然语言任务读取你的代码库、编辑文件并运行 shell 命令。", "它模型无关——你自带自己的 LLM 提供商密钥（OpenAI、Anthropic、Google、OpenRouter、Doubao、Azure，或本地的 Ollama 模型）——其行为固定在一个你可以提交的配置文件里。", "Open Design 把 Trae CLI 当作一等适配器，并通过 Agent Client Protocol（ACP）来驱动它，于是这个 agent 就嵌入了一条结构化、开源的设计流水线。"], "vendorLabel": "厂商", "vendor": "ByteDance", "credentialLabel": "凭证", "credential": "你自己的 LLM 提供商 API 密钥（BYOK）——OpenAI、Anthropic、Google、OpenRouter、Doubao、Azure，或本地的 Ollama", "designTitle": "用 Trae CLI 做设计", "designLead": "Trae CLI 的设计强项都围绕它开放、模型无关的本质：", "designPoints": [{"label": "自带你的模型", "body": "天生模型无关，所以你可以把 UI 工作交给在你的前端上推理最好的那个 LLM 提供商——日后再换掉它。"}, {"label": "开放且配置驱动", "body": "采用 MIT 许可，并固定在一个 trae_config.yaml 里，所以 agent 行为对一个团队来说透明且可复现。"}, {"label": "真实浏览器循环", "body": "文件、shell 和推理工具让它能构建、跑起开发服务器，并跨断点验证 UI。"}, {"label": "起步免费", "body": "agent 本身免费；你唯一的成本是你选的提供商——或者用本地 Ollama 模型则分文不花。"}], "linksTitle": "真实世界的资源", "linksLead": "Trae CLI 的官方仓库和产品页面：", "links": [{"label": "bytedance/trae-agent（GitHub）", "href": "https://github.com/bytedance/trae-agent", "source": "GitHub · 字节跳动"}, {"label": "Trae — 与智能协作", "href": "https://www.trae.ai/", "source": "官方站点 · 字节跳动"}, {"label": "Trae 文档", "href": "https://docs.trae.ai/ide/agent", "source": "文档 · 字节跳动"}], "withOdTitle": "Trae CLI + Open Design", "withOdLead": "Open Design 是围绕 Trae CLI 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI，通过 ACP 驱动。", "withOdSteps": ["安装 Open Design 并选择 Trae CLI 作为你的 agent。", "用你自己的 LLM 提供商密钥（BYOK）认证——凭证留在你的机器上。", "挑一个设计系统和 skill，然后以一致的品味生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都存在你自己的仓库里，而不是某个托管云上。"], "withOdClosing": "同一个 Trae CLI agent——外加一套围绕它的真正可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是字节跳动做的吗？", "text": "不是。Trae CLI（trae-agent）是字节跳动的产品；Open Design 是一个独立的开源项目，把它作为一等适配器集成进来。"}, {"name": "我需要付费吗？", "text": "Trae CLI 免费且开源；你自带自己的 LLM 提供商密钥（BYOK），所以你唯一的成本是你选的提供商。Open Design 绝不代理你的凭证。"}, {"name": "Open Design 和字节跳动有关联吗？", "text": "没有。Open Design 是独立的；Trae 是字节跳动的商标。"}], "ctaTitle": "用开放的方式，借 Trae CLI 做设计。", "ctaBody": "给仓库点 Star、下载桌面应用，或加入社区来请求一个适配器。"},
  aider: {"title": "用 Aider 做设计 — Open Design", "description": "人们如何用 Aider —— 运行在终端里的开源、模型无关的 AI 结对程序员 —— 来做 UI 与网页设计：基于 git 的原生改动、CONVENTIONS.md 文件、图像支持以及 BYOK；以及 Open Design 如何把 Aider 变成本地优先、开源的设计 agent。", "breadcrumb": "Aider", "label": "Agent · Aider", "heading": "用 Aider 做设计。", "lead": "Aider 是运行在你终端里、直接操作你 git 仓库的开源 AI 结对程序员。它是模型无关的 —— 用你自己的 key 把它接到 Claude、GPT-4o、DeepSeek 或 Gemini 上 —— 它会编辑文件、自动提交，并在支持视觉的模型上读取图像。一旦你给它参考图、规范和一套验证循环，它就成了一个真正的设计工具。Open Design 把它接入一套开源的设计工作流：你的供应商 key、你的文件、本地优先。", "tldrTitle": "TL;DR", "tldrBody": "Aider 把参考图和提示词变成可用的 UI，直接编辑你的 git 仓库并为每次改动提交一次 —— 用你自带的任何模型（BYOK）。Open Design 为它配上一套精选的设计系统与 skill 库，外加一套桌面工作流 —— 让你的 key 和一切都留在本地。", "toc": ["什么是 Aider", "用 Aider 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Aider 变成一个本地优先、开源的设计 agent —— 用你自己的供应商 API key、你的文件，外加一套围绕它的精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 里使用 Aider", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Aider 是一个开源的 AI 结对编程工具，运行在你的终端里，操作你 git 仓库中的代码。有两点让它对设计尤其有意思：它是模型无关的，所以你可以自带 key 接入几乎任何 LLM —— Claude、GPT-4o、DeepSeek、Gemini 或本地模型 —— 而且它是 git 原生的，会就地编辑文件，并为每次改动配上一条合理的提交信息，于是每一轮迭代都可审阅、可回退。在支持视觉的模型上，它还能读取图像，于是一张截图就成了提示词的一部分。配上合适的参考图、规范和一套验证循环，它就能搭出真正、响应式的 UI。这是一份实用、端到端的指南，讲如何用 Aider 做 UI、前端和设计系统的工作，以及如何把它接入 Open Design 的结构化设计工作流。", "它涵盖：Aider 究竟是什么、为什么一个模型无关、git 原生的工具适合做设计、如何从零搭起、截图到 UI 的循环、CONVENTIONS.md 和 Aider 的命令如何扩展它、它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比、那些让 AI 产物显得千篇一律的陷阱，以及 Open Design 如何作为一层开放、本地优先的设计层来弥合差距 —— 二者天然契合，因为它们都是开源的、都跑在你自己的机器上。"], "heroImage": {"src": "/agents/aider-design/aider-design-hero.webp", "alt": "Aider 设计反馈循环：一个终端 agent 读取参考图、一个带提交记录的 git 仓库、一个渲染 UI 的浏览器，以及一条回环的反馈箭头", "caption": "核心循环：Aider 在终端里读取你的参考图，在你的 git 仓库里编辑并提交 UI，再对照参考图反复迭代 —— 用你自带的任何模型。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-aider", "label": "Aider 究竟是什么"}, {"id": "why-design", "label": "为什么模型无关 + git 原生适合做设计"}, {"id": "setup", "label": "从零搭建用于设计的 Aider"}, {"id": "screenshot-workflow", "label": "截图到 UI 的工作流"}, {"id": "extend", "label": "CONVENTIONS.md、图像与命令"}, {"id": "vs", "label": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "陷阱与那股“AI 流水货”味"}, {"id": "open-design", "label": "在 Open Design 里用 Aider 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-aider", "heading": "Aider 究竟是什么", "blocks": [{"kind": "p", "text": "Aider 是一个开源（Apache-2.0）的 AI 结对编程工具，运行在你的终端里。它读取你已有的代码库，为上下文映射整个仓库，就地编辑文件，并自动为每次改动配上一条合理的提交信息 —— 于是你可以用早已熟悉的 git 工具来 diff、管理和撤销 AI 的工作。它支持 100 多种编程语言，既能开新项目，也能在已有项目上继续构建。"}, {"kind": "p", "text": "对设计工作而言，有两个特性格外突出。Aider 是模型无关的：你自带 key，把它接到几乎任何 LLM —— Claude、GPT-4o、DeepSeek、Gemini 或本地模型 —— 所以你永远不会被锁死在某一家供应商上。而在 GPT-4o、Claude 这类支持视觉的模型上，它能读取图像文件，把一张参考截图变成提示词的一部分。"}, {"kind": "steps", "items": [{"label": "规范文件", "body": "Aider 会读取一个 CONVENTIONS.md 文件，你用 /read CONVENTIONS.md（或 aider --read CONVENTIONS.md）加载它 —— 这是把你的设计规范、tokens 和评审清单编码为只读上下文的天然之处。"}, {"label": "git 原生的改动", "body": "每次改动都会应用到你仓库里的文件上并自动提交，于是每一轮设计迭代都能用熟悉的 git 工具来审阅和回退。"}, {"label": "自带你的模型", "body": "用你自己的 API key 接入 OpenAI、Anthropic、DeepSeek、Gemini 或本地模型；Aider 不绑定单一厂商，也不绑定某个托管后端。"}]}, {"kind": "ul", "items": ["供应商：Aider（Aider-AI，开源）—— 模型无关", "凭证：你自己的供应商 API key —— BYOK（OpenAI、Anthropic、DeepSeek、Gemini 或本地模型）", "许可证：Apache-2.0，开源"]}]}, {"id": "why-design", "heading": "为什么一个模型无关、git 原生的工具适合做设计", "blocks": [{"kind": "p", "text": "Aider 在设计上的优势，来自它与你的仓库以及你所选模型协作的方式 —— 但与所有 agent 一样，品味仍然得由你来提供。"}, {"kind": "steps", "items": [{"label": "模型无关，BYOK", "body": "挑一个最适合你任务和预算的、设计表现最好的模型 —— Claude、GPT-4o、DeepSeek、Gemini —— 并随意切换而不必改动你的工作流，全程用你自己的 key。"}, {"label": "git 原生的迭代", "body": "自动提交让每一轮设计都成为一段可回退、可审阅的 diff，于是你总是在一个干净的基线上迭代，而不是面对一堆未追踪的散乱改动。"}, {"label": "把规范放进 CONVENTIONS.md", "body": "一个 CONVENTIONS.md（以只读方式加载）把 agent 指向你的 tokens、组件和规则，于是它对照的是一套品牌，而不是某种默认观感。"}]}, {"kind": "image", "src": "/agents/aider-design/aider-design-taste-triangle.webp", "alt": "示意图：设计系统、skill 和参考图汇聚成优质的设计产出", "caption": "品味来自你提供的三项输入：一套设计系统、一个 skill 和真实的参考图。"}, {"kind": "p", "text": "这个教训和每个 agent 教给我们的一样：Aider 默认并没有品味。只有当你给它约束 —— 一套设计系统、一个审美 skill 和具体的参考 —— 它才会产出好设计。Open Design 恰恰把这些输入打包了起来，这正是二者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零搭建用于设计的 Aider", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器，到一个能构建并验证 UI 的 Aider 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Aider（推荐的安装器；Python 3.8–3.13）\npython -m pip install aider-install\naider-install\n# 或用 pipx：pipx install aider-chat\n\n# 2. 在你的 git 项目里启动它，并自带你的 key\ncd your-project\naider --model sonnet --api-key anthropic=<your-key>\n# 或：aider --api-key openai=<your-key>   （也支持 deepseek=、gemini=）\n\n# 3. 把你的设计规范作为只读上下文加载进来\naider --read CONVENTIONS.md\n\n# 4. 添加一张参考图（在支持视觉的模型上）\n#    在对话里：/add reference-desktop.png"}, {"kind": "image", "src": "/agents/aider-design/aider-design-setup-flow.webp", "alt": "五步搭建流程：安装、自带 key、加载 CONVENTIONS.md、添加参考图、验证", "caption": "搭建顺序：安装 → 自带你的 key → 加载 CONVENTIONS.md → 添加一张参考图 → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "把你的设计规则编码下来", "body": "把你的 tokens、基础元件和规范放进 CONVENTIONS.md 并以只读方式加载，于是产出贴合一套品牌，而不是退回某种千篇一律的观感。"}, {"label": "加上浏览器验证", "body": "跑一个开发服务器，让 Aider 在真实浏览器里渲染，并跨断点检查它的产出，而不是只确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Aider 做设计，杠杆最高的循环就是把一张参考图变成可用、响应式的 UI，并反复迭代直到匹配 —— 用一个支持视觉的模型把产出与参考图对比，每一轮都提交到 git。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考出发 —— 并且包含多种状态（桌面和移动端、悬停、空状态、加载中），而不只是一张大图。", "提示词要具体；含糊的提示词即便配上强模型也只会产出千篇一律的 UI。", "把你的设计系统和规范放进 CONVENTIONS.md，并告诉 Aider tokens 和标准基础元件在哪里。", "跑一个开发服务器，在真实浏览器里检查渲染结果，并缩放到各个断点。", "迭代的方式是让 Aider 把它的实现与截图对比 —— 而不只是确认它能构建通过。"]}, {"kind": "p", "text": "在支持视觉的模型上，用 /add 添加一张图（或用 /paste 从剪贴板粘贴），然后给出具体的约束："}, {"kind": "code", "lang": "bash", "code": "aider --model gpt-4o --read CONVENTIONS.md\n# 在对话里：\n> /add reference-desktop.png\n> /add reference-mobile.png\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from CONVENTIONS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  I'll render it in the browser and tell you what to fix until it matches\n  the references across breakpoints."}, {"kind": "p", "text": "让提示词保持小而聚焦。因为 Aider 会为每次改动提交一次，你就能留住好的迭代，并用 git（或 /undo）回退糟糕的那些 —— 于是每一轮都建立在一个干净的基线上。"}]}, {"id": "extend", "heading": "CONVENTIONS.md、图像与命令", "blocks": [{"kind": "p", "text": "有三项能力让 Aider 在持续的设计工作中切实可用，而这三项都能干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "CONVENTIONS.md 上下文", "body": "用 /read CONVENTIONS.md 或 aider --read CONVENTIONS.md 加载编码与设计规范，或在 .aider.conf.yml 里设置 read: CONVENTIONS.md 让它每次运行都加载。这是安放你 tokens、基础元件和规则的长久之所。"}, {"label": "图像与网页", "body": "在支持视觉的模型上，用 /add 添加一个图像文件，或用 /paste 从剪贴板粘贴，给 Aider 一张真实的参考；/web <url> 会把一个页面的文本抓进对话作为额外上下文。"}, {"label": "对话内命令", "body": "诸如 /add 把文件纳入上下文、/read 引入只读参考、/undo 回退上一次提交之类的命令，让它无需离开终端就能收集参考并跑完验证循环。"}]}, {"kind": "p", "text": "这些都是可移植、仓库原生的能力 —— 正是 Open Design 旨在去编排、而非每个项目重造一遍的那类东西。"}]}, {"id": "vs", "heading": "做设计：Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI", "blocks": [{"kind": "p", "text": "在设计工作上没有唯一的赢家 —— 每个 agent 各有所长，有经验的团队会把它们叠着用。一份公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Aider", "开源、模型无关（BYOK）、git 原生；自动提交让每一轮迭代都可审阅、可回退", "在你已有代码库上、用最擅长设计的模型做仓库原生的迭代"], ["Codex", "配合前端 skill，视觉精致度强；沙箱化的异步构建", "委托式的异步构建，以及可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex、间距、字体）和理解代码库的 UX", "前端推理与大上下文的重构"], ["Cursor", "带实时预览和内联编辑的“边改边看”视觉循环", "在 IDE 内做紧凑的“迭代即看”UI 工作"], ["Gemini CLI", "强大的多模态图像理解和 100 万 token 的上下文；开源且有免费档位", "截图密集的工作，以及把一整套设计系统装进上下文"]]}, {"kind": "p", "text": "社区反复给出的结论是：品味来自人类 —— 在没有 skill、参考和约束的情况下，它们全都会退回到一种千篇一律的审美。这才是真正要解决的问题 —— 而它是设计工具形状的，不是模型形状的。"}]}, {"id": "pitfalls", "heading": "陷阱，以及如何避开那股“AI 流水货”味", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨是它看起来千篇一律 —— 柔和的渐变、漂浮的面板、过大的圆角、夸张的阴影，一股“Inter 字体加紫色”的味道，“一眼就看出是 AI 做的”。其他被反映的问题还包括移动端布局错乱，以及指令泄露进 UI 文案。这些都不是 Aider 独有的；任何 agent 在缺少精选设计上下文时运行，都会出这些问题。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会迫使 agent 锚定一个真正的方向，而不是那种默认观感。"}, {"label": "在真实浏览器里验证", "body": "跨断点渲染并自检，让布局不会在移动端悄悄崩掉 —— 在支持视觉的模型上，把截图再喂回去。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图，是撬动产出质量的最大单一杠杆。"}, {"label": "把规则编码进 CONVENTIONS.md", "body": "把“不要大图卡片、最多两种字体、品牌优先的层级”这类风格规则，放在 agent 每次运行都会读到的地方。"}]}, {"kind": "p", "text": "请注意，每一项对策的核心都是给 agent 一份精选的设计上下文。而手工、逐项目地维护这份上下文，正是 Open Design 替你免去的苦差。"}]}, {"id": "open-design", "heading": "在 Open Design 里用 Aider 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面那套工作流一直在呼唤的那层开源设计层。它把 Aider 当作一等适配器，并用一套精选的 skill 与设计系统库、一条结构化的渲染管线和一个本地桌面 UI 把它包裹起来 —— 于是让 Aider 变好的那份设计上下文从第一次运行起就已就位，而不是每次都手工拼凑。二者都是开源、本地优先的，这让它们的搭配天然契合。"}, {"kind": "ol", "items": ["安装 Open Design 并选择 Aider 作为你的 agent。", "用你自己的供应商 API key 认证（BYOK）—— OpenAI、Anthropic、DeepSeek 或 Gemini；凭证留在你的机器上，绝不经我们中转。", "挑一套设计系统和一个 skill，然后以一致的品味生成幻灯片、原型和落地页。", "每一份产物和 DESIGN.md 文件都存活在你自己的 git 仓库里，而不是某个托管云端。"]}, {"kind": "p", "text": "同一个 Aider agent、同一把 key —— 外加一套围绕它的、真实、可移植、开源的设计工作流。它本地优先且开源，所以你的工作和凭证没有任何东西会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Aider 真能做设计工作吗？", "text": "能 —— 只要上下文里有一个审美 skill、一套设计系统和真实的参考图，Aider 就能产出生产级、响应式的 UI；在支持视觉的模型上，它会读取截图来把产出与参考对照验证。缺了这份上下文，它就容易退回到一种千篇一律的观感，而这正是 Open Design 填补的缺口。"}, {"name": "做设计时我能用哪些模型搭配 Aider？", "text": "Aider 是模型无关的。你自带 API key，接入几乎任何 LLM —— Claude、GPT-4o、DeepSeek、Gemini 或本地模型。做基于图像的设计工作时，请用 GPT-4o 或 Claude 这类支持视觉的模型。Open Design 绝不会中转你的凭证。"}, {"name": "Aider 究竟好在哪里、特别适合做设计？", "text": "两点：它是模型无关的，所以你能挑出最擅长你这项任务设计的模型；它是 git 原生的，会提交每一次改动，于是每一轮设计迭代都可审阅、可回退。两点都有帮助 —— 但品味仍然来自你提供的设计系统、skill 和参考。"}, {"name": "Aider 会编辑我的文件并提交到 git 吗？", "text": "会。Aider 直接在你的仓库里编辑文件，并自动为每次改动配上一条合理的提交信息，于是你可以用早已熟悉的 git 工具来 diff、管理和撤销 AI 的工作。"}, {"name": "我该如何把我的设计规范交给 Aider？", "text": "创建一个写有你 tokens、基础元件和规则的 CONVENTIONS.md，然后用 /read CONVENTIONS.md 或 aider --read CONVENTIONS.md 以只读方式加载它（或在 .aider.conf.yml 里设置 read: CONVENTIONS.md 让它每次运行都加载）。这样 Aider 对照的就是你的品牌，而不是某种默认观感。"}, {"name": "Open Design 和 Aider 有关联吗？", "text": "没有。Aider 是一个独立的开源项目（Aider-AI）；Open Design 是另一个独立的开源项目，把 Aider 作为一等适配器来支持。二者并无关联。"}, {"name": "我的文件和凭证安全吗？", "text": "安全 —— Open Design 本地优先且开源。你的文件、产物和 DESIGN.md 都留在你自己的 git 仓库里，而你的供应商 API key 由你的 agent 直接使用，绝不经 Open Design 的服务器转发。"}], "ctaTitle": "用开放的方式，与 Aider 一起做设计。", "ctaBody": "自带你的供应商 API key，让每一个文件都留在你的 git 仓库本地，并为你早已在用的 agent 配上一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 里使用 Aider", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "什么是 Aider", "aboutBody": ["Aider 是一个开源（Apache-2.0）的 AI 结对编程工具，运行在你的终端里。它映射你的代码库，就地编辑文件，并自动为每次改动配上一条合理的提交信息。", "它是模型无关的 —— 自带你的 key 接入 Claude、GPT-4o、DeepSeek、Gemini 或本地模型 —— 并在支持视觉的模型上读取参考图。", "Open Design 把 Aider 当作一等适配器，于是这个 agent 能嵌入一条结构化、开源的设计管线。"], "vendorLabel": "供应商", "vendor": "Aider (Aider-AI, open source) — model-agnostic", "credentialLabel": "凭证", "credential": "你自己的供应商 API key —— BYOK（OpenAI、Anthropic、DeepSeek、Gemini 或本地模型）", "designTitle": "用 Aider 做设计", "designLead": "Aider 的设计强项集中在它的模型自由度和 git 工作流上：", "designPoints": [{"label": "模型无关，BYOK", "body": "用你自己的 key 接入几乎任何 LLM，并用一个支持视觉的模型把一张参考图变成响应式标记。"}, {"label": "git 原生的迭代", "body": "自动提交让每一轮设计都成为一段你可撤销、可审阅的 diff，于是产出始终干净且可追溯。"}, {"label": "CONVENTIONS.md 上下文", "body": "一个只读的规范文件把你的 tokens、基础元件和设计规则带进每一次运行。"}, {"label": "开源", "body": "Apache-2.0 且本地优先，直接操作你自己仓库里的代码。"}], "linksTitle": "真实世界的资源", "linksLead": "Aider 的官方站点与仓库：", "links": [{"label": "Aider —— 在你终端里的 AI 结对编程", "href": "https://aider.chat/", "source": "文档 · Aider"}, {"label": "Aider-AI/aider（GitHub）", "href": "https://github.com/Aider-AI/aider", "source": "GitHub · Aider-AI"}, {"label": "Aider 安装指南", "href": "https://aider.chat/docs/install.html", "source": "文档 · Aider"}], "withOdTitle": "Aider + Open Design", "withOdLead": "Open Design 是围绕 Aider 的那层开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design 并选择 Aider 作为你的 agent。", "用你自己的供应商 API key 认证（BYOK）—— 凭证留在你的机器上。", "选择一套设计系统和一个 skill，然后以一致的品味生成幻灯片、原型和落地页。", "产物和 DESIGN.md 文件存活在你自己的 git 仓库里，而不是某个托管云端。"], "withOdClosing": "还是那个 Aider agent —— 外加一套围绕它的、真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Aider 做的吗？", "text": "不是。Aider 是一个独立的开源项目（Aider-AI）；Open Design 是另一个独立的开源项目，把它作为一等适配器集成进来。"}, {"name": "我需要某个特定的模型吗？", "text": "不需要 —— Aider 是模型无关的。自带你的 key 接入 OpenAI、Anthropic、DeepSeek、Gemini 或本地模型。Open Design 绝不会中转你的凭证。"}, {"name": "Open Design 和 Aider 有关联吗？", "text": "没有。Open Design 是独立的，与 Aider 并无关联。"}], "ctaTitle": "用开放的方式，与 Aider 一起做设计。", "ctaBody": "为仓库点 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  antigravity: {"title": "用 Antigravity 做设计 — Open Design", "description": "人们如何使用 Google Antigravity——Google 推出的、由多模态 Gemini 3.x 模型驱动的 agent 优先开发平台，配备编辑器视图、管理面板、集成浏览器控制与 Artifacts——来做 UI 和网页设计，以及 Open Design 如何把 Antigravity 变成一个本地优先、开源的设计 agent。", "breadcrumb": "Antigravity", "label": "Agent · Antigravity", "heading": "用 Antigravity 做设计。", "lead": "Antigravity 是 Google 的 agent 优先开发平台。它的 Gemini 3.x 模型能读取截图并对布局进行推理，它的集成浏览器让 agent 能验证自己构建的成果，它的 Artifacts 把 agent 的工作变成可审阅的交付物——只要你给它参考图、规范和一套验证闭环，它就是一个真正的设计工具。Open Design 把它接入一套开源设计工作流：用你自己的 Google 账号、你自己的文件，本地优先。", "tldrTitle": "TL;DR", "tldrBody": "Antigravity 借助多模态 Gemini 3.x 模型、用于自我验证的集成浏览器，以及可供你审阅的 Artifacts，把参考图转化为响应式 UI，用 Google 账号即可免费上手。Open Design 为它配上一套精选的设计系统与 skill 库，外加一套桌面工作流——让一切都留在本地。", "toc": ["什么是 Antigravity", "用 Antigravity 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Antigravity 变成一个本地优先、开源的设计 agent——用你自己的 Google 账号、你自己的文件，围绕它构建一套精选的 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Antigravity", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Antigravity 是 Google 的 agent 优先开发平台，与 Gemini 3 同时发布。有三点让它在设计领域格外值得关注：它的 agent 运行在原生多模态的 Gemini 3.x 模型上，因此能读懂一张截图，并对布局、间距和层级进行推理；它内置了一个 agent 可以操控的集成浏览器，因此会渲染并检查自己做出的 UI，而不是凭空猜测；它还会产出 Artifacts——任务清单、实现方案、截图和浏览器录制——把 agent 的工作变成你真正可以审阅的东西。配上合适的参考图、规范和一套验证闭环，它就能构建出真正的响应式 UI——而且用一个 Google 账号就能免费上手。这是一份关于如何用 Antigravity 做 UI、前端和设计系统工作，并把它接入一套结构化设计工作流（搭配 Open Design）的、务实的端到端指南。", "本文涵盖：Antigravity 究竟是什么，为什么多模态 Gemini 加集成浏览器很适合设计，如何从零搭建，截图到 UI 的闭环，它的 agent 上下文与工具如何扩展它，它与 Codex、Claude Code、Cursor、Gemini CLI 相比如何，哪些坑会让 AI 产出看起来千篇一律，以及 Open Design 如何作为一个开放、本地优先的设计层来弥合这道鸿沟——这是一对天然的搭档，因为 Open Design 本身就是开源的，并运行在你自己的机器上。"], "heroImage": {"src": "/agents/antigravity-design/antigravity-design-hero.webp", "alt": "Antigravity 设计反馈闭环：一个 agent 优先的 IDE 读取参考图、一个集成浏览器渲染 UI、一个管理面板，以及一条回环的反馈箭头", "caption": "核心闭环：Antigravity agent 读取你的参考图，在集成浏览器中构建并验证 UI，再对照参考图迭代——并把工作以可审阅的 Artifacts 形式呈现出来。"}, "tocLabel": "本页目录", "toc": [{"id": "what-is-antigravity", "label": "Antigravity 究竟是什么"}, {"id": "why-design", "label": "为什么多模态 Gemini + 内置浏览器适合设计"}, {"id": "setup", "label": "为设计搭建 Antigravity（从零开始）"}, {"id": "screenshot-workflow", "label": "截图到 UI 的工作流"}, {"id": "extend", "label": "Agent 上下文、工具与 Artifacts"}, {"id": "vs", "label": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "常见坑与“AI 味”观感"}, {"id": "open-design", "label": "在 Open Design 中用 Antigravity 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-antigravity", "heading": "Antigravity 究竟是什么", "blocks": [{"kind": "p", "text": "Antigravity 是 Google 的 agent 优先开发平台——一个为自主 agent（而非侧边栏聊天机器人）干活而打造的 AI 驱动 IDE。它于 2025 年 11 月 18 日与 Gemini 3 一同发布，并在公开预览阶段面向个人免费开放，让你能把复杂的、跨多种工具的软件任务委托给一个跨编辑器、终端和集成浏览器运作的 agent。它的 agent 主要运行在 Google 的多模态 Gemini 3.x 模型上。"}, {"kind": "p", "text": "对于设计工作来说，有三点尤为突出。它的 agent 能读取截图并对真实布局进行推理，因为 Gemini 3.x 是原生多模态的。它能操控一个真实的浏览器，因此会渲染并验证自己构建的成果。它还会呈现 Artifacts——任务清单、方案、截图和浏览器录制——让你审阅的是看得见摸得着的产出，而非原始的工具日志。"}, {"kind": "steps", "items": [{"label": "编辑器视图 + 管理面板", "body": "编辑器视图是一个熟悉的 AI IDE，带有 Tab 补全和内联命令；管理面板让你能跨工作区生成、编排并观察多个异步工作的 agent——是跑一个长时设计任务的理想之处。"}, {"label": "集成浏览器 + Artifacts", "body": "Agent 可以在内置浏览器中操作，并产出你可以留下反馈的 Artifacts（截图、浏览器录制、任务清单、方案）——一套内建于平台、而非事后拼接上去的验证闭环。"}, {"label": "免费上手", "body": "用个人 Google 账号登录即可获得 Gemini 3.x 的宽松速率限额；该平台可在 macOS、Windows 和 Linux 上运行。"}]}, {"kind": "ul", "items": ["厂商：Google", "凭证：Google 账号（个人 Gmail），公开预览期间免费", "可执行文件：用 agy 启动；可在 macOS、Windows 和 Linux 上运行"]}]}, {"id": "why-design", "heading": "为什么多模态 Gemini 和内置浏览器适合设计", "blocks": [{"kind": "p", "text": "Antigravity 的设计优势来自模型与平台的合力——但和每一个 agent 一样，品味仍然得由你来提供。"}, {"kind": "steps", "items": [{"label": "强大的多模态理解", "body": "由于 Gemini 3.x 是原生多模态的，agent 能很好地读懂参考截图——把自己渲染出的成果与一张图片对照，而不是从一段文字描述里猜。"}, {"label": "用集成浏览器来验证", "body": "Agent 操控一个真实的浏览器，因此会渲染 UI、跨各种状态检查它、揪出错乱的布局——并把结果捕获为一段你可以审阅的浏览器录制 Artifact。"}, {"label": "agent 会读取的规范", "body": "把你的 tokens、组件和审阅规则写进 agent 的项目上下文，让它对照你的品牌来工作，而不是套用一套默认观感。"}]}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-taste-triangle.webp", "alt": "示意图，展示设计系统、skill 和参考图三者汇聚成优秀的设计产出", "caption": "品味来自你提供的三项输入：一套设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这条经验和每一个 agent 教给我们的一样：Antigravity 默认并不具备品味。当你给它约束——一套设计系统、一个审美 skill 和具体的参考图——它就能产出优秀的设计。Open Design 恰恰把这些输入打包好了，这正是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零开始为设计工作搭建 Antigravity", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 Antigravity agent 的完整路径。预览期间应用内的具体菜单可能会变动，所以这里只讲你能放心依赖的层面。"}, {"kind": "code", "lang": "bash", "code": "# 1. 从官方下载页 antigravity.google/download\n#    为你的操作系统（macOS、Windows、Linux）下载 Antigravity\n\n# 2. 启动它并登录\nagy               # 打开 Antigravity；用你的 Google 账号登录\n\n# 3. 接受数据使用政策、选一个主题，并打开你的项目文件夹\n\n# 4. 在编辑器视图或管理面板中启动一个 agent 任务，\n#    选择一个 Gemini 3.x 模型（例如 Gemini 3.1 Pro）"}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-setup-flow.webp", "alt": "五步搭建流程：下载、用 Google 登录、打开项目、添加设计规则和一个 skill、启用浏览器验证", "caption": "搭建顺序：下载 → 用 Google 登录 → 打开你的项目 → 添加设计规则和一个 skill → 用集成浏览器验证。"}, {"kind": "steps", "items": [{"label": "编入你的设计规则", "body": "把你的 tokens、基础组件和规范放进 agent 的项目上下文，让产出贴合一个品牌，而不是退回到一套千篇一律的观感。"}, {"label": "使用集成浏览器", "body": "让 agent 在 Antigravity 的内置浏览器中渲染，并跨各种断点检查产出——验证的是 UI 看起来是否正确，而不仅仅是构建有没有通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Antigravity 时最高杠杆的设计闭环，就是把一张参考图转化为可用的响应式 UI，并不断迭代直到吻合——靠多模态模型把产出与参考图对照，靠集成浏览器来验证它。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考出发——并纳入多种状态（桌面端和移动端、悬停、空态、加载态），而不只是一张大图。", "提示词要具体；含糊的提示词即便配上强力模型也只会产出千篇一律的 UI。", "把你的设计系统和规范留在 agent 的项目上下文里，并告诉它 tokens 和规范的基础组件在哪里。", "让 agent 在 Antigravity 的集成浏览器中渲染，并调整到各个断点来检查结果。", "通过让 agent 把自己的实现与截图对照来迭代——而不只是确认它能构建——并审阅它产出的浏览器录制和截图 Artifacts。"]}, {"kind": "p", "text": "附上你的参考图、给出具体约束，然后让 agent 在浏览器里验证："}, {"kind": "code", "lang": "text", "code": "# 在一个 Antigravity agent 任务中，附上 reference-desktop.png 和\n# reference-mobile.png，然后输入提示词：\n\n用 React + Vite + Tailwind + TypeScript 实现这个设计。\n复用我已有的设计系统组件和 tokens。\n匹配间距、布局和层级；做成响应式。\n在集成浏览器中渲染并迭代，直到它跨各个断点都与\n参考图吻合，并把截图展示给我。"}, {"kind": "p", "text": "保持提示词小而聚焦，提交好的迭代、回退坏的迭代（回退时告诉 agent），这样每一轮都能在干净的基底上推进。"}]}, {"id": "extend", "heading": "Agent 上下文、工具与 Artifacts", "blocks": [{"kind": "p", "text": "有三个扩展点让 Antigravity 适合持续的设计工作，而这三者都能干净利落地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "项目上下文", "body": "持久化的项目规则是你设计规范的长久归宿——agent 在每个任务中都会读取的 tokens、基础组件和审阅清单，让产出始终贴合品牌。"}, {"label": "集成浏览器 + 终端", "body": "Agent 跨编辑器、终端和内置浏览器操作，因此能收集参考、跑一个开发服务器，并验证渲染出的 UI，全程不必离开平台。"}, {"label": "你来审阅的 Artifacts", "body": "任务清单、实现方案、截图和浏览器录制让 agent 的工作清晰可读；你在 Artifact 上留下反馈，agent 据此吸收修正。"}]}, {"kind": "p", "text": "这些正是一套严肃的设计闭环所需的能力——也恰恰是 Open Design 被设计来编排（而非每个项目重新造一遍）的那类东西。"}]}, {"id": "vs", "heading": "做设计时 Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI", "blocks": [{"kind": "p", "text": "设计工作没有唯一赢家——每个 agent 各有所长，有经验的团队会把它们叠加使用。一个公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Antigravity", "agent 优先的 IDE，搭配多模态 Gemini 3.x、用于自我验证的集成浏览器，以及可审阅的 Artifacts；预览期免费", "带内置浏览器 UI 验证的异步多 agent 构建"], ["Codex", "带前端 skill 的出色视觉打磨；沙箱化的异步构建", "委托式异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（色值、间距、字体）以及理解代码库的 UX", "前端推理与大上下文重构"], ["Cursor", "带实时预览和内联编辑的“边构建边看”视觉闭环", "在 IDE 内紧凑的“边迭代边看”UI 工作"], ["Gemini CLI", "运行在多模态 Gemini 上的开源终端 agent，带 1M tokens 上下文和免费档", "大量依赖截图的终端工作，以及把整套设计系统装进上下文"]]}, {"kind": "p", "text": "社区反复得出的结论是：品味来自人——它们在没有 skill、参考和约束时都会退回到一套千篇一律的审美。这才是真正要解决的问题——而它是设计工具形态的，不是模型形态的。"}]}, {"id": "pitfalls", "heading": "常见坑，以及如何避免“AI 味”观感", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的吐槽是它看起来千篇一律——柔和的渐变、悬浮的面板、过大的圆角、夸张的阴影，一股 Inter 字体配紫色、“一看就是 AI 做的”的味道。其他被反映的问题还包括移动端布局错乱，以及指令泄漏进 UI 文案。这些都不是 Antigravity 独有的；它们是任何 agent 在缺乏精选设计上下文时运行的必然结果。"}, {"kind": "steps", "items": [{"label": "加上一个审美 skill", "body": "一个精选的设计 skill 会逼着 agent 确定一个真实的方向，而不是套用默认观感。"}, {"label": "在集成浏览器中验证", "body": "用多模态模型和 Antigravity 的内置浏览器跨各个断点渲染并自检，让布局不会在移动端悄无声息地崩掉。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图是撬动产出质量的最大单一杠杆。"}, {"label": "把规则编入项目上下文", "body": "把“不用大图卡片、最多两种字体、品牌优先的层级”这类风格规则，放在 agent 每个任务都会读到的地方。"}]}, {"kind": "p", "text": "注意，每一项缓解措施都是在给 agent 一份精选的设计上下文。逐个项目手工维护那份上下文，正是 Open Design 替你免去的苦活。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Antigravity 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面那套工作流一再呼唤的开源设计层。它把 Antigravity 当作一等公民适配器，并用一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI 把它包起来——这样，让 Antigravity 变好的那份设计上下文从第一次运行起就在那儿，而不必每次都手工拼装。Open Design 是开源且本地优先的，这让这对搭档天然契合。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 Antigravity 作为你的 agent。", "用你的 Google 账号认证——凭证留在你的机器上，绝不经我们中转。", "挑一套设计系统和一个 skill，然后以一致的品味生成演示稿、原型和落地页。", "每一个 artifact 和 DESIGN.md 文件都存在你自己的仓库里，而非托管云端。"]}, {"kind": "p", "text": "还是同一个 Antigravity agent、同一个 Google 账号——只是外面多了一套真实、可移植、开源的设计工作流。Open Design 本地优先且采用 Apache-2.0，因此你的工作或凭证没有任何东西会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Antigravity 真的能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一套设计系统和真实的参考图，Antigravity 就能产出生产级的响应式 UI，而它多模态的 Gemini 3.x agent 会在集成浏览器中验证产出。缺了这份上下文，它就容易退回到一套千篇一律的观感，而这正是 Open Design 来填补的缺口。"}, {"name": "用 Antigravity 做设计需要付费吗？", "text": "Antigravity 在公开预览阶段面向个人免费开放，用个人 Google 账号登录时可享 Gemini 3.x 的宽松速率限额。无论如何，Open Design 都绝不会中转你的凭证。"}, {"name": "Antigravity 具体为什么适合做设计？", "text": "三点：它的 agent 运行在原生多模态、能很好读懂参考截图的 Gemini 3.x 模型上；它内置了一个 agent 可操控、用来验证 UI 的集成浏览器；它还会呈现 Artifacts——截图和浏览器录制——供你审阅。品味仍然来自你提供的设计系统、skill 和参考。"}, {"name": "前端设计该用 Antigravity 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体、理解代码库的设计决策见长；Antigravity 的优势在于它 agent 优先的平台——多模态 Gemini 3.x、用于验证的集成浏览器，以及可审阅的 Artifacts。许多团队两者并用——Open Design 让你能切换 agent 而无需改变你的设计工作流。"}, {"name": "我该如何验证 Antigravity 构建的成果？", "text": "Antigravity 内置了一个 agent 可操控的集成浏览器，因此它们会渲染 UI、跨各个断点检查它，并把截图和浏览器录制捕获为 Artifacts。审阅这些 Artifacts——并让 agent 把自己的产出与你的参考对照——就是你让结果不偏离规范的方式。"}, {"name": "Open Design 与 Google 有关联吗？", "text": "没有。Antigravity 是 Google 的产品；Open Design 是一个独立的开源项目，以一等公民适配器的形式支持它。Antigravity 和 Gemini 是 Google 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且采用 Apache-2.0。你的文件、artifact 和 DESIGN.md 都留在你自己的仓库里，而你的 Google 凭证由你的 agent 直接使用，绝不经由 Open Design 服务器中转。"}], "ctaTitle": "用开放的方式，用 Antigravity 做设计。", "ctaBody": "带上你自己的 Google 账号，让每个文件都留在本地，并围绕你已在用的 agent 获得一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Antigravity", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "什么是 Antigravity", "aboutBody": ["Antigravity 是 Google 的 agent 优先开发平台——一个 AI 驱动的 IDE，其中自主 agent 跨编辑器、终端和集成浏览器工作。它与 Gemini 3 一同进入公开预览。", "它的 agent 运行在原生多模态的 Gemini 3.x 模型上，因此能读取参考截图、在真实浏览器中验证 UI，并呈现 Artifacts——任务清单、方案、截图和浏览器录制——供你审阅。", "Open Design 把 Antigravity 当作一等公民适配器，让这个 agent 嵌入一条结构化、开源的设计流水线。"], "vendorLabel": "厂商", "vendor": "Google", "credentialLabel": "凭证", "credential": "Google 账号（个人 Gmail），公开预览期间免费", "designTitle": "用 Antigravity 做设计", "designLead": "Antigravity 的设计强项集中在它的 agent、浏览器和 Artifacts 上：", "designPoints": [{"label": "多模态截图 → UI", "body": "Gemini 3.x 的图像理解把一张参考图转化为响应式标记，并把结果与它对照检查。"}, {"label": "集成浏览器验证", "body": "Agent 操控一个内置浏览器来渲染 UI 并跨各个断点检查它，把结果捕获为 Artifacts。"}, {"label": "编辑器视图 + 管理面板", "body": "在编辑器视图里亲手写代码，或从管理面板异步编排多个 agent。"}, {"label": "免费上手", "body": "公开预览面向个人免费，通过 Google 账号即可享 Gemini 3.x 的宽松速率限额。"}], "linksTitle": "实战资源", "linksLead": "Google Antigravity 的官方站点与文档：", "links": [{"label": "Google Antigravity", "href": "https://antigravity.google/", "source": "Google"}, {"label": "Build with Google Antigravity, our new agentic development platform", "href": "https://developers.googleblog.com/build-with-google-antigravity-our-new-agentic-development-platform/", "source": "博客 · Google"}, {"label": "Getting Started with Google Antigravity", "href": "https://codelabs.developers.google.com/getting-started-google-antigravity", "source": "Codelabs · Google"}], "withOdTitle": "Antigravity + Open Design", "withOdLead": "Open Design 是围绕 Antigravity 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design，并选择 Antigravity 作为你的 agent。", "用你的 Google 账号认证——凭证留在你的机器上。", "选一套设计系统和一个 skill，然后以一致的品味生成演示稿、原型和落地页。", "Artifact 和 DESIGN.md 文件都存在你自己的仓库里，而非托管云端。"], "withOdClosing": "还是同一个 Antigravity agent——只是外面多了一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Google 做的吗？", "text": "不是。Antigravity 是 Google 的产品；Open Design 是一个独立的开源项目，以一等公民适配器的形式集成它。"}, {"name": "我需要付费吗？", "text": "Antigravity 在公开预览阶段通过 Google 账号面向个人免费。Open Design 绝不会中转你的凭证。"}, {"name": "Open Design 与 Google 有关联吗？", "text": "没有。Open Design 是独立的；Antigravity 和 Gemini 是 Google 的商标。"}], "ctaTitle": "用开放的方式，用 Antigravity 做设计。", "ctaBody": "为这个仓库点 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  reasonix: {"title": "DeepSeek Reasonix 用于设计 — Open Design", "description": "人们如何使用 DeepSeek Reasonix——这个由社区构建、DeepSeek 原生的终端编码代理——来做 UI 和网页设计，以及 Open Design 如何把它变成一个本地优先、开源的设计代理。BYOK，使用你自己的 DeepSeek API key。", "breadcrumb": "DeepSeek Reasonix", "label": "代理 · DeepSeek Reasonix", "heading": "DeepSeek Reasonix 用于设计。", "lead": "DeepSeek Reasonix 是一个开源、由社区构建、基于 DeepSeek 模型的终端编码代理。它能读取你的仓库、编辑文件并低成本地运行你的验证循环——它的整个设计都围绕 DeepSeek 的前缀缓存构建，从而让长会话保持经济实惠。配上参考素材、规范和浏览器校验，它就成了一个真正的设计工具。Open Design 把它接入一套开源的设计工作流：用你自己的 DeepSeek API key、你自己的文件、本地优先。", "tldrTitle": "太长不看", "tldrBody": "DeepSeek Reasonix 是一个由社区构建的终端代理，运行在 DeepSeek 的 deepseek-v4-pro 和 deepseek-v4-flash 模型上——成本高效、采用 MIT 许可，并且 BYOK，使用你自己的 DeepSeek API key。它能在你的仓库中编辑文件并运行验证循环。Open Design 为它提供一套精选的设计系统与 skill 库，外加一套桌面工作流——一切都保留在本地。", "toc": ["什么是 DeepSeek Reasonix", "用 DeepSeek Reasonix 做设计", "资源", "与 Open Design 配合", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 DeepSeek Reasonix 变成一个本地优先、开源的设计代理——用你自己的 DeepSeek API key、你自己的文件，外加围绕它的一套精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 DeepSeek Reasonix", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek Reasonix 是一个面向终端、开源、由社区构建的 AI 编码代理，基于 DeepSeek 的模型。它不是 DeepSeek 的官方产品——它由 esengine 这位 GitHub 作者和社区维护，并且专门围绕 DeepSeek 的前缀缓存机制构建，从而让长时间、迭代式的会话保持低成本。它能读取你的仓库、编辑文件、运行命令，并从自然语言任务出发工作，而不只是补全代码行。你自带 DeepSeek API key（BYOK），代理运行在 deepseek-v4-pro 和 deepseek-v4-flash 等 DeepSeek 模型上。这是一份实用、端到端的指南，介绍如何用 DeepSeek Reasonix 来做 UI、前端和设计系统工作，以及如何用 Open Design 把它接入一套结构化的设计工作流。", "本文涵盖：DeepSeek Reasonix 究竟是什么，为什么一个成本高效、由 DeepSeek 驱动的代理适合迭代式设计，如何用你自己的 key 从零开始搭建它，从参考到 UI 的循环，skill 和 MCP 如何扩展它，它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比，那些让 AI 产出显得千篇一律的陷阱，以及 Open Design 如何作为一个开放、本地优先的设计层来弥合这一差距——这是天然的搭配，因为两者都是开源的，且都运行在你自己的机器上。"], "heroImage": {"src": "/agents/reasonix-design/reasonix-design-hero.webp", "alt": "DeepSeek Reasonix 设计反馈循环：一个终端代理读取设计参考、一个浏览器渲染 UI、一个工作区，以及一个回环的反馈箭头", "caption": "核心循环：DeepSeek Reasonix 在终端中依据你的参考素材和规范工作，你在真实浏览器中校验 UI，它再迭代——而且很便宜，这要归功于 DeepSeek 的前缀缓存。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-reasonix", "label": "DeepSeek Reasonix 究竟是什么"}, {"id": "why-design", "label": "为什么成本高效的 DeepSeek 代理适合做设计"}, {"id": "setup", "label": "从零搭建用于设计的 DeepSeek Reasonix"}, {"id": "screenshot-workflow", "label": "从参考到 UI 的工作流"}, {"id": "extend", "label": "Skill、MCP 与配置"}, {"id": "vs", "label": "DeepSeek Reasonix 对比 Codex、Claude Code、Cursor 与 Gemini CLI"}, {"id": "pitfalls", "label": "陷阱与“AI 味”观感"}, {"id": "open-design", "label": "在 Open Design 中用 DeepSeek Reasonix 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-reasonix", "heading": "DeepSeek Reasonix 究竟是什么", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix 是一个面向终端、开源（MIT）的 AI 编码代理，由 esengine 这位 GitHub 作者和社区构建。它是 DeepSeek 原生的：围绕 DeepSeek 的前缀缓存机制设计，从而让长时间、迭代式的会话保持低成本。它能读取你的仓库，用一个带审查门控的 SEARCH/REPLACE 编辑器编辑文件，运行 shell 命令，并从自然语言任务出发工作——会规划和验证，而不只是补全代码行。需要明确的是，这是一个社区项目，而非 DeepSeek 公司的官方产品。"}, {"kind": "p", "text": "对设计工作而言，关键在于它是一个有能力、了解仓库的编码代理，以低成本运行在强大的 DeepSeek 模型上。它所用的 DeepSeek 模型是纯文本的——它们并不原生读取图像——所以实际的设计循环是参考驱动的，并在真实浏览器中校验，而不是让代理直接“看”一张截图。成本高效是与设计相关的真正优势：你可以多次迭代 UI，而不必担心那笔通常会让人放弃紧凑循环的账单。"}, {"kind": "steps", "items": [{"label": "DeepSeek 原生，BYOK", "body": "Reasonix 运行在 deepseek-v4-pro 和 deepseek-v4-flash 等 DeepSeek 模型上。你自带 DeepSeek API key——凭证存放在你的环境中，而不在代理的配置里。"}, {"label": "了解仓库的编辑", "body": "它用一个带审查门控的编辑器读取并编辑你项目中的文件，并运行 shell 命令，因此可以在你自己的仓库中构建和迭代真实的 UI 代码。"}, {"label": "Skill + MCP", "body": "它支持用 Markdown 编写的 skill 和 MCP 服务器，因此你可以为它提供持久的规范，并接入像设计源这样的外部上下文。"}]}, {"kind": "ul", "items": ["供应方：社区 / esengine 这位 GitHub 作者（不是 DeepSeek 公司）", "凭证：你自己的 DeepSeek API key（BYOK），通过环境变量提供", "许可：MIT，开源"]}]}, {"id": "why-design", "heading": "为什么成本高效的 DeepSeek 代理适合做设计", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix 的设计优势不在于某项炫目的单一能力，而更在于让迭代式 UI 工作变得便宜且可重复——但和每个代理一样，审美仍需由人来提供。"}, {"kind": "steps", "items": [{"label": "便宜、紧凑的迭代", "body": "因为它围绕 DeepSeek 的前缀缓存设计，长时间的设计会话保持实惠——所以你可以多次运行“构建-校验-精修”循环，而不必精打细算地省着用。"}, {"label": "了解仓库的复用", "body": "它直接在你的仓库中编辑文件，因此当你把它指向现有组件和 tokens 时，它能复用它们，而不是临时发明一次性的样式。"}, {"label": "规范写入 skill", "body": "Markdown skill 和项目配置让你能把 tokens、组件和审查规则编码进去，从而让代理依据你的品牌工作，而不是套用默认观感。"}]}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-taste-triangle.webp", "alt": "图示展示设计系统、skill 和参考图像汇聚成优秀的设计产出", "caption": "审美来自你提供的三项输入：一个设计系统、一个 skill，以及真实的参考图像。"}, {"kind": "p", "text": "这个教训和每个代理给出的是同一个：DeepSeek Reasonix 默认并不具备审美。当你给它约束时，它才会产出好的设计——一个设计系统、一个审美 skill，以及向它描述清楚的具体参考——再加上一个用来校验的浏览器。Open Design 恰好打包了这些输入，这正是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零搭建用于设计工作的 DeepSeek Reasonix", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器，到一个能够构建并校验 UI 的 DeepSeek Reasonix 的路径。因为它是一个社区项目，请始终遵循仓库 README 中的安装说明；下面的提纲只是大致的形态。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 DeepSeek Reasonix（Node 22+）—— 参见仓库 README\nnpm install -g reasonix\n\n# 2. 自带你的 DeepSeek API key（BYOK）\n#    Reasonix 从你的环境读取它，而不是从配置文件读取。\nexport DEEPSEEK_API_KEY=sk-...    # 你的 DeepSeek key\n\n# 3. 在你的项目中启动它\ncd your-project\nreasonix                         # 确切的子命令见 README\n\n# 4. 通过 MCP 添加一个设计源（可选）\n#    例如一个 Figma MCP 服务器，按仓库文档配置"}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-setup-flow.webp", "alt": "五步搭建流程：安装、添加你的 DeepSeek key、配置规范、添加 skill、在浏览器中校验", "caption": "搭建顺序：安装 → 添加你的 DeepSeek API key → 编码规范 → 添加 skill → 启用浏览器校验。"}, {"kind": "steps", "items": [{"label": "编码你的设计规则", "body": "把你的 tokens、基础元素和规范放进一个 skill 或项目配置，并把 Reasonix 指向它们，从而让产出贴合某个品牌，而不是退回到千篇一律的观感。"}, {"label": "加入浏览器校验", "body": "由于 DeepSeek 模型是纯文本的，接入一个 Playwright 或浏览器 MCP，让代理在真实浏览器中渲染并跨断点检查其产出，而不只是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "从参考到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 DeepSeek Reasonix 做设计时，杠杆最高的循环是把清晰的参考转化为可用、响应式的 UI，并迭代到匹配为止。因为 DeepSeek 模型是纯文本的，参考是以详细的描述和规格喂给它的——而不是被原生地当作图像读取——匹配则通过在真实浏览器中渲染来确认。"}, {"kind": "ol", "items": ["把你的参考翻译成具体的规格——用文字描述布局、间距、层级和各种状态（桌面和移动端、悬停、空状态、加载中），因为模型读的是文字，不是像素。", "在提示词中要具体；即便用上强模型，含糊的提示词也只会产出千篇一律的 UI。", "把你的设计系统和规范放进一个 skill 或项目配置，并告诉 Reasonix tokens 和规范化基础元素的位置。", "运行一个开发服务器，在真实浏览器中校验结果，并缩放到各个断点——接入一个浏览器 MCP，让代理可以自检。", "通过在浏览器中把渲染出的 UI 与你的参考相互比对来迭代——而不只是确认它能构建。"]}, {"kind": "p", "text": "在提示词中给代理具体的约束，而不是一份含糊的简报："}, {"kind": "code", "lang": "bash", "code": "reasonix\n# 在提示词中：\n> 用 React + Vite + Tailwind + TypeScript 实现这个设计。\n  参考：两栏式 hero、48px 垂直节奏、品牌青绿色\n  强调色、system-ui 字体——桌面和移动端见 DESIGN.md 中的描述。\n  复用我现有的设计系统组件和 tokens。\n  匹配间距、布局和层级；做成响应式。\n  在浏览器中渲染它，并迭代到跨断点都与规格匹配为止。"}, {"kind": "p", "text": "保持提示词小而聚焦，提交好的迭代、回退坏的迭代（在你回退时告诉 Reasonix），这样每一轮都建立在一个干净的基础上——也让那个便宜、对缓存友好的循环保持高效。"}]}, {"id": "extend", "heading": "Skill、MCP 与配置", "blocks": [{"kind": "p", "text": "有几个扩展点让 DeepSeek Reasonix 在持续的设计工作中变得实用，而且它们与一套开放的设计工作流能干净地对应起来。"}, {"kind": "steps", "items": [{"label": "Markdown skill", "body": "Reasonix 支持用 Markdown 编写的 skill——这是承载你设计规范、tokens 和审查清单的持久之所，每次运行都会被应用。"}, {"label": "MCP 服务器", "body": "它集成 MCP 服务器，这是引入设计上下文和外部工具的可移植方式——其中最相关的是像 Figma MCP 服务器这样的设计源——并且它们能跨代理通用，而不只限于 Reasonix。"}, {"label": "项目配置与内置工具", "body": "按项目划分的配置，加上内置的文件、shell 和网页工具，让它无需离开终端就能收集上下文并运行验证循环。确切的配置路径请查阅仓库 README。"}]}, {"kind": "p", "text": "这些都是可移植、跨代理的能力——正是 Open Design 旨在编排的那类东西，而不是在每个项目里重新造一遍。"}]}, {"id": "vs", "heading": "DeepSeek Reasonix 对比 Codex、Claude Code、Cursor 与 Gemini CLI 做设计", "blocks": [{"kind": "p", "text": "做设计工作并没有唯一的赢家——每个代理各有不同的强项，经验丰富的团队会把它们叠加使用。一个公允的小结："}, {"kind": "table", "columns": ["代理", "设计强项", "最适合"], "rows": [["DeepSeek Reasonix", "开源且由 DeepSeek 驱动；通过前缀缓存做到成本高效，BYOK 使用你自己的 DeepSeek key（社区构建，纯文本模型）", "在你自己的仓库里做便宜、高频的 UI 迭代"], ["Codex", "配合前端 skill 有出色的视觉打磨；沙箱化的异步构建", "委派式异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex 值、间距、字体）以及了解代码库的 UX", "前端推理和大上下文重构"], ["Cursor", "带实时预览和内联编辑的可视化“边构建边看”循环", "在 IDE 内做紧凑的“边迭代边观察”UI 工作"], ["Gemini CLI", "强大的多模态图像理解和 1M-token 上下文；开源且带免费额度", "截图密集型工作，以及把整个设计系统保持在上下文里"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人类——没有 skill、参考和约束，它们全都会默认退回到一种千篇一律的观感。这才是真正要解决的问题——而且它是设计工具形态的，不是模型形态的。"}]}, {"id": "pitfalls", "heading": "陷阱，以及如何避免“AI 味”观感", "blocks": [{"kind": "p", "text": "关于 AI 生成设计最常见的抱怨，就是它看起来千篇一律——柔和的渐变、悬浮的面板、过大的圆角、夸张的阴影，一股 Inter 加紫色的味道，“一眼就知道是 AI 做的”。其他被报告的问题还包括移动端布局错乱，以及指令泄漏进 UI 文案里。这些都不是 DeepSeek Reasonix 独有的；当任何代理在没有精选设计上下文的情况下运行时，都会出现这些情况——而且因为它的模型是纯文本的，精确地描述参考就更加重要。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会迫使代理拿出一个真正的方向，而不是套用默认观感。"}, {"label": "在真实浏览器中校验", "body": "由于模型看不见，要在真实浏览器中跨断点渲染并自检，这样布局就不会在移动端悄无声息地崩坏。"}, {"label": "提供 tokens 和描述清楚的参考", "body": "真实的设计 tokens 和被精确描述的参考状态，是对纯文本代理产出质量影响最大的单一杠杆。"}, {"label": "把规则编码进 skill 或配置", "body": "把“不用 hero 卡片、最多两种字体、品牌优先的层级”这类风格规则放在代理每次运行都会读到的地方。"}]}, {"kind": "p", "text": "请注意，每一项缓解措施都是在给代理提供一份精选的设计上下文。逐个项目手工维护那份上下文，正是 Open Design 帮你省去的苦差事。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 DeepSeek Reasonix 做设计", "blocks": [{"kind": "p", "text": "Open Design 就是上述工作流一再呼唤的那个开源设计层。它把 DeepSeek Reasonix 当作一等适配器，并为它包裹上一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI——这样，让 Reasonix 变好的那份设计上下文从第一次运行起就在那里，而不必每次手工拼凑。两者都是开源、本地优先的，这让这对组合成为天然契合。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 DeepSeek Reasonix 作为你的代理。", "用你自己的 DeepSeek API key 进行认证（BYOK）——凭证留在你的机器上，绝不经我们代理转发。", "挑选一个设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "每一个产物和 DESIGN.md 文件都存放在你自己的仓库里，而不是托管的云端。"]}, {"kind": "p", "text": "还是同一个 DeepSeek Reasonix 代理、同一把 key——只是围绕它多了一套真实、可移植、开源的设计工作流。它本地优先且开源，所以关于你的工作或凭证的一切都不会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "DeepSeek Reasonix 真的能做设计工作吗？", "text": "能——配上一个审美 skill、一个设计系统，以及上下文中被精确描述的参考，DeepSeek Reasonix 能在你自己的仓库里产出生产级、响应式的 UI，而你则在真实浏览器中校验产出。它的 DeepSeek 模型是纯文本的，所以这个循环是“描述参考并校验”，而不是“读取图像”。没有那份上下文，它往往会退回到一种千篇一律的观感，而这正是 Open Design 所填补的空白。"}, {"name": "用 DeepSeek Reasonix 做设计需要付费吗？", "text": "你自带 DeepSeek API key，所以你为用量向 DeepSeek 付费（BYOK）——但代理围绕 DeepSeek 的前缀缓存构建，从而在长会话中把这笔成本压低。Reasonix 本身是免费的，采用 MIT 许可。Open Design 绝不会代理转发你的凭证。"}, {"name": "DeepSeek Reasonix 是 DeepSeek 的官方产品吗？", "text": "不是。DeepSeek Reasonix 是 esengine 这位 GitHub 作者打造的、由社区构建的开源项目——它运行在 DeepSeek 的模型上并使用 DeepSeek API key，但它并非由 DeepSeek 公司制作或背书。DeepSeek 是其各自所有者的商标。"}, {"name": "做前端设计，选 DeepSeek Reasonix 还是 Claude Code？", "text": "两者都能做真正的设计工作。Claude Code 以具体、了解代码库的设计决策著称；DeepSeek Reasonix 的优势在于开源且成本高效，用你自己的 key 在 DeepSeek 模型上做便宜、高频的迭代。许多团队会同时用不止一个——Open Design 让你在不改变设计工作流的前提下切换代理。"}, {"name": "我如何把 DeepSeek Reasonix 连接到像 Figma 这样的设计源？", "text": "Reasonix 支持 MCP 服务器，所以你可以按仓库文档添加一个设计源 MCP（例如一个 Figma MCP 服务器）。代理随后就能把真实的设计上下文——组件、变量、布局数据——作为它可以处理的文本拉取进来，从而让生成的代码与设计源相匹配，而不是近似还原。"}, {"name": "Open Design 与 DeepSeek 有从属关系吗？", "text": "没有。DeepSeek Reasonix 是一个运行在 DeepSeek 模型上的社区项目；Open Design 是一个独立的开源项目，把它作为一等适配器来支持。它与 DeepSeek 公司和 Reasonix 维护者都没有从属关系。DeepSeek 是其各自所有者的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且开源。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的 DeepSeek API key 由你的代理直接使用，绝不会经 Open Design 服务器转发。"}], "ctaTitle": "以开放的方式，用 DeepSeek Reasonix 做设计。", "ctaBody": "自带你的 DeepSeek API key，让每一个文件都留在本地，并为你已经在用的那个开源代理配上一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 DeepSeek Reasonix", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的代理"}, "aboutTitle": "什么是 DeepSeek Reasonix", "aboutBody": ["DeepSeek Reasonix 是一个开源（MIT）、基于 DeepSeek 模型的终端 AI 编码代理。它由 esengine 这位 GitHub 作者社区构建——并非 DeepSeek 的官方产品——并围绕 DeepSeek 的前缀缓存设计，从而让长会话保持低成本。", "它能读取你的代码库，用一个带审查门控的编辑器编辑文件，运行命令，并支持 Markdown skill 和 MCP。它的 DeepSeek 模型（如 deepseek-v4-pro 和 deepseek-v4-flash）是纯文本的，所以设计循环是“描述参考并在浏览器中校验”。", "Open Design 把 DeepSeek Reasonix 当作一等适配器，因此该代理能嵌入一条结构化、开源的设计流水线。"], "vendorLabel": "供应方", "vendor": "Community / esengine (DeepSeek-powered, not DeepSeek the company)", "credentialLabel": "凭证", "credential": "你自己的 DeepSeek API key（BYOK）", "designTitle": "用 DeepSeek Reasonix 做设计", "designLead": "DeepSeek Reasonix 的设计强项集中在成本高效、了解仓库的迭代上：", "designPoints": [{"label": "便宜、紧凑的迭代", "body": "围绕 DeepSeek 的前缀缓存构建，因此“构建-校验-精修”循环在长时间的设计会话中都保持实惠。"}, {"label": "了解仓库的编辑", "body": "用一个带审查门控的编辑器直接在你的仓库中编辑文件，因此能复用你真实的组件和 tokens。"}, {"label": "Skill + MCP", "body": "Markdown skill 承载你的规范；MCP 服务器把像 Figma 源这样的设计上下文作为文本引入。"}, {"label": "开放且 BYOK", "body": "采用 MIT 许可、开源，用你自己的 DeepSeek API key 运行在 DeepSeek 模型上。"}], "linksTitle": "真实世界资源", "linksLead": "DeepSeek Reasonix 的官方仓库：", "links": [{"label": "esengine/DeepSeek-Reasonix（GitHub）", "href": "https://github.com/esengine/DeepSeek-Reasonix", "source": "GitHub · esengine（社区）"}], "withOdTitle": "DeepSeek Reasonix + Open Design", "withOdLead": "Open Design 是围绕 DeepSeek Reasonix 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design，并选择 DeepSeek Reasonix 作为你的代理。", "用你自己的 DeepSeek API key 进行认证（BYOK）——凭证留在你的机器上。", "挑选一个设计系统和 skill，然后以一致的审美生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都存放在你自己的仓库里，而不是托管的云端。"], "withOdClosing": "还是同一个 DeepSeek Reasonix 代理——只是围绕它多了一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 DeepSeek 做的吗？", "text": "不是。DeepSeek Reasonix 是一个运行在 DeepSeek 模型上的社区项目；Open Design 是一个独立的开源项目，把它作为一等适配器集成。两者都不是 DeepSeek 公司制作的。"}, {"name": "我需要付费吗？", "text": "你自带 DeepSeek API key（BYOK），所以你为用量向 DeepSeek 付费——这笔成本因前缀缓存而被压低。Reasonix 和 Open Design 都是免费且开源的，而且 Open Design 绝不会代理转发你的凭证。"}, {"name": "Open Design 与 DeepSeek 或 Reasonix 有从属关系吗？", "text": "没有。Open Design 独立于 DeepSeek 公司和 Reasonix 维护者。DeepSeek 是其各自所有者的商标。"}], "ctaTitle": "以开放的方式，用 DeepSeek Reasonix 做设计。", "ctaBody": "为仓库点 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  hermes: {"title": "用 Hermes 做设计 — Open Design", "description": "人们如何用 Nous Research 的 Hermes（这款自主、多供应商的终端编码 agent）做 UI 和网页设计，以及 Open Design 如何把它变成一个本地优先、开源的设计 agent——使用你自己的 xAI、OpenAI 或 Anthropic 密钥。", "breadcrumb": "Hermes", "label": "Agent · Hermes", "heading": "用 Hermes 做设计。", "lead": "Hermes 是 Nous Research 推出的开源自主终端 agent。它在自己的机器上自主规划、执行并委派工作——而且不绑定供应商，所以你可以自带 xAI、OpenAI 或 Anthropic 密钥。一旦你给它参考素材、规范和一套验证闭环，这份自主性就让它成为真正的设计工具。Open Design 把它接入一套开源设计工作流：你的密钥、你的文件、本地优先。", "tldrTitle": "太长不看", "tldrBody": "Hermes 是一个自主 agent，它会在你选定的供应商上规划并委派 UI 工作——默认是 xAI Grok，也可通过 BYOK 用 OpenAI 或 Anthropic。Open Design 为它配上一套精选的设计系统与 skill 库以及一套桌面工作流——自带密钥，一切保留在本地。", "toc": ["Hermes 是什么", "用 Hermes 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Hermes 变成一个本地优先、开源的设计 agent——你自己的 xAI、OpenAI 或 Anthropic 密钥、你的文件，外加围绕它的一套精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Hermes", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Hermes 是 Nous Research 推出的开源自主 AI agent。有两点让它对设计而言格外有意思：它是真正意义上的 agentic（自主代理），会规划任务、执行任务，并把局部工作委派给隔离的子 agent，而不只是逐行补全；它还不绑定供应商，所以你可以把它指向你信任的任意模型——默认是 xAI Grok，也可通过自带密钥用 OpenAI 和 Anthropic。配上合适的参考素材、规范和一套验证闭环，它就能在你自己的机器上构建真实、响应式的 UI。这是一份实用的端到端指南，教你如何用 Hermes 做 UI、前端和设计系统工作，并把它接入 Open Design 的结构化设计工作流。", "本文涵盖 Hermes 究竟是什么、为什么一个自主、多供应商的 agent 适合做设计、如何从零搭起、截图转 UI 的闭环、skill 与子 agent 如何扩展它、它与 Codex、Claude Code、Cursor、Gemini CLI 的对比、那些让 AI 产物显得千篇一律的坑，以及 Open Design 如何作为一个开放、本地优先的设计层填补落差——这是一种天然搭配，因为两者都开源、都跑在你自己的机器上。"], "heroImage": {"src": "/agents/hermes-design/hermes-design-hero.webp", "alt": "Hermes 设计反馈闭环：一个自主终端 agent 读取参考图、委派给子 agent、一个浏览器渲染 UI 以及一个工作区，反馈箭头回环往复", "caption": "核心闭环：Hermes 在终端里读取你的参考素材，规划并委派构建，在真实浏览器中验证 UI，并对照参考反复迭代——在你自带的任意模型上运行。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-hermes", "label": "Hermes 究竟是什么"}, {"id": "why-design", "label": "为什么自主、多供应商的 agent 适合做设计"}, {"id": "setup", "label": "为设计搭起 Hermes（从零开始）"}, {"id": "screenshot-workflow", "label": "截图转 UI 的工作流"}, {"id": "extend", "label": "Skill、子 agent 与供应商"}, {"id": "vs", "label": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "坑，以及“AI 流水货”观感"}, {"id": "open-design", "label": "在 Open Design 中用 Hermes 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-hermes", "heading": "Hermes 究竟是什么", "blocks": [{"kind": "p", "text": "Hermes 是 Nous Research 推出的开源（MIT）自主 AI agent。它持续运行在你自己的机器或服务器上，读取你的仓库、编辑文件、执行 shell 命令、搜索网络，并且——这是关键——自主规划并执行多步骤工作，把局部委派给隔离的子 agent。它是一个自主 agent，而不是绑死在 IDE 里的副驾。"}, {"kind": "p", "text": "对设计工作来说，有两个特性格外突出。它是真正 agentic 的，所以你可以交给它一个目标，它会规划、构建并验证，而不是等你逐行指挥。它还不绑定供应商：你自带密钥，默认用 xAI Grok，但也可自由指向 OpenAI、Anthropic 或任何其他受支持的端点——由你掌控让哪个模型来推理你的设计。"}, {"kind": "steps", "items": [{"label": "Skill", "body": "Hermes 会构建并复用 skill——它从经验中创造出的过程性记忆——这正是沉淀你的设计规范、tokens 和评审清单的天然之处，让它们在多次运行间持续生效。"}, {"label": "子 agent + 工具", "body": "它会派生隔离的子 agent 来并行处理多条工作流，并自带文件、shell、网络和浏览器工具，因此无需离开终端就能收集参考素材、跑一套构建并验证的闭环。"}, {"label": "自带密钥", "body": "Hermes 默认用 xAI Grok，并通过 BYOK 支持 OpenAI、Anthropic、OpenRouter 及许多其他供应商——设置一个密钥或走一遍 OAuth 流程，再挑选你的模型。"}]}, {"kind": "ul", "items": ["供应商：Nous Research", "凭证：通过 BYOK 自带的供应商密钥——xAI（Grok，默认）、OpenAI 或 Anthropic——用 hermes auth add 添加", "许可证：MIT，开源"]}]}, {"id": "why-design", "heading": "为什么自主、多供应商的 agent 适合做设计", "blocks": [{"kind": "p", "text": "Hermes 的设计优势来自两个特性——但和每一个 agent 一样，审美仍然得由你来供给。"}, {"kind": "steps", "items": [{"label": "自主规划并执行", "body": "因为 Hermes 会自主规划、执行并委派，所以它能接过一个设计目标——还原这张参考、把它做成响应式——并朝它迭代，而不需要把每一步都讲清楚。"}, {"label": "带上你信任的模型", "body": "不绑定供应商的 BYOK 意味着你为手头的活儿挑选推理模型：默认是 xAI Grok，想用 OpenAI 和 Anthropic 模型的长处时也能切——不被任何一家供应商的审美锁死。"}, {"label": "规范沉淀进 skill", "body": "Skill（再加上像 Figma 这样的 MCP 服务器）把 agent 指向你的 tokens、组件和真实规范，于是它针对一套品牌而非默认观感来工作。"}]}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-taste-triangle.webp", "alt": "示意图展示设计系统、skill 和参考图汇聚成优质设计产出", "caption": "审美来自你提供的三项输入：一套设计系统、一个 skill 和真实的参考图。"}, {"kind": "p", "text": "这是每一个 agent 都在教的同一课：Hermes 默认并没有审美。当你给它约束时——一套设计系统、一个审美 skill 和具体的参考——它才产出好设计。Open Design 恰恰把这些输入打包好了，这也是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零为设计工作搭起 Hermes", "blocks": [{"kind": "p", "text": "下面是从一台干净机器到一个能构建并验证 UI 的 Hermes 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Hermes（Nous Research 提供的一行安装脚本）\ncurl -fsSL https://hermes-agent.nousresearch.com/install.sh | bash\n\n# 2. 运行设置向导\nhermes setup\n\n# 3. 添加供应商并完成认证（BYOK）\n#    默认是 xAI Grok；同样支持 OpenAI / Anthropic\nhermes auth add        # 添加供应商密钥或走它的 OAuth 流程\nhermes model           # 挑选供应商和模型（默认 grok-4.3）\n\n# 4. 接入 Figma MCP 服务器（可选，用于设计交付）\n#    在 Hermes 的 MCP / 工具设置中配置它"}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-setup-flow.webp", "alt": "五步设置流程：安装、认证、配置 skill、添加设计系统、验证", "caption": "设置顺序：安装 → 添加供应商密钥 → 把设计规则收进一个 skill → 添加设计系统 → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "编码你的设计规则", "body": "把你的 tokens、基础元素和规范收进一个 Hermes skill 并把 agent 指向它们，让产出贴合一套品牌，而不是退回千篇一律的观感。"}, {"label": "加上浏览器验证", "body": "接入 Playwright 或浏览器 MCP，让 Hermes 在真实浏览器中渲染并跨断点检查其产出，而不仅仅是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图转 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Hermes 做设计杠杆最大的闭环，是把一张参考图变成可用、响应式的 UI，并迭代到匹配为止——让这个自主 agent 规划构建，并把自己的产出对照参考来比对。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考起步——并纳入多种状态（桌面和移动、悬停、空态、加载），而不只是一张主视觉。", "在提示里说具体；提示含糊，哪怕模型再强也只会产出千篇一律的 UI。", "把你的设计系统和规范放进一个 skill，并告诉 Hermes tokens 和标准基础元素在哪里。", "跑一个 dev server，让 Hermes 在真实浏览器中渲染，调整到各断点尺寸来检查结果。", "让 Hermes 把自己的实现对照截图比对来迭代——而不只是确认它能构建。"]}, {"kind": "p", "text": "把 Hermes 指向你的参考素材，并给出具体约束："}, {"kind": "code", "lang": "bash", "code": "hermes\n# 在提示里：\n> 使用本文件夹里的 reference-desktop.png 和 reference-mobile.png。\n  用 React + Vite + Tailwind + TypeScript 实现这个设计。\n  复用我 skill 里现有的设计系统组件和 tokens。\n  匹配间距、布局和层级；做成响应式。\n  在浏览器里渲染它，并迭代到跨断点都与参考匹配为止。"}, {"kind": "p", "text": "把提示保持小而聚焦，提交好的迭代、回退坏的迭代（回退时告诉 Hermes），这样每一轮都建立在干净的基础上。"}]}, {"id": "extend", "heading": "Skill、子 agent 与供应商", "blocks": [{"kind": "p", "text": "三个扩展点让 Hermes 适合持续的设计工作，而且这三者都能干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "Skill", "body": "Hermes 会构建并复用 skill——从经验中创造出的过程性记忆。它们是你设计规范的持久归宿，在后续运行中被直接应用，而不必每次重新解释。"}, {"label": "子 agent 与 MCP", "body": "它把工作委派给隔离的子 agent，并支持 MCP 服务器——这是引入设计上下文与外部工具的可移植方式，其中最相关的是 Figma MCP 服务器，它们跨 agent 通用，而不只服务于 Hermes。"}, {"label": "供应商选择", "body": "因为 Hermes 不绑定供应商（默认 xAI Grok，通过 BYOK 用 OpenAI 和 Anthropic），你可以为任务匹配模型，而无需重建你的工作流。"}]}, {"kind": "p", "text": "这些是可移植、多 agent 的能力——恰恰是 Open Design 生来要去编排的那类东西，而不是每个项目重造一遍。"}]}, {"id": "vs", "heading": "做设计时 Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI", "blocks": [{"kind": "p", "text": "做设计没有唯一赢家——每个 agent 各有不同长处，经验丰富的团队会把它们叠着用。一份公允的小结："}, {"kind": "table", "columns": ["Agent", "设计长处", "最适合"], "rows": [["Hermes", "自主的规划-执行-委派 agent；不绑定供应商的 BYOK（默认 xAI Grok，也支持 OpenAI/Anthropic）；开源且可自托管", "在你信任的任意模型上撒手交付的自主构建，且保留在本地"], ["Codex", "凭借前端 skill 带来出色的视觉打磨；沙箱化的异步构建", "委派式的异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（hex、间距、字体）和懂代码库的 UX", "前端推理和大上下文的重构"], ["Cursor", "带实时预览和内联编辑的可视化“边构建边看”闭环", "在 IDE 内紧凑的“迭代-观察”UI 工作"], ["Gemini CLI", "强大的多模态图像理解和 1M tokens 上下文；有免费档", "截图密集的工作，以及把整套设计系统装进上下文"]]}, {"kind": "p", "text": "社区反复给出的结论是：审美来自人——没有 skill、参考和约束，它们全都会退回千篇一律的观感。那才是真正要解决的问题——它是设计工具形态的，而非模型形态的。"}]}, {"id": "pitfalls", "heading": "坑，以及如何避开“AI 流水货”观感", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨，是它看起来千篇一律——柔和的渐变、悬浮的面板、过大的圆角、夸张的阴影，一股 Inter 加紫色的味道，“一眼就看出是 AI 做的”。其他被反映的问题还包括移动端布局崩坏，以及指令文字渗进了 UI 文案。这些都不是 Hermes 独有的；任何 agent 在没有精选设计上下文的情况下运行，都会这样。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会逼 agent 认定一个真实的方向，而不是默认观感。"}, {"label": "在真实浏览器中验证", "body": "让 Hermes 跨断点渲染并自检，使布局不会在移动端悄无声息地崩坏。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图，是撬动产出质量最大的那根杠杆。"}, {"label": "把规则编码进 skill", "body": "把诸如“不要主视觉卡片、最多两种字体、品牌优先的层级”这类规则放进一个 agent 每次运行都会应用的 skill。"}]}, {"kind": "p", "text": "注意，每一项缓解措施都是在给 agent 一套精选的设计上下文。手工地、逐项目地维护这套上下文，正是 Open Design 替你省掉的苦力活。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Hermes 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面那套工作流一直在呼唤的开源设计层。它把 Hermes 当作一等适配器，并用一套精选的 skill 与设计系统库、一条结构化的渲染流水线和一个本地桌面 UI 把它包起来——于是让 Hermes 变好的那套设计上下文，从第一次运行起就在那儿，而不是每次手工拼凑。两者都开源、都本地优先，这让它们的搭配水到渠成。"}, {"kind": "ol", "items": ["安装 Open Design 并选择 Hermes 作为你的 agent。", "用你自己的供应商密钥（BYOK）认证——默认 xAI Grok，或 OpenAI 或 Anthropic——凭证留在你的机器上，绝不经我们代理。", "挑一套设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "每一份产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管云端。"]}, {"kind": "p", "text": "同一个 Hermes agent、同一个密钥——再加上围绕它的一套真实、可移植、开源的设计工作流。它本地优先、采用 Apache-2.0，所以你的工作和凭证没有任何东西会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Hermes 真的能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一套设计系统和真实的参考图，Hermes 就能产出生产级、响应式的 UI；作为一个自主 agent，它还能自行渲染并对照参考验证产出。没有那套上下文，它往往会退回千篇一律的观感，而这正是 Open Design 填补的落差。"}, {"name": "Hermes 用哪些模型和密钥？", "text": "Hermes 不绑定供应商，且自带密钥。它默认用 xAI Grok（例如 grok-4.3），同时支持 OpenAI、Anthropic、OpenRouter 及许多其他供应商——你用 hermes auth add 添加供应商密钥（或走它的 OAuth 流程），用 hermes model 挑选模型。Open Design 从不代理你的凭证。"}, {"name": "Hermes 具体好在哪，让它适合做设计？", "text": "两点：它是真正自主的，所以会规划、构建并验证 UI，而不是等你逐行指挥；它还不绑定供应商，所以你能跑你信任的推理模型。两点都有帮助——但审美仍然来自你提供的设计系统、skill 和参考。"}, {"name": "做前端设计，选 Hermes 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体、懂代码库的设计决策著称；Hermes 的优势是自主规划并执行加上供应商选择——你甚至可以让 Hermes 指向一个 Anthropic 密钥。很多团队两者都用——Open Design 让你切换 agent 而无需改动你的设计工作流。"}, {"name": "我怎么把 Hermes 连到 Figma？", "text": "在 Hermes 的工具配置里添加一个 Figma MCP 服务器。Hermes 随后就能拉取真实的设计上下文——组件、变量、布局数据——使生成的代码与源头匹配，而不是近似还原。"}, {"name": "Open Design 隶属于 Nous Research 吗？", "text": "不。Hermes 是 Nous Research 的产品；Open Design 是一个独立的开源项目，以一等适配器的方式支持它。Hermes 和 Nous Research 是其各自所有者的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先，采用 Apache-2.0。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的供应商凭证由你的 agent 直接使用，绝不经 Open Design 服务器中转。"}], "ctaTitle": "用开放的方式，和 Hermes 一起做设计。", "ctaBody": "自带你自己的 xAI、OpenAI 或 Anthropic 密钥，把每个文件留在本地，并为你已经在用的 agent 配上一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Hermes", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "Hermes 是什么", "aboutBody": ["Hermes 是 Nous Research 推出的开源（MIT）自主终端 agent。它持续运行在你自己的机器上，读取你的代码库、编辑文件、执行命令，并把多步骤工作规划并委派给隔离的子 agent。", "它不绑定供应商，且自带密钥：默认 xAI Grok，同时支持 OpenAI、Anthropic 及许多其他供应商，因此由你掌控让哪个模型来推理你的设计。", "Open Design 把 Hermes 当作一等适配器，让这个 agent 嵌入一条结构化、开源的设计流水线。"], "vendorLabel": "供应商", "vendor": "Nous Research", "credentialLabel": "凭证", "credential": "通过 BYOK 自带的供应商密钥——xAI（Grok，默认）、OpenAI 或 Anthropic", "designTitle": "用 Hermes 做设计", "designLead": "Hermes 的设计长处集中在它的自主性和供应商选择上：", "designPoints": [{"label": "自主规划并执行", "body": "它规划、构建并把 UI 工作委派给子 agent，把一个设计目标转化为可用、响应式的标记，并检查结果。"}, {"label": "不绑定供应商的 BYOK", "body": "默认 xAI Grok，外加 OpenAI、Anthropic 及许多其他——为任务匹配推理模型而不被锁死。"}, {"label": "Skill + MCP", "body": "可复用的 skill 承载你的规范；一个 Figma MCP 服务器把真实的设计上下文带进代码。"}, {"label": "开放且自托管", "body": "采用 MIT 许可，运行在你自己的机器上，无遥测、无云依赖。"}], "linksTitle": "真实世界资源", "linksLead": "Hermes 的官方仓库和文档：", "links": [{"label": "NousResearch/hermes-agent（GitHub）", "href": "https://github.com/NousResearch/hermes-agent", "source": "GitHub · Nous Research"}, {"label": "Hermes Agent", "href": "https://hermes-agent.nousresearch.com/", "source": "Nous Research"}, {"label": "把 xAI Grok 连到 Hermes（OAuth）", "href": "https://hermes-agent.nousresearch.com/docs/guides/xai-grok-oauth", "source": "文档 · Nous Research"}], "withOdTitle": "Hermes + Open Design", "withOdLead": "Open Design 是围绕 Hermes 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design 并选择 Hermes 作为你的 agent。", "用你自己的供应商密钥（BYOK）认证——默认 xAI Grok，或 OpenAI 或 Anthropic——凭证留在你的机器上。", "选一套设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件存在你自己的仓库里，而不是托管云端。"], "withOdClosing": "同一个 Hermes agent——再加上围绕它的一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Nous Research 做的吗？", "text": "不。Hermes 是 Nous Research 的产品；Open Design 是一个独立的开源项目，以一等适配器的方式集成它。"}, {"name": "我需要某个特定的供应商吗？", "text": "不需要——Hermes 自带密钥且不绑定供应商。它默认用 xAI Grok，同时也支持 OpenAI、Anthropic 等。Open Design 从不代理你的凭证。"}, {"name": "Open Design 隶属于 Nous Research 吗？", "text": "不。Open Design 是独立的；Hermes 和 Nous Research 是其各自所有者的商标。"}], "ctaTitle": "用开放的方式，和 Hermes 一起做设计。", "ctaBody": "给仓库点 Star、下载桌面应用，或加入社区来请求一个适配器。"},
  devin: {"title": "用于设计的 Devin for Terminal — Open Design", "description": "人们如何把 Devin for Terminal——Cognition 在命令行中的自主式 AI 软件工程师——用于 UI 与网页设计，以及 Open Design 如何借助精选的 skill 与设计系统库，把它变成一个本地优先、开源的设计 agent。", "breadcrumb": "Devin for Terminal", "label": "Agent · Devin", "heading": "用于设计的 Devin for Terminal。", "lead": "Devin for Terminal 是 Cognition 的自主式 AI 软件工程师，运行在你的终端里。它能自行规划并执行多步骤任务，还能把会话移交给一个沙箱化的云端 agent——只要你给它参考素材、规范约定和一套验证循环，它就能成为真正交付前端工作的方式。Open Design 把它接入开源的设计工作流：用你自己的 Devin 账号、你自己的文件，本地优先。", "tldrTitle": "太长不看", "tldrBody": "Devin for Terminal 在命令行中运行 Cognition 的自主式 AI 软件工程师——它能规划、构建并验证多步骤的前端工作，还能移交给一个沙箱化的云端 agent。Open Design 为它提供精选的设计系统与 skill 库以及一套桌面工作流，并把一切都保留在你自己的机器上、本地运行。", "toc": ["什么是 Devin for Terminal", "用 Devin 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Devin for Terminal 变成一个本地优先、开源的设计 agent——用你自己的 Devin 账号、你自己的文件，围绕它配上精选的 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 里使用 Devin", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Devin for Terminal 是 Cognition 的自主式 AI 软件工程师，被带进了本地命令行。有两点让它在设计这件事上格外有意思：它是真正具备自主性的，能够规划并端到端地执行一个多步骤任务，而不只是补全代码行；它还能把会话移交给一个拥有自己计算机的沙箱化云端 agent，于是较长的构建任务在你合上笔记本之后仍能继续运行。配上合适的参考素材、规范约定和一套验证循环，它能构建出真正可用的响应式 UI。这是一份实用的、端到端的指南，讲如何把 Devin for Terminal 用于 UI、前端和设计系统工作，以及如何借助 Open Design 把它接入一套结构化的设计工作流。", "本文涵盖：Devin for Terminal 究竟是什么、为什么一个自主式软件工程师适合设计工作、如何从零开始把它配置好、截图转 UI 的循环、项目规则与外部工具如何扩展它、它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比、那些让 AI 产出看起来很「通用」的坑，以及 Open Design 如何作为一个开放、本地优先的设计层来弥合这道鸿沟——对任何能规划并交付前端工作的 agent 来说，这都是天然的搭配。"], "heroImage": {"src": "/agents/devin-design/devin-design-hero.webp", "alt": "Devin for Terminal 的设计反馈循环：一个自主式终端 agent 读取参考图、一个浏览器渲染 UI、一个工作区，以及一条回环的反馈箭头", "caption": "核心循环：Devin 在终端里读取你的参考素材，规划并构建 UI，在真实浏览器中验证，并对照参考不断迭代——必要时把较长的运行任务移交给云端。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-devin", "label": "Devin for Terminal 究竟是什么"}, {"id": "why-design", "label": "为什么自主式软件工程师适合设计"}, {"id": "setup", "label": "从零配置用于设计的 Devin"}, {"id": "screenshot-workflow", "label": "截图转 UI 的工作流"}, {"id": "extend", "label": "项目规则、工具与云端移交"}, {"id": "vs", "label": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "坑，以及那股「AI 味」"}, {"id": "open-design", "label": "在 Open Design 里用 Devin 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-devin", "heading": "Devin for Terminal 究竟是什么", "blocks": [{"kind": "p", "text": "Devin for Terminal 是 Devin——Cognition 的自主式 AI 软件工程师——的命令行版本。它作为一个本地编码 agent 运行，能访问你的代码库、工具和环境——读取你的仓库、编辑文件、执行 shell 命令，并从一条自然语言任务出发去规划和验证工作，而不只是补全代码行。Cognition 用 Rust 自研了一套终端渲染库，让界面保持快速、流畅。"}, {"kind": "p", "text": "对设计工作来说，有两个特性格外突出。它是真正自主的，所以你可以描述一个目标结果，它会执行通往该结果的多步骤路径。而当一个构建任务超出你笔记本的承载时，你可以把会话移交给一个运行在自己沙箱环境中的云端 agent，让它异步地继续工作——于是你回来时迎接你的是一个已完成的 pull request。"}, {"kind": "steps", "items": [{"label": "自主的、具备 agent 能力的执行", "body": "Devin 自行规划并执行一个多步骤任务——实现一项功能、构建 UI、运行并测试它——由带明确完成标准的清晰提示词来引导。"}, {"label": "本地 agent，云端移交", "body": "它在你的终端里本地运行，并且能把会话升级移交给一个拥有自己计算机的沙箱化云端 agent，在你离开后继续工作。"}, {"label": "基于账号，可选模型", "body": "你用 Devin（Cognition）账号登录；Devin 运行在前沿模型上——你可以在多个选项之间选择，比如 Cognition 自家的 SWE-1.6 以及其他前沿模型。"}]}, {"kind": "ul", "items": ["厂商：Cognition", "凭证：Devin（Cognition）账号——基于订阅/账号的登录，而非自带密钥（BYOK）", "形态：本地终端 agent，可选沙箱化云端移交"]}]}, {"id": "why-design", "heading": "为什么自主式软件工程师适合设计", "blocks": [{"kind": "p", "text": "Devin 的设计优势来自它的工作方式——自主的、端到端的执行——但和每个 agent 一样，审美仍然得由你来提供。"}, {"kind": "steps", "items": [{"label": "端到端、多步骤的构建", "body": "因为 Devin 会规划并执行整个任务，它可以一气呵成地搭好一个页面、接好组件、跑起开发服务器并测试结果，而不是停在一段代码片段上。"}, {"label": "沙箱化的云端运行", "body": "较长的前端工作——一整个落地页、一条多屏流程——可以移交给一个沙箱化的云端 agent 继续构建，于是迭代不会被你的笔记本卡住。"}, {"label": "把约定写进项目规则", "body": "通过项目的规则和文档，把 agent 指向你的 tokens、组件和真实规范，让它对着一个品牌工作，而不是一套默认外观。"}]}, {"kind": "image", "src": "/agents/devin-design/devin-design-taste-triangle.webp", "alt": "示意图：设计系统、skill 和参考图汇聚成优秀的设计产出", "caption": "审美来自你提供的三项输入：一套设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这条道理和每个 agent 教给我们的一样：Devin 默认并不具备审美。当你给它约束时，它才能产出好设计——一套设计系统、一个审美 skill，以及具体的参考素材。Open Design 恰好把这些输入打包好了，这正是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零配置用于设计工作的 Devin", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 Devin for Terminal 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Devin for Terminal\ncurl -fsSL https://cli.devin.ai/install.sh | bash\n\n# 2. 在你的项目里启动它，首次运行时登录\ncd your-project\ndevin             # 用你的 Devin（Cognition）账号登录\n\n# 3. 用自然语言描述任务，给出清晰的\n#    完成标准，让 Devin 自行规划并执行。\n\n# 4. 当一个构建任务超出你笔记本的承载时，把会话\n#    移交给一个沙箱化的云端 agent 继续工作。"}, {"kind": "image", "src": "/agents/devin-design/devin-design-setup-flow.webp", "alt": "五步配置流程：安装、登录、编码设计规则、添加参考素材、在浏览器中验证", "caption": "配置顺序：安装 → 登录 → 编码你的设计规则 → 提供参考素材 → 在真实浏览器中验证。"}, {"kind": "steps", "items": [{"label": "编码你的设计规则", "body": "把你的 tokens、基础元件和约定放到 agent 会读取的地方——你项目的规则和文档里——让产出对齐一个品牌，而不是退回到一套通用外观。"}, {"label": "加入浏览器验证", "body": "让 Devin 在真实浏览器中渲染，并跨断点检查它的产出，这样它就会对照设计进行验证，而不只是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图转 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Devin 做设计时，杠杆率最高的循环是把一张参考图变成可用的响应式 UI，并反复迭代直到匹配——让这个自主式 agent 去构建、运行，并把自己的产出对照参考进行比对。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考出发——并且包含多种状态（桌面端和移动端、悬停、空态、加载），而不只是一张主视觉。", "提示词要具体，并给出明确的完成标准；即使 agent 很强，含糊的提示词也会产出通用的 UI。", "把你的设计系统和约定放在项目规则里，并告诉 Devin tokens 和规范基础元件都在哪里。", "跑起一个开发服务器，让 Devin 在真实浏览器中渲染，并调整到各个断点来检查结果。", "通过让 Devin 把自己的实现对照参考进行比对来迭代——而不只是确认它能构建通过——并把较长的迭代移交给云端。"]}, {"kind": "p", "text": "把参考素材和具体约束交给 Devin，并给出清晰的「完成」定义："}, {"kind": "code", "lang": "bash", "code": "devin\n# 在提示词里：\n> Implement the attached reference (desktop + mobile) in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints. Done = pixel-close on both\n  desktop and mobile with no console errors."}, {"kind": "p", "text": "保持提示词聚焦，提交好的迭代、回退坏的迭代（回退时告诉 Devin），这样每一轮都建立在一个干净的基础之上。"}]}, {"id": "extend", "heading": "项目规则、工具与云端移交", "blocks": [{"kind": "p", "text": "三个扩展点让 Devin for Terminal 适合持续的设计工作，而且这三点都能干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "项目规则与上下文", "body": "把你的设计约定、tokens 和评审清单放在项目的规则和文档里，让 agent 每次运行都读取它们，并对着你的品牌工作。"}, {"label": "代码库、工具与环境", "body": "Devin 作为一个本地 agent 运行，能访问你的代码库、工具和环境——它可以跑开发服务器、执行构建并验证产出，全程不用离开终端。"}, {"label": "沙箱化云端移交", "body": "把会话移交给一个运行在自己沙箱里的云端 agent，异步地跑更长的构建、测试和 PR 创建，然后你回来迎接一个已完成的 pull request。"}]}, {"kind": "p", "text": "这些正是 Open Design 被设计来去编排、而非在每个项目里重新造一遍的那类可移植的、agent 形态的能力。"}]}, {"id": "vs", "heading": "用于设计时 Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI", "blocks": [{"kind": "p", "text": "在设计工作上没有唯一的赢家——每个 agent 各有所长，有经验的团队会把它们叠着用。一个公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Devin", "完全自主的软件工程师；规划并执行多步骤构建，并移交给一个沙箱化的云端 agent", "把端到端的前端构建委派出去，让它在你离开后继续运行"], ["Codex", "凭借 frontend skill 带来强视觉打磨；沙箱化异步构建", "委派式异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（十六进制色值、间距、字体）以及理解代码库的 UX", "前端推理和大上下文重构"], ["Cursor", "带实时预览和行内编辑的「边构建边看」循环", "在 IDE 内紧凑地「迭代并观察」的 UI 工作"], ["Gemini CLI", "强大的多模态图像理解和 1M token 的上下文；开源且带免费额度", "大量依赖截图的工作，以及在上下文里装下整套设计系统"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人类——没有 skill、参考素材和约束，它们都会默认退回一套通用审美。那才是真正要解决的问题——而它是设计工具形态的，不是模型形态的。"}]}, {"id": "pitfalls", "heading": "坑，以及如何避开那股「AI 味」", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨是它看起来很通用——柔和的渐变、漂浮的面板、过大的圆角、夸张的阴影，一种 Inter 字体加紫色的调调，「一眼就知道是 AI 做的」。其他被反映的问题还包括移动端布局错乱，以及提示语泄漏进 UI 文案里。这些都不是 Devin 独有的；任何 agent 在缺少精选设计上下文的情况下运行，都会出现这些问题。"}, {"kind": "steps", "items": [{"label": "加入一个审美 skill", "body": "一个精选的设计 skill 会迫使 agent 投向一个真实的方向，而不是那套默认外观。"}, {"label": "在真实浏览器中验证", "body": "让 Devin 渲染并跨断点自检，这样布局就不会在移动端悄悄崩掉。"}, {"label": "提供 tokens 和参考素材", "body": "真实的设计 tokens 和参考截图，是对产出质量影响最大的那个杠杆。"}, {"label": "把规则编码进项目上下文", "body": "把「不用主视觉卡片、最多两种字体、品牌优先的层级」这类风格规则放在 agent 每次运行都会读到的地方，并给出明确的完成标准。"}]}, {"kind": "p", "text": "注意，每一项缓解措施都是在给 agent 一份精选的设计上下文。靠手工、按项目去维护这份上下文，正是 Open Design 替你省掉的那份苦差。"}]}, {"id": "open-design", "heading": "在 Open Design 里用 Devin 做设计", "blocks": [{"kind": "p", "text": "Open Design 就是上面那套工作流一直在呼唤的开源设计层。它把 Devin for Terminal 当作一等公民适配器，并用一套精选的 skill 与设计系统库、一条结构化的渲染管线和一个本地桌面 UI 把它包裹起来——于是让 Devin 变好的那份设计上下文从第一次运行起就在那里，而不必每次都手工拼装。Open Design 是开源且本地优先的，这让它与一个你本就在终端里运行的 agent 天然契合。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 Devin for Terminal 作为你的 agent。", "用你的 Devin（Cognition）账号进行认证——凭证由你的 agent 直接使用，绝不经我们代理。", "选一套设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "每一份产出物和 DESIGN.md 文件都留在你自己的仓库里，而不是托管的云端。"]}, {"kind": "p", "text": "同一个 Devin agent、同一个账号——外加围绕它的一套真实、可移植、开源的设计工作流。Open Design 是本地优先且采用 Apache-2.0 许可的，所以你的工作和凭证都不会经由我们离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Devin for Terminal 真的能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一套设计系统和真实的参考图，Devin 就能产出生产级的响应式 UI，而且作为一个自主式 agent，它能构建、运行并对照你的参考验证结果。缺少这份上下文时，它往往会默认退回一套通用外观，而这正是 Open Design 填补的鸿沟。"}, {"name": "我该如何登录 Devin？", "text": "Devin 是基于账号的：你用一个 Devin（Cognition）账号登录，而不是自带模型密钥。安装 Devin for Terminal，在你的项目里运行它，并在首次运行时认证。Open Design 绝不代理你的凭证——你的 agent 会直接使用它们。"}, {"name": "Devin 在设计上具体好在哪里？", "text": "它是一个完全自主的软件工程师：它端到端地规划并执行多步骤的前端构建，还能把会话移交给一个沙箱化的云端 agent，让它在你离开后继续工作。审美仍然来自你提供的设计系统、skill 和参考素材。"}, {"name": "做前端设计该选 Devin 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体、理解代码库的设计决策见长；Devin 的优势在于完全自主、端到端的执行，外加沙箱化的云端移交。许多团队两者都用——Open Design 让你在不改变设计工作流的情况下切换 agent。"}, {"name": "Devin 在沙箱里运行吗？", "text": "Devin for Terminal 在本地运行，能访问你的代码库和环境，并且它可以把会话移交给一个运行在自己沙箱环境中的云端 agent——这对那些需要异步继续的较长构建、测试和 PR 创建很有用。"}, {"name": "Open Design 与 Cognition 有关联吗？", "text": "没有。Devin for Terminal 是 Cognition 的产品；Open Design 是一个独立的开源项目，以一等公民适配器的形式支持它。Devin 是 Cognition 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且采用 Apache-2.0 许可。你的文件、产出物和 DESIGN.md 都留在你自己的仓库里，你的 Devin 凭证由你的 agent 直接使用，绝不经由 Open Design 服务器中转。"}], "ctaTitle": "以开放的方式，和 Devin 一起做设计。", "ctaBody": "用你的 Devin 账号登录，让每个文件都留在本地，并围绕你已经在用的那个自主式 agent 配上一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 里使用 Devin", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "什么是 Devin for Terminal", "aboutBody": ["Devin for Terminal 是 Devin——Cognition 的自主式 AI 软件工程师——的命令行版本。它作为一个本地编码 agent 运行，能访问你的代码库、工具和环境，自行规划并执行多步骤任务。", "它能把会话移交给一个沙箱化的云端 agent 异步地继续工作，于是较长的构建任务会在你合上笔记本之后完成。", "Open Design 把 Devin for Terminal 当作一等公民适配器，于是这个 agent 能嵌入一条结构化的、开源的设计管线。"], "vendorLabel": "厂商", "vendor": "Cognition", "credentialLabel": "凭证", "credential": "Devin（Cognition）账号——基于账号的登录，而非 BYOK", "designTitle": "用 Devin 做设计", "designLead": "Devin 的设计强项集中在它的自主性和执行力上：", "designPoints": [{"label": "自主的多步骤构建", "body": "Devin 规划并执行整个前端任务——搭建脚手架、接好组件、运行并测试——而不是停在一段代码片段上。"}, {"label": "沙箱化云端移交", "body": "较长的构建可以移交给一个拥有自己计算机的云端 agent，在你离开后继续运行。"}, {"label": "项目规则 + 浏览器验证", "body": "项目上下文承载你的约定；真实浏览器渲染会跨断点、对照你的参考检查产出。"}, {"label": "基于账号，可选模型", "body": "用一个 Devin 账号登录；Devin 运行在前沿模型上，包括 Cognition 自家的 SWE-1.6。"}], "linksTitle": "真实世界的资源", "linksLead": "Devin 的官方站点、发布文章和文档：", "links": [{"label": "Devin — AI 软件工程师", "href": "https://devin.ai/", "source": "Cognition"}, {"label": "Devin CLI：从本地开始，移交给云端", "href": "https://cognition.ai/blog/devin-for-terminal", "source": "博客 · Cognition"}, {"label": "Devin 文档", "href": "https://docs.devin.ai/", "source": "文档 · Cognition"}], "withOdTitle": "Devin + Open Design", "withOdLead": "Open Design 是围绕 Devin for Terminal 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design，并选择 Devin for Terminal 作为你的 agent。", "用你的 Devin（Cognition）账号进行认证——凭证随你的 agent 留在你的机器上。", "选一套设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "产出物和 DESIGN.md 文件都留在你自己的仓库里，而不是托管的云端。"], "withOdClosing": "同一个 Devin agent——外加围绕它的一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Cognition 做的吗？", "text": "不是。Devin for Terminal 是 Cognition 的产品；Open Design 是一个独立的开源项目，以一等公民适配器的形式集成它。"}, {"name": "我该如何登录？", "text": "Devin 是基于账号的——用你的 Devin（Cognition）账号登录，而不是你自己的模型密钥。Open Design 绝不代理你的凭证。"}, {"name": "Open Design 与 Cognition 有关联吗？", "text": "没有。Open Design 是独立的；Devin 是 Cognition 的商标。"}], "ctaTitle": "以开放的方式，和 Devin 一起做设计。", "ctaBody": "给仓库点 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  pi: {"title": "用 Pi 做设计 — Open Design", "description": "人们如何用 Pi（开源的多供应商终端编码 agent）做 UI 与网页设计——它的任意模型路由、BYOK 供应商密钥、Skills 与 Extensions——以及 Open Design 如何把 Pi 变成本地优先的开源设计 agent。", "breadcrumb": "Pi", "label": "Agent · Pi", "heading": "用 Pi 做设计。", "lead": "Pi 是一个开源的终端编码 agent，可路由到任意模型——Anthropic、OpenAI、Google 及 20 多家供应商——全部用你自己的 API 密钥。这个与供应商无关的内核让它成为一款灵活的设计工具：选今天读截图最强的模型，明天再换，工作流不变。Open Design 把它接入一套开源设计工作流：你的供应商密钥、你的文件、本地优先。", "tldrTitle": "TL;DR", "tldrBody": "Pi 是一个 BYOK 终端 agent，能编辑你仓库里的文件并路由到任意供应商，所以你可以按任务选择模型。Open Design 为它配上一套精选的设计系统与 skill 库，外加一个桌面工作流——自带密钥，一切保持本地。", "toc": ["什么是 Pi", "用 Pi 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Pi 变成一个本地优先的开源设计 agent——用你自己的供应商 API 密钥、你的文件，外加围绕它的一套精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Pi", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Pi 是一个面向终端的开源（MIT）AI 编码 agent。对设计而言它的有趣之处在于：它与供应商无关——在一个统一接口背后把 Anthropic、OpenAI、Google 及另外 20 多家供应商规范成一致形态，所以你用自己的 API 密钥（BYOK）做认证、按任务挑模型——而且可以在一次会话中途切换模型，不必重新学习这套工具。再配上合适的参考、规范和一个验证回路，它能构建出真实、响应式的 UI。这是一份实用的端到端指南，讲如何用 Pi 做 UI、前端和设计系统工作，并把它接入 Open Design 的结构化设计工作流。", "它涵盖：Pi 到底是什么，为什么一个多供应商 BYOK agent 适合设计，如何从零搭建，截图转 UI 的回路，Skills 和 Extensions 如何扩展它，它与 Codex、Claude Code、Cursor、Gemini CLI 的对比，让 AI 产出看起来千篇一律的那些坑，以及 Open Design 如何作为一个开放、本地优先的设计层补上这道缺口——这是一种天然的搭配，因为两者都是开源、都在你自己的机器上运行。"], "heroImage": {"src": "/agents/pi-design/pi-design-hero.webp", "alt": "Pi 设计反馈回路：一个终端 agent 在读取参考图、一个浏览器在渲染 UI、一个工作区，还有一条回环的反馈箭头", "caption": "核心回路：Pi 在终端里读取你的参考，在真实浏览器中构建并验证 UI，再对照它们迭代——无论你把它指向哪家供应商。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-pi", "label": "Pi 到底是什么"}, {"id": "why-design", "label": "为什么多供应商 BYOK agent 适合设计"}, {"id": "setup", "label": "从零搭建用于设计的 Pi"}, {"id": "screenshot-workflow", "label": "截图转 UI 的工作流"}, {"id": "extend", "label": "Skills、Extensions 与主题"}, {"id": "vs", "label": "Pi 对比 Codex、Claude Code、Cursor、Gemini CLI"}, {"id": "pitfalls", "label": "坑，以及“AI 流水线感”的样子"}, {"id": "open-design", "label": "在 Open Design 中用 Pi 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-pi", "heading": "Pi 到底是什么", "blocks": [{"kind": "p", "text": "Pi 是一个面向终端的开源（MIT）AI 编码 agent，属于 earendil-works pi 工具集的一部分。它读取你的仓库、编辑文件、运行 shell 命令——从自然语言任务出发去规划并验证工作，而不只是补全几行代码。它的内核刻意精简：四个默认工具——read、write、edit 和 bash——外加内置的 grep、find 和 ls。"}, {"kind": "p", "text": "对设计工作来说，最突出的特性是 Pi 与供应商无关。它在一个统一 API 背后把 Anthropic、OpenAI、Google 及众多其他供应商规范成一致形态，所以你自带密钥、按任务挑模型——比如挑一个擅长读参考截图的多模态强模型——并在会话中途用 /model 或 Ctrl+L 切换，工作流照旧不变。"}, {"kind": "steps", "items": [{"label": "任意模型，你的密钥", "body": "Pi 可路由到 20 多家供应商，包括 Anthropic 和 OpenAI。你用自己的 API 密钥（BYOK）做认证，或用 /login 登录 Claude Pro/Max、ChatGPT Plus/Pro 或 GitHub Copilot 订阅。"}, {"label": "Skills + Extensions", "body": "Pi 加载 Skills（遵循 Agent Skills 标准的 Markdown 能力包）和 TypeScript Extensions——这正是编码你的设计规范、添加自定义工具的天然位置。"}, {"label": "可分支的会话", "body": "会话以 JSONL 树形式存储，所以你可以为一次探索拉出分支、在单个文件里浏览历史，而不会丢掉之前的尝试。"}]}, {"kind": "ul", "items": ["供应商：earendil-works（开源社区项目）", "凭证：你自己的供应商 API 密钥（BYOK——Anthropic、OpenAI、Google 等）或通过 /login 的订阅登录；本地存储在 ~/.pi/agent/auth.json（0600）", "许可证：MIT，开源"]}]}, {"id": "why-design", "heading": "为什么多供应商、BYOK 的 agent 适合设计", "blocks": [{"kind": "p", "text": "Pi 的设计优势在于灵活，而不在某个内置模型——但和每一个 agent 一样，品味仍然得由你提供。"}, {"kind": "steps", "items": [{"label": "按任务挑对模型", "body": "因为 Pi 能路由到任意供应商，你可以拿一个强多模态模型去读参考截图，再切到另一个去做重构——全程不离开 agent。"}, {"label": "你的密钥，无锁定", "body": "BYOK 意味着你不被某一家供应商的定价或上下文限制绑死；按眼前的设计任务挑选其优势最契合的模型。"}, {"label": "把规范放进 Skill", "body": "一个 Skill（再加上像 Figma 服务器这样的 MCP 来源）把 agent 指向你的 tokens、组件和真实规范，于是它针对一个品牌工作，而不是套用默认外观。"}]}, {"kind": "image", "src": "/agents/pi-design/pi-design-taste-triangle.webp", "alt": "示意图：设计系统、skill 和参考图汇聚成优秀的设计产出", "caption": "品味来自你提供的三项输入：一个设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这里的教训和每个 agent 教给我们的一样：Pi 默认没有品味，换什么模型都补不上。当你给它约束时——一个设计系统、一个审美 skill 和具体参考——它才能产出好设计。Open Design 恰好把这些输入打包好，这就是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零搭建用于设计的 Pi", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 Pi 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Pi 编码 agent CLI（Node）\nnpm install -g --ignore-scripts @earendil-works/pi-coding-agent\n\n# 2. 用你自己的供应商密钥做认证（BYOK）\nexport ANTHROPIC_API_KEY=sk-ant-...   # 或 OPENAI_API_KEY=sk-...\n#    （或在 Pi 内运行 /login 使用 Claude / ChatGPT / Copilot 订阅）\n\n# 3. 在你的项目里启动它\ncd your-project\npi\n\n# 4. 随时用 /model 或 Ctrl+L 切换模型"}, {"kind": "image", "src": "/agents/pi-design/pi-design-setup-flow.webp", "alt": "五步搭建流程：安装、认证、编码设计规则、添加 skill、验证", "caption": "搭建顺序：安装 → 认证（BYOK）→ 在 Skill 里编码设计规则 → 选一个模型 → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "编码你的设计规则", "body": "把你的 tokens、基础元素和规范放进一个 Skill 并把 Pi 指向它们，让产出贴合一个品牌，而不是退回到千篇一律的外观。"}, {"label": "加入浏览器验证", "body": "接上 Playwright 或浏览器 MCP，让 Pi 在真实浏览器中渲染、并跨断点检查产出，而不是只确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图转 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Pi 做设计杠杆最高的回路，是把一张参考图变成可用、响应式的 UI，然后迭代到匹配为止——靠一个多模态模型把产出对照参考来比较。因为 Pi 与供应商无关，本轮就把它指向最擅长读图的那个模型。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考入手——并包含多种状态（桌面端和移动端、悬停、空态、加载态），不要只给一张主视觉。", "用 /model 为本轮挑一个强多模态模型，因为图像理解才是截图转 UI 质量的关键驱动力。", "提示词要具体；含糊的提示词即便配强模型也会产出千篇一律的 UI。", "把你的设计系统和规范放进一个 Skill，并告诉 Pi tokens 和规范基础元素在哪里。", "跑一个开发服务器，让 Pi 在真实浏览器中渲染、缩放到各断点，然后把它的实现对照截图来迭代——而不是仅仅确认它能构建。"]}, {"kind": "p", "text": "一开始就把参考和具体约束交给 agent："}, {"kind": "code", "lang": "bash", "code": "pi\n# 在提示词里：\n> 用 React + Vite + Tailwind + TypeScript 实现\n  reference-desktop.png 和 reference-mobile.png。\n  复用我现有的设计系统组件和 tokens（见 Skill）。\n  匹配间距、布局和层级；做成响应式。\n  在浏览器里渲染并迭代，直到它跨断点都与参考匹配。"}, {"kind": "p", "text": "保持提示词小而聚焦，把好的迭代提交、把坏的回退掉（回退时告诉 Pi），这样每一轮都在干净的基底上推进。Pi 可分支的 JSONL 会话也让你在不丢失原始线索的情况下探索另一种方案。"}]}, {"id": "extend", "heading": "Skills、Extensions 与主题", "blocks": [{"kind": "p", "text": "Pi 在运行时通过几个层自我扩展，而它们干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "Skills", "body": "遵循 Agent Skills 标准的 Markdown 能力包——是你的设计规范、tokens 和评审清单耐用、可移植的归宿。同一个 Skill 在兼容的 agent 间通用，不止 Pi。"}, {"label": "Extensions 与提示词模板", "body": "TypeScript Extensions 添加自定义工具、命令和 UI；可复用的提示词模板通过 /name 运行。两者都让你在不离开终端的前提下脚本化验证回路。"}, {"label": "MCP 与主题", "body": "Pi 连接 MCP 服务器以引入外部设计上下文（最相关的是一个 Figma MCP 服务器），主题支持热重载，让终端 UI 在你工作时始终清晰可读。"}]}, {"kind": "p", "text": "这些都是可移植的能力——尤其是 Skills 和 MCP——正是 Open Design 被设计来编排、而非每个项目都重造一遍的那类东西。"}]}, {"id": "vs", "heading": "做设计时 Pi 对比 Codex、Claude Code、Cursor、Gemini CLI", "blocks": [{"kind": "p", "text": "设计工作没有唯一赢家——每个 agent 各有所长，老练的团队会把它们叠着用。一个公允的总结："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Pi", "与供应商无关、BYOK——可路由到任意模型（Anthropic、OpenAI、Google……）并在会话中途切换；MIT，可自我扩展", "按任务选用最佳模型，且不被供应商锁定"], ["Codex", "凭前端 skill 实现强视觉打磨；沙箱化的异步构建", "委托式异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（色值、间距、字体）和理解代码库的 UX", "前端推理和大上下文重构"], ["Cursor", "带实时预览和内联编辑的“构建即所见”视觉回路", "在 IDE 内紧凑的边迭代边看的 UI 工作"], ["Gemini CLI", "强多模态图像理解和 100 万 token 上下文；有免费层", "截图密集的工作，以及把整套设计系统装进上下文"]]}, {"kind": "p", "text": "Pi 的切入角度与其他几家正交：它是那个让你用自己的密钥去调用上述任意底层模型的 agent。社区反复得出的结论依然成立——品味来自人：它们在没有 skill、参考和约束时都会退回到千篇一律的审美。那才是真正要解决的问题，而它是设计工具形态的，不是模型形态的。"}]}, {"id": "pitfalls", "heading": "坑，以及如何避免“AI 流水线感”的样子", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨是它看起来千篇一律——柔和渐变、漂浮面板、过大的圆角、夸张的阴影，一种“一看就是 AI 做的”的 Inter 加紫色气味。其他被反映的问题还包括移动端布局崩坏、以及指令泄漏进 UI 文案。这些都不是 Pi 或某一个模型独有的；它们是任何 agent 在缺少精选设计上下文时都会发生的结果。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 迫使 agent 承诺一个真实的方向，而不是默认外观——而且因为它是可移植的 Skill，会跟着你跨模型走。"}, {"label": "在真实浏览器里验证", "body": "挑一个多模态模型，让 Pi 跨断点渲染并自检，这样布局不会在移动端悄悄崩掉。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图是对产出质量影响最大的那个杠杆。"}, {"label": "把规则编码到 Pi 读得到的地方", "body": "把“不要主视觉卡片、最多两种字体、品牌优先的层级”这类风格规则放进一个 agent 每次运行都加载的 Skill 里。"}]}, {"kind": "p", "text": "注意，每一条缓解措施都是在给 agent 一个精选的设计上下文——与你路由到哪家供应商无关。手工、逐项目地维护那份上下文，正是 Open Design 帮你免去的苦差。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Pi 做设计", "blocks": [{"kind": "p", "text": "Open Design 就是上面那套工作流一直在呼唤的那个开源设计层。它把 Pi 当作一级适配器，并围绕它包上一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI——于是让 Pi 变好的那份设计上下文从第一次运行起就在那里，而不是每次都手工拼装。两者都是开源、都本地优先，这让这对组合天然契合。"}, {"kind": "ol", "items": ["安装 Open Design 并选择 Pi 作为你的 agent。", "用你自己的供应商 API 密钥（BYOK）或一个订阅登录做认证——凭证留在你机器上的 ~/.pi/agent/auth.json，绝不经我们代理。", "挑一个设计系统和一个 skill，然后以一致的品味生成演示稿、原型和落地页。", "每一份产物和 DESIGN.md 文件都存在你自己的仓库里，而不是某个托管云端。"]}, {"kind": "p", "text": "同一个 Pi agent、同样的密钥、同样可以自由切换模型——再加上围绕它的一套真实、可移植的开源设计工作流。它本地优先、采用 MIT，所以关于你的工作或凭证的任何东西都不会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Pi 真的能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一个设计系统和真实的参考图，Pi 就能产出生产级的响应式 UI，而且你可以把它路由到一个强多模态模型，去把产出对照参考做验证。缺了那份上下文，它往往会退回到千篇一律的外观，而这正是 Open Design 要补上的缺口。"}, {"name": "用 Pi 做设计需要付费吗？", "text": "Pi 本身免费且开源（MIT）。你只为底层模型付费——自带供应商 API 密钥（BYOK），或通过 /login 使用 Claude Pro/Max、ChatGPT Plus/Pro 或 GitHub Copilot 订阅。无论哪种方式，Open Design 都绝不代理你的凭证。"}, {"name": "Pi 具体好在哪里、为何适合设计？", "text": "它与供应商无关：你自带密钥、可路由到 20 多家供应商中的任意一家，挑选其优势契合任务的模型并在会话中途切换。但品味仍然来自你提供的设计系统、skill 和参考，而非模型本身。"}, {"name": "做前端设计时我该用哪个模型搭配 Pi？", "text": "Pi 可路由到多家供应商，所以按任务来选——一个强多模态模型很会读参考截图，而别的模型可能更适合重构。Pi 的优势在于你可以切换而不改变工作流。Open Design 让你在所选的任意模型之间保持同一份设计上下文。"}, {"name": "我如何把 Pi 连到 Figma？", "text": "Pi 支持 MCP 服务器，所以你可以加一个 Figma MCP 服务器，拉取真实的设计上下文——组件、变量、布局数据——让生成的代码贴合源头，而不是近似还原。"}, {"name": "Open Design 和 Pi 有从属关系吗？", "text": "没有。Pi 是 earendil-works 出品的独立开源项目；Open Design 是一个单独的独立开源项目，以一级适配器的形式支持 Pi。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且开源。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的供应商密钥由 Pi 直接使用（本地存储在 ~/.pi/agent/auth.json），绝不经过 Open Design 服务器路由。"}], "ctaTitle": "以开放的方式，用 Pi 做设计。", "ctaBody": "自带供应商密钥、路由到任意模型、让每个文件都留在本地，并为你早已在用的 agent 配上一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Pi", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "什么是 Pi", "aboutBody": ["Pi 是 earendil-works 出品的一个面向终端的开源（MIT）AI 编码 agent。它从一个精简的四工具内核——read、write、edit、bash——读取你的代码库、编辑文件、运行命令。", "它与供应商无关：在 Anthropic、OpenAI、Google 及 20 多家供应商之间规范成一致形态，所以你自带密钥、可在会话中途切换模型。", "Open Design 把 Pi 当作一级适配器，让这个 agent 嵌入一条结构化的开源设计流水线。"], "vendorLabel": "供应商", "vendor": "community", "credentialLabel": "凭证", "credential": "你自己的供应商 API 密钥（BYOK）或通过 /login 的订阅登录", "designTitle": "用 Pi 做设计", "designLead": "Pi 的设计强项集中在灵活与开放上：", "designPoints": [{"label": "任意模型，你的密钥", "body": "用你自己的密钥路由到 Anthropic、OpenAI、Google 等；为截图转 UI 挑一个强多模态模型，并用 /model 切换。"}, {"label": "可移植的 Skills", "body": "把你的设计规范编码成 Agent Skills 标准的 Skills，可在兼容的 agent 间通用，不止 Pi。"}, {"label": "MCP + Extensions", "body": "通过 Figma MCP 服务器引入真实设计上下文，并用 TypeScript Extensions 脚本化验证回路。"}, {"label": "开放且 BYOK", "body": "采用 MIT 许可、本地优先；你只为底层模型付费，凭证留在你的机器上。"}], "linksTitle": "真实世界资源", "linksLead": "Pi 的官方仓库与文档：", "links": [{"label": "earendil-works/pi（GitHub）", "href": "https://github.com/earendil-works/pi", "source": "GitHub · earendil-works"}, {"label": "Pi 供应商与认证文档", "href": "https://pi.dev/docs/latest/providers", "source": "文档 · pi.dev"}], "withOdTitle": "Pi + Open Design", "withOdLead": "Open Design 是围绕 Pi 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design 并选择 Pi 作为你的 agent。", "用你自己的供应商 API 密钥（BYOK）或一个订阅登录做认证——凭证留在你的机器上。", "挑一个设计系统和 skill，然后以一致的品味生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都存在你自己的仓库里，而不是某个托管云端。"], "withOdClosing": "同一个 Pi agent——外加围绕它的一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Pi 团队做的吗？", "text": "不是。Pi 是 earendil-works 出品的独立开源项目；Open Design 是一个单独的独立开源项目，以一级适配器的形式集成它。"}, {"name": "我需要付费吗？", "text": "Pi 免费且开源（MIT）。你自带供应商密钥（BYOK）或一个订阅登录，只为底层模型付费。Open Design 绝不代理你的凭证。"}, {"name": "Open Design 和 Pi 有从属关系吗？", "text": "没有。Open Design 是独立的，并把 Pi 作为社区支持的适配器集成进来。"}], "ctaTitle": "以开放的方式，用 Pi 做设计。", "ctaBody": "给仓库点 Star、下载桌面应用，或加入社区来请求新的适配器。"},
  kiro: {"title": "用于设计的 Kiro CLI —— Open Design", "description": "人们如何用 Amazon 的 Kiro CLI 做 UI 与网页设计——它的规范驱动开发、agent 钩子、引导文件与 MCP——以及 Open Design 如何把 Kiro CLI 变成一个本地优先、开源的设计 agent。", "breadcrumb": "Kiro CLI", "label": "Agent · Kiro CLI", "heading": "用于设计的 Kiro CLI。", "lead": "Kiro CLI 是 Amazon 面向规范驱动开发的终端 agent——它会先把一个提示词变成一份需求规范、一份设计文档和一份任务清单，然后才动手写代码。这种结构正是设计工作所需要的：先定意图，再去构建。Open Design 把它接入开源的设计工作流：用你自己的 Builder ID 或登录方式、你自己的文件，本地优先。", "tldrTitle": "太长不看", "tldrBody": "Kiro CLI 把 Amazon 的规范驱动 agent 带到了终端——规范、agent 钩子和引导文件让构建始终对齐既定意图。Open Design 为它配上一套精选的设计系统与 skill 库，外加桌面工作流，于是这套结构产出的是契合品牌的 UI，而不是千篇一律的样子——自带登录、一切本地。Kiro 目前处于预览阶段。", "toc": ["什么是 Kiro CLI", "用 Kiro CLI 做设计", "资源", "与 Open Design 配合", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Kiro CLI 变成一个本地优先、开源的设计 agent——用你自己的 AWS Builder ID 或登录方式、你自己的文件，并围绕它配上一套精选的 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Kiro CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kiro CLI 是 Amazon 面向规范驱动开发的终端 agent。它的与众不同之处在于工作流：它不会从提示词直接跳到代码，而是先把需求形式化为一份规范，产出一份设计文档和一份有序的任务清单，然后才动手实现——让构建对既定意图负责。它还提供了在文件保存等事件上触发的 agent 钩子、把你的标准与约定带进每一次运行的引导文件，以及面向外部工具的 Model Context Protocol 支持。Kiro 目前处于预览阶段，提供 IDE、CLI 和网页界面三种形态，你可以免费开始使用。这是一份实用的端到端指南，讲解如何用 Kiro CLI 做 UI、前端和设计系统工作，以及如何借助 Open Design 把它接入一套结构化的设计工作流。", "本文涵盖：Kiro CLI 究竟是什么、为什么规范驱动的工作流契合设计、如何从零搭建、截图到 UI 的循环、引导文件、钩子与 MCP 如何扩展它、它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比、哪些坑会让 AI 产出显得千篇一律，以及 Open Design 如何作为围绕它的开放、本地优先的设计层来补齐这块短板。"], "heroImage": {"src": "/agents/kiro-design/kiro-design-hero.webp", "alt": "Kiro CLI 设计反馈闭环：一个终端 agent 把规范变成设计、一个浏览器渲染 UI、以及一个工作区，配有一条回环的反馈箭头", "caption": "核心闭环：Kiro CLI 在终端里把你的意图变成规范和任务清单，在真实浏览器中构建并验证 UI，并对照你的参考反复迭代。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-kiro", "label": "Kiro CLI 究竟是什么"}, {"id": "why-design", "label": "为什么规范驱动开发契合设计"}, {"id": "setup", "label": "从零搭建用于设计的 Kiro CLI"}, {"id": "screenshot-workflow", "label": "截图到 UI 的工作流"}, {"id": "extend", "label": "规范、引导文件、钩子与 MCP"}, {"id": "vs", "label": "Kiro 对比 Codex、Claude Code、Cursor 与 Gemini CLI"}, {"id": "pitfalls", "label": "常见坑与“AI 流水线感”外观"}, {"id": "open-design", "label": "在 Open Design 中用 Kiro CLI 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-kiro", "heading": "Kiro CLI 究竟是什么", "blocks": [{"kind": "p", "text": "Kiro 是 Amazon 推出的智能体式 AI，提供 IDE、命令行界面和网页界面三种形态，旨在借助规范驱动开发把你从原型一路带到生产。Kiro CLI 把这个 agent 带到你的终端：你可以开启一段交互式聊天会话、创建并管理 agent、运行 Model Context Protocol 服务器——全部都在命令行里完成。Kiro 目前处于预览阶段。"}, {"kind": "p", "text": "对设计工作而言，最关键的特性是它的工作流。Kiro 不会把提示词直接变成代码，而是先写一份规范——需求、一份设计文档和一份有序的任务清单——然后照着它去实现。这让 agent 的计划在任何 UI 被构建之前就可见、可审阅，这恰好契合设计决策应有的方式：先定意图，再去执行。"}, {"kind": "steps", "items": [{"label": "规范", "body": "Kiro 在写代码之前先把提示词变成一份结构化规范——需求、一份设计文档和一项项独立的任务——这样计划在一开始就可审阅。"}, {"label": "引导文件 + 钩子", "body": "引导文件把你的标准、约定和偏好的工具带进每一次运行；agent 钩子在文件保存等事件上触发，自动运行后台任务。"}, {"label": "免费起步、支持 MCP", "body": "用 Builder ID、Google、GitHub 或你所在的组织登录即可免费开始；Kiro CLI 还会管理 MCP 服务器，以引入外部上下文。"}]}, {"kind": "ul", "items": ["厂商：Amazon（AWS）", "凭证：通过 kiro-cli login 使用 AWS Builder ID、Google、GitHub 或 AWS IAM Identity Center（无需 AWS 账号）", "状态：预览阶段；提供 IDE、CLI 和网页界面"]}]}, {"id": "why-design", "heading": "为什么规范驱动开发契合设计", "blocks": [{"kind": "p", "text": "Kiro CLI 在设计上的优势来自它的工作流——但和每个 agent 一样，审美仍然得由人来提供。"}, {"kind": "steps", "items": [{"label": "先有意图，再有像素", "body": "因为 Kiro 会先写一份规范和一份设计文档，你可以在规划阶段就纠正布局、层级和范围——在 agent 还没落入一种千篇一律的实现之前。"}, {"label": "引导文件承载你的品牌", "body": "引导文件在每一次运行时都把你的 tokens、组件和约定摆在 agent 面前，于是产出契合品牌，而不是落入默认的样子。"}, {"label": "钩子强制执行闭环", "body": "agent 钩子可以在保存时自动跑检查——这是接入一个验证或评审步骤的好地方，而不必指望 agent 自己记得。"}]}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-taste-triangle.webp", "alt": "示意图展示设计系统、skill 与参考图汇聚成优质的设计产出", "caption": "审美来自你提供的三项输入：一套设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这个教训和每个 agent 教给我们的一样：Kiro CLI 默认并不具备审美。规范能让构建保持诚实，但只有当你给它约束——一套设计系统、一个审美 skill 和具体的参考——它才能产出好设计。Open Design 恰好把这些输入打包好了，这正是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零开始，搭建用于设计工作的 Kiro CLI", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 Kiro CLI 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Kiro CLI（macOS/Linux/Windows 的命令见 kiro.dev/docs/cli）\n\n# 2. 认证——会打开浏览器完成登录\nkiro-cli login   # 选择 Builder ID、Google、GitHub 或你所在的组织\n\n# 3. 确认你已登录\nkiro-cli whoami\n\n# 4. 在你的项目里开启交互式会话\ncd your-project\nkiro-cli chat\n\n# 5. 接入 MCP 服务器（可选，例如用于设计交付）\nkiro-cli mcp add ..."}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-setup-flow.webp", "alt": "五步搭建流程：安装、认证、添加引导文件、添加 skill、验证", "caption": "搭建顺序：安装 → 认证 → 添加引导文件和一份设计规范 → 添加 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "把你的设计规则编码进去", "body": "把你的 tokens、基础元素和约定写进引导文件，让 agent 在每一次运行时都读到它们，于是产出契合品牌，而不是落入千篇一律的默认样子。"}, {"label": "加入浏览器验证", "body": "接入一个 Playwright 或浏览器 MCP 服务器，让 Kiro 在真实浏览器中渲染并跨断点检查其产出，而不是只确认构建能通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Kiro CLI 做设计时杠杆最大的闭环，是把一张参考图变成可用的、响应式的 UI，并反复迭代直到吻合——让规范先捕捉意图，然后照着它去构建。"}, {"kind": "ol", "items": ["从你手头最清晰的视觉参考出发——并且要包含多种状态（桌面端和移动端、悬停、空态、加载），而不只是一张主视觉。", "让 Kiro 从你的提示词写出一份规范和设计文档，并在它构建之前审阅计划——这是你及早发现布局和范围问题的地方。", "把你的设计系统和约定放进引导文件，并告诉 Kiro tokens 和规范化基础元素在哪里。", "跑一个开发服务器，让 Kiro 在真实浏览器中渲染，并调整到各个断点来检查结果。", "通过让 Kiro 把它的实现对照参考来迭代——而不只是确认它能构建通过。"]}, {"kind": "p", "text": "开启一段交互式会话，并在一开始就给出具体约束，这样它写出的规范才能反映你真实的意图："}, {"kind": "code", "lang": "bash", "code": "kiro-cli chat\n# 在提示词中：\n> 这是我的参考图：reference-desktop.png 和 reference-mobile.png。\n  先写一份规范，然后用 React + Vite + Tailwind + TypeScript 实现这个设计。\n  复用我现有的设计系统组件和 tokens（见我的引导文件）。\n  对齐间距、布局和层级；做成响应式。\n  在浏览器里渲染它，并反复迭代直到它在各个断点上\n  都与参考图吻合。"}, {"kind": "p", "text": "保持任务小而聚焦，把好的迭代提交、把坏的回退掉（回退时告诉 Kiro），这样每一轮都建立在一个干净的基础之上。"}]}, {"id": "extend", "heading": "规范、引导文件、钩子与 MCP", "blocks": [{"kind": "p", "text": "四个扩展点让 Kiro CLI 在持续的设计工作中变得实用，而这四个都能干净地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "规范", "body": "需求、一份设计文档和一份有序的任务清单——记录一个功能本应是什么样的持久档案，在构建之前和构建之中都可审阅。"}, {"label": "引导文件", "body": "添加 agent 在每一次运行时都会读取的上下文、编码标准以及偏好的工作流或工具——这是安放你设计约定和 tokens 的天然之地。"}, {"label": "agent 钩子", "body": "在文件保存等事件上触发的自动化，运行检查或文档生成等后台任务——这是自动强制执行一个验证步骤的好地方。"}, {"label": "MCP 服务器", "body": "Kiro CLI 会管理 Model Context Protocol 服务器，这是引入外部设计上下文和工具的可移植方式，能跨 agent 通用，而不仅限于 Kiro。"}]}, {"kind": "p", "text": "这些都是可移植、跨 agent 的能力——正是 Open Design 生来要去编排的那类东西，而不是每个项目重造一遍。"}]}, {"id": "vs", "heading": "做设计时 Kiro 对比 Codex、Claude Code、Cursor 与 Gemini CLI", "blocks": [{"kind": "p", "text": "在设计工作上没有唯一赢家——每个 agent 各有不同的强项，经验丰富的团队会把它们叠加使用。一个公允的概括："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Kiro CLI", "规范驱动的工作流——先有需求、设计文档和任务清单，再写代码；引导文件和钩子让构建契合品牌", "结构化、可审阅的构建，在实现之前就锁定意图和范围"], ["Codex", "凭借前端 skill 带来出色的视觉打磨；沙箱化的异步构建", "委托式的异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（十六进制色值、间距、字体）以及理解代码库的 UX", "前端推理和大上下文重构"], ["Cursor", "带实时预览和行内编辑的视觉化“构建即所见”闭环", "在 IDE 内紧凑的“迭代即观察”UI 工作"], ["Gemini CLI", "出色的多模态图像理解和极大的上下文；开源且带免费额度", "大量依赖截图的工作，以及把整套设计系统装进上下文"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人类——它们在缺少 skill、参考和约束的情况下都会默认落入一种千篇一律的风格。那才是真正要解决的问题——而它是设计工具形态的问题，不是模型形态的问题。"}]}, {"id": "pitfalls", "heading": "常见坑，以及如何避免“AI 流水线感”外观", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨是它显得千篇一律——柔和的渐变、悬浮的面板、过大的圆角、夸张的阴影，一种 Inter 字体加紫色的调调，“一看就是 AI 做的”。其他被反映的问题还包括移动端布局错乱、以及指令泄漏进 UI 文案里。这些都不是 Kiro CLI 独有的；当任何 agent 在没有精选设计上下文的情况下运行时，就会这样——规范能让构建不跑题，但它无法提供审美。"}, {"kind": "steps", "items": [{"label": "加入一个审美 skill", "body": "一个精选的设计 skill 会迫使 agent 投入一个真正的方向，而不是默认的样子。"}, {"label": "在真实浏览器中验证", "body": "跨断点渲染并自检——能的话把它接成一个钩子——这样布局就不会在移动端悄无声息地崩掉。"}, {"label": "提供 tokens 和参考", "body": "真实的设计 tokens 和参考截图是对产出质量影响最大的单一杠杆。"}, {"label": "把规则编码进引导文件", "body": "把“不要主视觉卡片、最多两种字体、品牌优先的层级”这类风格规则放在 agent 每次运行都会读到的地方。"}]}, {"kind": "p", "text": "注意，每一种缓解办法都是关于给 agent 一份精选的设计上下文。每个项目手动维护那份上下文，正是 Open Design 要替你省掉的苦工。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Kiro CLI 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上述工作流一再呼唤的那个开源设计层。它把 Kiro CLI 当作第一方适配器，并用一套精选的 skill 与设计系统库、一条结构化的渲染流水线和一个本地桌面 UI 来包裹它——于是让 Kiro 变好的那份设计上下文从第一次运行起就在那里，而不是每次都手动拼凑。Open Design 本地优先，这让这对组合保持简单：你的文件和你的登录都留在你自己的机器上。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 Kiro CLI 作为你的 agent。", "用你的 AWS Builder ID 或其他登录方式认证——凭证留在你的机器上，绝不经我们代理。", "挑一套设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "每一件产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管云端。"]}, {"kind": "p", "text": "同一个 Kiro CLI agent、同一套登录——再加上围绕它的一套真实、可移植、开源的设计工作流。Open Design 本地优先且采用 Apache-2.0，所以你的工作和凭证没有任何东西会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Kiro CLI 真的能做设计工作吗？", "text": "能——在上下文里配上一个审美 skill、一套设计系统和真实的参考图，Kiro CLI 就能产出生产级、响应式的 UI，而它规范驱动的工作流会让构建对既定意图负责。没有那份上下文时，它往往会落入千篇一律的样子，这正是 Open Design 补齐的短板。"}, {"name": "使用 Kiro CLI 需要 AWS 账号吗？", "text": "不需要——Kiro 允许你用 AWS Builder ID、Google、GitHub 或你所在的组织（AWS IAM Identity Center）登录，使用它无需 AWS 账号。Kiro 目前处于预览阶段且可免费起步。无论哪种方式，Open Design 都绝不代理你的凭证。"}, {"name": "Kiro CLI 在设计上具体好在哪里？", "text": "它的规范驱动工作流：Kiro 在写代码之前先写需求、一份设计文档和一份任务清单，于是你能在构建落定之前纠正布局和范围。引导文件承载你的约定，钩子能强制执行检查——但审美仍然来自你提供的设计系统、skill 和参考。"}, {"name": "做前端设计，选 Kiro CLI 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体、理解代码库的设计决策著称；Kiro CLI 的优势在于其规范驱动、可审阅、带引导文件和钩子的工作流。很多团队两者都用——Open Design 让你在不改变设计工作流的前提下切换 agent。"}, {"name": "我如何把 Kiro CLI 连接到外部设计工具？", "text": "Kiro CLI 会管理 Model Context Protocol（MCP）服务器——用 kiro-cli mcp 来添加它们。一个 MCP 服务器能把真实的设计上下文和工具带进 agent，让生成的代码与源头吻合，而不是近似还原。"}, {"name": "Open Design 是否隶属于 Amazon 或 AWS？", "text": "不是。Kiro 是 Amazon（AWS）的产品；Open Design 是一个独立的开源项目，以第一方适配器的方式支持它。Kiro 是 Amazon 的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且采用 Apache-2.0。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的 Kiro 登录由你的 agent 直接使用，绝不经 Open Design 服务器中转。"}], "ctaTitle": "用开放的方式，与 Kiro CLI 一起做设计。", "ctaBody": "自带你的 AWS Builder ID 或登录方式，让每个文件都留在本地，并为你已经在用的 agent 配上一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Kiro CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的 agent"}, "aboutTitle": "什么是 Kiro CLI", "aboutBody": ["Kiro 是 Amazon（AWS）推出的智能体式 AI，提供 IDE、CLI 和网页界面三种形态，为从原型到生产的规范驱动开发而打造。它目前处于预览阶段。", "Kiro CLI 把这个 agent 带到你的终端——交互式聊天会话、自定义 agent、引导文件、agent 钩子，以及 Model Context Protocol 服务器。", "Open Design 把 Kiro CLI 当作第一方适配器，于是这个 agent 能嵌入一条结构化、开源的设计流水线。"], "vendorLabel": "厂商", "vendor": "Amazon (AWS)", "credentialLabel": "凭证", "credential": "AWS Builder ID、Google、GitHub 或 AWS IAM Identity Center（无需 AWS 账号）", "designTitle": "用 Kiro CLI 做设计", "designLead": "Kiro CLI 的设计强项都聚集在它规范驱动的工作流上：", "designPoints": [{"label": "先有规范，再有代码", "body": "Kiro 会先写需求、一份设计文档和一份任务清单，于是你能在构建落定之前纠正布局和范围。"}, {"label": "引导文件", "body": "你的标准、约定和 tokens 会被带进每一次运行，于是产出契合品牌，而不是落入默认的样子。"}, {"label": "agent 钩子", "body": "自动化在文件保存等事件上触发——这是强制执行一个验证或评审步骤的好地方，而不必依赖记忆。"}, {"label": "MCP 与免费起步", "body": "Kiro CLI 会管理 MCP 服务器以引入外部上下文，可用 Builder ID、Google、GitHub 或你所在的组织登录，并在预览阶段免费起步。"}], "linksTitle": "实战资源", "linksLead": "Kiro CLI 的官方站点与文档：", "links": [{"label": "Kiro —— 智能体式 IDE 与 CLI", "href": "https://kiro.dev/", "source": "Amazon · kiro.dev"}, {"label": "Kiro CLI 文档", "href": "https://kiro.dev/docs/cli/", "source": "文档 · Kiro"}, {"label": "kirodotdev/Kiro（GitHub）", "href": "https://github.com/kirodotdev/Kiro", "source": "GitHub · Kiro"}], "withOdTitle": "Kiro CLI + Open Design", "withOdLead": "Open Design 是围绕 Kiro CLI 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design，并选择 Kiro CLI 作为你的 agent。", "用你的 AWS Builder ID 或其他登录方式认证——凭证留在你的机器上。", "选一套设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管云端。"], "withOdClosing": "同一个 Kiro CLI agent——再加上围绕它的一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Amazon 做的吗？", "text": "不是。Kiro 是 Amazon（AWS）的产品；Open Design 是一个独立的开源项目，以第一方适配器的方式集成它。"}, {"name": "我需要 AWS 账号吗？", "text": "不需要——Kiro 可用 AWS Builder ID、Google、GitHub 或你所在的组织登录，无需 AWS 账号。它目前处于预览阶段且可免费起步。Open Design 绝不代理你的凭证。"}, {"name": "Open Design 是否隶属于 Amazon 或 AWS？", "text": "不是。Open Design 是独立的；Kiro 是 Amazon 的商标。"}], "ctaTitle": "用开放的方式，与 Kiro CLI 一起做设计。", "ctaBody": "给仓库点个 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  kilo: {"title": "用 Kilo Code 做设计 — Open Design", "description": "人们如何用 Kilo Code（开源、模型无关的 AI 编码 agent）来做 UI 与网页设计：它的 Architect/Code 模式、MCP 支持、跨众多供应商的 BYOK，以及 Open Design 如何把 Kilo 变成一个本地优先、开源的设计 agent。", "breadcrumb": "Kilo", "label": "Agent · Kilo", "heading": "用 Kilo Code 做设计。", "lead": "Kilo Code 是一个面向你的 IDE 与 CLI 的开源、模型无关的 AI 编码 agent。因为你几乎可以让它接入任意模型，并自带供应商密钥，所以只要你给它参考图、规范和一套验证回路，它就能成为一个真正的设计工具。Open Design 把它接入一套开源的设计工作流：你的供应商密钥、你的文件、本地优先。", "tldrTitle": "TL;DR", "tldrBody": "Kilo Code 能把参考图和明确的约束转化为响应式 UI，配有 Architect/Code 模式、MCP 支持，并可通过 BYOK 或 Kilo 自家网关任选 500 多个模型。Open Design 在它周围补上一套精选的设计系统与 skill 库，外加一套桌面工作流——自带密钥，一切留在本地。", "toc": ["什么是 Kilo Code", "用 Kilo Code 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Kilo Code 变成一个本地优先、开源的设计 agent——你的供应商密钥、你的文件，外加围绕它精选的 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Kilo Code", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kilo Code 是一个开源的 AI 编码 agent，可在 VS Code、JetBrains 系列 IDE 和终端中运行。有两点让它对设计尤其有意思：它是模型无关的，所以你可以选用最能读懂截图的前沿视觉模型来驱动它；它在众多供应商之间支持 BYOK，所以成本和凭证都掌握在你自己手里。配上合适的参考图、规范和一套验证回路，它能构建出真正的响应式 UI。本文是一份实用的端到端指南，讲如何用 Kilo Code 做 UI、前端和设计系统的工作，以及如何把它接入 Open Design 的结构化设计工作流。", "内容涵盖：Kilo Code 究竟是什么，为什么一个模型无关、开放的 agent 适合设计，如何从零开始把它配置好，截图到 UI 的回路，自定义规则和 MCP 如何扩展它，它与 Codex、Claude Code、Cursor、Gemini CLI 的对比，那些让 AI 输出显得千篇一律的陷阱，以及 Open Design 如何作为一个开放、本地优先的设计层来弥合这道鸿沟——这是天然的搭配，因为两者都是开源的，都跑在你自己的机器上。"], "heroImage": {"src": "/agents/kilo-design/kilo-design-hero.webp", "alt": "Kilo Code 设计反馈回路：IDE 与终端中的 agent 读取一张参考图，浏览器渲染 UI，以及一个工作区，反馈箭头回环往复", "caption": "核心回路：Kilo Code 在 IDE 或 CLI 中读取你的参考图，在真实浏览器里构建并验证 UI，再对照它们迭代——用你选定的模型。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-kilo", "label": "Kilo Code 究竟是什么"}, {"id": "why-design", "label": "为什么一个开放、模型无关的 agent 适合设计"}, {"id": "setup", "label": "从零配置 Kilo Code 做设计"}, {"id": "screenshot-workflow", "label": "截图到 UI 的工作流"}, {"id": "extend", "label": "模式、自定义规则与 MCP"}, {"id": "vs", "label": "Kilo Code 对比 Codex、Claude Code、Cursor、Gemini CLI"}, {"id": "pitfalls", "label": "陷阱与“AI 流水线感”的样子"}, {"id": "open-design", "label": "在 Open Design 中用 Kilo Code 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-kilo", "heading": "Kilo Code 究竟是什么", "blocks": [{"kind": "p", "text": "Kilo Code 是由 Kilo Code, Inc. 打造的开源 AI 编码 agent。它以 VS Code 扩展、JetBrains 系列 IDE 中的插件以及命令行界面的形式运行——读取你的代码仓库、编辑文件、执行命令，并从自然语言任务出发去规划和验证工作，而不只是补全几行代码。它最鲜明的特点是模型无关：由你选择驱动它的模型，并自带你的供应商密钥。"}, {"kind": "p", "text": "对设计工作而言，有两点格外突出。因为它模型无关，你可以让它接入最能读懂参考截图、最会推断布局的强力视觉模型。又因为它开源且支持 BYOK，你可以精确查看发送了哪些上下文，并把凭证与成本牢牢掌握在自己手中。"}, {"kind": "steps", "items": [{"label": "Agent 模式", "body": "Kilo 自带几种专门模式——Architect 负责规划、Code 负责构建、Debug 负责修复、Ask 负责答疑——还可自定义模式，于是你可以先规划设计，再在各自专注的环节里实现它。"}, {"label": "自定义规则 + MCP", "body": "它会读取项目级的自定义规则以保留持久上下文，并支持 MCP 服务器（还有 MCP 市场），于是你可以接入外部上下文，比如一份在线的 Figma 文件或设计工具。"}, {"label": "自带密钥", "body": "Kilo 在众多供应商之间支持 BYOK——Anthropic、OpenAI、Google、OpenRouter 等等——你也可以使用 Kilo 自家的网关，它按供应商成本提供 500 多个模型。"}]}, {"kind": "ul", "items": ["供应商：Kilo Code, Inc.（开源）", "凭证：你自己的供应商 API 密钥（BYOK——Anthropic、OpenAI、Google、OpenRouter 等）或 Kilo 自家网关", "许可：开源"]}]}, {"id": "why-design", "heading": "为什么一个开放、模型无关的 agent 适合设计", "blocks": [{"kind": "p", "text": "Kilo Code 在设计上的优势来自开放性和模型选择权——但和每一个 agent 一样，品味仍然得由人来提供。"}, {"kind": "steps", "items": [{"label": "天生模型无关", "body": "因为模型由你来选，你可以用最能读懂参考截图的视觉模型来驱动 Kilo——并在出现更好的模型时随时切换，无需改动工作流。"}, {"label": "开放且可审查", "body": "Kilo 是开源的，所以你能精确看到发送了哪些上下文和提示词——当你希望 agent 复用你真实的设计原语、而不是凭空造出一次性样式时，这一点很有用。"}, {"label": "把规范写进自定义规则", "body": "项目级自定义规则（再加一个 Figma 的 MCP 服务器）把 agent 指向你的 tokens、组件和真实规格，于是它是在对照一个品牌工作，而不是套用默认外观。"}]}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-taste-triangle.webp", "alt": "图示：设计系统、skill 与参考图汇聚成优秀的设计输出", "caption": "品味来自你提供的三项输入：一套设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这个道理每个 agent 都在教我们：Kilo Code 默认并没有品味。只有当你给它约束——一套设计系统、一个审美 skill 和具体的参考图——它才能产出优秀的设计。Open Design 恰好把这些输入打包好了，这正是两者契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零开始配置 Kilo Code 做设计", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 Kilo Code 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Kilo Code extension from the VS Code\n#    (or JetBrains) marketplace, or install the CLI.\n\n# 2. Open your project and sign in / add a provider key\ncd your-project\nkilo              # connect your provider (BYOK) or Kilo's gateway\n\n# 3. Add project context\n#    create custom rules for this project's design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it from the MCP marketplace / MCP settings"}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-setup-flow.webp", "alt": "五步配置流程：安装、认证、添加自定义规则、添加一个 skill、验证", "caption": "配置顺序：安装 → 接入一个供应商 → 添加自定义规则 → 添加一个 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "把你的设计规则编码下来", "body": "把你的 tokens、原语和规范放进 Kilo 的自定义规则，并把 agent 指向它们，让输出对齐一个品牌，而不是默认套上千篇一律的外观。"}, {"label": "加上浏览器验证", "body": "接入 Playwright 或浏览器 MCP，让 Kilo 在真实浏览器中渲染，并跨各个断点检查输出，而不只是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "截图到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Kilo Code 杠杆最高的设计回路，是把一张参考图变成可用的响应式 UI，并不断迭代直到它匹配为止——借助一个视觉模型把输出对照参考图反复比对。"}, {"kind": "ol", "items": ["从你手上最清晰的视觉参考开始——并包含多种状态（桌面端和移动端、悬停、空态、加载态），而不只是一张主视觉图。", "提示词要具体；含糊的提示词即便配上强力模型也只会产出千篇一律的 UI。", "把你的设计系统和规范放进 Kilo 的自定义规则，并告诉 agent tokens 和标准原语在哪里。", "跑一个开发服务器，让 Kilo 在真实浏览器中渲染，并缩放到各个断点来检查结果。", "让 Kilo 把自己的实现对照截图反复比对来迭代——而不只是确认它能构建通过。"]}, {"kind": "p", "text": "用 Architect 模式规划构建，然后切到 Code 模式，附上你的参考图并给出具体约束："}, {"kind": "code", "lang": "bash", "code": "# Plan in Architect mode, then build in Code mode:\n> Implement this design from @reference-desktop.png and\n  @reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens\n  from the custom rules.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints."}, {"kind": "p", "text": "让提示词保持小而专注，把好的迭代提交、把坏的回退（回退时告诉 Kilo），这样每一轮都建立在一个干净的基础之上。"}]}, {"id": "extend", "heading": "模式、自定义规则与 MCP", "blocks": [{"kind": "p", "text": "三个扩展点让 Kilo Code 在持续的设计工作中切实可用，而这三者都能干净利落地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "模式（Architect → Code）", "body": "在 Architect 模式下规划一个页面的结构，然后在 Code 模式下实现它，再在 Debug 模式下修复问题——把设计意图与实现分开。自定义模式还能让你编码出一套自己的设计评审环节。"}, {"label": "自定义规则", "body": "项目级自定义规则是你设计规范的长久归宿——tokens、原语和评审清单——每次运行都会读取，让 agent 对照你的品牌工作。"}, {"label": "MCP 服务器", "body": "Kilo 通过它的市场支持 MCP 服务器——这是引入设计上下文和外部工具的可移植方式，最相关的是一个 Figma 的 MCP 服务器，它们跨 agent 通用，不止限于 Kilo。"}]}, {"kind": "p", "text": "这些都是可移植、跨 agent 的能力——正是 Open Design 生来要去编排的那类东西，而不是每个项目都重新搭一遍。"}]}, {"id": "vs", "heading": "做设计：Kilo Code 对比 Codex、Claude Code、Cursor、Gemini CLI", "blocks": [{"kind": "p", "text": "设计工作没有单一赢家——每个 agent 都各有所长，有经验的团队会把它们叠加使用。一份公允的概括："}, {"kind": "table", "columns": ["Agent", "设计强项", "最适合"], "rows": [["Kilo Code", "开源、模型无关，跨众多供应商支持 BYOK；具备 Architect/Code 模式和 MCP", "按任务自选模型，并把成本与凭证掌握在自己手中"], ["Codex", "凭一个前端 skill 实现出色的视觉打磨；沙箱化的异步构建", "委托式异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（色值、间距、字体）以及对代码库有感知的 UX", "前端推理和大上下文重构"], ["Cursor", "带实时预览和内联编辑的“构建即所见”视觉回路", "在 IDE 内紧凑的“边改边看”UI 工作"], ["Gemini CLI", "强大的多模态图像理解和 100 万 token 的上下文", "大量截图的工作，以及把整套设计系统装进上下文"]]}, {"kind": "p", "text": "社区反复得出的结论是：品味来自人类——它们在缺少 skill、参考图和约束时，都会默认走向千篇一律的审美。这才是真正要解决的问题——而且它的形状是设计工具，而非模型。"}]}, {"id": "pitfalls", "heading": "陷阱，以及如何避开“AI 流水线感”的样子", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨是它看起来千篇一律——柔和的渐变、悬浮的面板、过大的圆角、夸张的阴影，一种 Inter 字体加紫色的调调，“一眼就知道是 AI 做的”。其他被反映的问题还包括移动端布局错乱，以及指令泄漏进了 UI 文案。这些都不是 Kilo Code 独有的；任何 agent 在缺乏精选设计上下文的情况下运行，都会这样。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会逼着 agent 投入一个真实的方向，而不是套用默认外观。"}, {"label": "在真实浏览器中验证", "body": "用一个视觉模型跨断点渲染并自检，这样布局就不会在移动端悄无声息地崩坏。"}, {"label": "提供 tokens 和参考图", "body": "真实的设计 tokens 和参考截图，是撬动输出质量最大的那根杠杆。"}, {"label": "把规则编码进自定义规则", "body": "把“不要 hero 卡片、最多两种字体、品牌优先的层级”这类风格规则放在 agent 每次运行都会读到的地方。"}]}, {"kind": "p", "text": "请注意，每一项缓解措施都是在给 agent 一份精选的设计上下文。手动逐项目维护这份上下文，正是 Open Design 替你免去的苦差。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Kilo Code 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上文那套工作流一直在呼唤的、开源的设计层。它把 Kilo Code 当作一等公民适配器，并在其外围包上一套精选的 skill 与设计系统库、一条结构化的渲染流水线和一个本地桌面 UI——于是让 Kilo 出色的那份设计上下文从第一次运行起就在那里，而不必每次都手动拼凑。两者都是开源、本地优先的，这让它们的搭配水到渠成。"}, {"kind": "ol", "items": ["安装 Open Design，并选择 Kilo Code 作为你的 agent。", "用你自己的供应商密钥（BYOK）或 Kilo 的网关进行认证——凭证留在你的机器上，绝不经我们中转。", "选定一套设计系统和一个 skill，然后以一致的品味生成演示稿、原型和落地页。", "每一份产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管的云端。"]}, {"kind": "p", "text": "还是同一个 Kilo Code agent、同一套密钥——只是外围多了一套真实、可移植、开源的设计工作流。它本地优先且开源，所以关于你工作或凭证的一切都不会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Kilo Code 真的能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一套设计系统和真实的参考图，Kilo Code 就能产出生产级的响应式 UI，再由一个视觉模型把输出对照参考图来验证。缺了这份上下文，它往往会默认走向千篇一律的外观，而这正是 Open Design 填补的空白。"}, {"name": "用 Kilo Code 做设计需要付费吗？", "text": "Kilo Code 是开源的，安装免费。你自带供应商 API 密钥（BYOK）并直接向该供应商付费，或者按供应商成本使用 Kilo 自家网关。无论哪种方式，Open Design 都绝不中转你的凭证。"}, {"name": "Kilo Code 在设计上具体好在哪里？", "text": "它模型无关且开源，所以你可以用最能读懂参考截图的视觉模型来驱动它，精确查看发送了哪些上下文，并把成本与凭证掌握在自己手中。品味仍然来自你提供的设计系统、skill 和参考图。"}, {"name": "前端设计选 Kilo Code 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体、对代码库有感知的设计决策著称；Kilo Code 的优势在于它开源、模型无关且支持 BYOK，模型由你来选。许多团队两者并用——Open Design 让你在不改动设计工作流的前提下切换 agent。"}, {"name": "我该如何把 Kilo Code 连到 Figma？", "text": "从 Kilo 的 MCP 市场或 MCP 设置里添加一个 Figma 的 MCP 服务器。这样 Kilo 就能拉取真实的设计上下文——组件、变量、布局数据——让生成的代码与源头一致，而不是近似还原。"}, {"name": "Open Design 和 Kilo Code 有关联吗？", "text": "没有。Kilo Code 是 Kilo Code, Inc. 的产品；Open Design 是一个独立的开源项目，把它作为一等公民适配器来支持。两者恰好都是开源的，但它们是各自独立的项目。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且开源。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的供应商凭证由你的 agent 直接使用，绝不经 Open Design 服务器中转。"}], "ctaTitle": "用开放的方式，和 Kilo Code 一起做设计。", "ctaBody": "自带你的供应商密钥，把每一个文件留在本地，并在你已经用着的 agent 周围获得一座精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Kilo Code", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上点 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支持的 agent"}, "aboutTitle": "什么是 Kilo Code", "aboutBody": ["Kilo Code 是来自 Kilo Code, Inc. 的开源 AI 编码 agent。它在 VS Code、JetBrains 系列 IDE 和终端中运行，读取你的代码库、编辑文件、执行命令。", "它模型无关，并在众多供应商之间支持 BYOK，配有 Architect/Code/Debug/Ask 模式和 MCP 支持，于是模型由你来选，凭证也掌握在你手中。", "Open Design 把 Kilo Code 当作一等公民适配器，于是这个 agent 能嵌入一条结构化、开源的设计流水线。"], "vendorLabel": "供应商", "vendor": "Kilo Code, Inc.", "credentialLabel": "凭证", "credential": "你自己的供应商 API 密钥（BYOK）或 Kilo 的网关", "designTitle": "用 Kilo Code 做设计", "designLead": "Kilo Code 的设计强项集中在开放性和模型选择权上：", "designPoints": [{"label": "模型无关的截图 → UI", "body": "用最擅长把参考图转成响应式标记的视觉模型来驱动它，再把结果对照参考图来检查。"}, {"label": "跨供应商的 BYOK", "body": "自带你的 Anthropic、OpenAI、Google、OpenRouter 等密钥——或使用 Kilo 的网关——让成本和凭证都属于你。"}, {"label": "模式 + 自定义规则 + MCP", "body": "在 Architect 模式下规划，在 Code 模式下构建，把规范放进自定义规则，再通过 Figma 的 MCP 服务器引入真实的设计上下文。"}, {"label": "开源", "body": "审查每一条提示词和上下文负载；没有任何隐藏，agent 就跑在你的 IDE 或 CLI 里。"}], "linksTitle": "真实世界的资源", "linksLead": "Kilo Code 的官方站点、仓库和文档：", "links": [{"label": "Kilo — 开源 AI 编码 Agent", "href": "https://kilo.ai/", "source": "站点 · Kilo Code"}, {"label": "Kilo-Org/kilocode（GitHub）", "href": "https://github.com/Kilo-Org/kilocode", "source": "GitHub · Kilo Code"}, {"label": "Kilo Code 文档", "href": "https://kilo.ai/docs", "source": "文档 · Kilo Code"}], "withOdTitle": "Kilo Code + Open Design", "withOdLead": "Open Design 是围绕 Kilo Code 的开源设计层：一套精选的 skill 与设计系统库、一条结构化的渲染流水线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design，并选择 Kilo Code 作为你的 agent。", "用你自己的供应商密钥（BYOK）或 Kilo 的网关进行认证——凭证留在你的机器上。", "选定一套设计系统和一个 skill，然后以一致的品味生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管的云端。"], "withOdClosing": "还是同一个 Kilo Code agent——只是外围多了一套真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Kilo Code 做的吗？", "text": "不是。Kilo Code 是 Kilo Code, Inc. 的产品；Open Design 是一个独立的开源项目，把它作为一等公民适配器来集成。"}, {"name": "需要付费吗？", "text": "Kilo Code 安装免费且开源；你自带供应商密钥（BYOK）并向该供应商付费，或使用 Kilo 的网关。Open Design 绝不中转你的凭证。"}, {"name": "Open Design 和 Kilo Code 有关联吗？", "text": "没有。Open Design 是一个独立项目；两者都是开源的，但它们各自独立。"}], "ctaTitle": "用开放的方式，和 Kilo Code 一起做设计。", "ctaBody": "给仓库点 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  vibe: {"title": "用 Mistral Vibe CLI 做设计 — Open Design", "description": "人们如何用 Mistral 的 Vibe CLI 做 UI 与网页设计 —— 它开放权重的 Devstral 编码模型、代理式多文件编辑、config.toml、MCP 与 ACP —— 以及 Open Design 如何把 Vibe CLI 变成一个本地优先、开源的设计代理。", "breadcrumb": "Mistral Vibe CLI", "label": "Agent · Mistral Vibe CLI", "heading": "用 Mistral Vibe CLI 做设计。", "lead": "Mistral Vibe CLI 是 Mistral AI 推出的开源终端编码代理，由 Devstral 模型家族驱动。它能编辑文件、运行命令，并基于 Agent Client Protocol 工作——只要你给它提供参考素材、规范约定和一套验证闭环，它就能成为一个真正的设计工具。Open Design 把它接入一套开源的设计工作流：用你自己的 Mistral API 密钥（BYOK）或本地模型、你自己的文件，本地优先。", "tldrTitle": "一句话总结", "tldrBody": "Vibe CLI 是 Mistral 的 Apache-2.0 终端代理，借助 Devstral 编码模型把提示词和参考素材变成响应式 UI——可以用你自己的 Mistral API 密钥，也可以在本地运行开放权重模型。Open Design 为它配上精选的设计系统与 skill 库，外加一套桌面工作流——BYOK 并把一切都留在本地。", "toc": ["Mistral Vibe CLI 是什么", "用 Vibe CLI 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Mistral Vibe CLI 变成一个本地优先、开源的设计代理——用你自己的 Mistral API 密钥或本地 Devstral 模型、你自己的文件，外加一套围绕它的精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Vibe CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Mistral Vibe CLI 是 Mistral AI 推出的开源（Apache-2.0）终端编码代理。它会扫描你项目的文件结构和 Git 状态来获取上下文，然后根据自然语言任务，在整个代码库中探索、编辑并运行改动。有两点让它在设计场景中格外值得关注：它由 Mistral 的 Devstral 编码模型驱动，这是一个开放权重生态的一部分，你既可以在本地运行，也可以放到云端；同时它支持 Agent Client Protocol（ACP），因此它能嵌入编辑器和各类工具，而不只是局限在某一个终端里。配上合适的参考素材、规范约定和一套验证闭环，它能构建出真正可用的响应式 UI。这是一份实用的端到端指南，讲解如何用 Vibe CLI 做 UI、前端和设计系统的工作，以及如何把它接入 Open Design 的结构化设计工作流。", "内容涵盖：Vibe CLI 究竟是什么、为什么一个开放权重的编码代理适合做设计、如何从零开始配置它、从参考素材到 UI 的闭环、config.toml、MCP 和 ACP 如何扩展它的能力、它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比、那些让 AI 产出显得千篇一律的陷阱，以及 Open Design 如何作为一个开放、本地优先的设计层来补上这道缺口——这是天然的搭配，因为两者都是开源的，并且都在你自己的机器上运行。"], "heroImage": {"src": "/agents/vibe-design/vibe-design-hero.webp", "alt": "Mistral Vibe CLI 设计反馈闭环：一个终端代理读取参考素材、一个浏览器渲染 UI、一个工作区，以及一个回环的反馈箭头", "caption": "核心闭环：Vibe CLI 在终端里读取你的参考素材，在真实浏览器中构建并验证 UI，再对照参考反复迭代——全程由 Mistral 的 Devstral 编码模型驱动。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-vibe", "label": "Mistral Vibe CLI 究竟是什么"}, {"id": "why-design", "label": "为什么开放权重的编码代理适合做设计"}, {"id": "setup", "label": "从零配置 Vibe CLI 做设计"}, {"id": "screenshot-workflow", "label": "从参考素材到 UI 的工作流"}, {"id": "extend", "label": "config.toml、MCP 和 ACP"}, {"id": "vs", "label": "Vibe CLI 对比 Codex、Claude Code、Cursor 和 Gemini CLI"}, {"id": "pitfalls", "label": "陷阱与「AI 味」外观"}, {"id": "open-design", "label": "在 Open Design 中用 Vibe CLI 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-vibe", "heading": "Mistral Vibe CLI 究竟是什么", "blocks": [{"kind": "p", "text": "Mistral Vibe CLI 是 Mistral AI 为终端推出的开源（Apache-2.0）编码代理。它提供一个交互式对话界面，配有文件操作、代码搜索、版本控制和命令执行等工具，并会自动扫描你项目的文件结构和 Git 状态，为代理提供相关上下文。它由 Mistral 的 Devstral 编码模型驱动——根据自然语言任务进行规划和验证，而不只是补全代码行。"}, {"kind": "p", "text": "对设计工作而言，有两个特性尤为突出。它运行在 Mistral 开放权重的 Devstral 家族上（Devstral 2 以及更小的 Devstral Small 2），因此你既可以让代理对接云端的 Mistral API，也可以对接本地模型——这对于注重隐私或离线的设计工作很有用。它还支持 Agent Client Protocol，因此同一个代理可以驱动编辑器和各类工具，而不只是一个终端会话。"}, {"kind": "steps", "items": [{"label": "配置文件", "body": "Vibe CLI 通过 config.toml 文件配置（项目级 ./.vibe/config.toml，并以 ~/.vibe/config.toml 作为回退）。这是个很实用的地方，可以把你的服务商、模型选择和项目设置都写进去。"}, {"label": "内置工具 + MCP", "body": "它自带文件、搜索、版本控制和命令执行工具，并支持 MCP 服务器（在 [[mcp_servers]] 区段下配置），以引入外部上下文，比如一个实时的 Figma 文件。"}, {"label": "BYOK 或本地", "body": "用 Mistral 控制台的 Mistral API 密钥进行认证，或把它指向本地/兼容模型，让它完全离线工作。"}]}, {"kind": "ul", "items": ["厂商：Mistral AI", "凭据：Mistral 控制台的 Mistral API 密钥（BYOK），或本地/兼容模型", "许可证：Apache-2.0，开源"]}]}, {"id": "why-design", "heading": "为什么开放权重的编码代理适合做设计", "blocks": [{"kind": "p", "text": "Vibe CLI 在设计上的优势来自它开放权重的模型家族和广泛的协议覆盖——但与每一个代理一样，审美仍然得由你来提供。"}, {"kind": "steps", "items": [{"label": "Devstral 编码模型", "body": "Vibe 运行在 Mistral 的 Devstral 家族上，这是为代理式、多文件工作打造的编码调优模型——因此代理是在一个真实的前端代码库中跨文件编辑，而不是产出孤立的代码片段。"}, {"label": "开放权重且对本地友好", "body": "Devstral Small 2 足够小，可以跑在消费级硬件上，因此设计工作可以完全保持在本地和离线状态——参考素材和代码永远不必离开你的机器。"}, {"label": "config.toml 中的约定 + 上下文", "body": "项目配置和你自己的指令会把代理引向你的 tokens、组件和真实规范，于是它是面向一个品牌工作，而不是套用默认外观。"}]}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-taste-triangle.webp", "alt": "示意图：设计系统、skill 和参考图汇聚成优质的设计产出", "caption": "审美来自你提供的三项输入：一个设计系统、一个 skill 和真实的参考图。"}, {"kind": "p", "text": "这条教训和每个代理给出的如出一辙：Vibe CLI 默认并不具备审美。当你给它约束时——一个设计系统、一个审美 skill 和具体的参考素材——它才能产出好的设计。Open Design 恰好把这些输入打包好了，这也是两者能契合的原因（下文详述）。"}]}, {"id": "setup", "heading": "从零配置 Vibe CLI 做设计工作", "blocks": [{"kind": "p", "text": "下面是从一台干净的机器到一个能构建并验证 UI 的 Vibe CLI 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Mistral Vibe CLI\nuv tool install mistral-vibe\n# 或：pip install mistral-vibe\n\n# 2. 运行配置向导以注册你的 API 密钥\nvibe --setup     # 将配置保存到 ~/.vibe/config.toml 和 ~/.vibe/.env\n#    或直接设置：  export MISTRAL_API_KEY=...\n\n# 3. 在你的项目中启动 Vibe\ncd your-project\nvibe\n\n# 4. 接入 Figma MCP 服务器（可选，用于设计交付）\n#    在你的 config.toml 中添加一个 [[mcp_servers]] 条目"}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-setup-flow.webp", "alt": "五步配置流程：安装、认证、配置 config.toml、添加 skill、验证", "caption": "配置流程：安装 → 认证 → 配置 config.toml → 添加 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "把你的设计规则写进去", "body": "把你的 tokens、基础元素和规范约定放在代理能读到的地方，并让 Vibe 指向它们，这样产出就会匹配一个品牌，而不是退回到千篇一律的外观。"}, {"label": "加上浏览器验证", "body": "接入一个 Playwright 或浏览器 MCP，让 Vibe 在真实浏览器中渲染，并跨断点检查产出，而不只是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "从参考素材到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Vibe CLI 做设计时收益最高的闭环，是把一份清晰的参考素材变成可用的响应式 UI，并反复迭代直到匹配为止——借助代理自身的工具来渲染、检查并修正它自己的产出。"}, {"kind": "ol", "items": ["从你手头最清晰的参考素材出发——并描述多种状态（桌面和移动端、悬停、空态、加载中），而不只是一张主视觉。", "提示词要具体；含糊的提示即便配上强大的模型也只会产出千篇一律的 UI。", "把你的设计系统和规范约定放在 Vibe 能读到的地方，并告诉它 tokens 和标准基础元素在哪里。", "运行一个开发服务器，让 Vibe 在真实浏览器中渲染，并调整到各个断点来检查结果。", "通过让 Vibe 把它的实现回头对照参考素材来迭代——而不只是确认它能构建通过。"]}, {"kind": "p", "text": "用 @ 引用文件（Vibe 会自动补全文件路径），用 / 调用斜杠命令，然后给出具体的约束："}, {"kind": "code", "lang": "bash", "code": "vibe\n# 在提示词里：\n> @design-spec.md @tokens.css\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until\n  it matches the references across breakpoints."}, {"kind": "p", "text": "保持提示词小而聚焦，提交好的迭代、回退坏的迭代（回退时要告诉 Vibe），这样每一轮都能在一个干净的基础上推进。"}]}, {"id": "extend", "heading": "config.toml、MCP 和 ACP", "blocks": [{"kind": "p", "text": "有三个扩展点让 Vibe CLI 适合做持续性的设计工作，而且这三个都能干净地对应到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "config.toml", "body": "项目规则以及服务商/模型设置都存放在 config.toml 中（项目级，并以 ~/.vibe 作为回退）。它是代理如何接入你项目的持久化归宿，每次运行都会被读取。"}, {"label": "MCP 服务器", "body": "在你的 config.toml 中配置 MCP 服务器（[[mcp_servers]]，支持 HTTP、可流式 HTTP 和 stdio 传输）——这是引入设计上下文和外部工具的可移植方式，其中最相关的就是 Figma MCP 服务器，并且这些在各类代理间通用，不只限于 Vibe。"}, {"label": "Agent Client Protocol", "body": "Vibe 支持 ACP，因此同一个代理可以从编辑器和其他 ACP 客户端来驱动。Open Design 正是这样集成它的——通过 vibe-acp 二进制文件经由 ACP 接入。"}]}, {"kind": "p", "text": "这些都是可移植、跨代理的能力——恰恰是 Open Design 旨在编排的那类东西，而不是在每个项目里重新造一遍。"}]}, {"id": "vs", "heading": "做设计时 Vibe CLI 对比 Codex、Claude Code、Cursor 和 Gemini CLI", "blocks": [{"kind": "p", "text": "在设计工作上没有唯一的赢家——每个代理各有所长，经验丰富的团队会把它们叠加使用。一个公允的总结："}, {"kind": "table", "columns": ["代理", "设计强项", "最适合"], "rows": [["Mistral Vibe CLI", "可在本地运行的开放权重 Devstral 编码模型；Apache-2.0 且原生支持 ACP", "注重隐私或离线的设计工作，以及一套开放权重的技术栈"], ["Codex", "配合前端 skill 的出色视觉打磨；沙盒化的异步构建", "委托式的异步构建和可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（十六进制色、间距、字体）以及理解代码库的 UX", "前端推理和大上下文重构"], ["Cursor", "带实时预览和内联编辑的「边做边看」可视化闭环", "在 IDE 内紧凑的「迭代-观察」式 UI 工作"], ["Gemini CLI", "出色的多模态图像理解和超大的上下文窗口", "大量依赖截图的工作，以及把整个设计系统装进上下文"]]}, {"kind": "p", "text": "社区反复得出的结论是：审美来自人类——若没有 skill、参考素材和约束，它们都会默认走向千篇一律的风格。这才是真正要解决的问题——而它是设计工具形态的，不是模型形态的。"}]}, {"id": "pitfalls", "heading": "陷阱，以及如何避开「AI 味」外观", "blocks": [{"kind": "p", "text": "对 AI 生成设计最常见的抱怨，就是它看起来千篇一律——柔和的渐变、漂浮的面板、过大的圆角、夸张的阴影，以及那种「一看就是 AI 做的」的 Inter 字体加紫色调调。其他被反映的问题还包括移动端布局错乱，以及指令文字泄漏进 UI 文案。这些都不是 Vibe CLI 独有的；只要任何代理在缺乏精选设计上下文的情况下运行，就会出现这些问题。"}, {"kind": "steps", "items": [{"label": "加上一个审美 skill", "body": "一个精选的设计 skill 会迫使代理给出一个真正的方向，而不是套用默认外观。"}, {"label": "在真实浏览器中验证", "body": "让 Vibe 跨断点渲染并自查，这样布局就不会在移动端悄无声息地崩掉。"}, {"label": "提供 tokens 和参考素材", "body": "真实的设计 tokens 和参考截图，是对产出质量影响最大的单一杠杆。"}, {"label": "把规则写进配置和上下文", "body": "把「不要主视觉卡片、最多两种字体、品牌优先的层级」这类风格规则放在代理每次运行都能读到的地方。"}]}, {"kind": "p", "text": "注意，每一项缓解措施都是在给代理一份精选的设计上下文。逐个项目手工维护这份上下文，正是 Open Design 替你省掉的苦工。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Vibe CLI 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上面这套工作流一直在呼唤的那个开源设计层。它把 Mistral Vibe CLI 当作一等适配器——通过 vibe-acp 二进制文件经由 ACP 来驱动它——并为它配上精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI。于是，让 Vibe 变好用的那份设计上下文从第一次运行起就已就位，而不必每次手工拼凑。两者都是开源且本地优先的，这让这对搭配水到渠成。"}, {"kind": "ol", "items": ["安装 Open Design 并选择 Mistral Vibe CLI 作为你的代理。", "用你的 Mistral API 密钥（BYOK）进行认证，或把 Vibe 指向本地模型——凭据留在你的机器上，绝不经我们代理转发。", "挑选一个设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "每一个产物和 DESIGN.md 文件都存在你自己的仓库里，而不是某个托管云端。"]}, {"kind": "p", "text": "同一个 Vibe CLI 代理，同一把密钥——外加一套围绕它的真实、可移植、开源的设计工作流。它本地优先且采用 Apache-2.0，因此你的工作内容和凭据没有任何一项会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Mistral Vibe CLI 真的能做设计工作吗？", "text": "能——只要上下文里有一个审美 skill、一个设计系统和真实的参考素材，Vibe CLI 就能产出生产级的响应式 UI，而它的 Devstral 模型会在一个真实的前端代码库中跨文件编辑。缺了这份上下文，它往往会退回到千篇一律的外观，而这正是 Open Design 要补上的缺口。"}, {"name": "我该如何认证 Vibe CLI？", "text": "运行 vibe --setup 启动配置向导来注册一个 Mistral API 密钥（来自 Mistral 控制台），或在你的环境中设置 MISTRAL_API_KEY。它也可以对接本地或兼容模型，完全离线运行。无论哪种方式，Open Design 都绝不会代理转发你的凭据。"}, {"name": "Vibe CLI 具体好在哪里、为什么适合做设计？", "text": "它是一个 Apache-2.0、原生支持 ACP 的代理，由 Mistral 开放权重的 Devstral 编码模型驱动——因此你可以在本地运行它来处理注重隐私的工作，并在一个真实的代码库中跨文件编辑。但审美仍然来自你提供的设计系统、skill 和参考素材。"}, {"name": "做前端设计，选 Vibe CLI 还是 Claude Code？", "text": "两者都很强。Claude Code 以具体的、理解代码库的设计决策著称；Vibe CLI 的优势在于可在本地运行的开放权重 Devstral 技术栈以及 Apache-2.0 许可证。很多团队两者都用——Open Design 让你可以切换代理而无需改变你的设计工作流。"}, {"name": "我该如何把 Vibe CLI 连接到 Figma？", "text": "在你的 config.toml 中以 [[mcp_servers]] 条目的形式添加 Figma MCP 服务器。Vibe 随后就能拉取真实的设计上下文——组件、变量、布局数据——从而让生成的代码匹配源文件，而不是近似地凑出来。"}, {"name": "Open Design 与 Mistral AI 有关联吗？", "text": "没有。Mistral Vibe CLI 是 Mistral AI 的产品；Open Design 是一个独立的开源项目，以一等适配器的形式支持它，并通过 ACP 来驱动。Mistral 是 Mistral AI 的商标。"}, {"name": "我的文件和凭据安全吗？", "text": "安全——Open Design 本地优先且采用 Apache-2.0。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的 Mistral 凭据由你的代理直接使用，绝不经由 Open Design 的服务器转发。"}], "ctaTitle": "用 Mistral Vibe CLI 做设计，以开放的方式。", "ctaBody": "用你自己的 Mistral API 密钥或本地模型，把每个文件都留在本地，并围绕你已经在用的代理获得一套精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Vibe CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有受支持的代理"}, "aboutTitle": "Mistral Vibe CLI 是什么", "aboutBody": ["Mistral Vibe CLI 是 Mistral AI 推出的开源（Apache-2.0）终端编码代理。它会扫描你项目的文件和 Git 状态，根据自然语言任务编辑代码、搜索、运行命令并处理版本控制。", "它由 Mistral 的 Devstral 编码模型驱动——这是一个开放权重家族，你既可以在云端运行，也可以在本地运行——并且它支持 Agent Client Protocol（ACP）。", "Open Design 把 Vibe CLI 当作一等适配器，通过 vibe-acp 二进制文件经由 ACP 来驱动它，于是这个代理就嵌入到一条结构化、开源的设计管线中。"], "vendorLabel": "厂商", "vendor": "Mistral AI", "credentialLabel": "凭据", "credential": "Mistral API 密钥（BYOK）或本地模型", "designTitle": "用 Mistral Vibe CLI 做设计", "designLead": "Vibe CLI 的设计强项主要集中在它的开放权重技术栈和广泛的协议覆盖上：", "designPoints": [{"label": "Devstral 编码模型", "body": "编码调优的代理式模型会在一个真实的前端代码库中跨文件编辑，而不是产出孤立的代码片段。"}, {"label": "开放权重且对本地友好", "body": "Devstral Small 2 可以跑在消费级硬件上，因此设计工作可以完全保持在本地和离线状态。"}, {"label": "config.toml + MCP", "body": "项目配置承载着代理如何接入；Figma MCP 服务器把真实的设计上下文带进代码。"}, {"label": "开放且原生支持 ACP", "body": "采用 Apache-2.0，构建于 Agent Client Protocol 之上，并通过 Mistral API 支持 BYOK。"}], "linksTitle": "真实世界的资源", "linksLead": "Mistral Vibe CLI 的官方仓库、发布公告和文档：", "links": [{"label": "mistralai/mistral-vibe（GitHub）", "href": "https://github.com/mistralai/mistral-vibe", "source": "GitHub · Mistral AI"}, {"label": "Devstral 2 与 Mistral Vibe CLI 发布介绍", "href": "https://mistral.ai/news/devstral-2-vibe-cli/", "source": "News · Mistral AI"}, {"label": "Mistral Vibe 文档", "href": "https://mistral.ai/products/vibe/code/", "source": "Docs · Mistral AI"}], "withOdTitle": "Mistral Vibe CLI + Open Design", "withOdLead": "Open Design 是围绕 Vibe CLI 的开源设计层：一个精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design 并选择 Mistral Vibe CLI 作为你的代理。", "用你的 Mistral API 密钥（BYOK）或本地模型进行认证——凭据留在你的机器上。", "选择一个设计系统和一个 skill，然后以一致的审美生成演示稿、原型和落地页。", "产物和 DESIGN.md 文件都存在你自己的仓库里，而不是某个托管云端。"], "withOdClosing": "同一个 Vibe CLI 代理——外加一套围绕它的真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是 Mistral AI 做的吗？", "text": "不是。Mistral Vibe CLI 是 Mistral AI 的产品；Open Design 是一个独立的开源项目，以一等适配器的形式通过 ACP 集成它。"}, {"name": "我需要一个 Mistral API 密钥吗？", "text": "你可以用自己的 Mistral API 密钥（BYOK），也可以让 Vibe 对接本地模型完全离线运行。Open Design 绝不会代理转发你的凭据。"}, {"name": "Open Design 与 Mistral AI 有关联吗？", "text": "没有。Open Design 是独立的；Mistral 是 Mistral AI 的商标。"}], "ctaTitle": "用 Mistral Vibe CLI 做设计，以开放的方式。", "ctaBody": "给仓库点个 Star、下载桌面应用，或加入社区来申请一个适配器。"},
  qoder: {"title": "用 Qoder CLI 做设计 — Open Design", "description": "人们如何用 Qoder CLI——阿里巴巴的智能体编码平台——来做 UI 与网页设计：它的 agent 与 quest 模式、深度的仓库理解与 repo wiki，以及 Lite/Efficient/Auto 模型档位——以及 Open Design 如何把 Qoder CLI 变成一个本地优先、开源的设计智能体。", "breadcrumb": "Qoder CLI", "label": "Agent · Qoder CLI", "heading": "用 Qoder CLI 做设计。", "lead": "Qoder CLI 是 Qoder——阿里巴巴的智能体编码平台——的终端智能体。它理解整个仓库——架构、模式以及在 repo wiki 中沉淀下来的约定——并以规范驱动的方式自主完成工作，这让它在你给出参考、约定与验证闭环之后，成为一个真正的设计工具。Open Design 把它接入开源设计工作流：你的 Qoder 账户、你的文件，本地优先。", "tldrTitle": "TL;DR", "tldrBody": "Qoder CLI 把 Qoder 那套智能体化、懂仓库的引擎带到终端——规范驱动的 quest、深度的代码库理解，以及 Lite/Efficient/Auto 模型档位，用 Qoder 账户登录。Open Design 在它之上提供精选的设计系统与 skill 库，外加一套桌面工作流——让一切都保留在本地。", "toc": ["什么是 Qoder CLI", "用 Qoder CLI 做设计", "资源", "搭配 Open Design", "常见问题"], "rich": {"heroCtaLead": "Open Design 把 Qoder CLI 变成一个本地优先、开源的设计智能体——你的 Qoder 账户、你的文件，外加一套围绕它的精选 skill 与设计系统库。", "heroCtaActions": [{"label": "在 Open Design 中使用 Qoder CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qoder CLI 是 Qoder——阿里巴巴的智能体编码平台——的终端智能体。有两点让它在设计上格外值得关注：它会建立起对你仓库的深度上下文——架构、设计模式，以及它提炼进 repository wiki 的约定——因此它复用你真实的基础组件，而不是为每个界面发明一次性的样式；它还会运行规范驱动、自主的 quest，对一项任务从头到尾地规划、实现并验证，而不只是补全代码行。配上合适的参考、约定与验证闭环，它能构建出真实、响应式的 UI。这是一份实用的端到端指南，讲如何用 Qoder CLI 做 UI、前端与设计系统的工作，以及如何用 Open Design 把它接入一套结构化的设计工作流。", "它涵盖了 Qoder CLI 究竟是什么、为什么它的仓库理解与智能体化 quest 契合设计、如何从零搭建、参考图到 UI 的闭环、规则/MCP 与 repo wiki 如何扩展它、它与 Codex、Claude Code、Cursor 和 Gemini CLI 的对比、那些让 AI 产出显得千篇一律的坑，以及 Open Design 如何作为一层开放、本地优先的设计层，弥合你已在使用的智能体与真正设计之间的差距。"], "heroImage": {"src": "/agents/qoder-design/qoder-design-hero.webp", "alt": "Qoder CLI 设计反馈闭环：一个终端智能体借助 repo-wiki 上下文读取一张参考图，一个浏览器渲染 UI，以及一个工作区，一条反馈箭头回环", "caption": "核心闭环：Qoder CLI 在终端读取你的参考与仓库上下文，在真实浏览器中构建并验证 UI，并对照它们持续迭代。"}, "tocLabel": "本页内容", "toc": [{"id": "what-is-qoder", "label": "Qoder CLI 究竟是什么"}, {"id": "why-design", "label": "为什么智能体化 + 仓库上下文契合设计"}, {"id": "setup", "label": "从零搭建用于设计的 Qoder CLI"}, {"id": "screenshot-workflow", "label": "参考图到 UI 的工作流"}, {"id": "extend", "label": "规则、MCP 与 repo wiki"}, {"id": "vs", "label": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "坑，以及“AI 味”观感"}, {"id": "open-design", "label": "在 Open Design 中用 Qoder CLI 做设计"}, {"id": "faq", "label": "常见问题"}], "sections": [{"id": "what-is-qoder", "heading": "Qoder CLI 究竟是什么", "blocks": [{"kind": "p", "text": "Qoder 是阿里巴巴推出的智能体编码平台——一个 AI 开发环境，既有桌面应用也有 CLI，能理解真实的代码库并端到端地完成开发任务。Qoder CLI 把这套引擎带到了终端：它读取你的仓库、编辑文件、运行 shell 命令，并从自然语言出发完成任务，而不只是补全代码行。它用 Qoder 账户登录。"}, {"kind": "p", "text": "对于设计工作，有两个特性尤为突出。Qoder 会建立起对你仓库的深度上下文——架构、设计模式，以及提炼进 repository wiki 的约定——因此它把产出锚定在你真实的基础组件上。它还运行一套智能体化、规范驱动的工作流：你勾勒出想要的东西，它便规划、实现并验证这项工作，包括跨多个步骤。"}, {"kind": "steps", "items": [{"label": "Agent 与 Quest 模式", "body": "Agent 模式是带人类介入检查点的对话式结对编程；Quest 模式则把更长的多步工作委派给一个自主智能体，由它规划、实现并自我验证——这正是交付一项规范驱动设计任务的天然落点。"}, {"label": "Repo wiki + MCP", "body": "Qoder 把你的代码库提炼成一份记录架构与约定的 repository wiki，并支持 MCP 服务器以引入外部上下文，比如一个实时的 Figma 文件。"}, {"label": "模型档位", "body": "Qoder CLI 提供 Lite、Efficient 和 Auto 三档；Auto 让它的调度器按任务挑选模型，这样你就无需手动管理模型选择。"}]}, {"kind": "ul", "items": ["厂商：Alibaba", "凭证：Qoder 账户（通过浏览器登录，或用 Qoder 个人访问令牌进行非交互式使用）", "模型档位：Lite、Efficient、Auto"]}]}, {"id": "why-design", "heading": "为什么一个智能体化、懂仓库的智能体契合设计", "blocks": [{"kind": "p", "text": "Qoder CLI 在设计上的优势来自两个特性——但和每个智能体一样，品味仍然得由人来提供。"}, {"kind": "steps", "items": [{"label": "深度的仓库理解", "body": "因为 Qoder 会建立起对你整个代码库的上下文并提炼成一份 repo wiki，智能体会复用你已有的组件和 tokens，而不是为每个界面发明一次性的样式。"}, {"label": "规范驱动、自主的 quest", "body": "Quest 模式把一份书面规范变成一个经过规划、实现并自我验证的结果，于是一项设计任务能端到端地跑完，而不是停在初稿。"}, {"label": "智能体会读取的约定", "body": "项目规则（再加上 Figma MCP 服务器）把智能体指向你的 tokens、组件和真实规范，于是它对着一个品牌工作，而不是一种默认观感。"}]}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-taste-triangle.webp", "alt": "图示：设计系统、skill 与参考图汇聚成优质的设计产出", "caption": "品味来自你提供的三项输入：一个设计系统、一个 skill，以及真实的参考图。"}, {"kind": "p", "text": "这个教训和每个智能体教给我们的一样：Qoder CLI 默认并不具备品味。当你给它约束——一个设计系统、一个审美 skill 和具体的参考——它才产出优质的设计。Open Design 恰恰把这些输入打包好了，这也是为什么两者契合（下文细说）。"}]}, {"id": "setup", "heading": "从零搭建用于设计工作的 Qoder CLI", "blocks": [{"kind": "p", "text": "这里是从一台干净的机器到一个能构建并验证 UI 的 Qoder CLI 的完整路径。"}, {"kind": "code", "lang": "bash", "code": "# 1. 安装 Qoder CLI（Node 20+）\nnpm install -g @qoder-ai/qodercli\n# （macOS/Linux 也可通过 Homebrew 安装）\n\n# 2. 验证安装\nqodercli --version\n\n# 3. 在你的项目里启动它，首次运行时登录\ncd your-project\nqodercli          # 然后 /login — 通过浏览器或 Qoder 访问令牌登录\n\n# 4. 为本次会话挑选一个模型档位\n#    Lite、Efficient 或 Auto（Auto 让调度器按任务选择）"}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-setup-flow.webp", "alt": "五步搭建流程：安装、认证、配置规则、添加 skill、验证", "caption": "搭建顺序：安装 → 登录 → 配置项目规则 → 添加 skill → 启用浏览器验证。"}, {"kind": "steps", "items": [{"label": "把你的设计规则写下来", "body": "把你的 tokens、基础组件和约定放在智能体会读取的地方，让产出贴合一个品牌，而不是退回到一种通用观感。Qoder 的 repo wiki 有助于让这份上下文保持最新。"}, {"label": "加上浏览器验证", "body": "接入一个 Playwright 或浏览器 MCP，让 Qoder 在真实浏览器中渲染，并跨断点检查其产出，而不只是确认构建通过。"}]}]}, {"id": "screenshot-workflow", "heading": "参考图到 UI 的工作流", "blocks": [{"kind": "p", "text": "用 Qoder CLI 最具杠杆效应的设计闭环，是把一张参考变成可用、响应式的 UI，并不断迭代直到它匹配为止——借助智能体的仓库上下文和一个真实的验证闭环，把产出对照回参考。"}, {"kind": "ol", "items": ["从你手上最清晰的视觉参考出发——并包含多种状态（桌面与移动端、悬停、空态、加载态），而不只是一张主视觉。", "在 prompt 里讲清楚；模糊的 prompt 即便配上能干的智能体也会产出通用的 UI。", "把 Qoder 指向你的设计系统和约定，并告诉它 tokens 和规范基础组件存放在哪里。", "跑一个 dev 服务器，让 Qoder 在真实浏览器中渲染，调整到各断点尺寸来检查结果。", "让 Qoder 把它的实现对照回参考来迭代——而不只是确认它能构建通过。"]}, {"kind": "p", "text": "把任务写成一份清晰的规范，让一个 quest 把它贯穿到底，并给出具体约束："}, {"kind": "code", "lang": "bash", "code": "qodercli\n# 在 prompt 里：\n> Implement this design from reference-desktop.png and\n  reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "保持 prompt 小而聚焦，提交好的迭代、回退坏的迭代（回退时告诉 Qoder），让每一轮都建立在一个干净的基底之上。"}]}, {"id": "extend", "heading": "规则、MCP 与 repo wiki", "blocks": [{"kind": "p", "text": "有三个扩展点让 Qoder CLI 适合持续的设计工作，而这三者都能干净利落地映射到一套开放的设计工作流上。"}, {"kind": "steps", "items": [{"label": "项目规则", "body": "把你的设计约定编码为智能体每次运行都会读取的持久项目规则——这是 tokens、基础组件和评审清单的归处。"}, {"label": "MCP 服务器", "body": "MCP 是引入设计上下文和外部工具的可移植方式，其中最相关的是 Figma MCP 服务器，而且它跨智能体可用，不只限于 Qoder。"}, {"label": "repo wiki", "body": "Qoder 的 repository wiki 会自动提炼架构与约定，于是智能体能持续复用你真实的组件，而不必每个任务都重新学习一遍代码库。"}]}, {"kind": "p", "text": "这些都是可移植、跨智能体的能力——恰恰是 Open Design 生来要编排的那类东西，而不是每个项目都重新造一遍。"}]}, {"id": "vs", "heading": "做设计时 Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI", "blocks": [{"kind": "p", "text": "做设计没有单一赢家——每个智能体各有所长，有经验的团队会把它们叠加使用。一个公允的小结："}, {"kind": "table", "columns": ["智能体", "设计强项", "最适合"], "rows": [["Qoder CLI", "带 repo wiki 的深度仓库理解，以及规范驱动、自主的 quest；Lite/Efficient/Auto 档位", "仓库上下文密集的工作，以及委派多步、规范驱动的构建"], ["Codex", "凭前端 skill 带来过硬的视觉打磨；沙箱化异步构建", "委派的异步构建与可移植的 AGENTS.md 规则"], ["Claude Code", "具体的设计决策（色值、间距、字体）与懂代码库的 UX", "前端推理与大上下文重构"], ["Cursor", "带实时预览和内联编辑的可视化“边建边看”闭环", "在 IDE 内紧密迭代、边看边改的 UI 工作"], ["Gemini CLI", "过硬的多模态图像理解与 100 万 token 的上下文；有免费档", "截图密集的工作，以及把整个设计系统放进上下文"]]}, {"kind": "p", "text": "社区反复得出的结论是：品味来自人类——没有 skill、参考和约束，它们全都会退回到一种通用审美。这才是真正要解决的问题——而它是设计工具形状的，不是模型形状的。"}]}, {"id": "pitfalls", "heading": "坑，以及如何避开“AI 味”观感", "blocks": [{"kind": "p", "text": "关于 AI 生成设计最常见的抱怨是它看起来千篇一律——柔和渐变、悬浮面板、过大的圆角、夸张的阴影，一种“一眼就知道是 AI 做的”的 Inter 配紫色既视感。其他被反映的问题还包括移动端布局错乱，以及指令文字泄漏进 UI 文案。这些都不是 Qoder CLI 独有的；任何智能体在没有精选设计上下文的情况下运行，都会这样。"}, {"kind": "steps", "items": [{"label": "加一个审美 skill", "body": "一个精选的设计 skill 会迫使智能体承诺一个真实的方向，而不是那种默认观感。"}, {"label": "在真实浏览器中验证", "body": "跨断点渲染并自检，这样布局就不会在移动端悄无声息地崩掉。"}, {"label": "提供 tokens 与参考", "body": "真实的设计 tokens 和参考截图，是撬动产出质量的最大单一杠杆。"}, {"label": "编码智能体会读取的规则", "body": "把“不要主视觉卡片、最多两种字体、品牌优先的层级”这类规则放进项目规则和 repo wiki，智能体每次运行都会读到它们。"}]}, {"kind": "p", "text": "注意，每一项缓解措施都关乎给智能体一份精选的设计上下文。逐个项目手工维护这份上下文，正是 Open Design 替你省掉的苦活。"}]}, {"id": "open-design", "heading": "在 Open Design 中用 Qoder CLI 做设计", "blocks": [{"kind": "p", "text": "Open Design 正是上文那套工作流一再呼唤的开源设计层。它把 Qoder CLI 当作一等适配器，并用一个精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI 把它包裹起来——于是让 Qoder 出色的那份设计上下文从第一次运行起就在那里，而不必每次手工拼凑。Open Design 是本地优先的，所以你的工作留在你自己的机器上。"}, {"kind": "ol", "items": ["安装 Open Design 并选择 Qoder CLI 作为你的智能体。", "用你的 Qoder 账户认证——凭证留在你的机器上，绝不经我们代理。", "挑一个设计系统和一个 skill，然后以一致的品味生成演示稿、原型与落地页。", "每个产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管云端。"]}, {"kind": "p", "text": "同一个 Qoder CLI 智能体、同一个账户——再加上一套围绕它的、真实、可移植、开源的设计工作流。它本地优先且采用 Apache-2.0 许可，所以你的工作或凭证没有任何东西会离开你的机器。"}]}], "faqTitle": "常见问题", "faq": [{"name": "Qoder CLI 真的能做设计工作吗？", "text": "能——在上下文中配上一个审美 skill、一个设计系统和真实的参考图，Qoder CLI 能产出生产级、响应式的 UI，而它深度的仓库理解能帮它复用你真实的组件。没有这份上下文，它往往会退回到一种通用观感，而这正是 Open Design 填补的差距。"}, {"name": "我该如何认证 Qoder CLI？", "text": "运行 qodercli 并用 /login 通过浏览器以你的 Qoder 账户登录，或为非交互式环境提供一个 Qoder 个人访问令牌。Open Design 从不代理你的凭证——智能体直接使用它们。"}, {"name": "究竟是什么让 Qoder CLI 适合做设计？", "text": "两点：它会建立起对你仓库的深度上下文——架构、约定和一份 repo wiki——所以它复用你真实的基础组件；它的规范驱动 quest 能端到端地跑完一项设计任务。两者都有帮助，但品味仍然来自你提供的设计系统、skill 和参考。"}, {"name": "Lite、Efficient 和 Auto 模型档位是什么？", "text": "Qoder CLI 让你挑选一个模型档位：Lite、Efficient 或 Auto。Auto 让 Qoder 的调度器按任务选择模型，这样你就无需手动管理模型选择。挑选契合任务的档位；Auto 是个稳妥的默认值。"}, {"name": "我该如何把 Qoder CLI 连到 Figma？", "text": "把 Figma MCP 服务器加进 Qoder 的 MCP 配置里。Qoder 随后就能拉取真实的设计上下文——组件、变量、布局数据——于是生成的代码贴合来源，而不是近似它。"}, {"name": "Open Design 与 Qoder 或 Alibaba 有关联吗？", "text": "没有。Qoder 是 Alibaba 的产品；Open Design 是一个独立的开源项目，以一等适配器的方式支持它。Qoder 是其各自所有者的商标。"}, {"name": "我的文件和凭证安全吗？", "text": "安全——Open Design 本地优先且采用 Apache-2.0 许可。你的文件、产物和 DESIGN.md 都留在你自己的仓库里，你的 Qoder 凭证由你的智能体直接使用，绝不会经过 Open Design 的服务器中转。"}], "ctaTitle": "用开放的方式，借 Qoder CLI 做设计。", "ctaBody": "带上你自己的 Qoder 账户，让每个文件都留在本地，并围绕你已在使用的智能体获得一个精选的设计库。", "ctaActions": [{"label": "在 Open Design 中使用 Qoder CLI", "href": "/quickstart/", "variant": "primary"}, {"label": "在 GitHub 上 Star", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "下载桌面应用", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "查看所有支持的智能体"}, "aboutTitle": "什么是 Qoder CLI", "aboutBody": ["Qoder 是阿里巴巴的智能体编码平台——一个 AI 开发环境，既有桌面应用也有 CLI。Qoder CLI 把这套引擎带到终端：它读取你的代码库、编辑文件、运行命令，并从自然语言出发完成任务。", "它会建立起对你仓库的深度上下文——提炼成一份 repo wiki——并运行规范驱动、自主的 quest，配有 Lite/Efficient/Auto 模型档位。", "Open Design 把 Qoder CLI 当作一等适配器，于是这个智能体能嵌入一条结构化、开源的设计管线。"], "vendorLabel": "厂商", "vendor": "Alibaba", "credentialLabel": "凭证", "credential": "Qoder 账户", "designTitle": "用 Qoder CLI 做设计", "designLead": "Qoder CLI 的设计强项集中在它的仓库上下文与智能体化工作流上：", "designPoints": [{"label": "深度的仓库理解", "body": "对架构与约定的上下文——提炼成一份 repo wiki——于是产出复用你真实的组件和 tokens。"}, {"label": "规范驱动的 quest", "body": "Quest 模式把一份书面规范变成一个经过规划、实现并自我验证的结果，端到端完成。"}, {"label": "规则 + MCP", "body": "项目规则承载你的约定；Figma MCP 服务器把真实的设计上下文带进代码。"}, {"label": "Lite / Efficient / Auto", "body": "每次会话挑选一个模型档位；Auto 让 Qoder 的调度器按任务选择模型。"}], "linksTitle": "真实世界的资源", "linksLead": "Qoder 与 Qoder CLI 的官方站点和文档：", "links": [{"label": "Qoder — 智能体编码平台", "href": "https://qoder.com", "source": "Qoder · Alibaba"}, {"label": "Qoder 文档", "href": "https://docs.qoder.com", "source": "Docs · Qoder"}, {"label": "Qoder CLI — 快速开始", "href": "https://docs.qoder.com/en/cli/quick-start", "source": "Docs · Qoder"}], "withOdTitle": "Qoder CLI + Open Design", "withOdLead": "Open Design 是围绕 Qoder CLI 的开源设计层：一个精选的 skill 与设计系统库、一条结构化的渲染管线，以及一个本地桌面 UI。", "withOdSteps": ["安装 Open Design 并选择 Qoder CLI 作为你的智能体。", "用你的 Qoder 账户认证——凭证留在你的机器上。", "选择一个设计系统和 skill，然后以一致的品味生成演示稿、原型与落地页。", "产物和 DESIGN.md 文件都存在你自己的仓库里，而不是托管云端。"], "withOdClosing": "同一个 Qoder CLI 智能体——再加上一套围绕它的、真实、可移植的设计工作流。", "faqTitle": "常见问题", "faq": [{"name": "Open Design 是阿里巴巴做的吗？", "text": "不是。Qoder 是 Alibaba 的产品；Open Design 是一个独立的开源项目，以一等适配器的方式集成它。"}, {"name": "登录我需要什么？", "text": "一个 Qoder 账户——通过浏览器或 Qoder 访问令牌登录。Open Design 从不代理你的凭证。"}, {"name": "Open Design 与 Qoder 有关联吗？", "text": "没有。Open Design 是独立的；Qoder 是其各自所有者的商标。"}], "ctaTitle": "用开放的方式，借 Qoder CLI 做设计。", "ctaBody": "给仓库点个 Star、下载桌面应用，或加入社区来申请一个适配器。"},
};
